def _normalize_adoption_project_reset_scopes(value: Any) -> list[str]:
    requested = value if isinstance(value, list) else []
    out: list[str] = []
    seen: set[str] = set()
    valid_scopes = set(_ADOPTION_PROJECT_RESET_SCOPE_ORDER)
    for item in requested:
        scope = str(item or "").strip().lower()
        if not scope or scope not in valid_scopes or scope in seen:
            continue
        out.append(scope)
        seen.add(scope)
    if not out:
        out = list(_ADOPTION_PROJECT_RESET_DEFAULT_SCOPES)
        seen = set(out)
    changed = True
    while changed:
        changed = False
        for scope in list(out):
            for dependency in _ADOPTION_PROJECT_RESET_SCOPE_DEPENDENCIES.get(scope, ()):
                if dependency in valid_scopes and dependency not in seen:
                    out.append(dependency)
                    seen.add(dependency)
                    changed = True
    order = {scope: idx for idx, scope in enumerate(_ADOPTION_PROJECT_RESET_SCOPE_ORDER)}
    out.sort(key=lambda scope: order.get(scope, 999))
    return out


def _count_orphan_draft_pages(conn, *, project_id: str) -> int:
    required = ("wiki_pages", "wiki_draft_changes", "wiki_statements")
    if not all(_public_table_exists(conn, table_name) for table_name in required):
        return 0
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT COUNT(*)::bigint
            FROM wiki_pages p
            WHERE p.project_id = %s
              AND p.status = 'draft'
              AND COALESCE(p.metadata->>'mode', '') = 'draft_generation'
              AND NOT EXISTS (
                SELECT 1
                FROM wiki_draft_changes d
                WHERE d.page_id = p.id
              )
              AND NOT EXISTS (
                SELECT 1
                FROM wiki_statements s
                WHERE s.page_id = p.id
              )
            """,
            (project_id,),
        )
        row = cur.fetchone()
    return int((row[0] if row else 0) or 0)


def _cleanup_orphan_draft_pages(conn, *, project_id: str) -> int:
    required = ("wiki_pages", "wiki_draft_changes", "wiki_statements")
    if not all(_public_table_exists(conn, table_name) for table_name in required):
        return 0
    with conn.cursor() as cur:
        cur.execute(
            """
            DELETE FROM wiki_pages p
            WHERE p.project_id = %s
              AND p.status = 'draft'
              AND COALESCE(p.metadata->>'mode', '') = 'draft_generation'
              AND NOT EXISTS (
                SELECT 1
                FROM wiki_draft_changes d
                WHERE d.page_id = p.id
              )
              AND NOT EXISTS (
                SELECT 1
                FROM wiki_statements s
                WHERE s.page_id = p.id
              )
            """,
            (project_id,),
        )
        return int(cur.rowcount or 0)


def _collect_adoption_project_reset_preview(
    conn,
    *,
    project_id: str,
    scopes: list[str],
    cascade_cleanup_orphan_draft_pages: bool = False,
) -> dict[str, Any]:
    plan_by_scope = _adoption_project_reset_scope_plan()
    preview_scopes: list[dict[str, Any]] = []
    totals: dict[str, int] = {}
    with conn.cursor() as cur:
        for scope in scopes:
            operations = plan_by_scope.get(scope, [])
            scope_total = 0
            rows: list[dict[str, Any]] = []
            for operation in operations:
                table_key = str(operation.get("table_key") or "unknown")
                required_tables = [str(item) for item in (operation.get("required_tables") or []) if str(item).strip()]
                available = bool(required_tables) and all(_public_table_exists(conn, name) for name in required_tables)
                count_value = 0
                if available:
                    cur.execute(str(operation["count_sql"]), (project_id,))
                    count_row = cur.fetchone()
                    count_value = int((count_row[0] if count_row else 0) or 0)
                rows.append(
                    {
                        "table": table_key,
                        "available": available,
                        "rows": count_value,
                    }
                )
                scope_total += count_value
                totals[table_key] = int(totals.get(table_key, 0)) + count_value
            preview_scopes.append({"scope": scope, "rows_total": scope_total, "tables": rows})
    response = {
        "scopes": preview_scopes,
        "totals": {
            "rows_total": int(sum(item["rows_total"] for item in preview_scopes)),
            "tables": totals,
        },
    }
    if bool(cascade_cleanup_orphan_draft_pages):
        orphan_rows = _count_orphan_draft_pages(conn, project_id=project_id)
        response["cascade_cleanup"] = {
            "orphan_draft_pages": orphan_rows,
            "enabled": True,
        }
    return response


def _apply_adoption_project_reset(
    conn,
    *,
    project_id: str,
    scopes: list[str],
    cascade_cleanup_orphan_draft_pages: bool = False,
) -> dict[str, int]:
    plan_by_scope = _adoption_project_reset_scope_plan()
    deleted: dict[str, int] = {}
    with conn.cursor() as cur:
        for scope in scopes:
            for operation in plan_by_scope.get(scope, []):
                table_key = str(operation.get("table_key") or "unknown")
                required_tables = [str(item) for item in (operation.get("required_tables") or []) if str(item).strip()]
                available = bool(required_tables) and all(_public_table_exists(conn, name) for name in required_tables)
                if not available:
                    continue
                cur.execute(str(operation["delete_sql"]), (project_id,))
                deleted[table_key] = int(deleted.get(table_key, 0)) + int(cur.rowcount or 0)
    if bool(cascade_cleanup_orphan_draft_pages):
        removed = _cleanup_orphan_draft_pages(conn, project_id=project_id)
        if removed > 0:
            deleted["wiki_pages_orphan_draft_cleanup"] = int(deleted.get("wiki_pages_orphan_draft_cleanup", 0)) + removed
    return deleted


def _insert_adoption_project_reset_audit(
    conn,
    *,
    reset_id: UUID,
    project_id: str,
    requested_by: str,
    reason: str | None,
    scopes: list[str],
    dry_run: bool,
    status: str,
    rows_preview: dict[str, Any],
    rows_deleted: dict[str, Any],
    error_message: str | None = None,
) -> None:
    with conn.cursor() as cur:
        cur.execute(
            """
            INSERT INTO adoption_project_resets (
              id,
              project_id,
              requested_by,
              reason,
              scopes,
              dry_run,
              status,
              rows_preview,
              rows_deleted,
              error_message,
              created_at
            )
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NOW())
            """,
            (
                reset_id,
                project_id,
                requested_by,
                reason,
                Jsonb(scopes),
                bool(dry_run),
                status,
                Jsonb(rows_preview),
                Jsonb(rows_deleted),
                error_message,
            ),
        )


def _normalize_adoption_bootstrap_profile(value: Any) -> str:
    profile = str(value or "").strip().lower()
    if profile in _ADOPTION_BOOTSTRAP_PROFILE_ORDER:
        return profile
    return _ADOPTION_BOOTSTRAP_PROFILE_ORDER[0]


def _build_adoption_bootstrap_profile_target_config(
    *,
    profile: str,
    current_config: dict[str, Any],
) -> dict[str, Any]:
    normalized_profile = _normalize_adoption_bootstrap_profile(profile)
    current = current_config if isinstance(current_config, dict) else {}
    target = dict(current)
    routing_current = _normalize_gatekeeper_routing_policy(current.get("routing_policy"))
    routing_target = dict(routing_current)
    routing_target.update(_ADOPTION_BOOTSTRAP_PROFILE_ROUTING_OVERRIDES.get(normalized_profile, {}))
    target.update(_ADOPTION_BOOTSTRAP_PROFILE_CONFIG_OVERRIDES.get(normalized_profile, {}))
    target["routing_policy"] = routing_target
    return target


def _build_adoption_bootstrap_profile_diff(
    *,
    current_config: dict[str, Any],
    target_config: dict[str, Any],
) -> dict[str, Any]:
    current = current_config if isinstance(current_config, dict) else {}
    target = target_config if isinstance(target_config, dict) else {}
    top_level_keys = [
        "min_sources_for_golden",
        "conflict_free_days",
        "min_score_for_golden",
        "publish_mode_default",
        "auto_publish_min_score",
        "auto_publish_min_sources",
        "auto_publish_require_golden",
        "auto_publish_allow_conflicts",
    ]
    top_level: dict[str, dict[str, Any]] = {}
    for key in top_level_keys:
        old = current.get(key)
        new = target.get(key)
        if old != new:
            top_level[key] = {"current": old, "target": new}

    routing_current = _normalize_gatekeeper_routing_policy(current.get("routing_policy"))
    routing_target = _normalize_gatekeeper_routing_policy(target.get("routing_policy"))
    routing_keys = [
        "require_multi_source_for_wiki",
        "min_sources_for_wiki_candidate",
        "min_evidence_for_wiki_candidate",
        "min_durable_signal_hits",
        "min_durable_signal_hits_for_backfill",
        "backfill_requires_policy_signal",
        "allow_policy_or_incident_override",
    ]
    routing: dict[str, dict[str, Any]] = {}
    for key in routing_keys:
        old = routing_current.get(key)
        new = routing_target.get(key)
        if old != new:
            routing[key] = {"current": old, "target": new}

    return {
        "top_level": top_level,
        "routing_policy": routing,
        "changed_keys": {
            "top_level": sorted(top_level.keys()),
            "routing_policy": sorted(routing.keys()),
        },
    }


def _adoption_bootstrap_profile_gatekeeper_excerpt(config: dict[str, Any]) -> dict[str, Any]:
    routing = _normalize_gatekeeper_routing_policy(config.get("routing_policy"))
    return {
        "min_sources_for_golden": config.get("min_sources_for_golden"),
        "conflict_free_days": config.get("conflict_free_days"),
        "min_score_for_golden": config.get("min_score_for_golden"),
        "publish_mode_default": config.get("publish_mode_default"),
        "auto_publish_min_score": config.get("auto_publish_min_score"),
        "auto_publish_min_sources": config.get("auto_publish_min_sources"),
        "auto_publish_require_golden": config.get("auto_publish_require_golden"),
        "auto_publish_allow_conflicts": config.get("auto_publish_allow_conflicts"),
        "routing_policy": {
            "require_multi_source_for_wiki": routing.get("require_multi_source_for_wiki"),
            "min_sources_for_wiki_candidate": routing.get("min_sources_for_wiki_candidate"),
            "min_evidence_for_wiki_candidate": routing.get("min_evidence_for_wiki_candidate"),
            "min_durable_signal_hits": routing.get("min_durable_signal_hits"),
            "min_durable_signal_hits_for_backfill": routing.get("min_durable_signal_hits_for_backfill"),
            "backfill_requires_policy_signal": routing.get("backfill_requires_policy_signal"),
            "allow_policy_or_incident_override": routing.get("allow_policy_or_incident_override"),
        },
    }


def _coerce_int(value: Any, default: int) -> int:
    try:
        if isinstance(value, bool):
            return default
        if isinstance(value, int):
            return value
        if isinstance(value, float):
            return int(value)
        if isinstance(value, str):
            text = value.strip()
            if text:
                return int(float(text))
    except Exception:
        return default
    return default


def _coerce_float(value: Any, default: float) -> float:
    try:
        if isinstance(value, bool):
            return default
        if isinstance(value, (int, float)):
            return float(value)
        if isinstance(value, str):
            text = value.strip()
            if text:
                return float(text)
    except Exception:
        return default
    return default


def _coerce_bool(value: Any, default: bool) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    if isinstance(value, str):
        text = value.strip().lower()
        if text in {"1", "true", "yes", "y", "on"}:
            return True
        if text in {"0", "false", "no", "n", "off"}:
            return False
    return default


def _normalize_publish_mode(value: Any, *, default: str = "auto_publish") -> str:
    mode = str(value or "").strip().lower()
    if mode not in {"human_required", "conditional", "auto_publish"}:
        return default
    return mode


def _normalize_publish_mode_map(value: Any) -> dict[str, str]:
    if not isinstance(value, dict):
        return {}
    out: dict[str, str] = {}
    for raw_key, raw_mode in value.items():
        key = str(raw_key or "").strip().lower()
        if not key:
            continue
        out[key[:64]] = _normalize_publish_mode(raw_mode)
    return out


def _normalize_policy_keyword_list(value: Any, *, fallback: list[str], limit: int = 64) -> list[str]:
    if not isinstance(value, list):
        return list(fallback)
    out: list[str] = []
    seen: set[str] = set()
    for item in value:
        text = unicodedata.normalize("NFKC", str(item or "")).strip().lower()
        text = re.sub(r"\s+", " ", text)
        if not text:
            continue
        if len(text) > 96:
            text = text[:96]
        if text in seen:
            continue
        seen.add(text)
        out.append(text)
        if len(out) >= limit:
            break
    if not out:
        return list(fallback)
    return out


def _normalize_timezone_name(value: Any, *, default: str = "UTC") -> str:
    timezone_name = str(value or "").strip()
    if not timezone_name:
        return default
    try:
        ZoneInfo(timezone_name)
    except ZoneInfoNotFoundError:
        return default
    return timezone_name


