@app.get("/v1/meta/compatibility")
def get_meta_compatibility(
    web_build: str | None = Query(default=None),
) -> dict[str, Any]:
    contract = _load_api_web_compat_contract()
    minimum_web_build = str(contract.get("minimum_web_build") or "").strip()
    provided_web_build = str(web_build or "").strip()

    web_status = "not_provided"
    if provided_web_build:
        if minimum_web_build:
            cmp = _compare_version_strings(provided_web_build, minimum_web_build)
            web_status = "ok" if cmp >= 0 else "outdated"
        else:
            web_status = "unknown"

    return {
        "compatibility": contract,
        "web_build": provided_web_build or None,
        "web_build_status": web_status,
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/adoption/selfhost/consistency")
def get_selfhost_consistency_gate(
    web_build: str | None = Query(default=None),
    ui_profile: str | None = Query(default=None),
    route_path: str | None = Query(default=None),
) -> dict[str, Any]:
    compat = get_meta_compatibility(web_build=web_build)
    normalized_profile = str(ui_profile or "").strip().lower()
    normalized_route = str(route_path or "").strip().lower()
    checks: list[dict[str, Any]] = []

    checks.append(
        {
            "key": "web_build_compatibility",
            "status": "ok" if compat.get("web_build_status") in {"ok", "not_provided"} else "warning",
            "message": (
                "Web build is compatible with API contract."
                if compat.get("web_build_status") in {"ok", "not_provided"}
                else "Web build is below API minimum compatibility contract."
            ),
            "meta": {
                "web_build": compat.get("web_build"),
                "web_build_status": compat.get("web_build_status"),
                "minimum_web_build": (compat.get("compatibility") or {}).get("minimum_web_build"),
                "recommended_web_build": (compat.get("compatibility") or {}).get("recommended_web_build"),
            },
        }
    )

    profile_ok = normalized_profile in {"", "core", "core-only", "wiki", "wiki-first"}
    checks.append(
        {
            "key": "ui_profile_core",
            "status": "ok" if profile_ok else "warning",
            "message": "UI profile is wiki-first." if profile_ok else "UI profile is not core wiki-first.",
            "meta": {
                "ui_profile": normalized_profile or None,
                "expected_profiles": ["core", "core-only", "wiki", "wiki-first"],
            },
        }
    )

    route_ok = normalized_route in {"", "/wiki"} or normalized_route.startswith("/wiki/")
    checks.append(
        {
            "key": "route_is_wiki",
            "status": "ok" if route_ok else "warning",
            "message": "Route is wiki-first." if route_ok else "Route is not /wiki; users may land outside core workspace.",
            "meta": {
                "route_path": normalized_route or None,
                "expected_prefix": "/wiki",
            },
        }
    )

    warnings = [item for item in checks if item.get("status") != "ok"]
    return {
        "status": "ok" if not warnings else "warning",
        "checks": checks,
        "warnings_total": len(warnings),
        "recommendations": [
            "Set web route to `/wiki` for default entry.",
            "Run latest web build if compatibility status is outdated.",
            "Keep UI profile in core/wiki-first mode for self-host onboarding.",
        ],
        "generated_at": datetime.now(UTC).isoformat(),
    }


def _normalize_roles_list(values: list[str] | None) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for raw in values or []:
        role = str(raw or "").strip().lower()
        if not role or role in seen:
            continue
        seen.add(role)
        out.append(role[:64])
    return out[:32]


def _enterprise_readiness_table_presence(conn) -> list[dict[str, Any]]:
    table_specs = [
        ("tenants", "Tenant registry", True),
        ("tenant_memberships", "Tenant user memberships", True),
        ("tenant_projects", "Tenant project mapping", True),
        ("auth_sessions", "OIDC/auth sessions", True),
        ("access_policy_decisions", "RBAC decision audit", False),
        ("enterprise_idp_connections", "IdP/SAML bridge config", False),
        ("scim_api_tokens", "SCIM token store", False),
        ("scim_directory_users", "SCIM provisioned users", False),
    ]
    checks: list[dict[str, Any]] = []
    for table_name, label, required in table_specs:
        exists = _public_table_exists(conn, table_name)
        checks.append(
            {
                "table": table_name,
                "label": label,
                "required": required,
                "exists": bool(exists),
                "status": "ok" if exists else ("critical" if required else "warning"),
            }
        )
    return checks


def _enterprise_readiness_counts(conn, *, project_id: str | None = None) -> dict[str, Any]:
    counts: dict[str, Any] = {}
    with conn.cursor() as cur:
        if _public_table_exists(conn, "tenants"):
            cur.execute("SELECT COUNT(*)::bigint FROM tenants")
            row = cur.fetchone()
            counts["tenants"] = int(row[0] if row and row[0] is not None else 0)
        if _public_table_exists(conn, "tenant_memberships"):
            cur.execute("SELECT COUNT(*)::bigint FROM tenant_memberships")
            row = cur.fetchone()
            counts["tenant_memberships"] = int(row[0] if row and row[0] is not None else 0)
        if _public_table_exists(conn, "tenant_projects"):
            cur.execute("SELECT COUNT(*)::bigint FROM tenant_projects")
            row = cur.fetchone()
            counts["tenant_projects"] = int(row[0] if row and row[0] is not None else 0)
        if _public_table_exists(conn, "auth_sessions"):
            cur.execute("SELECT COUNT(*)::bigint FROM auth_sessions WHERE expires_at > NOW()")
            row = cur.fetchone()
            counts["active_auth_sessions"] = int(row[0] if row and row[0] is not None else 0)
        if _public_table_exists(conn, "enterprise_idp_connections"):
            cur.execute("SELECT COUNT(*)::bigint FROM enterprise_idp_connections WHERE status = 'active'")
            row = cur.fetchone()
            counts["active_idp_connections"] = int(row[0] if row and row[0] is not None else 0)
        if _public_table_exists(conn, "scim_api_tokens"):
            cur.execute(
                """
                SELECT COUNT(*)::bigint
                FROM scim_api_tokens
                WHERE status = 'active'
                  AND (expires_at IS NULL OR expires_at > NOW())
                """
            )
            row = cur.fetchone()
            counts["active_scim_tokens"] = int(row[0] if row and row[0] is not None else 0)
        if _public_table_exists(conn, "access_policy_decisions"):
            if project_id:
                cur.execute(
                    """
                    SELECT COUNT(*)::bigint
                    FROM access_policy_decisions
                    WHERE created_at >= NOW() - INTERVAL '24 hours'
                      AND %s = ANY(project_ids)
                    """,
                    (project_id,),
                )
            else:
                cur.execute(
                    """
                    SELECT COUNT(*)::bigint
                    FROM access_policy_decisions
                    WHERE created_at >= NOW() - INTERVAL '24 hours'
                    """
                )
            row = cur.fetchone()
            counts["rbac_decisions_24h"] = int(row[0] if row and row[0] is not None else 0)
    return counts


@app.get("/v1/auth/mode")
def get_auth_mode() -> dict[str, Any]:
    return enterprise.auth_mode_payload(enterprise.get_enterprise_settings())


@app.get("/v1/enterprise/readiness")
def get_enterprise_readiness(
    project_id: str | None = Query(default=None),
) -> dict[str, Any]:
    settings = enterprise.get_enterprise_settings()
    normalized_project_id = str(project_id or "").strip() or None
    with get_conn() as conn:
        table_checks = _enterprise_readiness_table_presence(conn)
        counts = _enterprise_readiness_counts(conn, project_id=normalized_project_id)

    warnings: list[dict[str, Any]] = []
    for check in table_checks:
        status = str(check.get("status") or "ok")
        if status == "ok":
            continue
        warnings.append(
            {
                "code": f"table_{check.get('table')}_missing",
                "severity": "critical" if bool(check.get("required")) else "warning",
                "message": f"{check.get('label')}: table `{check.get('table')}` is missing.",
            }
        )

    if settings.auth_mode == "oidc" and not bool(settings.oidc_issuer_url):
        warnings.append(
            {
                "code": "oidc_issuer_missing",
                "severity": "critical",
                "message": "SYNAPSE_AUTH_MODE=oidc requires SYNAPSE_OIDC_ISSUER_URL.",
            }
        )
    if settings.auth_mode == "oidc" and not bool(settings.oidc_audience):
        warnings.append(
            {
                "code": "oidc_audience_missing",
                "severity": "warning",
                "message": "SYNAPSE_OIDC_AUDIENCE is not set; token audience checks may be too permissive.",
            }
        )
    critical = [item for item in warnings if str(item.get("severity") or "").lower() == "critical"]
    status = "healthy"
    if critical:
        status = "critical"
    elif warnings:
        status = "warning"

    return {
        "status": status,
        "project_id": normalized_project_id,
        "auth": enterprise.auth_mode_payload(settings),
        "checks": table_checks,
        "counts": counts,
        "warnings": warnings,
        "summary": {
            "critical": len(critical),
            "warnings": len(warnings) - len(critical),
            "auth_mode": settings.auth_mode,
            "rbac_mode": settings.rbac_mode,
            "tenancy_mode": settings.tenancy_mode,
        },
        "recommendations": [
            "Use `SYNAPSE_AUTH_MODE=oidc` + enforce RBAC/tenancy for production tenants.",
            "Keep at least one active IdP connection and SCIM token for automated provisioning.",
            "Monitor `/v1/enterprise/rbac/decisions` for deny spikes after policy changes.",
        ],
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/enterprise/rbac/decisions")
def list_access_policy_decisions(
    project_id: str | None = Query(default=None),
    subject: str | None = Query(default=None),
    decision: str | None = Query(default=None),
    path_prefix: str | None = Query(default=None),
    limit: int = Query(default=100, ge=1, le=500),
    offset: int = Query(default=0, ge=0, le=50000),
) -> dict[str, Any]:
    normalized_project_id = str(project_id or "").strip()
    normalized_subject = str(subject or "").strip()
    normalized_decision = str(decision or "").strip().lower()
    normalized_path_prefix = str(path_prefix or "").strip()
    if normalized_decision and normalized_decision not in {"allow", "deny", "bypass"}:
        raise HTTPException(status_code=422, detail="rbac_audit_decision_invalid")

    filters: list[str] = []
    params: list[Any] = []
    if normalized_project_id:
        filters.append("%s = ANY(project_ids)")
        params.append(normalized_project_id)
    if normalized_subject:
        filters.append("subject ILIKE %s")
        params.append(f"%{normalized_subject[:256]}%")
    if normalized_decision:
        filters.append("decision = %s")
        params.append(normalized_decision)
    if normalized_path_prefix:
        filters.append("path ILIKE %s")
        params.append(f"{normalized_path_prefix[:256]}%")
    where_sql = f"WHERE {' AND '.join(filters)}" if filters else ""
    normalized_limit = normalize_limit_value(limit, default=100, minimum=1, maximum=500)
    normalized_offset = max(0, int(offset))

    with get_conn() as conn:
        if not _access_policy_decisions_table_exists(conn):
            raise HTTPException(status_code=503, detail="rbac_audit_table_missing")
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT COUNT(*)::bigint
                FROM access_policy_decisions
                {where_sql}
                """,
                tuple(params),
            )
            total_row = cur.fetchone()
            total = int(total_row[0] if total_row and total_row[0] is not None else 0)
            cur.execute(
                f"""
                SELECT
                  id::text,
                  created_at,
                  subject,
                  email,
                  tenant_id,
                  auth_source,
                  method,
                  path,
                  route_action,
                  project_ids,
                  decision,
                  deny_code,
                  required_roles,
                  actor_roles,
                  rbac_mode,
                  tenancy_mode,
                  metadata
                FROM access_policy_decisions
                {where_sql}
                ORDER BY created_at DESC
                LIMIT %s OFFSET %s
                """,
                (*params, normalized_limit, normalized_offset),
            )
            rows = cur.fetchall()
            cur.execute(
                f"""
                SELECT decision, COUNT(*)::bigint
                FROM access_policy_decisions
                {where_sql}
                GROUP BY decision
                """,
                tuple(params),
            )
            by_decision_rows = cur.fetchall()

    items = [
        {
            "id": str(row[0]),
            "created_at": row[1].isoformat() if row[1] is not None else None,
            "subject": str(row[2] or ""),
            "email": str(row[3]) if row[3] is not None else None,
            "tenant_id": str(row[4]) if row[4] is not None else None,
            "auth_source": str(row[5] or ""),
            "method": str(row[6] or ""),
            "path": str(row[7] or ""),
            "route_action": str(row[8]) if row[8] is not None else None,
            "project_ids": [str(item) for item in (row[9] or [])],
            "decision": str(row[10] or ""),
            "deny_code": str(row[11]) if row[11] is not None else None,
            "required_roles": [str(item) for item in (row[12] or [])],
            "actor_roles": [str(item) for item in (row[13] or [])],
            "rbac_mode": str(row[14] or "open"),
            "tenancy_mode": str(row[15] or "open"),
            "metadata": dict(row[16]) if isinstance(row[16], dict) else {},
        }
        for row in rows
    ]
    by_decision = {str(row[0]): int(row[1]) for row in by_decision_rows}
    return {
        "decisions": items,
        "meta": {
            "filters_applied": {
                "project_id": normalized_project_id or None,
                "subject": normalized_subject or None,
                "decision": normalized_decision or None,
                "path_prefix": normalized_path_prefix or None,
                "limit": normalized_limit,
                "offset": normalized_offset,
            },
            "total": total,
            "returned": len(items),
            "counts_by_decision": by_decision,
        },
    }


@app.post("/v1/auth/session", response_model=None)
def create_auth_session(
    payload: AuthSessionCreateRequest,
    authorization: str | None = Header(default=None, alias="Authorization"),
) -> Any:
    settings = enterprise.get_enterprise_settings()
    with get_conn() as conn:
        session = enterprise.create_oidc_session(
            conn=conn,
            settings=settings,
            authorization=authorization,
            requested_ttl_minutes=payload.session_ttl_minutes,
            metadata=payload.metadata,
        )
    return {"status": "ok", "session": session}


@app.get("/v1/auth/session")
def get_auth_session(
    authorization: str | None = Header(default=None, alias="Authorization"),
    x_synapse_session: str | None = Header(default=None, alias="X-Synapse-Session"),
) -> dict[str, Any]:
    token = enterprise.extract_session_token(x_synapse_session, authorization)
    if not token:
        raise HTTPException(status_code=401, detail={"code": "session_token_required"})
    with get_conn() as conn:
        session = enterprise.get_session_payload(conn, token)
    return {"status": "ok", "session": session}


@app.delete("/v1/auth/session", response_model=None)
def delete_auth_session(
    authorization: str | None = Header(default=None, alias="Authorization"),
    x_synapse_session: str | None = Header(default=None, alias="X-Synapse-Session"),
) -> Any:
    token = enterprise.extract_session_token(x_synapse_session, authorization)
    if not token:
        raise HTTPException(status_code=401, detail={"code": "session_token_required"})
    with get_conn() as conn:
        deleted = enterprise.revoke_session(conn, token)
    return {"status": "ok", "revoked": bool(deleted)}


