@app.get("/v1/backfill/batches/{batch_id}")
def get_memory_backfill_batch(batch_id: UUID, project_id: str) -> Any:
    with get_conn() as conn:
        has_decision_counters = _backfill_batch_has_decision_counters(conn)
        with conn.cursor() as cur:
            if has_decision_counters:
                cur.execute(
                    """
                    SELECT
                      id::text,
                      project_id,
                      source_system,
                      agent_id,
                      session_id,
                      status,
                      total_items,
                      inserted_events,
                      processed_events,
                      generated_claims,
                      dropped_event_like,
                      kept_durable,
                      trusted_bypass,
                      cursor,
                      created_by,
                      created_at,
                      updated_at
                    FROM memory_backfill_batches
                    WHERE id = %s
                      AND project_id = %s
                    LIMIT 1
                    """,
                    (batch_id, project_id),
                )
            else:
                cur.execute(
                    """
                    SELECT
                      id::text,
                      project_id,
                      source_system,
                      agent_id,
                      session_id,
                      status,
                      total_items,
                      inserted_events,
                      processed_events,
                      generated_claims,
                      cursor,
                      created_by,
                      created_at,
                      updated_at
                    FROM memory_backfill_batches
                    WHERE id = %s
                      AND project_id = %s
                    LIMIT 1
                    """,
                    (batch_id, project_id),
                )
            row = cur.fetchone()
            if row is None:
                return JSONResponse(status_code=404, content={"error": "backfill_batch_not_found"})
    if has_decision_counters:
        dropped_event_like = int(row[10])
        kept_durable = int(row[11])
        trusted_bypass = int(row[12])
        cursor = row[13]
        created_by = row[14]
        created_at = row[15]
        updated_at = row[16]
    else:
        dropped_event_like = 0
        kept_durable = 0
        trusted_bypass = 0
        cursor = row[10]
        created_by = row[11]
        created_at = row[12]
        updated_at = row[13]
    return {
        "batch": {
            "id": row[0],
            "project_id": row[1],
            "source_system": row[2],
            "agent_id": row[3],
            "session_id": row[4],
            "status": row[5],
            "total_items": int(row[6]),
            "inserted_events": int(row[7]),
            "processed_events": int(row[8]),
            "generated_claims": int(row[9]),
            "dropped_event_like": dropped_event_like,
            "kept_durable": kept_durable,
            "trusted_bypass": trusted_bypass,
            "cursor": cursor,
            "created_by": created_by,
            "created_at": created_at.isoformat(),
            "updated_at": updated_at.isoformat(),
        }
    }


@app.post("/v1/wiki/pages", response_model=None)
def create_wiki_page(
    payload: WikiPageCreateRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = "/v1/wiki/pages"
    request_payload = payload.model_dump(mode="json")
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_resolve_request_source_system(request, fallback=payload.created_by or "synapse_api"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                title = payload.title.strip()
                slug = _normalize_wiki_slug(payload.slug, title)
                space_key = _wiki_space_key_from_slug(slug)
                entity_key = (payload.entity_key or "").strip() or slug
                page_type = re.sub(r"[^a-z0-9_/-]+", "_", payload.page_type.strip().lower() or "operations").strip("_")
                if not page_type:
                    page_type = "operations"
                markdown = (payload.initial_markdown or "").strip()
                if not markdown:
                    markdown = f"# {title}\n\n## Overview\n- Add first approved fact.\n"
                elif not markdown.endswith("\n"):
                    markdown = f"{markdown}\n"
                status = payload.status
                markdown = _apply_wiki_schema_contract(
                    markdown=markdown,
                    title=title,
                    page_type=page_type,
                    slug=slug,
                    status=status,
                    generated_at=datetime.now(UTC),
                )
                publish_enrichment: dict[str, Any] | None = None
                if status == "published":
                    markdown, publish_enrichment = _maybe_enrich_wiki_markdown_before_publish(
                        conn,
                        project_id=payload.project_id,
                        slug=slug,
                        title=title,
                        page_type=page_type,
                        status=status,
                        markdown=markdown,
                        actor=payload.created_by,
                    )
                schema_contract = _evaluate_wiki_schema_contract(
                    markdown=markdown,
                    page_type=page_type,
                    slug=slug,
                )
                decision_quality = _evaluate_decision_focused_quality_gate(
                    markdown,
                    page_type=page_type,
                )
                change_summary = (
                    payload.change_summary.strip() if isinstance(payload.change_summary, str) and payload.change_summary.strip() else None
                ) or f"Page created by {payload.created_by}"
                policy_check = _check_wiki_policy_access(
                    cur,
                    project_id=payload.project_id,
                    space_key=space_key,
                    actor=payload.created_by,
                    action="write",
                    page_id=None,
                )
                if not policy_check["allowed"]:
                    response = {
                        "error": "wiki_policy_denied",
                        "project_id": payload.project_id,
                        "slug": slug,
                        "space_key": space_key,
                        "action": "write",
                        "reason": policy_check["reason"],
                        "policy": policy_check["policy"],
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=403,
                        response_body=response,
                    )
                    return JSONResponse(status_code=403, content=response)
                agent_publish_guard = _resolve_agent_publish_mode(
                    cur,
                    project_id=payload.project_id,
                    actor=payload.created_by,
                    page_type=page_type,
                )
                if status == "published" and str(agent_publish_guard.get("mode") or "") == "human_required":
                    response = {
                        "error": "agent_publish_policy_requires_review",
                        "project_id": payload.project_id,
                        "slug": slug,
                        "page_type": page_type,
                        "required_status": "reviewed",
                        "agent_publish_guard": agent_publish_guard,
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=409,
                        response_body=response,
                    )
                    return JSONResponse(status_code=409, content=response)
                if status == "published" and not bool(schema_contract.get("passed")):
                    response = {
                        "error": "wiki_schema_contract_required_for_publish",
                        "project_id": payload.project_id,
                        "slug": slug,
                        "page_type": page_type,
                        "missing_markers": list(schema_contract.get("missing_markers") or []),
                        "hint": "Provide summary/status/last_updated frontmatter, backlinks, and decisions log quality fields.",
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=409,
                        response_body=response,
                    )
                    return JSONResponse(status_code=409, content=response)
                if status == "published" and not bool(decision_quality.get("passed")):
                    response = {
                        "error": "wiki_quality_gate_decisions_required",
                        "project_id": payload.project_id,
                        "slug": slug,
                        "page_type": page_type,
                        "quality_gate": decision_quality,
                        "hint": "Publish path requires decision-first content with dated decisions and explicit source links.",
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=409,
                        response_body=response,
                    )
                    return JSONResponse(status_code=409, content=response)
                if (
                    status == "published"
                    and bool(policy_check["policy"].get("review_assignment_required"))
                    and not bool(policy_check["actor_is_owner"])
                ):
                    response = {
                        "error": "wiki_review_assignment_required",
                        "project_id": payload.project_id,
                        "slug": slug,
                        "space_key": space_key,
                        "detail": "Published creation requires owner or prior review assignment for this space policy.",
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=403,
                        response_body=response,
                    )
                    return JSONResponse(status_code=403, content=response)

                cur.execute(
                    """
                    SELECT id::text, title, slug, entity_key, page_type, status, current_version
                    FROM wiki_pages
                    WHERE project_id = %s
                      AND slug = %s
                    LIMIT 1
                    """,
                    (payload.project_id, slug),
                )
                existing = cur.fetchone()
                if existing is not None:
                    existing_payload = {
                        "id": existing[0],
                        "title": existing[1],
                        "slug": existing[2],
                        "entity_key": existing[3],
                        "page_type": existing[4],
                        "status": existing[5],
                        "current_version": int(existing[6]),
                    }
                    if payload.allow_existing:
                        response = {"status": "existing", "page": existing_payload}
                        if source_ownership_advisories > 0:
                            response["source_ownership_advisories"] = source_ownership_advisories
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response
                    response = {
                        "error": "page_slug_exists",
                        "existing_page": existing_payload,
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=409,
                        response_body=response,
                    )
                    return JSONResponse(status_code=409, content=response)

                page_id = uuid4()
                cur.execute(
                    """
                    INSERT INTO wiki_pages (
                      id, project_id, page_type, title, slug, entity_key, status, current_version, metadata
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s, 1, %s)
                    """,
                    (
                        page_id,
                        payload.project_id,
                        page_type,
                        title,
                        slug,
                        entity_key,
                        status,
                        Jsonb({"source": "guided_builder", "created_by": payload.created_by}),
                    ),
                )
                cur.execute(
                    """
                    INSERT INTO wiki_page_versions (
                      id, page_id, version, markdown, ast_json, source, created_by, change_summary
                    )
                    VALUES (%s, %s, 1, %s, %s, 'human', %s, %s)
                    """,
                    (uuid4(), page_id, markdown, Jsonb([]), payload.created_by, change_summary),
                )

                sections = _extract_sections_from_markdown(markdown)
                inserted_statement_ids: list[str] = []
                for index, section in enumerate(sections):
                    section_key = str(section.get("section_key") or f"section_{index + 1}")
                    heading = str(section.get("heading") or _section_heading_from_key(section_key))
                    statements = section.get("statements") or []
                    cur.execute(
                        """
                        INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                        VALUES (%s, %s, %s, %s, %s)
                        ON CONFLICT (page_id, section_key) DO UPDATE
                        SET heading = EXCLUDED.heading,
                            order_index = EXCLUDED.order_index,
                            statement_count = EXCLUDED.statement_count
                        """,
                        (
                            page_id,
                            section_key,
                            heading,
                            index,
                            len(statements),
                        ),
                    )
                    for statement_text in statements:
                        statement = str(statement_text).strip()
                        if not statement:
                            continue
                        statement_id = uuid4()
                        fingerprint = _compute_claim_fingerprint(payload.project_id, entity_key, page_type, statement)
                        cur.execute(
                            """
                            INSERT INTO wiki_statements (
                              id, project_id, page_id, section_key, statement_text, normalized_text,
                              claim_fingerprint, status, metadata, valid_from
                            )
                            VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, NOW())
                            """,
                            (
                                statement_id,
                                payload.project_id,
                                page_id,
                                section_key,
                                statement,
                                _normalize_statement_text(statement),
                                fingerprint,
                                Jsonb({"source": "manual_page_create", "created_by": payload.created_by}),
                            ),
                        )
                        inserted_statement_ids.append(str(statement_id))

                snapshot_id = uuid4()
                cur.execute(
                    """
                    INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                    VALUES (%s, %s, %s, %s)
                    """,
                    (snapshot_id, payload.project_id, payload.created_by, change_summary),
                )
                cur.execute(
                    """
                    INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                    VALUES (%s, %s, 1)
                    """,
                    (snapshot_id, page_id),
                )
                response = {
                    "status": "created",
                    "page": {
                        "id": str(page_id),
                        "title": title,
                        "slug": slug,
                        "entity_key": entity_key,
                        "page_type": page_type,
                        "status": status,
                        "current_version": 1,
                    },
                    "latest_version": {
                        "version": 1,
                        "markdown": markdown,
                        "source": "human",
                        "created_by": payload.created_by,
                    },
                    "snapshot_id": str(snapshot_id),
                    "inserted_statements": len(inserted_statement_ids),
                    "schema_contract": schema_contract,
                    "quality_gate": decision_quality,
                }
                if publish_enrichment is not None:
                    response["publish_enrichment"] = publish_enrichment
                if source_ownership_advisories > 0:
                    response["source_ownership_advisories"] = source_ownership_advisories
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.put("/v1/wiki/pages/{slug}", response_model=None)
def update_wiki_page(
    slug: str,
    payload: WikiPageUpdateRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    endpoint = f"/v1/wiki/pages/{normalized_slug}"
    request_payload = {"slug": normalized_slug, **payload.model_dump(mode="json")}
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_resolve_request_source_system(request, fallback=payload.updated_by or "human_editor"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                with conn.transaction():
                    page_row = _resolve_wiki_page_row_by_slug_or_alias(
                        cur,
                        project_id=payload.project_id,
                        slug_or_alias=normalized_slug,
                        for_update=True,
                    )
                    if page_row is None:
                        response = {
                            "error": "wiki_page_not_found",
                            "project_id": payload.project_id,
                            "slug": normalized_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=404,
                            response_body=response,
                        )
                        return JSONResponse(status_code=404, content=response)

                    page_id: UUID = page_row[0]
                    existing_title = str(page_row[1] or "").strip() or normalized_slug
                    existing_slug = str(page_row[2] or normalized_slug).strip() or normalized_slug
                    space_key = _wiki_space_key_from_slug(existing_slug)
                    entity_key = str(page_row[3] or existing_slug).strip() or existing_slug
                    existing_page_type = str(page_row[4] or "operations").strip() or "operations"
                    existing_status = str(page_row[5] or "published").strip() or "published"
                    current_version = int(page_row[6] or 0)
                    policy_check = _check_wiki_policy_access(
                        cur,
                        project_id=payload.project_id,
                        space_key=space_key,
                        actor=payload.updated_by,
                        action="write",
                        page_id=str(page_id),
                    )
                    if not policy_check["allowed"]:
                        response = {
                            "error": "wiki_policy_denied",
                            "project_id": payload.project_id,
                            "slug": existing_slug,
                            "space_key": space_key,
                            "action": "write",
                            "reason": policy_check["reason"],
                            "policy": policy_check["policy"],
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=403,
                            response_body=response,
                        )
                        return JSONResponse(status_code=403, content=response)

                    next_title = (
                        payload.title.strip()
                        if isinstance(payload.title, str) and payload.title.strip()
                        else existing_title
                    )
                    if payload.page_type is not None:
                        next_page_type = (
                            re.sub(r"[^a-z0-9_/-]+", "_", payload.page_type.strip().lower()).strip("_") or existing_page_type
                        )
                    else:
                        next_page_type = existing_page_type
                    next_status = payload.status or existing_status
                    markdown = payload.markdown.strip()
                    if not markdown:
                        raise HTTPException(status_code=409, detail="empty_markdown_not_allowed")
                    if not markdown.endswith("\n"):
                        markdown = f"{markdown}\n"
                    markdown = _apply_wiki_schema_contract(
                        markdown=markdown,
                        title=next_title,
                        page_type=next_page_type,
                        slug=existing_slug,
                        status=next_status,
                        generated_at=datetime.now(UTC),
                    )
                    publish_enrichment: dict[str, Any] | None = None
                    if next_status == "published":
                        markdown, publish_enrichment = _maybe_enrich_wiki_markdown_before_publish(
                            conn,
                            project_id=payload.project_id,
                            slug=existing_slug,
                            title=next_title,
                            page_type=next_page_type,
                            status=next_status,
                            markdown=markdown,
                            actor=payload.updated_by,
                        )
                    schema_contract = _evaluate_wiki_schema_contract(
                        markdown=markdown,
                        page_type=next_page_type,
                        slug=existing_slug,
                    )
                    decision_quality = _evaluate_decision_focused_quality_gate(
                        markdown,
                        page_type=next_page_type,
                    )
                    change_summary = (
                        payload.change_summary.strip()
                        if isinstance(payload.change_summary, str) and payload.change_summary.strip()
                        else None
                    ) or f"Page edited by {payload.updated_by}"
                    agent_publish_guard = _resolve_agent_publish_mode(
                        cur,
                        project_id=payload.project_id,
                        actor=payload.updated_by,
                        page_type=next_page_type,
                    )
                    if next_status == "published" and str(agent_publish_guard.get("mode") or "") == "human_required":
                        response = {
                            "error": "agent_publish_policy_requires_review",
                            "project_id": payload.project_id,
                            "slug": existing_slug,
                            "page_type": next_page_type,
                            "required_status": "reviewed",
                            "agent_publish_guard": agent_publish_guard,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=409,
                            response_body=response,
                        )
                        return JSONResponse(status_code=409, content=response)
                    if next_status == "published" and not bool(schema_contract.get("passed")):
                        response = {
                            "error": "wiki_schema_contract_required_for_publish",
                            "project_id": payload.project_id,
                            "slug": existing_slug,
                            "page_type": next_page_type,
                            "missing_markers": list(schema_contract.get("missing_markers") or []),
                            "hint": "Provide summary/status/last_updated frontmatter, backlinks, and decisions log quality fields.",
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=409,
                            response_body=response,
                        )
                        return JSONResponse(status_code=409, content=response)
                    if next_status == "published" and not bool(decision_quality.get("passed")) and not bool(payload.confirm_high_risk_publish):
                        response = {
                            "error": "wiki_quality_gate_decisions_required",
                            "project_id": payload.project_id,
                            "slug": existing_slug,
                            "page_type": next_page_type,
                            "quality_gate": decision_quality,
                            "required_confirmation": "confirm_high_risk_publish=true",
                            "hint": "Publish path requires decision-first content with dated decisions and explicit source links.",
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=409,
                            response_body=response,
                        )
                        return JSONResponse(status_code=409, content=response)

                    cur.execute(
                        """
                        SELECT markdown
                        FROM wiki_page_versions
                        WHERE page_id = %s
                          AND version = %s
                        LIMIT 1
                        """,
                        (page_id, current_version),
                    )
                    latest_row = cur.fetchone()
                    latest_markdown = str(latest_row[0]) if latest_row and latest_row[0] is not None else ""
                    if (
                        latest_markdown.strip() == markdown.strip()
                        and next_title == existing_title
                        and next_page_type == existing_page_type
                        and next_status == existing_status
                    ):
                        response = {
                            "status": "no_change",
                            "page": {
                                "id": str(page_id),
                                "title": existing_title,
                                "slug": existing_slug,
                                "entity_key": entity_key,
                                "page_type": existing_page_type,
                                "status": existing_status,
                                "current_version": current_version,
                            },
                        }
                        if source_ownership_advisories > 0:
                            response["source_ownership_advisories"] = source_ownership_advisories
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response

                    if (
                        next_status == "published"
                        and bool(policy_check["policy"].get("review_assignment_required"))
                        and not bool(policy_check["actor_is_owner"])
                        and _wiki_feature_table_exists(cur, "public.wiki_page_review_assignments")
                    ):
                        cur.execute(
                            """
                            SELECT COUNT(*)::int
                            FROM wiki_page_review_assignments
                            WHERE project_id = %s
                              AND page_id = %s
                              AND status = 'resolved'
                            """,
                            (payload.project_id, page_id),
                        )
                        resolved_count_row = cur.fetchone()
                        resolved_count = int(resolved_count_row[0] if resolved_count_row and resolved_count_row[0] is not None else 0)
                        if resolved_count <= 0:
                            response = {
                                "error": "wiki_review_assignment_required",
                                "project_id": payload.project_id,
                                "slug": existing_slug,
                                "space_key": space_key,
                                "detail": "At least one resolved review assignment is required before publish in this space.",
                            }
                            mark_request_completed(
                                conn,
                                endpoint=endpoint,
                                idempotency_key=idempotency_key,
                                status_code=403,
                                response_body=response,
                            )
                            return JSONResponse(status_code=403, content=response)

                    process_simulation_result: dict[str, Any] | None = None
                    if next_status == "published":
                        routing_policy = _load_project_routing_policy(conn, project_id=payload.project_id)
                        enforced_page_types = {
                            str(item).strip().lower()
                            for item in (routing_policy.get("process_simulation_require_for_page_types") or [])
                            if str(item).strip()
                        }
                        if not enforced_page_types:
                            enforced_page_types = {"process", "policy", "incident"}
                        normalized_next_page_type = str(next_page_type or "").strip().lower()
                        if normalized_next_page_type in enforced_page_types:
                            simulation_limit = int(routing_policy.get("process_simulation_sample_limit", 10))
                            process_simulation_result = _run_wiki_process_simulation(
                                conn,
                                project_id=payload.project_id,
                                page_slug=existing_slug,
                                proposed_markdown=markdown,
                                baseline_markdown=latest_markdown,
                                sample_limit=simulation_limit,
                            )
                            risk_obj = (
                                process_simulation_result.get("risk")
                                if isinstance(process_simulation_result.get("risk"), dict)
                                else {}
                            )
                            risk_level = str(risk_obj.get("level") or "low").strip().lower()
                            block_levels = {
                                str(item).strip().lower()
                                for item in (routing_policy.get("process_simulation_block_levels") or ["high"])
                                if str(item).strip()
                            }
                            should_block_publish = bool(risk_obj.get("should_block_publish")) or risk_level in block_levels
                            if should_block_publish and not bool(payload.confirm_high_risk_publish):
                                response = {
                                    "error": "publish_blocked_by_process_simulation",
                                    "project_id": payload.project_id,
                                    "slug": existing_slug,
                                    "page_type": next_page_type,
                                    "required_confirmation": "confirm_high_risk_publish=true",
                                    "simulation": process_simulation_result,
                                }
                                mark_request_completed(
                                    conn,
                                    endpoint=endpoint,
                                    idempotency_key=idempotency_key,
                                    status_code=409,
                                    response_body=response,
                                )
                                return JSONResponse(status_code=409, content=response)

                    next_version = current_version + 1
                    cur.execute(
                        """
                        INSERT INTO wiki_page_versions (
                          id, page_id, version, markdown, ast_json, source, created_by, change_summary
                        )
                        VALUES (%s, %s, %s, %s, %s, 'human', %s, %s)
                        """,
                        (
                            uuid4(),
                            page_id,
                            next_version,
                            markdown,
                            Jsonb([]),
                            payload.updated_by,
                            change_summary,
                        ),
                    )

                    cur.execute(
                        """
                        UPDATE wiki_statements
                        SET status = 'superseded',
                            valid_to = COALESCE(valid_to, NOW()),
                            updated_at = NOW(),
                            metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb
                        WHERE page_id = %s
                          AND status = 'active'
                        """,
                        (
                            Jsonb(
                                {
                                    "superseded_by": payload.updated_by,
                                    "superseded_by_version": next_version,
                                }
                            ),
                            page_id,
                        ),
                    )
                    superseded_statements = int(cur.rowcount)

                    sections = _extract_sections_from_markdown(markdown)
                    inserted_statement_ids: list[str] = []
                    section_keys: list[str] = []
                    for index, section in enumerate(sections):
                        section_key = str(section.get("section_key") or f"section_{index + 1}").strip() or f"section_{index + 1}"
                        heading = str(section.get("heading") or _section_heading_from_key(section_key)).strip()
                        statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
                        section_keys.append(section_key)
                        cur.execute(
                            """
                            INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                            VALUES (%s, %s, %s, %s, %s)
                            ON CONFLICT (page_id, section_key) DO UPDATE
                            SET heading = EXCLUDED.heading,
                                order_index = EXCLUDED.order_index,
                                statement_count = EXCLUDED.statement_count
                            """,
                            (
                                page_id,
                                section_key,
                                heading or _section_heading_from_key(section_key),
                                index,
                                len(statements),
                            ),
                        )
                        for statement_text in statements:
                            statement_id = uuid4()
                            fingerprint = _compute_claim_fingerprint(
                                payload.project_id,
                                entity_key,
                                next_page_type,
                                statement_text,
                            )
                            cur.execute(
                                """
                                INSERT INTO wiki_statements (
                                  id, project_id, page_id, section_key, statement_text, normalized_text,
                                  claim_fingerprint, status, metadata, valid_from
                                )
                                VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, NOW())
                                """,
                                (
                                    statement_id,
                                    payload.project_id,
                                    page_id,
                                    section_key,
                                    statement_text,
                                    _normalize_statement_text(statement_text),
                                    fingerprint,
                                    Jsonb(
                                        {
                                            "source": "manual_page_edit",
                                            "updated_by": payload.updated_by,
                                            "page_version": next_version,
                                        }
                                    ),
                                ),
                            )
                            inserted_statement_ids.append(str(statement_id))

                    cur.execute(
                        """
                        DELETE FROM wiki_sections
                        WHERE page_id = %s
                          AND NOT (section_key = ANY(%s::text[]))
                        """,
                        (page_id, section_keys),
                    )

                    cur.execute(
                        """
                        UPDATE wiki_pages
                        SET title = %s,
                            page_type = %s,
                            status = %s,
                            current_version = %s,
                            metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb,
                            updated_at = NOW()
                        WHERE id = %s
                        """,
                        (
                            next_title,
                            next_page_type,
                            next_status,
                            next_version,
                            Jsonb(
                                {
                                    "updated_by": payload.updated_by,
                                    "last_change_summary": change_summary,
                                }
                            ),
                            page_id,
                        ),
                    )

                    snapshot_id = uuid4()
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                        VALUES (%s, %s, %s, %s)
                        """,
                        (snapshot_id, payload.project_id, payload.updated_by, change_summary),
                    )
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                        VALUES (%s, %s, %s)
                        """,
                        (snapshot_id, page_id, next_version),
                    )

                    response = {
                        "status": "updated",
                        "page": {
                            "id": str(page_id),
                            "title": next_title,
                            "slug": existing_slug,
                            "entity_key": entity_key,
                            "page_type": next_page_type,
                            "status": next_status,
                            "current_version": next_version,
                        },
                        "latest_version": {
                            "version": next_version,
                            "markdown": markdown,
                            "source": "human",
                            "created_by": payload.updated_by,
                            "change_summary": change_summary,
                        },
                        "snapshot_id": str(snapshot_id),
                        "superseded_statements": superseded_statements,
                        "inserted_statements": len(inserted_statement_ids),
                        "schema_contract": schema_contract,
                        "quality_gate": decision_quality,
                    }
                    if publish_enrichment is not None:
                        response["publish_enrichment"] = publish_enrichment
                    if process_simulation_result is not None:
                        response["process_simulation"] = process_simulation_result
                        response["process_simulation_acknowledged"] = bool(payload.confirm_high_risk_publish)
                    notification_ids = _insert_wiki_notifications(
                        cur,
                        project_id=payload.project_id,
                        recipients=set(_collect_wiki_page_watchers(cur, project_id=payload.project_id, page_id=str(page_id))),
                        actor=payload.updated_by,
                        kind="wiki.page_updated",
                        title=f"Page updated: {existing_slug}",
                        body=change_summary,
                        link=f"/wiki/{existing_slug}",
                        metadata={
                            "page_id": str(page_id),
                            "slug": existing_slug,
                            "version": next_version,
                            "change_summary": change_summary,
                        },
                    )
                    if notification_ids:
                        response["notifications"] = {"inserted": len(notification_ids)}
                    if source_ownership_advisories > 0:
                        response["source_ownership_advisories"] = source_ownership_advisories
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=200,
                        response_body=response,
                    )
                    return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.put("/v1/wiki/pages/{slug}/move", response_model=None)
def move_wiki_page(
    slug: str,
    payload: WikiPageMoveRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    normalized_new_slug = _normalize_wiki_slug(payload.new_slug, payload.new_slug)
    endpoint = f"/v1/wiki/pages/{normalized_slug}/move"
    request_payload = {
        "slug": normalized_slug,
        "new_slug": normalized_new_slug,
        **payload.model_dump(mode="json"),
    }
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_resolve_request_source_system(request, fallback=payload.moved_by or "human_editor"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                with conn.transaction():
                    root_page = _resolve_wiki_page_row_by_slug_or_alias(
                        cur,
                        project_id=payload.project_id,
                        slug_or_alias=normalized_slug,
                        for_update=True,
                    )
                    if root_page is None:
                        response = {
                            "error": "wiki_page_not_found",
                            "project_id": payload.project_id,
                            "slug": normalized_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=404,
                            response_body=response,
                        )
                        return JSONResponse(status_code=404, content=response)

                    root_slug = str(root_page[2] or normalized_slug).strip() or normalized_slug
                    space_key = _wiki_space_key_from_slug(root_slug)
                    policy_check = _check_wiki_policy_access(
                        cur,
                        project_id=payload.project_id,
                        space_key=space_key,
                        actor=payload.moved_by,
                        action="write",
                        page_id=str(root_page[0]),
                    )
                    if not policy_check["allowed"]:
                        response = {
                            "error": "wiki_policy_denied",
                            "project_id": payload.project_id,
                            "slug": root_slug,
                            "space_key": space_key,
                            "action": "write",
                            "reason": policy_check["reason"],
                            "policy": policy_check["policy"],
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=403,
                            response_body=response,
                        )
                        return JSONResponse(status_code=403, content=response)
                    if payload.include_descendants and normalized_new_slug.startswith(f"{root_slug}/"):
                        response = {
                            "error": "wiki_page_move_invalid_descendant_target",
                            "slug": root_slug,
                            "new_slug": normalized_new_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=409,
                            response_body=response,
                        )
                        return JSONResponse(status_code=409, content=response)
                    include_descendants = bool(payload.include_descendants)
                    if include_descendants:
                        cur.execute(
                            """
                            SELECT id::text, title, slug, entity_key, current_version
                            FROM wiki_pages
                            WHERE project_id = %s
                              AND (slug = %s OR slug LIKE %s)
                            ORDER BY LENGTH(slug) ASC, slug ASC
                            FOR UPDATE
                            """,
                            (payload.project_id, root_slug, f"{root_slug}/%"),
                        )
                    else:
                        cur.execute(
                            """
                            SELECT id::text, title, slug, entity_key, current_version
                            FROM wiki_pages
                            WHERE project_id = %s
                              AND slug = %s
                            ORDER BY slug ASC
                            FOR UPDATE
                            """,
                            (payload.project_id, root_slug),
                        )
                    affected_rows = cur.fetchall()
                    if not affected_rows:
                        response = {
                            "error": "wiki_page_not_found",
                            "project_id": payload.project_id,
                            "slug": normalized_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=404,
                            response_body=response,
                        )
                        return JSONResponse(status_code=404, content=response)

                    mappings: list[dict[str, Any]] = []
                    for row in affected_rows:
                        page_id = str(row[0])
                        old_title = str(row[1] or "").strip() or str(row[2])
                        old_slug = str(row[2] or "").strip()
                        old_entity_key = str(row[3] or "").strip()
                        current_version = int(row[4] or 0)
                        if old_slug == root_slug:
                            new_slug = normalized_new_slug
                        elif include_descendants and old_slug.startswith(f"{root_slug}/"):
                            suffix = old_slug[len(root_slug) :]
                            new_slug = f"{normalized_new_slug}{suffix}"
                        else:
                            new_slug = old_slug
                        mappings.append(
                            {
                                "id": page_id,
                                "old_slug": old_slug,
                                "new_slug": new_slug,
                                "old_title": old_title,
                                "old_entity_key": old_entity_key,
                                "current_version": current_version,
                            }
                        )

                    target_slugs = [str(item["new_slug"]) for item in mappings]
                    if len(set(target_slugs)) != len(target_slugs):
                        response = {
                            "error": "wiki_page_move_slug_conflict",
                            "detail": "duplicate_target_slugs",
                            "slug": normalized_slug,
                            "new_slug": normalized_new_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=409,
                            response_body=response,
                        )
                        return JSONResponse(status_code=409, content=response)

                    affected_ids = [str(item["id"]) for item in mappings]
                    cur.execute(
                        """
                        SELECT id::text, slug
                        FROM wiki_pages
                        WHERE project_id = %s
                          AND slug = ANY(%s)
                          AND NOT (id::text = ANY(%s))
                        LIMIT 50
                        """,
                        (payload.project_id, target_slugs, affected_ids),
                    )
                    collisions = cur.fetchall()
                    if collisions:
                        response = {
                            "error": "wiki_page_move_slug_conflict",
                            "slug": normalized_slug,
                            "new_slug": normalized_new_slug,
                            "collisions": [{"id": str(row[0]), "slug": str(row[1])} for row in collisions],
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=409,
                            response_body=response,
                        )
                        return JSONResponse(status_code=409, content=response)

                    root_title = str(root_page[1] or "").strip() or root_slug
                    requested_root_title = (
                        payload.new_title.strip()
                        if isinstance(payload.new_title, str) and payload.new_title.strip()
                        else root_title
                    )
                    has_any_slug_change = any(str(item["old_slug"]) != str(item["new_slug"]) for item in mappings)
                    has_title_change = requested_root_title != root_title
                    if not has_any_slug_change and not has_title_change:
                        response = {
                            "status": "no_change",
                            "page": {
                                "id": str(root_page[0]),
                                "title": root_title,
                                "slug": root_slug,
                                "entity_key": root_page[3],
                                "page_type": root_page[4],
                                "status": root_page[5],
                                "current_version": int(root_page[6]) if root_page[6] is not None else None,
                            },
                            "moved_pages": [],
                        }
                        if source_ownership_advisories > 0:
                            response["source_ownership_advisories"] = source_ownership_advisories
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response

                    update_targets = mappings
                    if not has_any_slug_change:
                        update_targets = [item for item in mappings if str(item["old_slug"]) == root_slug]

                    snapshot_id = uuid4()
                    change_summary = (
                        payload.change_summary.strip()
                        if isinstance(payload.change_summary, str) and payload.change_summary.strip()
                        else None
                    ) or f"Page moved by {payload.moved_by}: {root_slug} -> {normalized_new_slug}"
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                        VALUES (%s, %s, %s, %s)
                        """,
                        (snapshot_id, payload.project_id, payload.moved_by, change_summary),
                    )
                    moved_pages: list[dict[str, Any]] = []
                    now_iso = datetime.now(UTC).isoformat()
                    for item in update_targets:
                        page_id = str(item["id"])
                        old_slug = str(item["old_slug"])
                        new_slug = str(item["new_slug"])
                        old_title = str(item["old_title"])
                        old_entity_key = str(item["old_entity_key"])
                        current_version = int(item["current_version"])
                        next_title = requested_root_title if old_slug == root_slug else old_title
                        next_entity_key = new_slug if old_entity_key == old_slug else old_entity_key
                        cur.execute(
                            """
                            UPDATE wiki_pages
                            SET slug = %s,
                                title = %s,
                                entity_key = %s,
                                metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb,
                                updated_at = NOW()
                            WHERE id::text = %s
                            """,
                            (
                                new_slug,
                                next_title,
                                next_entity_key,
                                Jsonb(
                                    {
                                        "last_move": {
                                            "moved_by": payload.moved_by,
                                            "from_slug": old_slug,
                                            "to_slug": new_slug,
                                            "at": now_iso,
                                        }
                                    }
                                ),
                                page_id,
                            ),
                        )
                        if old_slug != new_slug:
                            cur.execute(
                                """
                                INSERT INTO wiki_page_aliases (page_id, alias_text)
                                VALUES (%s, %s)
                                ON CONFLICT (page_id, alias_text) DO NOTHING
                                """,
                                (page_id, old_slug),
                            )
                        if old_slug == normalized_slug and next_title != old_title:
                            cur.execute(
                                """
                                INSERT INTO wiki_page_aliases (page_id, alias_text)
                                VALUES (%s, %s)
                                ON CONFLICT (page_id, alias_text) DO NOTHING
                                """,
                                (page_id, old_title),
                            )
                        cur.execute(
                            """
                            INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                            VALUES (%s, %s, %s)
                            ON CONFLICT (snapshot_id, page_id) DO NOTHING
                            """,
                            (snapshot_id, page_id, current_version),
                        )
                        moved_pages.append(
                            {
                                "id": page_id,
                                "old_slug": old_slug,
                                "new_slug": new_slug,
                                "old_title": old_title,
                                "new_title": next_title,
                            }
                        )

                    response = {
                        "status": "moved",
                        "page": {
                                "id": str(root_page[0]),
                                "title": requested_root_title,
                                "slug": normalized_new_slug,
                                "entity_key": normalized_new_slug if str(root_page[3] or "") == root_slug else root_page[3],
                                "page_type": root_page[4],
                                "status": root_page[5],
                                "current_version": int(root_page[6]) if root_page[6] is not None else None,
                        },
                        "include_descendants": include_descendants,
                        "moved_pages": moved_pages,
                        "snapshot_id": str(snapshot_id),
                    }
                    move_watchers: set[str] = set()
                    for item in moved_pages:
                        move_watchers.update(
                            _collect_wiki_page_watchers(
                                cur,
                                project_id=payload.project_id,
                                page_id=str(item["id"]),
                            )
                        )
                    notification_ids = _insert_wiki_notifications(
                        cur,
                        project_id=payload.project_id,
                        recipients=move_watchers,
                        actor=payload.moved_by,
                        kind="wiki.page_moved",
                        title=f"Page moved: {root_slug} -> {normalized_new_slug}",
                        body=change_summary,
                        link=f"/wiki/{normalized_new_slug}",
                        metadata={
                            "root_slug": root_slug,
                            "new_slug": normalized_new_slug,
                            "include_descendants": include_descendants,
                            "moved_pages": moved_pages,
                        },
                    )
                    if notification_ids:
                        response["notifications"] = {"inserted": len(notification_ids)}
                    if source_ownership_advisories > 0:
                        response["source_ownership_advisories"] = source_ownership_advisories
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=200,
                        response_body=response,
                    )
                    return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.put("/v1/wiki/pages/{slug}/reparent", response_model=None)
def reparent_wiki_page(
    slug: str,
    payload: WikiPageReparentRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    old_segments = [segment for segment in normalized_slug.split("/") if segment]
    default_leaf = old_segments[-1] if old_segments else _slugify_segment(normalized_slug)
    new_leaf = _slugify_segment(payload.new_slug_leaf or default_leaf)
    parent_slug_raw = str(payload.new_parent_slug or "").strip()
    if parent_slug_raw:
        normalized_parent_slug = _normalize_wiki_slug(parent_slug_raw, parent_slug_raw)
        target_slug = f"{normalized_parent_slug}/{new_leaf}"
    else:
        target_slug = new_leaf
    move_payload = WikiPageMoveRequest(
        project_id=payload.project_id,
        moved_by=payload.moved_by,
        new_slug=target_slug,
        new_title=payload.new_title,
        include_descendants=payload.include_descendants,
        change_summary=payload.change_summary,
    )
    return move_wiki_page(
        slug=normalized_slug,
        payload=move_payload,
        request=request,
        idempotency_key=idempotency_key,
    )


@app.put("/v1/wiki/pages/{slug}/archive", response_model=None)
def archive_wiki_page(
    slug: str,
    payload: WikiPageStatusTransitionRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    endpoint = f"/v1/wiki/pages/{normalized_slug}/archive"
    request_payload = {"slug": normalized_slug, **payload.model_dump(mode="json")}
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_resolve_request_source_system(request, fallback=payload.updated_by or "human_editor"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                with conn.transaction():
                    root_row = _resolve_wiki_page_row_by_slug_or_alias(
                        cur,
                        project_id=payload.project_id,
                        slug_or_alias=normalized_slug,
                        for_update=True,
                    )
                    if root_row is None:
                        response = {
                            "error": "wiki_page_not_found",
                            "project_id": payload.project_id,
                            "slug": normalized_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=404,
                            response_body=response,
                        )
                        return JSONResponse(status_code=404, content=response)
                    root_slug = str(root_row[2] or normalized_slug).strip() or normalized_slug
                    space_key = _wiki_space_key_from_slug(root_slug)
                    policy_check = _check_wiki_policy_access(
                        cur,
                        project_id=payload.project_id,
                        space_key=space_key,
                        actor=payload.updated_by,
                        action="write",
                        page_id=str(root_row[0]),
                    )
                    if not policy_check["allowed"]:
                        response = {
                            "error": "wiki_policy_denied",
                            "project_id": payload.project_id,
                            "slug": root_slug,
                            "space_key": space_key,
                            "action": "write",
                            "reason": policy_check["reason"],
                            "policy": policy_check["policy"],
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=403,
                            response_body=response,
                        )
                        return JSONResponse(status_code=403, content=response)

                    if payload.include_descendants:
                        cur.execute(
                            """
                            SELECT id::text, title, slug, status, current_version
                            FROM wiki_pages
                            WHERE project_id = %s
                              AND (slug = %s OR slug LIKE %s)
                            ORDER BY LENGTH(slug) ASC, slug ASC
                            FOR UPDATE
                            """,
                            (payload.project_id, root_slug, f"{root_slug}/%"),
                        )
                    else:
                        cur.execute(
                            """
                            SELECT id::text, title, slug, status, current_version
                            FROM wiki_pages
                            WHERE project_id = %s
                              AND slug = %s
                            ORDER BY slug ASC
                            FOR UPDATE
                            """,
                            (payload.project_id, root_slug),
                        )
                    rows = cur.fetchall()
                    by_slug = {str(row[2]): row for row in rows}
                    root_row = by_slug.get(root_slug) or rows[0]
                    changed_rows = [row for row in rows if str(row[3]) != "archived"]
                    if not changed_rows:
                        response = {
                            "status": "no_change",
                            "page": {
                                "id": str(root_row[0]),
                                "title": str(root_row[1] or root_row[2]),
                                "slug": str(root_row[2]),
                                "status": str(root_row[3]),
                                "current_version": int(root_row[4]) if root_row[4] is not None else None,
                            },
                            "changed_pages": [],
                        }
                        if source_ownership_advisories > 0:
                            response["source_ownership_advisories"] = source_ownership_advisories
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response

                    changed_ids = [str(row[0]) for row in changed_rows]
                    change_summary = (
                        payload.change_summary.strip()
                        if isinstance(payload.change_summary, str) and payload.change_summary.strip()
                        else None
                    ) or f"Page archived by {payload.updated_by}"
                    cur.execute(
                        """
                        UPDATE wiki_pages
                        SET status = 'archived',
                            metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb,
                            updated_at = NOW()
                        WHERE id::text = ANY(%s)
                        """,
                        (
                            Jsonb(
                                {
                                    "status_transition": {
                                        "updated_by": payload.updated_by,
                                        "to_status": "archived",
                                        "summary": change_summary,
                                        "at": datetime.now(UTC).isoformat(),
                                    }
                                }
                            ),
                            changed_ids,
                        ),
                    )

                    snapshot_id = uuid4()
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                        VALUES (%s, %s, %s, %s)
                        """,
                        (snapshot_id, payload.project_id, payload.updated_by, change_summary),
                    )
                    for row in changed_rows:
                        cur.execute(
                            """
                            INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                            VALUES (%s, %s, %s)
                            ON CONFLICT (snapshot_id, page_id) DO NOTHING
                            """,
                            (
                                snapshot_id,
                                str(row[0]),
                                int(row[4]) if row[4] is not None else 0,
                            ),
                        )

                    changed_pages = [
                        {
                            "id": str(row[0]),
                            "title": str(row[1] or row[2]),
                            "slug": str(row[2]),
                            "previous_status": str(row[3]),
                            "status": "archived",
                        }
                        for row in changed_rows
                    ]
                    response = {
                        "status": "updated",
                        "page": {
                            "id": str(root_row[0]),
                            "title": str(root_row[1] or root_row[2]),
                            "slug": str(root_row[2]),
                            "status": "archived",
                            "current_version": int(root_row[4]) if root_row[4] is not None else None,
                        },
                        "include_descendants": bool(payload.include_descendants),
                        "changed_pages": changed_pages,
                        "snapshot_id": str(snapshot_id),
                    }
                    archive_watchers: set[str] = set()
                    for row in changed_rows:
                        archive_watchers.update(
                            _collect_wiki_page_watchers(
                                cur,
                                project_id=payload.project_id,
                                page_id=str(row[0]),
                            )
                        )
                    notification_ids = _insert_wiki_notifications(
                        cur,
                        project_id=payload.project_id,
                        recipients=archive_watchers,
                        actor=payload.updated_by,
                        kind="wiki.page_archived",
                        title=f"Page archived: {root_slug}",
                        body=change_summary,
                        link=f"/wiki/{root_slug}",
                        metadata={
                            "root_slug": root_slug,
                            "include_descendants": bool(payload.include_descendants),
                            "changed_pages": changed_pages,
                        },
                    )
                    if notification_ids:
                        response["notifications"] = {"inserted": len(notification_ids)}
                    if source_ownership_advisories > 0:
                        response["source_ownership_advisories"] = source_ownership_advisories
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=200,
                        response_body=response,
                    )
                    return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.put("/v1/wiki/pages/{slug}/restore", response_model=None)
def restore_wiki_page(
    slug: str,
    payload: WikiPageStatusTransitionRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    normalized_slug = _normalize_wiki_slug(slug, slug)
    endpoint = f"/v1/wiki/pages/{normalized_slug}/restore"
    request_payload = {"slug": normalized_slug, **payload.model_dump(mode="json")}
    target_status = payload.restore_status
    source_ownership_advisories = 0
    with get_conn() as conn:
        if _source_ownership_table_exists(conn):
            policies = _load_source_ownership_policies(conn, payload.project_id)
            check = _enforce_source_ownership_write(
                policies_by_domain=policies,
                project_id=payload.project_id,
                domain="synapse_wiki",
                source_system=_resolve_request_source_system(request, fallback=payload.updated_by or "human_editor"),
                endpoint=endpoint,
            )
            if check.get("status") == "advisory":
                source_ownership_advisories += 1
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                with conn.transaction():
                    root_row = _resolve_wiki_page_row_by_slug_or_alias(
                        cur,
                        project_id=payload.project_id,
                        slug_or_alias=normalized_slug,
                        for_update=True,
                    )
                    if root_row is None:
                        response = {
                            "error": "wiki_page_not_found",
                            "project_id": payload.project_id,
                            "slug": normalized_slug,
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=404,
                            response_body=response,
                        )
                        return JSONResponse(status_code=404, content=response)
                    root_slug = str(root_row[2] or normalized_slug).strip() or normalized_slug
                    space_key = _wiki_space_key_from_slug(root_slug)
                    policy_check = _check_wiki_policy_access(
                        cur,
                        project_id=payload.project_id,
                        space_key=space_key,
                        actor=payload.updated_by,
                        action="write",
                        page_id=str(root_row[0]),
                    )
                    if not policy_check["allowed"]:
                        response = {
                            "error": "wiki_policy_denied",
                            "project_id": payload.project_id,
                            "slug": root_slug,
                            "space_key": space_key,
                            "action": "write",
                            "reason": policy_check["reason"],
                            "policy": policy_check["policy"],
                        }
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=403,
                            response_body=response,
                        )
                        return JSONResponse(status_code=403, content=response)

                    if payload.include_descendants:
                        cur.execute(
                            """
                            SELECT id::text, title, slug, status, current_version
                            FROM wiki_pages
                            WHERE project_id = %s
                              AND (slug = %s OR slug LIKE %s)
                            ORDER BY LENGTH(slug) ASC, slug ASC
                            FOR UPDATE
                            """,
                            (payload.project_id, root_slug, f"{root_slug}/%"),
                        )
                    else:
                        cur.execute(
                            """
                            SELECT id::text, title, slug, status, current_version
                            FROM wiki_pages
                            WHERE project_id = %s
                              AND slug = %s
                            ORDER BY slug ASC
                            FOR UPDATE
                            """,
                            (payload.project_id, root_slug),
                        )
                    rows = cur.fetchall()
                    by_slug = {str(row[2]): row for row in rows}
                    root_row = by_slug.get(root_slug) or rows[0]
                    changed_rows = [row for row in rows if str(row[3]) != target_status]
                    if not changed_rows:
                        response = {
                            "status": "no_change",
                            "page": {
                                "id": str(root_row[0]),
                                "title": str(root_row[1] or root_row[2]),
                                "slug": str(root_row[2]),
                                "status": str(root_row[3]),
                                "current_version": int(root_row[4]) if root_row[4] is not None else None,
                            },
                            "changed_pages": [],
                        }
                        if source_ownership_advisories > 0:
                            response["source_ownership_advisories"] = source_ownership_advisories
                        mark_request_completed(
                            conn,
                            endpoint=endpoint,
                            idempotency_key=idempotency_key,
                            status_code=200,
                            response_body=response,
                        )
                        return response

                    changed_ids = [str(row[0]) for row in changed_rows]
                    change_summary = (
                        payload.change_summary.strip()
                        if isinstance(payload.change_summary, str) and payload.change_summary.strip()
                        else None
                    ) or f"Page restored by {payload.updated_by} to {target_status}"
                    cur.execute(
                        """
                        UPDATE wiki_pages
                        SET status = %s,
                            metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb,
                            updated_at = NOW()
                        WHERE id::text = ANY(%s)
                        """,
                        (
                            target_status,
                            Jsonb(
                                {
                                    "status_transition": {
                                        "updated_by": payload.updated_by,
                                        "to_status": target_status,
                                        "summary": change_summary,
                                        "at": datetime.now(UTC).isoformat(),
                                    }
                                }
                            ),
                            changed_ids,
                        ),
                    )

                    snapshot_id = uuid4()
                    cur.execute(
                        """
                        INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                        VALUES (%s, %s, %s, %s)
                        """,
                        (snapshot_id, payload.project_id, payload.updated_by, change_summary),
                    )
                    for row in changed_rows:
                        cur.execute(
                            """
                            INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                            VALUES (%s, %s, %s)
                            ON CONFLICT (snapshot_id, page_id) DO NOTHING
                            """,
                            (
                                snapshot_id,
                                str(row[0]),
                                int(row[4]) if row[4] is not None else 0,
                            ),
                        )

                    changed_pages = [
                        {
                            "id": str(row[0]),
                            "title": str(row[1] or row[2]),
                            "slug": str(row[2]),
                            "previous_status": str(row[3]),
                            "status": target_status,
                        }
                        for row in changed_rows
                    ]
                    response = {
                        "status": "updated",
                        "page": {
                            "id": str(root_row[0]),
                            "title": str(root_row[1] or root_row[2]),
                            "slug": str(root_row[2]),
                            "status": target_status if str(root_row[3]) != target_status else str(root_row[3]),
                            "current_version": int(root_row[4]) if root_row[4] is not None else None,
                        },
                        "include_descendants": bool(payload.include_descendants),
                        "changed_pages": changed_pages,
                        "snapshot_id": str(snapshot_id),
                    }
                    restore_watchers: set[str] = set()
                    for row in changed_rows:
                        restore_watchers.update(
                            _collect_wiki_page_watchers(
                                cur,
                                project_id=payload.project_id,
                                page_id=str(row[0]),
                            )
                        )
                    notification_ids = _insert_wiki_notifications(
                        cur,
                        project_id=payload.project_id,
                        recipients=restore_watchers,
                        actor=payload.updated_by,
                        kind="wiki.page_restored",
                        title=f"Page restored: {root_slug}",
                        body=change_summary,
                        link=f"/wiki/{root_slug}",
                        metadata={
                            "root_slug": root_slug,
                            "target_status": target_status,
                            "include_descendants": bool(payload.include_descendants),
                            "changed_pages": changed_pages,
                        },
                    )
                    if notification_ids:
                        response["notifications"] = {"inserted": len(notification_ids)}
                    if source_ownership_advisories > 0:
                        response["source_ownership_advisories"] = source_ownership_advisories
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=200,
                        response_body=response,
                    )
                    return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.get("/v1/wiki/pages/search")
def search_wiki_pages(
    project_id: str,
    q: str = Query(min_length=1),
    limit: int = Query(default=20, ge=1, le=100),
) -> dict[str, Any]:
    needle = q.strip().lower()
    wildcard_all = needle in {"*", "all", "__all__"}
    like = f"%{needle}%"
    with get_conn() as conn:
        with conn.cursor() as cur:
            if wildcard_all:
                cur.execute(
                    """
                    SELECT
                      p.id::text,
                      p.title,
                      p.slug,
                      p.entity_key,
                      p.page_type,
                      p.status,
                      0.50::float AS score
                    FROM wiki_pages p
                    WHERE p.project_id = %s
                    ORDER BY p.updated_at DESC, p.created_at DESC
                    LIMIT %s
                    """,
                    (project_id, limit),
                )
            else:
                cur.execute(
                    """
                    SELECT
                      p.id::text,
                      p.title,
                      p.slug,
                      p.entity_key,
                      p.page_type,
                      p.status,
                      CASE
                        WHEN lower(p.entity_key) = %s THEN 1.00
                        WHEN lower(p.slug) = %s THEN 0.95
                        WHEN lower(p.title) LIKE %s THEN 0.85
                        WHEN EXISTS (
                          SELECT 1
                          FROM wiki_page_aliases a
                          WHERE a.page_id = p.id
                            AND lower(a.alias_text) LIKE %s
                        ) THEN 0.80
                        ELSE 0.40
                      END AS score
                    FROM wiki_pages p
                    WHERE p.project_id = %s
                      AND (
                        lower(p.entity_key) = %s
                        OR lower(p.slug) = %s
                        OR lower(p.title) LIKE %s
                        OR EXISTS (
                          SELECT 1
                          FROM wiki_page_aliases a
                          WHERE a.page_id = p.id
                            AND lower(a.alias_text) LIKE %s
                        )
                      )
                    ORDER BY score DESC, p.updated_at DESC
                    LIMIT %s
                    """,
                    (needle, needle, like, like, project_id, needle, needle, like, like, limit),
                )
            rows = cur.fetchall()
            cur.execute(
                """
                SELECT status, COUNT(*)::bigint
                FROM wiki_pages
                WHERE project_id = %s
                GROUP BY status
                """,
                (project_id,),
            )
            page_count_rows = cur.fetchall()
            cur.execute(
                """
                SELECT status, COUNT(*)::bigint
                FROM wiki_draft_changes
                WHERE project_id = %s
                GROUP BY status
                """,
                (project_id,),
            )
            draft_count_rows = cur.fetchall()
    results = [
        {
            "id": row[0],
            "title": row[1],
            "slug": row[2],
            "entity_key": row[3],
            "page_type": row[4],
            "status": row[5],
            "score": float(row[6]),
        }
        for row in rows
    ]
    pages_by_status = {str(row[0]): int(row[1]) for row in page_count_rows}
    drafts_by_status = {str(row[0]): int(row[1]) for row in draft_count_rows}
    published_count = int(pages_by_status.get("published", 0))
    drafts_total = int(sum(drafts_by_status.values()))
    response: dict[str, Any] = {
        "results": results,
        "meta": {
            "searched_scope": {
                "project_id": project_id,
                "tables": ["wiki_pages", "wiki_page_aliases"],
            },
            "filters_applied": {
                "query": q.strip(),
                "normalized_query": needle,
                "query_mode": "all_pages" if wildcard_all else "search",
                "limit": int(limit),
            },
            "counts": {
                "results": len(results),
                "pages_by_status": pages_by_status,
                "drafts_by_status": drafts_by_status,
                "published_count": published_count,
                "draft_count": drafts_total,
            },
        },
    }
    if not results:
        response["meta"]["debug_hint"] = (
            "No wiki page match. Check `project_id`, moderation status, or whether imported claims were approved into pages."
        )
    return response


_DEFAULT_PAGE_TYPE_FRESHNESS_WINDOWS: dict[str, tuple[int, int]] = {
    "policy": (3, 7),
    "access": (3, 7),
    "incident": (3, 7),
    "process": (7, 14),
    "runbook": (7, 14),
    "agent_profile": (7, 14),
    "metric": (7, 14),
    "operations": (14, 30),
    "data_map": (14, 30),
    "decision_log": (21, 45),
    "workstream": (14, 30),
    "person": (14, 30),
    "experiment": (14, 30),
}


def _page_type_freshness_thresholds(
    *,
    page_type: str,
    fallback_stale_days: int,
    fallback_critical_days: int,
    page_type_aware: bool,
) -> dict[str, Any]:
    normalized_type = str(page_type or "").strip().lower() or "operations"
    if not page_type_aware:
        return {
            "page_type": normalized_type,
            "stale_days": int(max(1, fallback_stale_days)),
            "critical_days": int(max(int(max(1, fallback_stale_days)), fallback_critical_days)),
            "source": "global",
        }
    typed = _DEFAULT_PAGE_TYPE_FRESHNESS_WINDOWS.get(normalized_type)
    if typed is None:
        return {
            "page_type": normalized_type,
            "stale_days": int(max(1, fallback_stale_days)),
            "critical_days": int(max(int(max(1, fallback_stale_days)), fallback_critical_days)),
            "source": "global_fallback",
        }
    stale_days, critical_days = typed
    return {
        "page_type": normalized_type,
        "stale_days": int(max(1, stale_days)),
        "critical_days": int(max(stale_days, critical_days)),
        "source": "page_type",
    }


@app.get("/v1/wiki/pages")
def list_wiki_pages(
    project_id: str,
    status: str | None = Query(default=None),
    updated_by: str | None = Query(default=None, min_length=1, max_length=256),
    with_open_drafts: bool | None = Query(default=None),
    q: str | None = Query(default=None),
    limit: int = Query(default=200, ge=1, le=1000),
    offset: int = Query(default=0, ge=0, le=50000),
    sort_by: str = Query(default="activity"),
    sort_dir: str = Query(default="desc"),
    stale_days: int = Query(default=7, ge=1, le=365),
    critical_days: int = Query(default=14, ge=1, le=365),
    page_type_aware: bool = Query(default=True),
) -> dict[str, Any]:
    normalized_status = str(status or "").strip().lower()
    if normalized_status and normalized_status not in {"draft", "reviewed", "published", "archived"}:
        raise HTTPException(status_code=422, detail="wiki_page_status_invalid")

    normalized_updated_by = str(updated_by or "").strip()
    normalized_query = str(q or "").strip()
    wildcard_all = normalized_query.lower() in {"*", "all", "__all__"}
    if wildcard_all:
        normalized_query = ""
    normalized_limit = normalize_limit_value(limit, default=200, minimum=1, maximum=1000)
    normalized_offset = max(0, int(offset))
    normalized_sort_by = str(sort_by or "activity").strip().lower()
    normalized_sort_dir = str(sort_dir or "desc").strip().lower()
    normalized_stale_days = max(1, int(stale_days))
    normalized_stale_critical_days = max(normalized_stale_days, int(critical_days))
    if normalized_sort_dir not in {"asc", "desc"}:
        raise HTTPException(status_code=422, detail="wiki_page_sort_dir_invalid")
    direction_sql = "ASC" if normalized_sort_dir == "asc" else "DESC"
    sort_sql = {
        "activity": "COALESCE(dm.latest_draft_at, p.updated_at, p.created_at)",
        "title": "LOWER(p.title)",
        "slug": "LOWER(p.slug)",
        "updated_at": "p.updated_at",
        "created_at": "p.created_at",
        "open_drafts": "COALESCE(dm.open_count, 0)",
    }.get(normalized_sort_by)
    if sort_sql is None:
        raise HTTPException(status_code=422, detail="wiki_page_sort_by_invalid")

    filters: list[str] = ["p.project_id = %s"]
    filter_params: list[Any] = [project_id]
    if normalized_status:
        filters.append("p.status = %s")
        filter_params.append(normalized_status)
    if normalized_updated_by:
        filters.append(
            """
            LOWER(COALESCE(NULLIF(TRIM(p.metadata ->> 'updated_by'), ''), NULLIF(TRIM(p.metadata ->> 'created_by'), ''), ''))
            = LOWER(%s)
            """.strip()
        )
        filter_params.append(normalized_updated_by[:256])
    if with_open_drafts is True:
        filters.append(
            """
            EXISTS (
              SELECT 1
              FROM wiki_draft_changes wd
              WHERE wd.project_id = p.project_id
                AND wd.page_id = p.id
                AND wd.status IN ('pending_review', 'blocked_conflict')
            )
            """.strip()
        )
    elif with_open_drafts is False:
        filters.append(
            """
            NOT EXISTS (
              SELECT 1
              FROM wiki_draft_changes wd
              WHERE wd.project_id = p.project_id
                AND wd.page_id = p.id
                AND wd.status IN ('pending_review', 'blocked_conflict')
            )
            """.strip()
        )
    if normalized_query:
        needle = f"%{normalized_query[:250]}%"
        filters.append("(p.title ILIKE %s OR p.slug ILIKE %s OR COALESCE(p.entity_key, '') ILIKE %s)")
        filter_params.extend([needle, needle, needle])
    where_sql = f"WHERE {' AND '.join(filters)}"

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT COUNT(*)::bigint
                FROM wiki_pages p
                {where_sql}
                """,
                tuple(filter_params),
            )
            total_row = cur.fetchone()
            total = int(total_row[0] if total_row else 0)

            cur.execute(
                f"""
                WITH draft_metrics AS (
                  SELECT
                    page_id,
                    COUNT(*)::bigint AS draft_count,
                    COUNT(*) FILTER (WHERE status IN ('pending_review', 'blocked_conflict'))::bigint AS open_count,
                    MAX(created_at) AS latest_draft_at
                  FROM wiki_draft_changes
                  WHERE project_id = %s
                  GROUP BY page_id
                )
                SELECT
                  p.id::text,
                  p.title,
                  p.slug,
                  p.entity_key,
                  p.page_type,
                  p.status,
                  p.current_version,
                  p.created_at,
                  p.updated_at,
                  COALESCE(dm.draft_count, 0)::bigint,
                  COALESCE(dm.open_count, 0)::bigint,
                  dm.latest_draft_at
                FROM wiki_pages p
                LEFT JOIN draft_metrics dm ON dm.page_id = p.id
                {where_sql}
                ORDER BY {sort_sql} {direction_sql} NULLS LAST, LOWER(p.slug) ASC
                LIMIT %s OFFSET %s
                """,
                (project_id, *filter_params, normalized_limit, normalized_offset),
            )
            rows = cur.fetchall()

    now = datetime.now(UTC)
    pages: list[dict[str, Any]] = []
    stale_warning_total = 0
    stale_critical_total = 0
    for row in rows:
        created_at = row[7] if isinstance(row[7], datetime) else None
        updated_at = row[8] if isinstance(row[8], datetime) else None
        last_activity = updated_at or created_at
        stale_age_days: int | None = None
        stale_warning = False
        stale_critical = False
        freshness = _page_type_freshness_thresholds(
            page_type=str(row[4] or "operations"),
            fallback_stale_days=normalized_stale_days,
            fallback_critical_days=normalized_stale_critical_days,
            page_type_aware=bool(page_type_aware),
        )
        if isinstance(last_activity, datetime):
            stale_age_days = max(0, int((now - last_activity.astimezone(UTC)).total_seconds() // 86400))
            stale_warning = stale_age_days >= int(freshness["stale_days"])
            stale_critical = stale_age_days >= int(freshness["critical_days"])
        if stale_warning:
            stale_warning_total += 1
        if stale_critical:
            stale_critical_total += 1
        pages.append(
            {
                "id": row[0],
                "title": row[1],
                "slug": row[2],
                "entity_key": row[3],
                "page_type": row[4],
                "status": row[5],
                "current_version": int(row[6]) if row[6] is not None else None,
                "created_at": created_at.isoformat() if created_at is not None else None,
                "updated_at": updated_at.isoformat() if updated_at is not None else None,
                "draft_count": int(row[9]),
                "open_draft_count": int(row[10]),
                "latest_draft_at": row[11].isoformat() if row[11] is not None else None,
                "stale_age_days": stale_age_days,
                "stale_warning": bool(stale_warning),
                "stale_critical": bool(stale_critical),
                "freshness": freshness,
            }
        )
    return {
        "pages": pages,
        "meta": {
            "project_id": project_id,
            "filters_applied": {
                "status": normalized_status or None,
                "updated_by": normalized_updated_by or None,
                "with_open_drafts": with_open_drafts,
                "query": normalized_query or None,
                "query_mode": "all_pages" if wildcard_all else "search",
                "limit": normalized_limit,
                "offset": normalized_offset,
                "sort_by": normalized_sort_by,
                "sort_dir": normalized_sort_dir,
                "stale_days": normalized_stale_days,
                "critical_days": normalized_stale_critical_days,
                "page_type_aware": bool(page_type_aware),
            },
            "total": total,
            "returned": len(pages),
            "stale_summary": {
                "stale_days": normalized_stale_days,
                "critical_days": normalized_stale_critical_days,
                "page_type_aware": bool(page_type_aware),
                "warning_total": int(stale_warning_total),
                "critical_total": int(stale_critical_total),
            },
            "freshness_defaults_by_page_type": {
                page_type_key: {"stale_days": int(values[0]), "critical_days": int(values[1])}
                for page_type_key, values in sorted(_DEFAULT_PAGE_TYPE_FRESHNESS_WINDOWS.items())
            },
        },
    }


_LIFECYCLE_TELEMETRY_KIND_SHOWN = "empty_scope_action_shown"
_LIFECYCLE_TELEMETRY_KIND_APPLIED = "empty_scope_action_applied"
_LIFECYCLE_TELEMETRY_KINDS = (_LIFECYCLE_TELEMETRY_KIND_SHOWN, _LIFECYCLE_TELEMETRY_KIND_APPLIED)


def _normalize_lifecycle_action_key(value: str | None) -> str:
    normalized = re.sub(r"[^a-z0-9_]+", "_", str(value or "").strip().lower())
    normalized = re.sub(r"_+", "_", normalized).strip("_")
    if not normalized:
        return ""
    return normalized[:96]


def _normalize_lifecycle_action_counts(raw: dict[str, Any] | None) -> dict[str, int]:
    if not isinstance(raw, dict):
        return {}
    normalized: dict[str, int] = {}
    for action, count in raw.items():
        action_key = _normalize_lifecycle_action_key(str(action or ""))
        if not action_key:
            continue
        try:
            numeric_count = int(count)
        except (TypeError, ValueError):
            continue
        bounded = max(0, min(1_000_000_000, numeric_count))
        normalized[action_key] = bounded
    return normalized


def _load_lifecycle_action_telemetry_summary(
    conn,
    *,
    project_id: str,
    days: int,
    action_key: str | None = None,
) -> dict[str, Any]:
    normalized_days = max(1, min(90, int(days)))
    normalized_action_key = _normalize_lifecycle_action_key(action_key)
    since_date = datetime.now(UTC).date() - timedelta(days=normalized_days - 1)
    until_date = datetime.now(UTC).date()

    action_filter_sql = "AND action_key = %s" if normalized_action_key else ""
    base_params: tuple[Any, ...] = (
        _LIFECYCLE_TELEMETRY_KIND_SHOWN,
        _LIFECYCLE_TELEMETRY_KIND_APPLIED,
        project_id,
        since_date,
    )
    if normalized_action_key:
        base_params = (*base_params, normalized_action_key)

    with conn.cursor() as cur:
        cur.execute(
            f"""
            SELECT
              action_key,
              COALESCE(SUM(total_count) FILTER (WHERE metric_kind = %s), 0)::bigint AS shown_total,
              COALESCE(SUM(total_count) FILTER (WHERE metric_kind = %s), 0)::bigint AS applied_total
            FROM wiki_lifecycle_action_telemetry_daily
            WHERE project_id = %s
              AND metric_date >= %s
              {action_filter_sql}
            GROUP BY action_key
            ORDER BY applied_total DESC, shown_total DESC, action_key ASC
            """,
            base_params,
        )
        action_rows = cur.fetchall() or []

        cur.execute(
            f"""
            SELECT
              metric_date,
              COALESCE(SUM(total_count) FILTER (WHERE metric_kind = %s), 0)::bigint AS shown_total,
              COALESCE(SUM(total_count) FILTER (WHERE metric_kind = %s), 0)::bigint AS applied_total
            FROM wiki_lifecycle_action_telemetry_daily
            WHERE project_id = %s
              AND metric_date >= %s
              {action_filter_sql}
            GROUP BY metric_date
            ORDER BY metric_date ASC
            """,
            base_params,
        )
        daily_rows = cur.fetchall() or []

    action_items: list[dict[str, Any]] = []
    shown_total_all = 0
    applied_total_all = 0
    for row in action_rows:
        shown_total = int(row[1] or 0)
        applied_total = int(row[2] or 0)
        shown_total_all += shown_total
        applied_total_all += applied_total
        action_items.append(
            {
                "action_key": str(row[0] or ""),
                "shown_total": shown_total,
                "applied_total": applied_total,
                "apply_rate": _safe_ratio(applied_total, max(1, shown_total)),
            }
        )

    daily_map: dict[str, dict[str, int]] = {}
    for row in daily_rows:
        metric_day: date = row[0]
        day_key = metric_day.isoformat()
        daily_map[day_key] = {
            "shown_total": int(row[1] or 0),
            "applied_total": int(row[2] or 0),
        }

    daily_series: list[dict[str, Any]] = []
    for offset in range(normalized_days):
        day_value = since_date + timedelta(days=offset)
        day_key = day_value.isoformat()
        bucket = daily_map.get(day_key) or {"shown_total": 0, "applied_total": 0}
        daily_series.append(
            {
                "metric_date": day_key,
                "shown_total": int(bucket["shown_total"]),
                "applied_total": int(bucket["applied_total"]),
            }
        )

    return {
        "project_id": project_id,
        "action_key": normalized_action_key or None,
        "days": normalized_days,
        "since": since_date.isoformat(),
        "until": until_date.isoformat(),
        "summary": {
            "shown_total": shown_total_all,
            "applied_total": applied_total_all,
            "apply_rate": _safe_ratio(applied_total_all, max(1, shown_total_all)),
            "actions": action_items,
        },
        "daily": daily_series,
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/wiki/lifecycle/stats")
def get_wiki_lifecycle_stats(
    project_id: str,
    stale_days: int = Query(default=7, ge=1, le=365),
    critical_days: int = Query(default=14, ge=1, le=365),
    stale_limit: int = Query(default=20, ge=1, le=200),
    space_key: str | None = Query(default=None),
    page_type_aware: bool = Query(default=True),
) -> dict[str, Any]:
    normalized_stale_days = max(1, int(stale_days))
    normalized_critical_days = max(normalized_stale_days, int(critical_days))
    normalized_limit = normalize_limit_value(stale_limit, default=20, minimum=1, maximum=200)
    normalized_space_raw = str(space_key or "").strip()
    normalized_space_key = _slugify_segment(normalized_space_raw) if normalized_space_raw else None

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                WITH draft_metrics AS (
                  SELECT
                    page_id,
                    COUNT(*) FILTER (WHERE status IN ('pending_review', 'blocked_conflict'))::bigint AS open_count,
                    MAX(created_at) AS latest_draft_at
                  FROM wiki_draft_changes
                  WHERE project_id = %s
                  GROUP BY page_id
                )
                SELECT
                  p.slug,
                  p.title,
                  p.page_type,
                  p.status,
                  p.created_at,
                  p.updated_at,
                  COALESCE(dm.open_count, 0)::bigint AS open_draft_count,
                  COALESCE(dm.latest_draft_at, p.updated_at, p.created_at) AS activity_at
                FROM wiki_pages p
                LEFT JOIN draft_metrics dm ON dm.page_id = p.id
                WHERE p.project_id = %s
                  AND (%s::text IS NULL OR split_part(p.slug, '/', 1) = %s::text)
                ORDER BY COALESCE(dm.latest_draft_at, p.updated_at, p.created_at) ASC, p.slug ASC
                """,
                (
                    project_id,
                    project_id,
                    normalized_space_key,
                    normalized_space_key,
                ),
            )
            page_rows = cur.fetchall() or []

    now = datetime.now(UTC)
    stale_pages: list[dict[str, Any]] = []
    stale_critical_pages: list[dict[str, Any]] = []
    counts = {
        "total_pages": 0,
        "draft_pages": 0,
        "reviewed_pages": 0,
        "published_pages": 0,
        "archived_pages": 0,
        "pages_with_open_drafts": 0,
        "stale_warning_pages": 0,
        "stale_critical_pages": 0,
        "published_pages_with_open_drafts": 0,
        "published_pages_without_open_drafts": 0,
        "published_pages_below_stale_threshold": 0,
    }
    stale_candidates: list[dict[str, Any]] = []
    for row in page_rows:
        slug = str(row[0] or "")
        title = str(row[1] or "")
        page_type = str(row[2] or "operations")
        status_value = str(row[3] or "")
        created_at = row[4] if isinstance(row[4], datetime) else None
        updated_at = row[5] if isinstance(row[5], datetime) else None
        open_draft_count = int(row[6] or 0)
        activity_at = row[7] if isinstance(row[7], datetime) else (updated_at or created_at)
        counts["total_pages"] += 1
        if status_value == "draft":
            counts["draft_pages"] += 1
        elif status_value == "reviewed":
            counts["reviewed_pages"] += 1
        elif status_value == "published":
            counts["published_pages"] += 1
        elif status_value == "archived":
            counts["archived_pages"] += 1
        if open_draft_count > 0:
            counts["pages_with_open_drafts"] += 1

        freshness = _page_type_freshness_thresholds(
            page_type=page_type,
            fallback_stale_days=normalized_stale_days,
            fallback_critical_days=normalized_critical_days,
            page_type_aware=bool(page_type_aware),
        )
        age_days: float | None = None
        if activity_at is not None:
            age_days = max(0.0, (now - activity_at.astimezone(UTC)).total_seconds() / 86400.0)
        if status_value == "published":
            if open_draft_count > 0:
                counts["published_pages_with_open_drafts"] += 1
            else:
                counts["published_pages_without_open_drafts"] += 1
                if age_days is not None and age_days >= float(freshness["stale_days"]):
                    counts["stale_warning_pages"] += 1
                    severity = "critical" if age_days >= float(freshness["critical_days"]) else "warning"
                    item = {
                        "slug": slug,
                        "title": title,
                        "page_type": page_type,
                        "status": status_value,
                        "open_draft_count": open_draft_count,
                        "activity_at": activity_at.isoformat() if activity_at is not None else None,
                        "updated_at": updated_at.isoformat() if updated_at is not None else None,
                        "age_days": round(age_days, 1),
                        "severity": severity,
                        "freshness": freshness,
                    }
                    stale_candidates.append(item)
                    if severity == "critical":
                        counts["stale_critical_pages"] += 1
                else:
                    counts["published_pages_below_stale_threshold"] += 1

    stale_candidates.sort(
        key=lambda item: (-float(item.get("age_days") or 0.0), str(item.get("slug") or "")),
    )
    stale_pages = stale_candidates[:normalized_limit]
    stale_critical_pages = [item for item in stale_pages if str(item.get("severity") or "") == "critical"]

    published_pages = int(counts["published_pages"])
    published_pages_with_open_drafts = int(counts["published_pages_with_open_drafts"])
    published_pages_without_open_drafts = int(counts["published_pages_without_open_drafts"])
    published_pages_below_stale_threshold = int(counts["published_pages_below_stale_threshold"])

    empty_scope: dict[str, Any] | None = None
    if len(stale_pages) == 0:
        if published_pages <= 0:
            empty_scope = {
                "code": "no_published",
                "message": "No published pages in selected scope.",
                "details": {
                    "published_pages": published_pages,
                    "published_pages_with_open_drafts": published_pages_with_open_drafts,
                    "published_pages_without_open_drafts": published_pages_without_open_drafts,
                    "published_pages_below_stale_threshold": published_pages_below_stale_threshold,
                    "stale_days": normalized_stale_days,
                    "page_type_aware": bool(page_type_aware),
                },
                "suggested_actions": [
                    {
                        "action": "create_page",
                        "label": "Create first wiki page",
                        "deep_link": {
                            "core_tab": "wiki",
                        },
                    }
                ],
            }
        elif published_pages_without_open_drafts <= 0 and published_pages_with_open_drafts > 0:
            empty_scope = {
                "code": "all_open_drafts",
                "message": "All published pages currently have open drafts, so stale detection is deferred.",
                "details": {
                    "published_pages": published_pages,
                    "published_pages_with_open_drafts": published_pages_with_open_drafts,
                    "published_pages_without_open_drafts": published_pages_without_open_drafts,
                    "published_pages_below_stale_threshold": published_pages_below_stale_threshold,
                    "stale_days": normalized_stale_days,
                    "page_type_aware": bool(page_type_aware),
                },
                "suggested_actions": [
                    {
                        "action": "review_open_drafts",
                        "label": "Review open drafts",
                        "deep_link": {
                            "core_tab": "drafts",
                            "wiki_focus": "draft_inbox",
                        },
                    }
                ],
            }
        else:
            empty_scope = {
                "code": "below_threshold",
                "message": "Published pages are within freshness threshold for current stale window.",
                "details": {
                    "published_pages": published_pages,
                    "published_pages_with_open_drafts": published_pages_with_open_drafts,
                    "published_pages_without_open_drafts": published_pages_without_open_drafts,
                    "published_pages_below_stale_threshold": published_pages_below_stale_threshold,
                    "stale_days": normalized_stale_days,
                    "page_type_aware": bool(page_type_aware),
                },
                "suggested_actions": [
                    {
                        "action": "lower_threshold",
                        "label": "Use 21/45 preset",
                    },
                    {
                        "action": "create_page",
                        "label": "Create policy page",
                        "deep_link": {
                            "core_tab": "wiki",
                        },
                    },
                ],
            }

    return {
        "project_id": project_id,
        "thresholds": {
            "stale_days": normalized_stale_days,
            "critical_days": normalized_critical_days,
            "page_type_aware": bool(page_type_aware),
        },
        "counts": counts,
        "stale_pages": stale_pages,
        "stale_critical_pages": stale_critical_pages,
        "meta": {
            "generated_at": datetime.now(UTC).isoformat(),
            "limit": normalized_limit,
            "space_key": normalized_space_key,
            "freshness_defaults_by_page_type": {
                page_type_key: {"stale_days": int(values[0]), "critical_days": int(values[1])}
                for page_type_key, values in sorted(_DEFAULT_PAGE_TYPE_FRESHNESS_WINDOWS.items())
            },
            "searched_scope": {
                "project_id": project_id,
                "space_key": normalized_space_key,
                "status_scope": "published_without_open_drafts",
            },
            "filters_applied": {
                "stale_days": normalized_stale_days,
                "critical_days": normalized_critical_days,
                "stale_limit": normalized_limit,
                "space_key": normalized_space_key,
                "page_type_aware": bool(page_type_aware),
            },
            "empty_scope": empty_scope,
        },
    }


@app.post("/v1/wiki/lifecycle/telemetry/snapshot")
def upsert_wiki_lifecycle_telemetry_snapshot(payload: WikiLifecycleTelemetrySnapshotRequest) -> dict[str, Any]:
    observed_at = payload.observed_at or datetime.now(UTC)
    metric_date = observed_at.date()
    shown_counts = _normalize_lifecycle_action_counts(payload.empty_scope_action_shown)
    applied_counts = _normalize_lifecycle_action_counts(payload.empty_scope_action_applied)
    source = str(payload.source or "web_ui").strip() or "web_ui"

    ingested_rows = 0
    ingested_by_kind = {
        _LIFECYCLE_TELEMETRY_KIND_SHOWN: 0,
        _LIFECYCLE_TELEMETRY_KIND_APPLIED: 0,
    }
    delta_by_kind = {
        _LIFECYCLE_TELEMETRY_KIND_SHOWN: 0,
        _LIFECYCLE_TELEMETRY_KIND_APPLIED: 0,
    }

    with get_conn() as conn:
        with conn.cursor() as cur:
            for metric_kind, counters in (
                (_LIFECYCLE_TELEMETRY_KIND_SHOWN, shown_counts),
                (_LIFECYCLE_TELEMETRY_KIND_APPLIED, applied_counts),
            ):
                if not counters:
                    continue
                for action_key, counter_value in counters.items():
                    cur.execute(
                        """
                        SELECT counter_value
                        FROM wiki_lifecycle_action_telemetry_snapshots
                        WHERE project_id = %s
                          AND session_id = %s
                          AND metric_kind = %s
                          AND action_key = %s
                        FOR UPDATE
                        """,
                        (payload.project_id, payload.session_id, metric_kind, action_key),
                    )
                    previous_row = cur.fetchone()
                    previous_value = int(previous_row[0] or 0) if previous_row is not None else 0
                    next_value = max(previous_value, int(counter_value))
                    delta = max(0, next_value - previous_value)

                    if previous_row is None:
                        cur.execute(
                            """
                            INSERT INTO wiki_lifecycle_action_telemetry_snapshots (
                              project_id,
                              session_id,
                              metric_kind,
                              action_key,
                              counter_value,
                              source,
                              observed_at,
                              updated_at
                            )
                            VALUES (%s, %s, %s, %s, %s, %s, %s, NOW())
                            """,
                            (
                                payload.project_id,
                                payload.session_id,
                                metric_kind,
                                action_key,
                                next_value,
                                source,
                                observed_at,
                            ),
                        )
                    elif next_value != previous_value:
                        cur.execute(
                            """
                            UPDATE wiki_lifecycle_action_telemetry_snapshots
                            SET counter_value = %s,
                                source = %s,
                                observed_at = %s,
                                updated_at = NOW()
                            WHERE project_id = %s
                              AND session_id = %s
                              AND metric_kind = %s
                              AND action_key = %s
                            """,
                            (
                                next_value,
                                source,
                                observed_at,
                                payload.project_id,
                                payload.session_id,
                                metric_kind,
                                action_key,
                            ),
                        )

                    if delta > 0:
                        cur.execute(
                            """
                            INSERT INTO wiki_lifecycle_action_telemetry_daily (
                              project_id,
                              metric_date,
                              metric_kind,
                              action_key,
                              total_count,
                              updated_at
                            )
                            VALUES (%s, %s, %s, %s, %s, NOW())
                            ON CONFLICT (project_id, metric_date, metric_kind, action_key) DO UPDATE
                            SET total_count = wiki_lifecycle_action_telemetry_daily.total_count + EXCLUDED.total_count,
                                updated_at = NOW()
                            """,
                            (payload.project_id, metric_date, metric_kind, action_key, int(delta)),
                        )
                        ingested_rows += 1
                        ingested_by_kind[metric_kind] = int(ingested_by_kind[metric_kind]) + 1
                        delta_by_kind[metric_kind] = int(delta_by_kind[metric_kind]) + int(delta)

        summary = _load_lifecycle_action_telemetry_summary(conn, project_id=payload.project_id, days=7)

    return {
        "status": "ok",
        "project_id": payload.project_id,
        "session_id": payload.session_id,
        "observed_at": observed_at.isoformat(),
        "metric_date": metric_date.isoformat(),
        "ingested_rows": ingested_rows,
        "ingested_by_kind": ingested_by_kind,
        "delta_by_kind": delta_by_kind,
        "summary_7d": summary.get("summary") if isinstance(summary, dict) else {},
    }


@app.get("/v1/wiki/lifecycle/telemetry")
def get_wiki_lifecycle_telemetry(
    project_id: str,
    days: int = Query(default=7, ge=1, le=90),
    action_key: str | None = Query(default=None),
) -> dict[str, Any]:
    with get_conn() as conn:
        return _load_lifecycle_action_telemetry_summary(
            conn,
            project_id=project_id,
            days=days,
            action_key=action_key,
        )


def _compute_wiki_routing_metrics(conn, *, project_id: str, window_days: int) -> dict[str, Any]:
    normalized_window_days = max(1, min(180, int(window_days)))
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT
              COUNT(*)::bigint,
              COUNT(*) FILTER (WHERE decision = 'new_page')::bigint,
              COUNT(*) FILTER (WHERE decision = 'new_statement')::bigint,
              COUNT(*) FILTER (WHERE decision = 'new_section')::bigint,
              COUNT(*) FILTER (WHERE decision = 'conflict')::bigint,
              COUNT(*) FILTER (WHERE rationale ILIKE 'ambiguous route near new-page threshold%%')::bigint,
              COUNT(*) FILTER (WHERE rationale ILIKE 'weak page match%%')::bigint
            FROM wiki_draft_changes
            WHERE project_id = %s
              AND created_at >= NOW() - (%s::text || ' days')::interval
            """,
            (project_id, normalized_window_days),
        )
        draft_row = cur.fetchone() or (0, 0, 0, 0, 0, 0, 0)

        cur.execute(
            """
            SELECT
              COUNT(*) FILTER (WHERE action_type = 'approve')::bigint,
              COUNT(*) FILTER (
                WHERE action_type = 'approve'
                  AND decision_before IS NOT NULL
                  AND decision_after IS NOT NULL
                  AND decision_before <> decision_after
              )::bigint,
              COUNT(*) FILTER (
                WHERE action_type = 'approve'
                  AND decision_before = 'new_page'
              )::bigint,
              COUNT(*) FILTER (
                WHERE action_type = 'approve'
                  AND decision_before = 'new_page'
                  AND COALESCE(decision_after, '') <> 'new_page'
              )::bigint
            FROM moderation_actions
            WHERE project_id = %s
              AND created_at >= NOW() - (%s::text || ' days')::interval
            """,
            (project_id, normalized_window_days),
        )
        moderation_row = cur.fetchone() or (0, 0, 0, 0)

        cur.execute(
            """
            SELECT
              percentile_cont(0.5) WITHIN GROUP (
                ORDER BY EXTRACT(EPOCH FROM (ma.created_at - d.created_at)) / 3600.0
              ) AS p50_hours,
              percentile_cont(0.9) WITHIN GROUP (
                ORDER BY EXTRACT(EPOCH FROM (ma.created_at - d.created_at)) / 3600.0
              ) AS p90_hours
            FROM moderation_actions ma
            JOIN wiki_draft_changes d ON d.id = ma.draft_id
            WHERE ma.project_id = %s
              AND ma.action_type = 'approve'
              AND ma.created_at >= NOW() - (%s::text || ' days')::interval
            """,
            (project_id, normalized_window_days),
        )
        latency_row = cur.fetchone() or (None, None)

    drafts_total = int(draft_row[0] or 0)
    new_page_proposed = int(draft_row[1] or 0)
    new_statement_proposed = int(draft_row[2] or 0)
    new_section_proposed = int(draft_row[3] or 0)
    conflicts_total = int(draft_row[4] or 0)
    ambiguous_total = int(draft_row[5] or 0)
    weak_match_total = int(draft_row[6] or 0)

    approvals_total = int(moderation_row[0] or 0)
    manual_reassign_total = int(moderation_row[1] or 0)
    new_page_approved_total = int(moderation_row[2] or 0)
    new_page_false_positive_total = int(moderation_row[3] or 0)

    conflict_rate = (float(conflicts_total) / float(drafts_total)) if drafts_total > 0 else 0.0
    ambiguous_rate = (float(ambiguous_total) / float(drafts_total)) if drafts_total > 0 else 0.0
    weak_match_rate = (float(weak_match_total) / float(drafts_total)) if drafts_total > 0 else 0.0
    manual_reassign_rate = (float(manual_reassign_total) / float(approvals_total)) if approvals_total > 0 else 0.0
    route_precision_at_1 = max(0.0, 1.0 - manual_reassign_rate)
    new_page_false_positive_rate = (
        float(new_page_false_positive_total) / float(new_page_approved_total)
        if new_page_approved_total > 0
        else 0.0
    )
    decision_latency_p50_hours = float(latency_row[0]) if latency_row and latency_row[0] is not None else None
    decision_latency_p90_hours = float(latency_row[1]) if latency_row and latency_row[1] is not None else None

    return {
        "project_id": project_id,
        "window_days": normalized_window_days,
        "generated_at": datetime.now(UTC).isoformat(),
        "counts": {
            "drafts_total": drafts_total,
            "new_page_proposed": new_page_proposed,
            "new_statement_proposed": new_statement_proposed,
            "new_section_proposed": new_section_proposed,
            "conflicts_total": conflicts_total,
            "ambiguous_routes_total": ambiguous_total,
            "weak_matches_total": weak_match_total,
            "approvals_total": approvals_total,
            "manual_reassign_total": manual_reassign_total,
            "new_page_approved_total": new_page_approved_total,
            "new_page_false_positive_total": new_page_false_positive_total,
        },
        "rates": {
            "route_precision_at_1": round(route_precision_at_1, 4),
            "new_page_false_positive_rate": round(new_page_false_positive_rate, 4),
            "manual_reassign_rate": round(manual_reassign_rate, 4),
            "conflict_rate": round(conflict_rate, 4),
            "ambiguous_route_rate": round(ambiguous_rate, 4),
            "weak_match_rate": round(weak_match_rate, 4),
        },
        "latency": {
            "decision_latency_p50_hours": round(decision_latency_p50_hours, 3)
            if decision_latency_p50_hours is not None
            else None,
            "decision_latency_p90_hours": round(decision_latency_p90_hours, 3)
            if decision_latency_p90_hours is not None
            else None,
        },
    }


