@app.get("/v1/wiki/routing/recommendations")
def get_wiki_routing_recommendations(
    project_id: str,
    window_days: int = Query(default=30, ge=1, le=180),
    threshold_high: float = Query(default=0.82, ge=0.0, le=1.0),
    threshold_mid: float = Query(default=0.55, ge=0.0, le=1.0),
    new_page_margin: float = Query(default=0.08, ge=0.0, le=0.3),
    ambiguity_gap: float = Query(default=0.06, ge=0.0, le=1.0),
) -> dict[str, Any]:
    with get_conn() as conn:
        metrics = _compute_wiki_routing_metrics(conn, project_id=project_id, window_days=window_days)

    rates = metrics.get("rates") or {}
    counts = metrics.get("counts") or {}
    fp_rate = float(rates.get("new_page_false_positive_rate") or 0.0)
    conflict_rate = float(rates.get("conflict_rate") or 0.0)
    ambiguous_rate = float(rates.get("ambiguous_route_rate") or 0.0)
    new_page_approved_total = int(counts.get("new_page_approved_total") or 0)
    drafts_total = int(counts.get("drafts_total") or 0)

    suggested_mid = float(threshold_mid)
    suggested_margin = float(new_page_margin)
    suggested_gap = float(ambiguity_gap)
    reasons: list[str] = []

    if new_page_approved_total >= 10:
        if fp_rate >= 0.2:
            suggested_margin += 0.03
            reasons.append("Increase new-page margin due to elevated new_page false-positive rate (>=0.20).")
        if fp_rate >= 0.35:
            suggested_margin += 0.03
            reasons.append("Further increase new-page margin due to severe new_page false-positive rate (>=0.35).")
    if drafts_total >= 30 and conflict_rate >= 0.25:
        suggested_mid += 0.01
        suggested_margin -= 0.03
        suggested_gap -= 0.01
        reasons.append("Raise routing strictness and reduce ambiguity window due to high conflict rate (>=0.25).")
    if drafts_total >= 30 and ambiguous_rate > 0.35 and conflict_rate < 0.12:
        suggested_margin += 0.01
        reasons.append("Slightly increase ambiguity margin to reduce borderline new-page proposals.")

    suggested_mid = max(0.0, min(0.99, suggested_mid))
    suggested_margin = max(0.0, min(0.3, suggested_margin))
    suggested_gap = max(0.0, min(1.0, suggested_gap))
    if not reasons:
        reasons.append("Current routing metrics do not indicate a strong threshold adjustment signal.")

    return {
        "project_id": project_id,
        "window_days": int(window_days),
        "current": {
            "threshold_high": float(threshold_high),
            "threshold_mid": float(threshold_mid),
            "new_page_margin": float(new_page_margin),
            "ambiguity_gap": float(ambiguity_gap),
        },
        "suggested": {
            "threshold_high": float(threshold_high),
            "threshold_mid": round(suggested_mid, 4),
            "new_page_margin": round(suggested_margin, 4),
            "ambiguity_gap": round(suggested_gap, 4),
        },
        "metrics": metrics,
        "reasons": reasons,
    }


@app.get("/v1/wiki/stats")
def get_wiki_stats(project_id: str) -> dict[str, Any]:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT status, COUNT(*)::bigint
                FROM wiki_pages
                WHERE project_id = %s
                GROUP BY status
                """,
                (project_id,),
            )
            page_count_rows = cur.fetchall()
            cur.execute(
                """
                SELECT status, COUNT(*)::bigint
                FROM wiki_draft_changes
                WHERE project_id = %s
                GROUP BY status
                """,
                (project_id,),
            )
            draft_count_rows = cur.fetchall()
            cur.execute(
                """
                SELECT
                  MAX(CASE WHEN status = 'published' THEN updated_at END),
                  MAX(created_at)
                FROM wiki_pages
                WHERE project_id = %s
                """,
                (project_id,),
            )
            page_time_row = cur.fetchone()
            cur.execute(
                """
                SELECT
                  MAX(created_at),
                  MAX(updated_at)
                FROM wiki_draft_changes
                WHERE project_id = %s
                """,
                (project_id,),
            )
            draft_time_row = cur.fetchone()

    pages_by_status = {str(row[0]): int(row[1]) for row in page_count_rows}
    drafts_by_status = {str(row[0]): int(row[1]) for row in draft_count_rows}
    published_count = int(pages_by_status.get("published", 0))
    draft_total = int(sum(drafts_by_status.values()))
    return {
        "project_id": project_id,
        "pages": {
            "by_status": pages_by_status,
            "total": int(sum(pages_by_status.values())),
            "published": published_count,
            "last_published_at": page_time_row[0].isoformat() if page_time_row and page_time_row[0] is not None else None,
            "last_updated_at": page_time_row[1].isoformat() if page_time_row and page_time_row[1] is not None else None,
        },
        "drafts": {
            "by_status": drafts_by_status,
            "total": draft_total,
            "last_created_at": draft_time_row[0].isoformat() if draft_time_row and draft_time_row[0] is not None else None,
            "last_updated_at": draft_time_row[1].isoformat() if draft_time_row and draft_time_row[1] is not None else None,
        },
    }


@app.get("/v1/mcp/retrieval/explain")
def explain_mcp_retrieval(
    response: Response,
    project_id: str,
    q: str = Query(min_length=1),
    limit: int = Query(default=10, ge=1, le=100),
    entity_key: str | None = Query(default=None),
    category: str | None = Query(default=None),
    page_type: str | None = Query(default=None),
    related_entity_key: str | None = Query(default=None),
    retrieval_intent: str | None = Query(default=None),
    max_context_snippets: int = Query(default=3, ge=1, le=10),
    context_policy_mode: str | None = Query(default=None),
    min_retrieval_confidence: float | None = Query(default=None, ge=0.0, le=1.0),
    min_total_score: float | None = Query(default=None, ge=0.0, le=2.0),
    min_lexical_score: float | None = Query(default=None, ge=0.0, le=2.0),
    min_token_overlap_ratio: float | None = Query(default=None, ge=0.0, le=1.0),
) -> dict[str, Any]:
    normalized_query = q.strip()
    normalized_limit = normalize_limit_value(limit, default=10, minimum=1, maximum=100)
    normalized_related = clean_optional_filter(related_entity_key)
    normalized_intent = normalize_retrieval_intent(retrieval_intent, default="auto")
    normalized_max_context_snippets = normalize_limit_value(max_context_snippets, default=3, minimum=1, maximum=10)
    entity_filter = clean_optional_filter(entity_key)
    category_filter = clean_optional_filter(category)
    page_type_filter = clean_optional_filter(page_type)
    graph_config = load_graph_config_from_env()
    graph_config_payload = serialize_graph_config(graph_config)
    context_policy = resolve_context_policy_config(
        base=load_context_policy_config_from_env(),
        mode=context_policy_mode,
        min_confidence=min_retrieval_confidence,
        min_total_score=min_total_score,
        min_lexical_score=min_lexical_score,
        min_token_overlap_ratio=min_token_overlap_ratio,
    )
    context_policy_payload = serialize_context_policy_config(context_policy)
    for header_key, header_value in build_graph_config_headers(graph_config).items():
        response.headers[header_key] = header_value
    for header_key, header_value in build_context_policy_headers(context_policy).items():
        response.headers[header_key] = header_value
    if not normalized_query:
        return {
            "project_id": project_id,
            "query": "",
            "source": "api_mcp_compatible_retrieval_explain",
            "filters": {
                "entity_key": entity_filter,
                "category": category_filter,
                "page_type": page_type_filter,
                "related_entity_key": normalized_related,
            },
            "results": [],
            "graph_config": graph_config_payload,
            "context_policy": context_policy_payload,
            "policy_filtered_out": 0,
            "explainability": {
                "version": "v1",
                "query_tokens": [],
                "related_entity_key": normalized_related,
                "context_policy": context_policy_payload,
                "intent": normalized_intent,
                "max_context_snippets": normalized_max_context_snippets,
            },
            "context_injection": {"intent": normalized_intent, "snippets": []},
        }
    plan = build_retrieval_search_plan(
        project_id=project_id,
        query=normalized_query,
        limit=normalized_limit,
        entity_key=entity_filter,
        category=category_filter,
        page_type=page_type_filter,
        related_entity_key=normalized_related,
        graph_config=graph_config,
    )
    if plan is None:
        return {
            "project_id": project_id,
            "query": "",
            "source": "api_mcp_compatible_retrieval_explain",
            "filters": {
                "entity_key": entity_filter,
                "category": category_filter,
                "page_type": page_type_filter,
                "related_entity_key": normalized_related,
            },
            "results": [],
            "graph_config": graph_config_payload,
            "context_policy": context_policy_payload,
            "policy_filtered_out": 0,
            "explainability": {
                "version": "v1",
                "query_tokens": [],
                "related_entity_key": normalized_related,
                "context_policy": context_policy_payload,
                "intent": normalized_intent,
                "max_context_snippets": normalized_max_context_snippets,
            },
            "context_injection": {"intent": normalized_intent, "snippets": []},
        }

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(plan.sql, plan.params)
            rows = cur.fetchall()

    results: list[dict[str, Any]] = []
    for row in rows:
        payload = {
            "statement_id": row[0],
            "statement_text": row[1],
            "section_key": row[2],
            "valid_from": row[3].isoformat() if row[3] is not None else None,
            "valid_to": row[4].isoformat() if row[4] is not None else None,
            "created_at": row[5].isoformat() if row[5] is not None else None,
            "page": {
                "id": row[6],
                "title": row[7],
                "slug": row[8],
                "entity_key": row[9],
                "page_type": row[10],
            },
            "category": row[11] or None,
            "claim_id": row[12] or None,
            "claim_metadata": row[13] if isinstance(row[13], dict) else {},
            "claim_evidence": row[14] if isinstance(row[14], list) else [],
            "claim_observed_at": row[15].isoformat() if row[15] is not None else None,
            "score": round(float(row[16]), 4),
            "graph_hops": int(row[17]) if row[17] is not None else None,
            "graph_boost": round(float(row[18]), 4),
        }
        results.append(
            build_retrieval_explain_fields(
                query=plan.query,
                related_entity_key=plan.related_entity_key,
                result=payload,
                query_tokens_override=plan.query_tokens,
                context_policy=context_policy,
            )
        )
    filtered_out = 0
    if normalize_context_policy_mode(context_policy.mode) == "enforced":
        before = len(results)
        results = [
            row
            for row in results
            if isinstance(row.get("context_policy"), dict) and bool(row["context_policy"].get("eligible"))
        ]
        filtered_out = max(0, before - len(results))
    reranked_results, intent_payload = apply_intent_reranking(
        query=plan.query,
        results=results,
        explicit_intent=normalized_intent,
        max_context_snippets=normalized_max_context_snippets,
        query_tokens_override=plan.query_tokens,
    )
    explainability_payload = {
        "version": "v1",
        "query_tokens": list(plan.query_tokens),
        "related_entity_key": plan.related_entity_key,
        "context_policy": context_policy_payload,
    }
    if isinstance(intent_payload.get("explainability"), dict):
        explainability_payload.update(intent_payload["explainability"])

    return {
        "project_id": project_id,
        "query": plan.query,
        "source": "api_mcp_compatible_retrieval_explain",
        "filters": {
            "entity_key": plan.entity_key,
            "category": plan.category,
            "page_type": plan.page_type,
            "related_entity_key": plan.related_entity_key,
        },
        "results": reranked_results,
        "graph_config": graph_config_payload,
        "context_policy": context_policy_payload,
        "policy_filtered_out": filtered_out,
        "context_injection": {
            "intent": explainability_payload.get("intent", normalized_intent),
            "snippets": intent_payload.get("context_snippets") or [],
        },
        "explainability": explainability_payload,
    }


@app.post("/v1/mcp/retrieval/feedback")
def write_mcp_retrieval_feedback(payload: RetrievalFeedbackWriteRequest) -> dict[str, Any]:
    project_id = payload.project_id.strip()
    if not project_id:
        raise HTTPException(status_code=422, detail={"code": "project_id_required"})
    with get_conn() as conn:
        if not _wiki_retrieval_feedback_table_exists(conn):
            raise HTTPException(
                status_code=503,
                detail={
                    "code": "retrieval_feedback_not_available",
                    "hint": "apply migration 050_retrieval_feedback_loop.sql",
                },
            )
        page_id: str | None = None
        if payload.page_slug:
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT id::text
                    FROM wiki_pages
                    WHERE project_id = %s
                      AND slug = %s
                    LIMIT 1
                    """,
                    (project_id, _normalize_wiki_slug(payload.page_slug, payload.page_slug)),
                )
                row = cur.fetchone()
                if row is not None:
                    page_id = str(row[0])
        feedback_id = uuid4()
        with conn.cursor() as cur:
            cur.execute(
                """
                INSERT INTO wiki_retrieval_feedback (
                  id,
                  project_id,
                  claim_id,
                  page_id,
                  feedback,
                  usefulness_score,
                  query_text,
                  session_id,
                  source_system,
                  metadata
                )
                VALUES (
                  %s, %s, %s, %s::uuid, %s, %s, %s, %s, %s, %s
                )
                """,
                (
                    feedback_id,
                    project_id,
                    payload.claim_id,
                    page_id,
                    payload.feedback,
                    payload.usefulness_score,
                    payload.query.strip() if isinstance(payload.query, str) and payload.query.strip() else None,
                    payload.session_id.strip() if isinstance(payload.session_id, str) and payload.session_id.strip() else None,
                    _normalize_source_system(payload.source_system, default="unknown"),
                    Jsonb(payload.metadata or {}),
                ),
            )
    return {
        "status": "ok",
        "feedback_id": str(feedback_id),
        "project_id": project_id,
        "feedback": payload.feedback,
        "claim_id": str(payload.claim_id) if payload.claim_id is not None else None,
        "page_id": page_id,
        "created_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/mcp/retrieval/feedback/stats")
def get_mcp_retrieval_feedback_stats(
    project_id: str,
    days: int = Query(default=30, ge=1, le=365),
    limit: int = Query(default=100, ge=1, le=500),
) -> dict[str, Any]:
    with get_conn() as conn:
        if not _wiki_retrieval_feedback_table_exists(conn):
            raise HTTPException(
                status_code=503,
                detail={
                    "code": "retrieval_feedback_not_available",
                    "hint": "apply migration 050_retrieval_feedback_loop.sql",
                },
            )
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  COALESCE(claim_id::text, '') AS claim_id,
                  SUM(CASE WHEN feedback = 'positive' THEN 1 ELSE 0 END) AS positive_count,
                  SUM(CASE WHEN feedback = 'negative' THEN 1 ELSE 0 END) AS negative_count,
                  SUM(CASE WHEN feedback = 'neutral' THEN 1 ELSE 0 END) AS neutral_count,
                  COUNT(*)::bigint AS total_count,
                  MAX(created_at) AS last_feedback_at
                FROM wiki_retrieval_feedback
                WHERE project_id = %s
                  AND created_at >= NOW() - make_interval(days => %s)
                GROUP BY COALESCE(claim_id::text, '')
                ORDER BY COUNT(*) DESC, MAX(created_at) DESC
                LIMIT %s
                """,
                (project_id, int(days), int(limit)),
            )
            rows = cur.fetchall() or []
    items: list[dict[str, Any]] = []
    for row in rows:
        positive = int(row[1] or 0)
        negative = int(row[2] or 0)
        neutral = int(row[3] or 0)
        total = int(row[4] or 0)
        negative_ratio = (float(negative) / float(total)) if total > 0 else 0.0
        items.append(
            {
                "claim_id": str(row[0]) or None,
                "positive_count": positive,
                "negative_count": negative,
                "neutral_count": neutral,
                "total_count": total,
                "negative_ratio": round(negative_ratio, 4),
                "negative_balance": negative - positive,
                "last_feedback_at": row[5].isoformat() if row[5] is not None else None,
            }
        )
    return {
        "project_id": project_id,
        "window_days": int(days),
        "items": items,
        "generated_at": datetime.now(UTC).isoformat(),
    }


