def _split_markdown_sections(markdown: str) -> tuple[list[str], list[tuple[str, str]]]:
    frontmatter, body, has_frontmatter = _parse_markdown_frontmatter(markdown)
    frontmatter_lines = (
        _render_markdown_frontmatter(frontmatter).strip().splitlines()
        if has_frontmatter and frontmatter
        else []
    )
    lines = body.splitlines()
    preamble: list[str] = []
    sections: list[tuple[str, str]] = []
    current_heading: str | None = None
    current_lines: list[str] = []
    saw_section = False
    for raw in lines:
        stripped = raw.strip()
        if stripped.startswith("## "):
            if current_heading is not None:
                sections.append((current_heading, "\n".join(current_lines).strip()))
            elif current_lines:
                preamble = current_lines[:]
            current_heading = stripped[3:].strip() or "Section"
            current_lines = []
            saw_section = True
            continue
        current_lines.append(raw)
    if current_heading is not None:
        sections.append((current_heading, "\n".join(current_lines).strip()))
    elif current_lines and not saw_section:
        preamble = current_lines[:]
    return frontmatter_lines + ([""] if frontmatter_lines else []), sections if sections else [("Overview", "\n".join(preamble).strip())]


def _section_content_is_placeholder_like(content: str) -> bool:
    lowered = str(content or "").strip().lower()
    if not lowered:
        return True
    words = re.findall(r"[a-zа-я0-9_]+", lowered)
    if len(words) < 18:
        return True
    placeholder_hits = sum(lowered.count(token) for token in _BOOTSTRAP_PLACEHOLDER_TOKENS)
    return placeholder_hits >= 2


def _merge_markdown_with_enrichment(
    *,
    markdown: str,
    candidate_markdown: str,
    page_type: str,
    title: str,
    slug: str,
    status: str,
    generated_at: datetime,
) -> tuple[str, dict[str, Any]]:
    original_frontmatter, original_body, _ = _parse_markdown_frontmatter(markdown)
    _, candidate_body, _ = _parse_markdown_frontmatter(candidate_markdown)
    original_sections = _extract_sections_from_markdown(original_body or markdown)
    candidate_sections = _extract_sections_from_markdown(candidate_body or candidate_markdown)
    candidate_by_heading: dict[str, list[str]] = {}
    for section in candidate_sections:
        heading = str(section.get("heading") or "").strip()
        statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
        if heading and statements:
            candidate_by_heading[heading.lower()] = statements

    merged_sections: list[dict[str, Any]] = []
    filled_sections: list[str] = []
    existing_headings: set[str] = set()
    for section in original_sections:
        heading = str(section.get("heading") or "Overview").strip() or "Overview"
        statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
        existing_headings.add(heading.lower())
        if (not statements or _section_content_is_placeholder_like("\n".join(statements))) and heading.lower() in candidate_by_heading:
            statements = list(candidate_by_heading[heading.lower()])
            filled_sections.append(heading)
        merged_sections.append(
            {
                "heading": heading,
                "section_key": str(section.get("section_key") or _slugify_segment(heading).replace("-", "_")),
                "statements": statements,
            }
        )

    added_sections: list[str] = []
    for section in candidate_sections:
        heading = str(section.get("heading") or "").strip()
        if not heading or heading.lower() in existing_headings:
            continue
        statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
        if not statements:
            continue
        merged_sections.append(
            {
                "heading": heading,
                "section_key": str(section.get("section_key") or _slugify_segment(heading).replace("-", "_")),
                "statements": statements,
            }
        )
        added_sections.append(heading)

    first_heading = str(re.search(r"^#\s+(.+)$", original_body or markdown, flags=re.MULTILINE).group(1)) if re.search(r"^#\s+(.+)$", original_body or markdown, flags=re.MULTILINE) else title
    lines = [f"# {first_heading.strip() or title}"]
    for section in merged_sections:
        heading = str(section.get("heading") or "Overview").strip() or "Overview"
        lines.extend(["", f"## {heading}"])
        statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
        if statements:
            lines.extend([f"- {item}" for item in statements])
        else:
            lines.append("- Enrichment pending.")
    merged_markdown = "\n".join(lines).strip() + "\n"
    if original_frontmatter:
        original_frontmatter.setdefault("summary", str(original_frontmatter.get("summary") or "").strip() or f"{title} knowledge page.")
    applied = _apply_wiki_schema_contract(
        markdown=merged_markdown,
        title=title,
        page_type=page_type,
        slug=slug,
        status=status,
        generated_at=generated_at,
    )
    return applied, {
        "filled_sections": filled_sections,
        "added_sections": added_sections,
        "used_candidate": bool(filled_sections or added_sections),
    }


def _evaluate_publish_enrichment_need(markdown: str, *, page_type: str, slug: str) -> dict[str, Any]:
    schema = _evaluate_wiki_schema_contract(markdown=markdown, page_type=page_type, slug=slug)
    frontmatter, body, _ = _parse_markdown_frontmatter(markdown)
    text = body if body.strip() else markdown
    words = re.findall(r"[a-zа-я0-9_]+", text.lower())
    min_words = int(_WIKI_ENRICHMENT_MIN_WORDS_BY_PAGE_TYPE.get(str(page_type or "").strip().lower(), 90))
    placeholder_hits = sum(text.lower().count(token) for token in _BOOTSTRAP_PLACEHOLDER_TOKENS)
    placeholder_ratio = round(float(placeholder_hits) / float(max(1, len(words))), 4)
    needs_enrichment = bool(
        not bool(schema.get("passed"))
        or len(words) < min_words
        or placeholder_ratio >= 0.04
    )
    return {
        "needs_enrichment": needs_enrichment,
        "schema_contract": schema,
        "word_count": len(words),
        "min_word_count": min_words,
        "placeholder_ratio": placeholder_ratio,
        "frontmatter": frontmatter,
    }


def _build_decisions_log_compiler_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_entries: int,
) -> list[dict[str, str]]:
    bundle_rows = _load_evidence_bundles_for_bootstrap(
        cur,
        project_id=project_id,
        bundle_types=["decision", "process", "policy"],
        statuses=["ready", "candidate"],
        limit=max(10, min(120, int(max_entries) * 3)),
    )
    claim_rows: list[tuple[Any, ...]] = []
    if _wiki_feature_table_exists(cur, "public.claims"):
        cur.execute(
            """
            SELECT claim_text, category, metadata, created_at, updated_at
            FROM claims
            WHERE project_id = %s
              AND status <> 'rejected'
              AND (
                lower(COALESCE(category, '')) IN ('decision', 'policy', 'process', 'runbook')
                OR metadata ? 'operator_decision'
              )
            ORDER BY updated_at DESC, created_at DESC
            LIMIT %s
            """,
            (project_id, max(20, min(300, int(max_entries) * 6))),
        )
        claim_rows = cur.fetchall() or []

    entries: list[dict[str, Any]] = []
    seen_markers: set[str] = set()
    for bundle in bundle_rows:
        bundle_metadata = bundle.get("metadata") if isinstance(bundle.get("metadata"), dict) else {}
        sample_claims = bundle.get("sample_claims") if isinstance(bundle.get("sample_claims"), list) else []
        sample = sample_claims[0] if sample_claims and isinstance(sample_claims[0], dict) else {}
        claim_text = str(sample.get("claim_text") or "").strip()
        if not claim_text:
            claim_text = f"{str(bundle.get('entity_key') or 'decision')} requires follow-through based on durable evidence."
        marker = _normalize_statement_text(claim_text)[:180]
        if marker in seen_markers:
            continue
        seen_markers.add(marker)
        source_parts = []
        for item in (
            bundle_metadata.get("source_system"),
            bundle_metadata.get("source"),
            bundle.get("bundle_key"),
        ):
            text = str(item or "").strip()
            if text:
                source_parts.append(text)
        date_value = str(bundle.get("last_seen_at") or datetime.now(UTC).date().isoformat())[:10]
        entries.append(
            {
                "date": date_value,
                "area": str(bundle.get("entity_key") or bundle.get("bundle_type") or "operations").replace("_", " ").title(),
                "decision": claim_text[:320],
                "source": " / ".join(source_parts[:3]) or "internal://evidence-bundle",
                "confidence": float(bundle.get("quality_score") or 0.0),
                "support": int(bundle.get("support_count") or 0),
            }
        )
        if len(entries) >= max_entries:
            break

    for row in claim_rows:
        claim_text = str(row[0] or "").strip()
        category = str(row[1] or "operations").strip() or "operations"
        metadata = row[2] if isinstance(row[2], dict) else {}
        if not claim_text:
            continue
        marker = _normalize_statement_text(claim_text)[:180]
        if marker in seen_markers:
            continue
        seen_markers.add(marker)
        operator_decision = metadata.get("operator_decision") if isinstance(metadata.get("operator_decision"), dict) else {}
        source_text = str(
            metadata.get("source_system")
            or metadata.get("source")
            or operator_decision.get("source")
            or "internal://claim"
        ).strip()
        outcome = str(operator_decision.get("outcome") or "").strip()
        decision_text = claim_text if not outcome else f"{claim_text} Outcome: {outcome}."
        created_at = row[4] if isinstance(row[4], datetime) else row[3]
        entries.append(
            {
                "date": (created_at.astimezone(UTC).date().isoformat() if isinstance(created_at, datetime) else datetime.now(UTC).date().isoformat()),
                "area": category.replace("_", " ").title(),
                "decision": decision_text[:320],
                "source": source_text or "internal://claim",
                "confidence": float(metadata.get("llm_confidence") or metadata.get("confidence") or 0.65),
                "support": len(metadata.get("linked_ticket_ids") or []),
            }
        )
        if len(entries) >= max_entries:
            break

    lines = [
        "# Decisions Log",
        "",
        "Canonical decisions that changed how agents should operate.",
        "",
        "## How To Use",
        "- Record durable decisions, not raw discussion.",
        "- Link each decision to impacted process/playbook pages and rollback criteria.",
        "",
        "## Decision Index",
        "| Date | Area | Confidence | Support | Source |",
        "|---|---|---:|---:|---|",
    ]
    if entries:
        for item in entries[:max_entries]:
            lines.append(
                f"| {item['date']} | {str(item['area']).replace('|', '/')} | {int(round(float(item['confidence']) * 100))}% | {int(item['support'])} | {str(item['source']).replace('|', '/')} |"
            )
        lines.extend(["", "## Decisions Log"])
        for item in entries[:max_entries]:
            lines.append(
                f"- {item['date']} - {item['decision']} | Source: {item['source']}"
            )
    else:
        lines.extend(
            [
                "| n/a | n/a | 0% | 0 | internal://pending-bootstrap |",
                "",
                "## Decisions Log",
                f"- {datetime.now(UTC).date().isoformat()} - Bootstrap baseline created; first durable decisions will appear after claims and bundles accumulate. | Source: internal://bootstrap",
            ]
        )
    return [
        {
            "title": "Decisions Log",
            "slug": _space_slug(space_key, "decisions-log"),
            "page_type": "decision_log",
            "markdown": "\n".join(lines),
        }
    ]


def _build_publish_enrichment_candidates(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    page_type: str,
    slug: str,
) -> list[dict[str, str]]:
    candidates: list[dict[str, str]] = []
    normalized_type = str(page_type or "").strip().lower()
    normalized_slug = _normalize_wiki_slug(slug, slug)
    if normalized_type in {"agent_profile", "operations"} or normalized_slug.endswith("/agent-capability-profile"):
        candidates.extend(
            _build_agent_capability_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_agents=60,
            )
        )
    if normalized_type in {"data_map", "operations"} or normalized_slug.endswith("/data-sources-catalog") or "/source-" in normalized_slug:
        candidates.extend(
            _build_data_sources_catalog_pages(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_sources=40,
            )
        )
    if normalized_type in {"process", "runbook", "policy", "operations"} or normalized_slug.endswith("/process-playbooks"):
        candidates.extend(
            _build_process_playbooks_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_signals=40,
            )
        )
    if normalized_type in {"decision_log", "process", "operations"} or normalized_slug.endswith("/decisions-log"):
        candidates.extend(
            _build_decisions_log_compiler_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_entries=24,
            )
        )
    if normalized_type == "operations" or normalized_slug.endswith("/company-operating-context"):
        candidates.extend(
            _build_company_operating_context_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_signals=24,
            )
        )
    return candidates


def _maybe_enrich_wiki_markdown_before_publish(
    conn,
    *,
    project_id: str,
    slug: str,
    title: str,
    page_type: str,
    status: str,
    markdown: str,
    actor: str,
) -> tuple[str, dict[str, Any]]:
    normalized_status = str(status or "").strip().lower()
    evaluation = _evaluate_publish_enrichment_need(markdown, page_type=page_type, slug=slug)
    if normalized_status != "published" and not bool(evaluation.get("needs_enrichment")):
        return markdown, {"applied": False, "reason": "not_needed", **evaluation}
    if not bool(evaluation.get("needs_enrichment")):
        return markdown, {"applied": False, "reason": "quality_sufficient", **evaluation}

    space_key = _wiki_space_key_from_slug(slug)
    with conn.cursor() as cur:
        candidates = _build_publish_enrichment_candidates(
            cur,
            project_id=project_id,
            space_key=space_key,
            page_type=page_type,
            slug=slug,
        )
    candidate = next((item for item in candidates if _normalize_wiki_slug(str(item.get("slug") or ""), title) == slug), None)
    if candidate is None:
        candidate = next((item for item in candidates if str(item.get("page_type") or "") == str(page_type or "")), None)
    if candidate is None:
        return markdown, {"applied": False, "reason": "no_candidate", **evaluation}
    enriched_markdown, merge_meta = _merge_markdown_with_enrichment(
        markdown=markdown,
        candidate_markdown=str(candidate.get("markdown") or ""),
        page_type=page_type,
        title=title,
        slug=slug,
        status=status,
        generated_at=datetime.now(UTC),
    )
    enriched_eval = _evaluate_publish_enrichment_need(enriched_markdown, page_type=page_type, slug=slug)
    return enriched_markdown, {
        "applied": bool(merge_meta.get("used_candidate")),
        "actor": actor,
        "candidate_slug": str(candidate.get("slug") or ""),
        "merge": merge_meta,
        "before": evaluation,
        "after": enriched_eval,
    }


def _insert_bootstrap_pages(
    conn,
    *,
    project_id: str,
    created_by: str,
    profile: str,
    pages: list[dict[str, str]],
    requested_status: str,
    policy_space_fallback_enabled: bool = False,
    policy_space_fallback_candidates: list[str] | None = None,
    force_publish_slugs: list[str] | None = None,
) -> dict[str, Any]:
    def _assess_bootstrap_page_quality(
        *,
        page_type: str,
        title: str,
        slug: str,
        markdown: str,
    ) -> dict[str, Any]:
        text = str(markdown or "")
        normalized = text.lower()
        lines = [line.strip() for line in text.splitlines() if line.strip()]
        words = re.findall(r"[a-zа-я0-9_]+", normalized)
        heading_lines = [line for line in lines if line.startswith("#")]
        bullet_lines = [line for line in lines if line.startswith("- ") or line.startswith("* ")]
        table_lines = [line for line in lines if line.startswith("|") and line.count("|") >= 2]
        placeholder_tokens = [
            "n/a",
            "tbd",
            "todo",
            "runtime discovery pending",
            "no explicit usage mapped yet",
            "no high-signal patterns yet",
        ]
        placeholder_hits = [token for token in placeholder_tokens if token in normalized]
        factual_signals = sum(
            1
            for line in lines
            if any(
                token in line.lower()
                for token in (
                    "policy",
                    "process",
                    "runbook",
                    "owner",
                    "sla",
                    "escalat",
                    "source",
                    "tool",
                    "handoff",
                    "when ",
                    "if ",
                    "then ",
                )
            )
        )
        required_sections_by_type: dict[str, list[str]] = {
            "agent_profile": ["## Orgchart", "## Capability Matrix", "## Capability Signals", "## Handoffs"],
            "data_map": ["##", "Owner", "Freshness"],
            "process": ["##", "Escalat"],
            "runbook": ["##", "Action"],
            "policy": ["##", "Rule"],
        }
        required_markers = required_sections_by_type.get(str(page_type or "").strip().lower(), ["##"])
        missing_required = [marker for marker in required_markers if marker.lower() not in normalized]
        capability_contract: dict[str, Any] | None = None
        if str(page_type or "").strip().lower() == "agent_profile":
            capability_contract = _evaluate_agent_capability_bootstrap_contract(
                text,
                min_sections=4,
                min_facts=6,
            )
            missing_required.extend(list(capability_contract.get("missing_sections") or []))
        schema_contract = _evaluate_wiki_schema_contract(
            markdown=text,
            page_type=page_type,
            slug=slug,
        )
        missing_required.extend(list(schema_contract.get("missing_markers") or []))
        min_words_by_type = {
            "agent_profile": 120,
            "data_map": 80,
            "process": 55,
            "runbook": 55,
            "policy": 55,
        }
        min_words = int(min_words_by_type.get(str(page_type or "").strip().lower(), 40))
        quality_score = 0.0
        quality_score += min(0.35, len(words) / float(max(min_words, 1)) * 0.35)
        quality_score += min(0.2, len(heading_lines) / 4.0 * 0.2)
        quality_score += min(0.2, (len(bullet_lines) + len(table_lines)) / 10.0 * 0.2)
        quality_score += min(0.25, factual_signals / 8.0 * 0.25)
        quality_score -= min(0.25, len(placeholder_hits) * 0.08)
        quality_score = round(max(0.0, min(1.0, quality_score)), 4)
        publish_ready = bool(
            len(words) >= min_words
            and len(heading_lines) >= 2
            and (len(bullet_lines) + len(table_lines)) >= 3
            and factual_signals >= 3
            and len(missing_required) == 0
            and len(placeholder_hits) <= 1
        )
        if capability_contract is not None:
            publish_ready = bool(publish_ready and capability_contract.get("passed"))
        publish_ready = bool(publish_ready and schema_contract.get("passed"))
        return {
            "page_type": str(page_type or "operations"),
            "title": str(title or ""),
            "slug": str(slug or ""),
            "words": len(words),
            "headings": len(heading_lines),
            "bullets": len(bullet_lines),
            "table_rows": len(table_lines),
            "factual_signals": int(factual_signals),
            "placeholder_hits": placeholder_hits,
            "missing_required_markers": missing_required,
            "min_words": min_words,
            "quality_score": quality_score,
            "publish_ready": publish_ready,
            "capability_contract": capability_contract,
            "schema_contract": schema_contract,
        }

    def _rewrite_wiki_space_links(markdown_value: str, *, from_space_key: str, to_space_key: str) -> str:
        text = str(markdown_value or "")
        if not text:
            return text
        source_space = _normalize_space_key(from_space_key, default="")
        target_space = _normalize_space_key(to_space_key, default="")
        if not source_space or not target_space or source_space == target_space:
            return text
        return text.replace(f"/wiki/{source_space}/", f"/wiki/{target_space}/")

    def _rewrite_slug_space(slug_value: str, *, target_space_key: str) -> str:
        normalized_slug = _normalize_wiki_slug(slug_value, slug_value)
        if "/" in normalized_slug:
            _, leaf = normalized_slug.split("/", 1)
        else:
            leaf = normalized_slug
        return _space_slug(target_space_key, leaf or "page")

    def _resolve_writable_space(
        cur: Any,
        *,
        actor: str,
        requested_space_key: str,
    ) -> tuple[str | None, list[dict[str, Any]]]:
        candidates_raw = [requested_space_key, *(policy_space_fallback_candidates or []), "logistics", "general", "operations"]
        candidates: list[str] = []
        seen_candidates: set[str] = set()
        for item in candidates_raw:
            normalized = _normalize_space_key(item, default="")
            if not normalized:
                continue
            if normalized in seen_candidates:
                continue
            seen_candidates.add(normalized)
            candidates.append(normalized)
        diagnostics: list[dict[str, Any]] = []
        for candidate in candidates:
            check = _check_wiki_policy_access(
                cur,
                project_id=project_id,
                space_key=candidate,
                actor=actor,
                action="write",
                page_id=None,
            )
            diagnostics.append(
                {
                    "space_key": candidate,
                    "allowed": bool(check["allowed"]),
                    "reason": str(check.get("reason") or ""),
                    "policy": check.get("policy") if isinstance(check.get("policy"), dict) else {},
                }
            )
            if bool(check["allowed"]):
                return candidate, diagnostics
        return None, diagnostics

    created: list[dict[str, Any]] = []
    existing: list[dict[str, Any]] = []
    skipped: list[dict[str, Any]] = []
    policy_space_fallback: list[dict[str, Any]] = []
    downgraded_to_reviewed = 0
    downgraded_by_quality_gate = 0
    force_published_core_pages = 0
    force_publish_slug_set = {
        _normalize_wiki_slug(str(item or ""), str(item or "page"))
        for item in (force_publish_slugs or [])
        if str(item or "").strip()
    }
    created_page_ids: list[str] = []
    snapshot_id_text: str | None = None

    with conn.cursor() as cur:
        for spec in pages:
            title = str(spec.get("title") or "").strip()
            slug = _normalize_wiki_slug(str(spec.get("slug") or title), title)
            page_type = str(spec.get("page_type") or "operations").strip().lower() or "operations"
            raw_markdown = str(spec.get("markdown") or f"# {title}\n")
            markdown = _apply_wiki_schema_contract(
                markdown=raw_markdown,
                title=title,
                page_type=page_type,
                slug=slug,
                status=requested_status,
                generated_at=datetime.now(UTC),
            )
            space_key = _wiki_space_key_from_slug(slug)
            original_space_key = space_key
            entity_key = slug
            fallback_applied_for_page = False

            if policy_space_fallback_enabled:
                resolved_space_key, diagnostics = _resolve_writable_space(
                    cur,
                    actor=created_by,
                    requested_space_key=space_key,
                )
                if not resolved_space_key:
                    skipped.append(
                        {
                            "slug": slug,
                            "title": title,
                            "reason": "wiki_policy_denied_no_writable_space",
                            "detail": "No writable wiki space found for bootstrap actor.",
                            "policy_candidates": diagnostics,
                        }
                    )
                    continue
                if resolved_space_key != space_key:
                    previous_slug = slug
                    slug = _rewrite_slug_space(slug, target_space_key=resolved_space_key)
                    space_key = resolved_space_key
                    entity_key = slug
                    fallback_applied_for_page = True
                    policy_space_fallback.append(
                        {
                            "title": title,
                            "from_slug": previous_slug,
                            "to_slug": slug,
                            "space_key": space_key,
                            "policy_candidates": diagnostics,
                        }
                    )
            if fallback_applied_for_page:
                markdown = _rewrite_wiki_space_links(
                    markdown,
                    from_space_key=original_space_key,
                    to_space_key=space_key,
                )

            cur.execute(
                """
                SELECT id::text, status, current_version
                FROM wiki_pages
                WHERE project_id = %s
                  AND slug = %s
                LIMIT 1
                """,
                (project_id, slug),
            )
            current = cur.fetchone()
            if current is not None:
                existing.append(
                    {
                        "id": current[0],
                        "slug": slug,
                        "title": title,
                        "status": str(current[1] or ""),
                        "version": int(current[2] or 1),
                    }
                )
                continue

            policy_check = _check_wiki_policy_access(
                cur,
                project_id=project_id,
                space_key=space_key,
                actor=created_by,
                action="write",
                page_id=None,
            )
            if not policy_check["allowed"]:
                skipped.append(
                    {
                        "slug": slug,
                        "title": title,
                        "reason": "wiki_policy_denied",
                        "detail": str(policy_check.get("reason") or "not_allowed"),
                    }
                )
                continue

            status = requested_status
            quality_assessment = _assess_bootstrap_page_quality(
                page_type=page_type,
                title=title,
                slug=slug,
                markdown=markdown,
            )
            importance = _bootstrap_page_importance(slug=slug, page_type=page_type)
            quality_assessment["importance"] = importance
            if status == "published":
                guard = _resolve_agent_publish_mode(
                    cur,
                    project_id=project_id,
                    actor=created_by,
                    page_type=page_type,
                )
                if str(guard.get("mode") or "") == "human_required":
                    status = "reviewed"
                    downgraded_to_reviewed += 1
                elif not bool(quality_assessment.get("publish_ready")):
                    quality_score = float(quality_assessment.get("quality_score") or 0.0)
                    importance_floor = float(importance.get("publish_floor") or 0.0)
                    if slug in force_publish_slug_set or (
                        _is_core_bootstrap_page_slug(slug)
                        and int(importance.get("priority") or 0) >= 88
                        and quality_score >= importance_floor
                    ):
                        quality_assessment["forced_publish_core"] = True
                        quality_assessment["publish_warning"] = "bootstrap_publish_core_override"
                        markdown = _prepend_bootstrap_publish_notice(
                            markdown,
                            title=title,
                            importance=importance,
                            quality_assessment=quality_assessment,
                        )
                        force_published_core_pages += 1
                    else:
                        status = "reviewed"
                        downgraded_to_reviewed += 1
                        downgraded_by_quality_gate += 1

            page_id = uuid4()
            cur.execute(
                """
                INSERT INTO wiki_pages (
                  id, project_id, page_type, title, slug, entity_key, status, current_version, metadata
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, 1, %s)
                """,
                (
                    page_id,
                    project_id,
                    page_type,
                    title,
                    slug,
                    entity_key,
                    status,
                    Jsonb(
                        {
                            "source": "first_run_bootstrap",
                            "created_by": created_by,
                            "profile": profile,
                            "policy_space_fallback": bool(fallback_applied_for_page),
                            "bootstrap_quality_gate": quality_assessment,
                        }
                    ),
                ),
            )
            cur.execute(
                """
                INSERT INTO wiki_page_versions (
                  id, page_id, version, markdown, ast_json, source, created_by, change_summary
                )
                VALUES (%s, %s, 1, %s, %s, 'human', %s, %s)
                """,
                (uuid4(), page_id, markdown, Jsonb([]), created_by, "Created by first-run bootstrap"),
            )

            sections = _extract_sections_from_markdown(markdown)
            statements_count = 0
            for index, section in enumerate(sections):
                section_key = str(section.get("section_key") or f"section_{index + 1}")
                heading = str(section.get("heading") or _section_heading_from_key(section_key))
                statements = section.get("statements") or []
                cur.execute(
                    """
                    INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                    VALUES (%s, %s, %s, %s, %s)
                    ON CONFLICT (page_id, section_key) DO UPDATE
                    SET heading = EXCLUDED.heading,
                        order_index = EXCLUDED.order_index,
                        statement_count = EXCLUDED.statement_count
                    """,
                    (page_id, section_key, heading, index, len(statements)),
                )
                for statement_text in statements:
                    statement = str(statement_text).strip()
                    if not statement:
                        continue
                    statements_count += 1
                    statement_id = uuid4()
                    cur.execute(
                        """
                        INSERT INTO wiki_statements (
                          id, project_id, page_id, section_key, statement_text, normalized_text,
                          claim_fingerprint, status, metadata, valid_from
                        )
                        VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, NOW())
                        """,
                        (
                            statement_id,
                            project_id,
                            page_id,
                            section_key,
                            statement,
                            _normalize_statement_text(statement),
                            _compute_claim_fingerprint(project_id, entity_key, page_type, statement),
                            Jsonb({"source": "first_run_bootstrap", "created_by": created_by}),
                        ),
                    )

            created.append(
                {
                    "id": str(page_id),
                    "slug": slug,
                    "title": title,
                    "status": status,
                    "version": 1,
                    "sections": len(sections),
                    "statements": statements_count,
                    "quality_gate": quality_assessment,
                }
            )
            created_page_ids.append(str(page_id))

        if created_page_ids:
            snapshot_id = uuid4()
            snapshot_id_text = str(snapshot_id)
            cur.execute(
                """
                INSERT INTO knowledge_snapshots (id, project_id, created_by, note)
                VALUES (%s, %s, %s, %s)
                """,
                (
                    snapshot_id,
                    project_id,
                    created_by,
                    f"Bootstrap ({profile}) created {len(created_page_ids)} page(s)",
                ),
            )
            for page_id_text in created_page_ids:
                cur.execute(
                    """
                    INSERT INTO knowledge_snapshot_pages (snapshot_id, page_id, page_version)
                    VALUES (%s, %s::uuid, 1)
                    """,
                    (snapshot_id, page_id_text),
                )

    return {
        "created": created,
        "existing": existing,
        "skipped": skipped,
        "policy_space_fallback": {
            "enabled": bool(policy_space_fallback_enabled),
            "applied": policy_space_fallback,
            "applied_count": len(policy_space_fallback),
        },
        "summary": {
            "created": len(created),
            "existing": len(existing),
            "skipped": len(skipped),
            "published_downgraded_to_reviewed": downgraded_to_reviewed,
            "published_downgraded_by_quality_gate": downgraded_by_quality_gate,
            "force_published_core_pages": force_published_core_pages,
        },
        "snapshot_id": snapshot_id_text,
    }


