        {
            "template_key": "support_ops",
            "label": "Support Ops",
            "default_space_key": "support",
            "description": "Triage, escalation, and customer communication playbooks.",
            "policy": {"write_mode": "owners_only", "comment_mode": "open", "review_assignment_required": True},
        },
