def _queue_enabled_legacy_sources_for_project(conn, *, project_id: str, requested_by: str) -> dict[str, Any]:
    if not _legacy_import_sources_table_exists(conn) or not _public_table_exists(conn, "legacy_import_sync_runs"):
        return {"available": False, "queued": 0, "already_queued": 0, "sources_scanned": 0, "run_ids": []}
    queued = 0
    already_queued = 0
    run_ids: list[str] = []
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT id
            FROM legacy_import_sources
            WHERE project_id = %s
              AND enabled = TRUE
            ORDER BY updated_at DESC
            LIMIT 200
            """,
            (project_id,),
        )
        source_rows = cur.fetchall() or []
        for row in source_rows:
            source_id = row[0]
            cur.execute(
                """
                SELECT 1
                FROM legacy_import_sync_runs
                WHERE source_id = %s
                  AND status IN ('queued', 'running')
                LIMIT 1
                """,
                (source_id,),
            )
            if cur.fetchone() is not None:
                already_queued += 1
                continue
            run_id = uuid4()
            cur.execute(
                """
                INSERT INTO legacy_import_sync_runs (
                  id,
                  source_id,
                  project_id,
                  status,
                  trigger_mode,
                  requested_by,
                  summary,
                  created_at,
                  updated_at
                )
                VALUES (%s, %s, %s, 'queued', 'manual', %s, '{}'::jsonb, NOW(), NOW())
                """,
                (run_id, source_id, project_id, requested_by),
            )
            queued += 1
            run_ids.append(str(run_id))
    return {
        "available": True,
        "sources_scanned": len(source_rows),
        "queued": queued,
        "already_queued": already_queued,
        "run_ids": run_ids,
    }


def _legacy_sync_processor_health(
    conn,
    *,
    project_id: str,
    lookback_minutes: int = 30,
) -> dict[str, Any]:
    if not _legacy_import_sources_table_exists(conn) or not _public_table_exists(conn, "legacy_import_sync_runs"):
        return {
            "status": "unavailable",
            "processor_available": False,
            "reason_code": "legacy_sync_tables_unavailable",
            "lookback_minutes": int(max(1, lookback_minutes)),
            "queue": {
                "queued": 0,
                "running": 0,
            },
            "activity": {
                "completed_recent": 0,
                "failed_recent": 0,
                "last_progress_at": None,
            },
        }

    lookback = max(1, int(lookback_minutes))
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT
              COUNT(*) FILTER (WHERE status = 'queued')::bigint AS queued_count,
              COUNT(*) FILTER (WHERE status = 'running')::bigint AS running_count,
              COUNT(*) FILTER (
                WHERE status = 'completed'
                  AND COALESCE(finished_at, updated_at, created_at) >= NOW() - (%s * INTERVAL '1 minute')
              )::bigint AS completed_recent,
              COUNT(*) FILTER (
                WHERE status = 'failed'
                  AND COALESCE(finished_at, updated_at, created_at) >= NOW() - (%s * INTERVAL '1 minute')
              )::bigint AS failed_recent,
              MAX(COALESCE(updated_at, finished_at, started_at, created_at)) FILTER (
                WHERE status IN ('running', 'completed', 'failed', 'skipped')
              ) AS last_progress_at
            FROM legacy_import_sync_runs
            WHERE project_id = %s
            """,
            (lookback, lookback, project_id),
        )
        row = cur.fetchone() or (0, 0, 0, 0, None)

    queued = int(row[0] or 0)
    running = int(row[1] or 0)
    completed_recent = int(row[2] or 0)
    failed_recent = int(row[3] or 0)
    last_progress_at = row[4]
    has_recent_activity = running > 0 or completed_recent > 0 or failed_recent > 0
    processor_available = has_recent_activity

    status = "healthy"
    reason_code = "processor_active_recently"
    if queued > 0 and not has_recent_activity:
        status = "unavailable"
        reason_code = "queue_has_no_recent_processor_activity"
    elif queued == 0 and not has_recent_activity:
        status = "idle"
        reason_code = "no_recent_runs"

    return {
        "status": status,
        "processor_available": bool(processor_available),
        "reason_code": reason_code,
        "lookback_minutes": lookback,
        "queue": {
            "queued": queued,
            "running": running,
        },
        "activity": {
            "completed_recent": completed_recent,
            "failed_recent": failed_recent,
            "last_progress_at": None if last_progress_at is None else last_progress_at.isoformat(),
        },
    }


def _legacy_sync_cursor_health(conn, *, project_id: str, stale_after_hours: int = 24) -> dict[str, Any]:
    if not _legacy_import_sources_table_exists(conn):
        return {
            "status": "unavailable",
            "reason_code": "legacy_sync_sources_unavailable",
            "sources_total": 0,
            "polling_sources": 0,
            "cursor_missing": 0,
            "cursor_stale": 0,
            "generated_at": datetime.now(UTC).isoformat(),
            "sources": [],
        }
    stale_after = max(1, int(stale_after_hours))
    now = datetime.now(UTC)
    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT id::text, source_type, source_ref, enabled, last_success_at, last_run_at, config
            FROM legacy_import_sources
            WHERE project_id = %s
              AND enabled = TRUE
            ORDER BY updated_at DESC
            LIMIT 500
            """,
            (project_id,),
        )
        rows = cur.fetchall() or []
    sources: list[dict[str, Any]] = []
    polling_sources = 0
    cursor_missing = 0
    cursor_stale = 0
    for row in rows:
        source_id = str(row[0] or "").strip()
        source_type = str(row[1] or "").strip().lower()
        source_ref = str(row[2] or "").strip()
        last_success_at = row[4] if isinstance(row[4], datetime) else None
        last_run_at = row[5] if isinstance(row[5], datetime) else None
        config = row[6] if isinstance(row[6], dict) else {}
        sync_mode = str(config.get("sql_sync_mode") or "polling").strip().lower() or "polling"
        cursor_key = str(config.get("sql_cursor_state_key") or "sql_last_cursor").strip() or "sql_last_cursor"
        cursor_value = str(config.get(cursor_key) or "").strip()
        last_synced_raw = str(config.get("sql_last_synced_at") or "").strip()
        last_synced_at: datetime | None = None
        if last_synced_raw:
            try:
                parsed = datetime.fromisoformat(last_synced_raw.replace("Z", "+00:00"))
                if parsed.tzinfo is None:
                    parsed = parsed.replace(tzinfo=UTC)
                last_synced_at = parsed.astimezone(UTC)
            except Exception:
                last_synced_at = None

        is_polling = source_type == "postgres_sql" and sync_mode in {"polling", "query"}
        status = "ok"
        reason_code = "cursor_progressing"
        if is_polling:
            polling_sources += 1
            if not cursor_value:
                status = "warn"
                reason_code = "cursor_missing"
                cursor_missing += 1
            reference_ts = last_synced_at or last_success_at or last_run_at
            if reference_ts is not None:
                age_hours = (now - reference_ts).total_seconds() / 3600.0
                if age_hours >= float(stale_after):
                    status = "warn"
                    reason_code = "cursor_stale"
                    cursor_stale += 1

        sources.append(
            {
                "source_id": source_id,
                "source_type": source_type,
                "source_ref": source_ref[:200],
                "sync_mode": sync_mode,
                "cursor_key": cursor_key if is_polling else None,
                "cursor_present": bool(cursor_value) if is_polling else None,
                "last_success_at": last_success_at.isoformat() if isinstance(last_success_at, datetime) else None,
                "last_run_at": last_run_at.isoformat() if isinstance(last_run_at, datetime) else None,
                "last_synced_at": last_synced_at.isoformat() if isinstance(last_synced_at, datetime) else None,
                "status": status,
                "reason_code": reason_code,
            }
        )

    health_status = "healthy"
    if cursor_missing > 0 or cursor_stale > 0:
        health_status = "watch"
    if polling_sources > 0 and (cursor_missing >= polling_sources or cursor_stale >= polling_sources):
        health_status = "critical"

    return {
        "status": health_status,
        "reason_code": "cursor_health_summary",
        "sources_total": len(rows),
        "polling_sources": polling_sources,
        "cursor_missing": cursor_missing,
        "cursor_stale": cursor_stale,
        "stale_after_hours": stale_after,
        "generated_at": now.isoformat(),
        "sources": sources,
    }


def _source_ref_slug(source_type: str, source_ref: str) -> str:
    source_bits = [bit for bit in re.split(r"[^a-zA-Z0-9]+", str(source_ref or "")) if bit]
    short_ref = "-".join(source_bits[:6]).lower() or "source"
    return _slugify_segment(f"{_slugify_segment(source_type)}-{short_ref}")


def _format_freshness_label(last_success_at: datetime | None, last_run_at: datetime | None) -> str:
    ts = last_success_at or last_run_at
    if ts is None:
        return "unknown"
    delta = datetime.now(UTC) - ts
    hours = int(max(0, delta.total_seconds() // 3600))
    if hours < 1:
        return "fresh (<1h)"
    if hours < 24:
        return f"fresh ({hours}h)"
    days = int(hours // 24)
    return f"stale ({days}d)"


def _extract_source_location(source_type: str, source_ref: str, config: dict[str, Any]) -> str:
    if source_type == "postgres_sql":
        dsn_env = str(config.get("sql_dsn_env") or "").strip()
        table = str(config.get("sql_table") or "").strip()
        query = str(config.get("sql_query") or "").strip()
        profile = str(config.get("sql_profile") or config.get("profile") or "").strip()
        table_or_query = table or ("custom_query" if query else "")
        if dsn_env and table_or_query:
            return f"{dsn_env}:{table_or_query}"
        if dsn_env:
            return dsn_env
        if table_or_query:
            return table_or_query
        if profile:
            return f"profile:{profile}"
    if source_type == "memory_api":
        api_url = str(config.get("api_url") or source_ref or "").strip()
        method = str(config.get("api_method") or "GET").strip().upper()
        return f"{method} {api_url}" if api_url else method
    if source_ref:
        return str(source_ref).strip()
    return "n/a"


def _extract_source_owner(config: dict[str, Any], fallback: str) -> str:
    owner = (
        config.get("owner")
        or config.get("owner_name")
        or config.get("team_owner")
        or config.get("data_owner")
        or config.get("updated_by")
        or fallback
    )
    text = str(owner or "").strip()
    return text or "unassigned"


def _extract_source_key_fields(source_type: str, config: dict[str, Any]) -> list[str]:
    raw: list[str] = []
    if source_type == "postgres_sql":
        for key in (
            "sql_cursor_field",
            "sql_updated_field",
            "sql_entity_field",
            "sql_category_field",
            "sql_cursor_column",
            "sql_profile_resolved_table",
        ):
            value = str(config.get(key) or "").strip()
            if value:
                raw.append(value)
        sql_mapping = config.get("sql_mapping") if isinstance(config.get("sql_mapping"), dict) else {}
        for key in (
            "source_id_field",
            "entity_key_field",
            "category_field",
            "observed_at_field",
            "content_field",
        ):
            value = str(sql_mapping.get(key) or "").strip()
            if value:
                raw.append(value)
        content_fields = sql_mapping.get("content_fields") if isinstance(sql_mapping.get("content_fields"), list) else []
        for item in content_fields:
            value = str(item or "").strip()
            if value:
                raw.append(value)
    if source_type == "memory_api":
        mapping = config.get("api_mapping") if isinstance(config.get("api_mapping"), dict) else {}
        for key in ("id", "content", "observed_at", "entity_key", "category", "source_system", "namespace"):
            value = str(mapping.get(key) or "").strip()
            if value:
                raw.append(value)
    generic = config.get("key_fields")
    if isinstance(generic, list):
        for item in generic:
            value = str(item or "").strip()
            if value:
                raw.append(value)
    deduped: list[str] = []
    seen: set[str] = set()
    for value in raw:
        key = value.lower()
        if key in seen:
            continue
        seen.add(key)
        deduped.append(value)
    return deduped[:8]


def _extract_source_schema_sample(source_type: str, config: dict[str, Any]) -> list[str]:
    sample: list[str] = []
    if source_type == "postgres_sql":
        sql_mapping = config.get("sql_mapping") if isinstance(config.get("sql_mapping"), dict) else {}
        for key in ("source_id_field", "entity_key_field", "category_field", "observed_at_field"):
            value = str(sql_mapping.get(key) or "").strip()
            if value:
                sample.append(f"{key}: {value}")
        content_fields = sql_mapping.get("content_fields") if isinstance(sql_mapping.get("content_fields"), list) else []
        if content_fields:
            joined = ", ".join(str(item).strip() for item in content_fields if str(item).strip())
            if joined:
                sample.append(f"content_fields: {joined}")
        table_name = str(config.get("sql_profile_resolved_table") or config.get("sql_profile_table") or config.get("sql_table") or "").strip()
        if table_name:
            sample.append(f"table: {table_name}")
    elif source_type == "memory_api":
        mapping = config.get("api_mapping") if isinstance(config.get("api_mapping"), dict) else {}
        for key in ("id", "content", "observed_at", "entity_key", "category", "source_system", "namespace"):
            value = str(mapping.get(key) or "").strip()
            if value:
                sample.append(f"{key}: {value}")
    return sample[:12]


def _collect_agent_source_usage(
    cur: Any,
    *,
    project_id: str,
) -> dict[str, dict[str, set[str]]]:
    usage: dict[str, dict[str, set[str]]] = {}

    def _ensure_bucket(token: str) -> dict[str, set[str]]:
        bucket = usage.get(token)
        if bucket is None:
            bucket = {
                "agents": set(),
                "scenarios": set(),
                "capabilities": set(),
                "actions": set(),
                "processes": set(),
                "tools": set(),
            }
            usage[token] = bucket
        return bucket

    def _register(
        token: str,
        *,
        agent_id: str,
        scenario: str | None = None,
        capability: str | None = None,
        action: str | None = None,
        process: str | None = None,
        tool: str | None = None,
    ) -> None:
        normalized = str(token or "").strip().lower()
        if not normalized:
            return
        bucket = _ensure_bucket(normalized)
        bucket["agents"].add(agent_id)
        if scenario:
            bucket["scenarios"].add(str(scenario).strip()[:180])
        if capability:
            bucket["capabilities"].add(str(capability).strip()[:180])
        if action:
            bucket["actions"].add(str(action).strip()[:180])
        if process:
            bucket["processes"].add(str(process).strip()[:180])
        if tool:
            bucket["tools"].add(str(tool).strip()[:180])

    if not _wiki_feature_table_exists(cur, "public.agent_directory_profiles"):
        return usage
    cur.execute(
        """
        SELECT agent_id, data_sources, responsibilities, tools, metadata
        FROM agent_directory_profiles
        WHERE project_id = %s
        """,
        (project_id,),
    )
    rows = cur.fetchall() or []
    for row in rows:
        agent_id = str(row[0] or "").strip()
        data_sources = row[1] if isinstance(row[1], list) else []
        responsibilities = row[2] if isinstance(row[2], list) else []
        tools = row[3] if isinstance(row[3], list) else []
        metadata = row[4] if isinstance(row[4], dict) else {}
        if not agent_id:
            continue
        scenario_hints: list[str] = []
        metadata_scenarios = metadata.get("scenarios") if isinstance(metadata.get("scenarios"), list) else []
        process_hints = [str(item or "").strip() for item in (metadata.get("processes") or []) if str(item or "").strip()]
        action_hints = [str(item or "").strip() for item in (metadata.get("allowed_actions") or []) if str(item or "").strip()]
        capability_hints = [str(item or "").strip() for item in responsibilities if str(item or "").strip()]
        for item in metadata_scenarios:
            value = str(item or "").strip()
            if value:
                scenario_hints.append(value[:180])
                if len(scenario_hints) >= 5:
                    break
        for item in data_sources:
            token = str(item or "").strip().lower()
            if not token:
                continue
            _register(
                token,
                agent_id=agent_id,
                scenario=scenario_hints[0] if scenario_hints else None,
                capability=capability_hints[0] if capability_hints else None,
                action=action_hints[0] if action_hints else None,
                process=process_hints[0] if process_hints else None,
                tool=str(tools[0]).strip() if tools else None,
            )
            for part in re.split(r"[^a-zA-Z0-9_:/.-]+", token):
                normalized = part.strip().lower()
                if normalized:
                    _register(
                        normalized,
                        agent_id=agent_id,
                        scenario=scenario_hints[0] if scenario_hints else None,
                        capability=capability_hints[0] if capability_hints else None,
                        action=action_hints[0] if action_hints else None,
                        process=process_hints[0] if process_hints else None,
                        tool=str(tools[0]).strip() if tools else None,
                    )

    if _wiki_feature_table_exists(cur, "public.events"):
        cutoff = datetime.now(UTC) - timedelta(days=30)
        runtime_agent_expr = _runtime_agent_id_sql_expr(table_alias="e")
        runtime_agent_filter = _runtime_agent_filter_sql(column="runtime_agent_id")
        cur.execute(
            f"""
            WITH runtime_events AS (
              SELECT
                {runtime_agent_expr} AS runtime_agent_id,
                lower(trim(COALESCE(
                  NULLIF(e.payload#>>'{{metadata,source_system}}', ''),
                  NULLIF(e.payload#>>'{{backfill,source_system}}', ''),
                  NULLIF(e.payload->>'source_system', ''),
                  NULLIF(e.payload#>>'{{metadata,source}}', '')
                ))) AS source_name,
                trim(COALESCE(
                  NULLIF(e.payload->>'action_type', ''),
                  NULLIF(e.payload#>>'{{metadata,action_type}}', ''),
                  NULLIF(e.payload->>'intent', ''),
                  e.event_type
                )) AS action_type,
                trim(COALESCE(
                  NULLIF(e.payload->>'tool_name', ''),
                  NULLIF(e.payload->>'tool', ''),
                  NULLIF(e.payload#>>'{{tool,name}}', '')
                )) AS tool_name,
                e.observed_at
              FROM events e
              WHERE e.project_id = %s
                AND e.observed_at >= %s
            )
            SELECT
              runtime_agent_id AS agent_id,
              source_name,
              action_type,
              tool_name
            FROM runtime_events
            WHERE {runtime_agent_filter}
            ORDER BY observed_at DESC
            LIMIT 40000
            """,
            (project_id, cutoff),
        )
        event_rows = cur.fetchall() or []
        for row in event_rows:
            agent_id = str(row[0] or "").strip().lower()
            source_name = str(row[1] or "").strip().lower()
            action_type = str(row[2] or "").strip()
            tool_name = str(row[3] or "").strip()
            if not agent_id or not source_name:
                continue
            scenario = action_type or "runtime_event"
            if tool_name:
                scenario = f"{scenario} via {tool_name}"
            _register(
                source_name,
                agent_id=agent_id,
                scenario=scenario,
                action=action_type or None,
                process=action_type or None,
                tool=tool_name or None,
            )
            for part in re.split(r"[^a-zA-Z0-9_:/.-]+", source_name):
                normalized = part.strip().lower()
                if normalized:
                    _register(
                        normalized,
                        agent_id=agent_id,
                        scenario=scenario,
                        action=action_type or None,
                        process=action_type or None,
                        tool=tool_name or None,
                    )
    return usage


def _build_data_sources_catalog_pages(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_sources: int,
) -> list[dict[str, str]]:
    def _collect_bundle_source_tokens(bundle: dict[str, Any]) -> set[str]:
        metadata = bundle.get("metadata") if isinstance(bundle.get("metadata"), dict) else {}
        tokens: set[str] = set()

        def _add(value: Any) -> None:
            if isinstance(value, list):
                for item in value:
                    _add(item)
                return
            normalized = _normalize_statement_text(str(value or ""))
            if normalized:
                tokens.add(normalized)

        _add(bundle.get("entity_key"))
        _add(bundle.get("bundle_key"))
        _add(metadata.get("source_system"))
        _add(metadata.get("source"))
        _add(metadata.get("source_ref"))
        _add(metadata.get("source_name"))
        _add(metadata.get("source_id"))
        _add(metadata.get("claim_entity_key"))
        _add(metadata.get("source_systems"))
        _add(metadata.get("source_refs"))
        _add(metadata.get("sources"))
        return tokens

    def _source_stale_risk_label(freshness_label: str, *, bundle_ready: int, used_by_count: int) -> str:
        normalized = str(freshness_label or "").strip().lower()
        if "never synced" in normalized or "failed" in normalized:
            return "critical - source has no trustworthy recent sync"
        if "stale" in normalized and used_by_count >= 1:
            return "high - stale source can mislead active agent workflows"
        if "today" in normalized or "hours" in normalized:
            return "low - source freshness is within expected operating window"
        if bundle_ready >= 2 and used_by_count >= 2:
            return "medium - durable knowledge depends on this source; verify freshness before policy promotion"
        return "medium - monitor freshness and confirm owner for durable wiki synthesis"

    pages: list[dict[str, str]] = []
    if not _legacy_import_sources_table_exists_from_cursor(cur):
        return pages

    cur.execute(
        """
        SELECT
          source_type,
          source_ref,
          config,
          updated_by,
          last_success_at,
          last_run_at
        FROM legacy_import_sources
        WHERE project_id = %s
          AND enabled = TRUE
        ORDER BY updated_at DESC
        LIMIT %s
        """,
        (project_id, max(1, min(150, int(max_sources)))),
    )
    source_rows = cur.fetchall() or []
    usage_map = _collect_agent_source_usage(cur, project_id=project_id)
    source_bundles = _load_evidence_bundles_for_bootstrap(
        cur,
        project_id=project_id,
        bundle_types=["data_source", "decision", "process"],
        statuses=["ready", "candidate"],
        limit=max(18, min(240, int(max_sources) * 6)),
    )
    bundles_by_token: dict[str, list[dict[str, Any]]] = {}
    for bundle in source_bundles:
        for token in _collect_bundle_source_tokens(bundle):
            bundles_by_token.setdefault(token, []).append(bundle)

    table_lines = [
        "# Data Sources Catalog",
        "",
        "This catalog is the operational map of data feeding your agent workflows.",
        "Use it to answer: where data lives, who owns it, freshness/SLA posture, and which agents depend on it.",
        "",
        "## Connected Sources",
        "| Source | Type | Location | Owner | Freshness | Key Fields | Used by Agents | Capability / Process Impact |",
        "|---|---|---|---|---|---|---|---|",
    ]
    if not source_rows:
        table_lines.extend(
            [
                "| n/a | n/a | n/a | n/a | n/a | n/a | n/a | n/a |",
                "",
                "## Bootstrap Guidance",
                "- Connect at least one trusted memory source (`ops_kb_items` or equivalent policy/process store).",
                "- Ensure `curated_import.enabled=true` and noise preset is `enterprise_wiki_bootstrap`.",
                "- Define source owner and freshness SLA to avoid stale policy pages.",
                "",
            ]
        )
    detail_pages: list[dict[str, str]] = []
    for row in source_rows:
        source_type = _normalize_source_system(row[0], default="unknown")
        source_ref = str(row[1] or "").strip() or "source"
        config = row[2] if isinstance(row[2], dict) else {}
        updated_by = str(row[3] or "").strip() or "unknown"
        last_success_at = row[4] if isinstance(row[4], datetime) else None
        last_run_at = row[5] if isinstance(row[5], datetime) else None
        location = _extract_source_location(source_type, source_ref, config)
        owner = _extract_source_owner(config, updated_by)
        freshness = _format_freshness_label(last_success_at, last_run_at)
        key_fields = _extract_source_key_fields(source_type, config)
        schema_sample = _extract_source_schema_sample(source_type, config)
        key_fields_label = ", ".join(key_fields[:5]) if key_fields else "n/a"

        usage_tokens = {
            source_ref.lower(),
            source_type.lower(),
            str(config.get("sql_profile") or "").strip().lower(),
            str(config.get("source_system") or "").strip().lower(),
        }
        used_by: set[str] = set()
        scenario_hints: set[str] = set()
        capability_hints: set[str] = set()
        process_hints: set[str] = set()
        action_hints: set[str] = set()
        tool_hints: set[str] = set()
        for token in usage_tokens:
            if not token:
                continue
            usage_bucket = usage_map.get(token) if isinstance(usage_map.get(token), dict) else {}
            used_by.update(set(usage_bucket.get("agents") or set()))
            scenario_hints.update(set(usage_bucket.get("scenarios") or set()))
            capability_hints.update(set(usage_bucket.get("capabilities") or set()))
            process_hints.update(set(usage_bucket.get("processes") or set()))
            action_hints.update(set(usage_bucket.get("actions") or set()))
            tool_hints.update(set(usage_bucket.get("tools") or set()))
        used_by_agents = ", ".join(sorted(used_by)[:4]) if used_by else "none"
        source_scenarios = "; ".join(sorted(scenario_hints)[:3]) if scenario_hints else "n/a"
        capability_summary = "; ".join(sorted(capability_hints)[:2]) if capability_hints else "n/a"
        process_summary = "; ".join(sorted(process_hints)[:2]) if process_hints else "n/a"
        action_summary = "; ".join(sorted(action_hints)[:2]) if action_hints else "n/a"
        tool_summary = ", ".join(sorted(tool_hints)[:4]) if tool_hints else "n/a"
        bundle_matches: list[dict[str, Any]] = []
        seen_bundle_ids: set[str] = set()
        for token in usage_tokens:
            normalized_token = _normalize_statement_text(token)
            if not normalized_token:
                continue
            for bundle in bundles_by_token.get(normalized_token, []):
                bundle_id = str(bundle.get("id") or bundle.get("bundle_key") or "")
                if bundle_id and bundle_id in seen_bundle_ids:
                    continue
                if bundle_id:
                    seen_bundle_ids.add(bundle_id)
                bundle_matches.append(bundle)
        bundle_ready = sum(1 for bundle in bundle_matches if str(bundle.get("bundle_status") or "") == "ready")
        bundle_candidate = sum(1 for bundle in bundle_matches if str(bundle.get("bundle_status") or "") == "candidate")
        bundle_insights: list[str] = []
        bundle_process_hints: list[str] = []
        bundle_decision_hints: list[str] = []
        bundle_process_seen: set[str] = set()
        for bundle in bundle_matches[:4]:
            metadata = bundle.get("metadata") if isinstance(bundle.get("metadata"), dict) else {}
            for sample_entry in bundle.get("sample_claims") or []:
                if not isinstance(sample_entry, dict):
                    continue
                claim_text = str(sample_entry.get("claim_text") or "").strip()
                if claim_text:
                    bundle_insights.append(claim_text[:180])
                    if str(sample_entry.get("category") or "").strip().lower() == "decision":
                        bundle_decision_hints.append(claim_text[:180])
                    break
            for candidate in (
                metadata.get("process_name"),
                metadata.get("process"),
                metadata.get("processes"),
                metadata.get("capability"),
                metadata.get("capabilities"),
            ):
                values = candidate if isinstance(candidate, list) else [candidate]
                for value in values:
                    text = str(value or "").strip()
                    marker = text.lower()
                    if not text or marker in bundle_process_seen:
                        continue
                    bundle_process_seen.add(marker)
                    bundle_process_hints.append(text[:120])
                    if len(bundle_process_hints) >= 3:
                        break
                if len(bundle_process_hints) >= 3:
                    break
        bundle_signal_summary = (
            "; ".join(bundle_process_hints[:2])
            if bundle_process_hints
            else (f"ready {bundle_ready} / candidate {bundle_candidate}" if bundle_matches else "n/a")
        )
        impact_summary = process_summary if process_summary != "n/a" else capability_summary
        if impact_summary == "n/a":
            impact_summary = bundle_signal_summary
        downstream_decisions = "; ".join(bundle_decision_hints[:2]) if bundle_decision_hints else "n/a"
        stale_risk = _source_stale_risk_label(freshness, bundle_ready=bundle_ready, used_by_count=len(used_by))
        human_review_boundary = (
            "Require human review before publishing policy/process pages driven by this source."
            if "critical" in stale_risk or "high" in stale_risk or bundle_candidate > 0
            else "Autonomous synthesis is acceptable until bundle confidence drops or freshness degrades."
        )
        ownership_posture = (
            "single owner confirmed" if owner not in {"unknown", "n/a"} else "owner missing - add accountable maintainer"
        )

        source_slug_leaf = _source_ref_slug(source_type, source_ref)
        source_slug = _space_slug(space_key, f"source-{source_slug_leaf}")
        detail_pages.append(
            {
                "title": f"Source: {source_ref}",
                "slug": source_slug,
                "page_type": "data_map",
                "markdown": "\n".join(
                    [
                        f"# Source: {source_ref}",
                        "",
                        "## Contract",
                        f"- Type: `{source_type}`",
                        f"- Location: `{location}`",
                        f"- Owner: `{owner}`",
                        f"- Freshness: `{freshness}`",
                        "",
                        "## Key Fields",
                        *([f"- `{field}`" for field in key_fields] if key_fields else ["- n/a"]),
                        "",
                        "## Schema Sample",
                        *([f"- `{field}`" for field in schema_sample] if schema_sample else ["- n/a"]),
                        "",
                        "## Agent Usage",
                        (f"- Used by: {used_by_agents}" if used_by else "- No explicit usage mapped yet."),
                        f"- Scenarios: {source_scenarios}",
                        *([f"- Capabilities: {capability_summary}"] if capability_summary != "n/a" else []),
                        *([f"- Actions: {action_summary}"] if action_summary != "n/a" else []),
                        *([f"- Process impact: {process_summary}"] if process_summary != "n/a" else []),
                        *([f"- Tools observed: {tool_summary}"] if tool_summary != "n/a" else []),
                        "",
                        "## Knowledge Signals",
                        (
                            f"- Bundle coverage: ready {bundle_ready} / candidate {bundle_candidate}"
                            if bundle_matches
                            else "- Bundle coverage: no durable source bundle linked yet."
                        ),
                        *([f"- Bundle process/capability hints: {'; '.join(bundle_process_hints[:3])}"] if bundle_process_hints else []),
                        *([f"- Downstream decisions: {downstream_decisions}"] if downstream_decisions != "n/a" else []),
                        *([f"- Evidence preview: {'; '.join(bundle_insights[:2])}"] if bundle_insights else []),
                        "",
                        "## Reliability & Risk",
                        f"- Stale risk: {stale_risk}",
                        f"- Ownership posture: {ownership_posture}",
                        f"- Human review boundary: {human_review_boundary}",
                        f"- Dependent agents: {used_by_agents}",
                        "",
                        "## Operational Notes",
                        "- Verify ownership and freshness before allowing auto-publish for policy/process pages.",
                        "- If this source is event-like, keep it in operational lane and out of wiki synthesis.",
                        "",
                    ]
                ),
            }
        )
        safe_source_ref = source_ref.replace("|", "/")
        table_lines.append(
            f"| [{safe_source_ref}](/wiki/{source_slug}) | {source_type} | `{location}` | {owner} | {freshness} | {key_fields_label} | {used_by_agents} | {impact_summary} |"
        )
    if source_bundles:
        table_lines.extend(
            [
                "",
                "## Durable Source Signals",
                "| Bundle | Status | Support | Suggested Page |",
                "|---|---|---:|---|",
            ]
        )
        for bundle in source_bundles[: min(12, len(source_bundles))]:
            table_lines.append(
                f"| `{str(bundle.get('bundle_key') or 'bundle')}` | {str(bundle.get('bundle_status') or 'candidate')} | "
                f"{int(bundle.get('support_count') or 0)} | {str(bundle.get('suggested_page_type') or 'data_map')} |"
            )
    table_lines.extend(
        [
            "",
            "## Source Governance",
            "- Prefer sources with explicit owner + recent freshness for policy/process synthesis.",
            "- If a source contributes to downstream decisions, publish wiki changes with warnings unless the freshness/owner posture is healthy.",
            "",
            "## Governance",
            "- High-signal knowledge (policy/process/runbook) can be promoted to published wiki pages.",
            "- Event/payload-like streams should remain in operational lane and never dominate draft queue.",
            "",
        ]
    )
    catalog_slug = _space_slug(space_key, "data-sources-catalog")
    pages.append(
        {
            "title": "Data Sources Catalog",
            "slug": catalog_slug,
            "page_type": "data_map",
            "markdown": "\n".join(table_lines),
        }
    )
    pages.extend(detail_pages[:50])
    return pages


def _load_evidence_bundles_for_bootstrap(
    cur: Any,
    *,
    project_id: str,
    bundle_types: list[str] | None = None,
    statuses: list[str] | None = None,
    limit: int = 50,
) -> list[dict[str, Any]]:
    if not _wiki_feature_table_exists(cur, "public.evidence_bundles"):
        return []
    has_links = _wiki_feature_table_exists(cur, "public.evidence_bundle_claim_links")
    has_claims = _wiki_feature_table_exists(cur, "public.claims")
    normalized_bundle_types = [str(item).strip().lower() for item in (bundle_types or []) if str(item).strip()]
    normalized_statuses = [str(item).strip().lower() for item in (statuses or []) if str(item).strip()]
    where_parts = ["b.project_id = %s"]
    params: list[Any] = [project_id]
    if normalized_bundle_types:
        where_parts.append("b.bundle_type = ANY(%s::text[])")
        params.append(normalized_bundle_types)
    if normalized_statuses:
        where_parts.append("b.bundle_status = ANY(%s::text[])")
        params.append(normalized_statuses)
    sample_claims_sql = "'[]'::jsonb AS sample_claims"
    if has_links and has_claims:
        sample_claims_sql = """
        COALESCE((
          SELECT jsonb_agg(
            jsonb_build_object(
              'claim_text', picked.claim_text,
              'category', picked.category,
              'metadata', picked.metadata
            )
          )
          FROM (
            SELECT c.claim_text, c.category, c.metadata
            FROM evidence_bundle_claim_links l
            JOIN claims c ON c.id = l.claim_id
            WHERE l.bundle_id = b.id
            ORDER BY c.updated_at DESC, c.created_at DESC
            LIMIT 3
          ) picked
        ), '[]'::jsonb) AS sample_claims
        """
    cur.execute(
        f"""
        SELECT
          b.id::text,
          b.bundle_key,
          b.bundle_type,
          b.suggested_page_type,
          b.entity_key,
          b.bundle_status,
          b.support_count,
          b.repeated_claims,
          b.source_diversity,
          b.evidence_count,
          b.quality_score,
          b.last_seen_at,
          b.metadata,
          {sample_claims_sql}
        FROM evidence_bundles b
        WHERE {' AND '.join(where_parts)}
        ORDER BY
          CASE b.bundle_status
            WHEN 'ready' THEN 0
            WHEN 'candidate' THEN 1
            WHEN 'observed' THEN 2
            ELSE 3
          END,
          b.quality_score DESC,
          b.last_seen_at DESC NULLS LAST,
          b.bundle_key ASC
        LIMIT %s
        """,
        tuple([*params, int(max(1, min(500, limit)))]),
    )
    rows = cur.fetchall() or []
    bundles: list[dict[str, Any]] = []
    for row in rows:
        metadata = row[12] if isinstance(row[12], dict) else {}
        sample_claims = row[13] if isinstance(row[13], list) else []
        bundles.append(
            {
                "id": row[0],
                "bundle_key": str(row[1] or ""),
                "bundle_type": str(row[2] or ""),
                "suggested_page_type": str(row[3] or ""),
                "entity_key": str(row[4] or ""),
                "bundle_status": str(row[5] or ""),
                "support_count": int(row[6] or 0),
                "repeated_claims": int(row[7] or 0),
                "source_diversity": int(row[8] or 0),
                "evidence_count": int(row[9] or 0),
                "quality_score": float(row[10] or 0.0),
                "last_seen_at": row[11].isoformat() if row[11] is not None else None,
                "metadata": metadata,
                "sample_claims": sample_claims,
            }
        )
    return bundles


def _load_bundle_context_by_keys(
    *,
    project_id: str,
    bundle_keys: set[str] | list[str],
) -> dict[str, dict[str, Any]]:
    normalized_keys = [str(item).strip() for item in bundle_keys if str(item).strip()]
    if not normalized_keys:
        return {}
    context: dict[str, dict[str, Any]] = {}
    with get_conn() as conn:
        with conn.cursor() as cur:
            if not _wiki_feature_table_exists(cur, "public.evidence_bundles"):
                return {}
            has_links = _wiki_feature_table_exists(cur, "public.evidence_bundle_claim_links")
            has_claims = _wiki_feature_table_exists(cur, "public.claims")
            sample_claims_sql = "'[]'::jsonb AS sample_claims"
            if has_links and has_claims:
                sample_claims_sql = """
                COALESCE((
                  SELECT jsonb_agg(
                    jsonb_build_object(
                      'claim_text', picked.claim_text,
                      'category', picked.category
                    )
                  )
                  FROM (
                    SELECT c.claim_text, c.category
                    FROM evidence_bundle_claim_links l
                    JOIN claims c ON c.id = l.claim_id
                    WHERE l.bundle_id = b.id
                    ORDER BY c.updated_at DESC, c.created_at DESC
                    LIMIT 2
                  ) picked
                ), '[]'::jsonb) AS sample_claims
                """
            cur.execute(
                f"""
                SELECT
                  b.bundle_key,
                  b.bundle_type,
                  b.suggested_page_type,
                  b.entity_key,
                  b.bundle_status,
                  b.support_count,
                  b.source_diversity,
                  b.evidence_count,
                  b.quality_score,
                  b.metadata,
                  {sample_claims_sql}
                FROM evidence_bundles b
                WHERE b.project_id = %s
                  AND b.bundle_key = ANY(%s::text[])
                """,
                (project_id, normalized_keys),
            )
            for row in (cur.fetchall() or []):
                metadata = row[9] if isinstance(row[9], dict) else {}
                sample_claims = row[10] if isinstance(row[10], list) else []
                context[str(row[0] or "")] = {
                    "bundle_key": str(row[0] or ""),
                    "bundle_type": str(row[1] or ""),
                    "suggested_page_type": str(row[2] or ""),
                    "entity_key": str(row[3] or ""),
                    "bundle_status": str(row[4] or ""),
                    "support_count": int(row[5] or 0),
                    "source_diversity": int(row[6] or 0),
                    "evidence_count": int(row[7] or 0),
                    "quality_score": float(row[8] or 0.0),
                    "knowledge_taxonomy_class": str(metadata.get("knowledge_taxonomy_class") or "") or None,
                    "normalized_target_type": str(metadata.get("normalized_target_type") or "") or None,
                    "sample_claims": sample_claims,
                }
    return context


def _build_agent_capability_bootstrap_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_agents: int,
) -> list[dict[str, str]]:
    pages: list[dict[str, str]] = []
    matrix: list[dict[str, Any]] = []
    if _agent_directory_table_exists_from_cursor(cur):
        matrix = _build_agent_capability_matrix(cur, project_id=project_id, max_agents=max_agents)
    if not matrix:
        matrix = _build_runtime_agent_capability_matrix(cur, project_id=project_id, max_agents=max_agents)

    orgchart_payload = get_agent_orgchart(
        project_id=project_id,
        include_handoffs=True,
        include_retired=False,
        max_agents=max_agents,
        max_edges=500,
    )
    nodes = orgchart_payload.get("nodes") if isinstance(orgchart_payload, dict) else []
    edges = orgchart_payload.get("edges") if isinstance(orgchart_payload, dict) else []
    teams = orgchart_payload.get("teams") if isinstance(orgchart_payload, dict) else []
    if not isinstance(nodes, list) or not nodes:
        nodes = [
            {
                "agent_id": str(item.get("agent_id") or ""),
                "display_name": str(item.get("display_name") or item.get("agent_id") or "Agent"),
                "team": str(item.get("team") or "Runtime Agents"),
                "role": str(item.get("role") or "Runtime Agent"),
                "status": str(item.get("status") or "active"),
                "profile_slug": f"agents/{_slugify_segment(str(item.get('agent_id') or 'agent'))}",
            }
            for item in matrix
            if str(item.get("agent_id") or "").strip()
        ]
    if not isinstance(teams, list) or not teams:
        team_counts: dict[str, int] = {}
        for item in matrix:
            team_name = str(item.get("team") or "Runtime Agents")
            team_counts[team_name] = int(team_counts.get(team_name, 0)) + 1
        teams = [{"team": team_name, "agents_total": total} for team_name, total in sorted(team_counts.items())]
    capability_bundles = _load_evidence_bundles_for_bootstrap(
        cur,
        project_id=project_id,
        bundle_types=["capability", "decision", "process"],
        statuses=["ready", "candidate"],
        limit=max(20, min(300, max_agents * 6)),
    )
    bundles_by_entity: dict[str, list[dict[str, Any]]] = {}
    for bundle in capability_bundles:
        entity_tokens = {
            _normalize_statement_text(str(bundle.get("entity_key") or "")),
            _normalize_statement_text(str((bundle.get("metadata") or {}).get("claim_entity_key") or "")),
        }
        for token in list(entity_tokens):
            if token:
                buckets = bundles_by_entity.setdefault(token, [])
                buckets.append(bundle)

    lines = [
        "# Agent Capability Profile",
        "",
        "## Orgchart",
        "| Agent | Team | Role | Status | Profile |",
        "|---|---|---|---|---|",
    ]
    if isinstance(nodes, list) and nodes:
        for node in nodes[: max_agents]:
            agent_id = str(node.get("agent_id") or "").strip()
            display_name = str(node.get("display_name") or agent_id or "Agent").strip() or "Agent"
            team = str(node.get("team") or "Unassigned")
            role = str(node.get("role") or "Agent")
            status = str(node.get("status") or "active")
            profile_slug = str(node.get("profile_slug") or f"agents/{_slugify_segment(agent_id)}")
            lines.append(f"| {display_name} (`{agent_id}`) | {team} | {role} | {status} | [Open](/wiki/{profile_slug}) |")
    else:
        lines.append("| Runtime discovery pending | Runtime Agents | Runtime Agent | discovering | `/wiki/agents` |")

    if not _agent_directory_table_exists_from_cursor(cur):
        lines.extend(
            [
                "",
                "> Profiles are inferred from runtime activity. Register explicit agent profiles via `/v1/agents/register` for richer org metadata.",
            ]
        )

    lines.extend(
        [
            "",
            "## Capability Matrix",
            _render_agent_capability_matrix_markdown(matrix=matrix).strip(),
            "",
            "## Capability Signals",
            "- Runtime intents observed in sessions/tasks and converted into reusable actions.",
            "- Tool invocations and handoff contracts between agents.",
            "- Data-source access patterns, policy limits, and escalation pathways.",
            "",
        ]
    )
    if capability_bundles:
        lines.extend(
            [
                "## Bundle Signals",
                "| Bundle | Status | Support | Suggested Page |",
                "|---|---|---:|---|",
            ]
        )
        for bundle in capability_bundles[: min(12, len(capability_bundles))]:
            lines.append(
                f"| `{str(bundle.get('bundle_key') or 'bundle')}` | {str(bundle.get('bundle_status') or 'candidate')} | "
                f"{int(bundle.get('support_count') or 0)} | {str(bundle.get('suggested_page_type') or 'operations')} |"
            )
        lines.append("")
    lines.extend(["## Capability Deep Dive"])
    if matrix:
        for item in matrix[: max(1, min(20, max_agents))]:
            agent_id = str(item.get("agent_id") or "").strip()
            display_name = str(item.get("display_name") or agent_id or "Agent").strip() or "Agent"
            role = str(item.get("role") or "Agent")
            team = str(item.get("team") or "Unassigned")
            actions = [str(v).strip() for v in (item.get("typical_actions") or []) if str(v).strip()]
            escalations = [str(v).strip() for v in (item.get("escalation_rules") or []) if str(v).strip()]
            limits = [str(v).strip() for v in (item.get("limits") or []) if str(v).strip()]
            tools = [str(v).strip() for v in (item.get("tools") or []) if str(v).strip()]
            data_sources = [str(v).strip() for v in (item.get("data_sources") or []) if str(v).strip()]
            scenarios = [str(v).strip() for v in (item.get("scenario_examples") or []) if str(v).strip()]
            allowed_actions = [str(v).strip() for v in (item.get("allowed_actions") or []) if str(v).strip()]
            approval_rules = [str(v).strip() for v in (item.get("approval_rules") or []) if str(v).strip()]
            static_config_keys = [str(v).strip() for v in (item.get("static_config_keys") or []) if str(v).strip()]
            scheduled_tasks = [str(v).strip() for v in (item.get("scheduled_tasks") or []) if str(v).strip()]
            standing_orders = [str(v).strip() for v in (item.get("standing_orders") or []) if str(v).strip()]
            source_bindings = [str(v).strip() for v in (item.get("source_bindings") or []) if str(v).strip()]
            integrations = [str(v).strip() for v in (item.get("integrations") or []) if str(v).strip()]
            model_routing = [str(v).strip() for v in (item.get("model_routing") or []) if str(v).strip()]
            prompt_signal = str(item.get("prompt_signal") or "").strip()
            observed_strengths = [str(v).strip() for v in (item.get("observed_strengths") or []) if str(v).strip()]
            observed_decisions = [str(v).strip() for v in (item.get("observed_decisions") or []) if str(v).strip()]
            observed_questions = [str(v).strip() for v in (item.get("observed_questions") or []) if str(v).strip()]
            observed_uncertainties = [str(v).strip() for v in (item.get("observed_uncertainties") or []) if str(v).strip()]
            observed_actions = [str(v).strip() for v in (item.get("observed_actions") or []) if str(v).strip()]
            reflection_summary = str(item.get("latest_reflection_summary") or "").strip()
            reflection_outcome = str(item.get("latest_reflection_outcome") or "").strip()
            reflection_count = int(item.get("reflection_count") or 0)
            bundle_matches = bundles_by_entity.get(_normalize_statement_text(agent_id), []) or bundles_by_entity.get(
                _normalize_statement_text(display_name),
                [],
            )
            bundle_ready = sum(1 for bundle in bundle_matches if str(bundle.get("bundle_status") or "") == "ready")
            bundle_candidate = sum(1 for bundle in bundle_matches if str(bundle.get("bundle_status") or "") == "candidate")
            bundle_insights: list[str] = []
            for bundle in bundle_matches[:3]:
                for claim_entry in bundle.get("sample_claims") or []:
                    if not isinstance(claim_entry, dict):
                        continue
                    claim_text = str(claim_entry.get("claim_text") or "").strip()
                    if claim_text:
                        bundle_insights.append(claim_text[:180])
                        break
                if len(bundle_insights) >= 3:
                    break
            detail_lines = [
                "",
                f"### {display_name} (`{agent_id}`)",
                f"- Team / Role: {team} / {role}",
                f"- Typical actions: {'; '.join(actions[:3]) if actions else 'n/a'}",
                f"- Escalation rules: {'; '.join(escalations[:2]) if escalations else 'n/a'}",
                f"- Toolset: {', '.join(tools[:6]) if tools else 'n/a'}",
                f"- Data sources: {', '.join(data_sources[:6]) if data_sources else 'n/a'}",
                f"- Constraints: {'; '.join(limits[:3]) if limits else 'n/a'}",
                f"- Allowed actions: {', '.join(allowed_actions[:6]) if allowed_actions else 'n/a'}",
                f"- Approval rules: {', '.join(approval_rules[:4]) if approval_rules else 'n/a'}",
                f"- Config keys: {', '.join(static_config_keys[:8]) if static_config_keys else 'n/a'}",
            ]
            if scheduled_tasks:
                detail_lines.append(f"- Scheduled tasks: {'; '.join(scheduled_tasks[:3])}")
            if standing_orders:
                detail_lines.append(f"- Standing orders / processes: {'; '.join(standing_orders[:3])}")
            if source_bindings:
                detail_lines.append(f"- Source bindings: {'; '.join(source_bindings[:3])}")
            if model_routing:
                detail_lines.append(f"- Model routing / failover: {'; '.join(model_routing[:3])}")
            if integrations:
                detail_lines.append(f"- Integrations: {', '.join(integrations[:5])}")
            if prompt_signal:
                detail_lines.append(f"- Prompt context: {prompt_signal[:200]}")
            detail_lines.append(f"- Scenario examples: {'; '.join(scenarios[:2]) if scenarios else 'n/a'}")
            if observed_actions:
                detail_lines.append(f"- Observed workflow actions: {'; '.join(observed_actions[:3])}")
            if observed_strengths:
                detail_lines.append(f"- Durable rules learned: {'; '.join(observed_strengths[:3])}")
            if observed_decisions:
                detail_lines.append(f"- Decisions recorded: {'; '.join(observed_decisions[:2])}")
            if reflection_count > 0:
                detail_lines.append(
                    f"- Reflection coverage: {reflection_count} debrief(s){f'; latest outcome: {reflection_outcome}' if reflection_outcome else ''}"
                )
            if reflection_summary:
                detail_lines.append(f"- Latest debrief: {reflection_summary[:220]}")
            if observed_questions:
                detail_lines.append(f"- Missing documentation questions: {'; '.join(observed_questions[:2])}")
            if observed_uncertainties:
                detail_lines.append(f"- Open uncertainties: {'; '.join(observed_uncertainties[:2])}")
            if bundle_matches:
                detail_lines.append(f"- Bundle evidence: ready {bundle_ready} / candidate {bundle_candidate}")
                detail_lines.append(
                    f"- Bundle-backed insights: {'; '.join(bundle_insights[:2]) if bundle_insights else 'Knowledge bundle linked; enrichment pending.'}"
                )
            lines.extend(detail_lines)
    else:
        lines.extend(
            [
                "",
                "- Runtime discovery pending. Connect at least one active agent or register profiles via `/v1/agents/register`.",
            ]
        )
    lines.append("")
    lines.extend(["## Handoffs", _render_agent_handoff_markdown(edges=edges if isinstance(edges, list) else []).strip(), ""])
    if isinstance(teams, list) and teams:
        lines.extend(["## Teams", "| Team | Agents |", "|---|---:|"])
        for team in teams[:30]:
            lines.append(f"| {str(team.get('team') or 'Unassigned')} | {int(team.get('agents_total') or 0)} |")
        lines.append("")
    pages.append(
        {
            "title": "Agent Capability Profile",
            "slug": _space_slug(space_key, "agent-capability-profile"),
            "page_type": "agent_profile",
            "markdown": "\n".join(lines),
        }
    )
    return pages


def _build_tooling_map_bootstrap_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_agents: int,
) -> list[dict[str, str]]:
    matrix: list[dict[str, Any]] = []
    if _agent_directory_table_exists_from_cursor(cur):
        matrix = _build_agent_capability_matrix(cur, project_id=project_id, max_agents=max_agents)
    if not matrix:
        matrix = _build_runtime_agent_capability_matrix(cur, project_id=project_id, max_agents=max_agents)

    tool_index: dict[str, dict[str, Any]] = {}
    for item in matrix:
        agent_id = str(item.get("agent_id") or "").strip()
        if not agent_id:
            continue
        tools = [str(tool).strip() for tool in (item.get("tools") or []) if str(tool).strip()]
        scenarios = [str(v).strip() for v in (item.get("scenario_examples") or []) if str(v).strip()]
        guardrails = [
            *[str(v).strip() for v in (item.get("limits") or []) if str(v).strip()],
            *[str(v).strip() for v in (item.get("approval_rules") or []) if str(v).strip()],
        ]
        for tool in tools:
            key = tool.lower()
            bucket = tool_index.get(key)
            if bucket is None:
                bucket = {
                    "tool": tool,
                    "agents": set(),
                    "scenarios": set(),
                    "guardrails": set(),
                }
                tool_index[key] = bucket
            bucket["agents"].add(agent_id)
            for scenario in scenarios[:3]:
                bucket["scenarios"].add(scenario)
            for rule in guardrails[:3]:
                bucket["guardrails"].add(rule)

    lines = [
        "# Tooling Map",
        "",
        "## Registry",
        "| Tool | Used By Agents | Purpose / Scenario | Guardrails |",
        "|---|---|---|---|",
    ]
    if tool_index:
        for _, bucket in sorted(
            tool_index.items(),
            key=lambda item: (-len(item[1].get("agents") or []), str(item[1].get("tool") or "").lower()),
        )[:200]:
            agents = ", ".join(sorted(bucket["agents"])[:4]) if bucket["agents"] else "n/a"
            scenario = "; ".join(sorted(bucket["scenarios"])[:2]) if bucket["scenarios"] else "n/a"
            guardrails = "; ".join(sorted(bucket["guardrails"])[:2]) if bucket["guardrails"] else "n/a"
            lines.append(f"| `{bucket['tool']}` | {agents} | {scenario} | {guardrails} |")
    else:
        lines.append("| n/a | n/a | Runtime tool discovery pending | Register tools via `/v1/agents/register` |")
    lines.extend(
        [
            "",
            "## Governance",
            "- Any tool touching finance/compliance/customer identity should require approval or reviewer assignment.",
            "- Prefer policy/process backed actions over direct payload-driven decisions.",
            "",
        ]
    )
    return [
        {
            "title": "Tooling Map",
            "slug": _space_slug(space_key, "tooling-map"),
            "page_type": "operations",
            "markdown": "\n".join(lines),
        }
    ]


def _build_process_playbooks_bootstrap_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_signals: int,
) -> list[dict[str, str]]:
    def _extract_process_triplet(claim_text: str, metadata: dict[str, Any]) -> dict[str, Any]:
        operator_decision = metadata.get("operator_decision") if isinstance(metadata.get("operator_decision"), dict) else {}
        metadata_triplet = metadata.get("process_triplet") if isinstance(metadata.get("process_triplet"), dict) else None
        if metadata_triplet is None and isinstance(operator_decision.get("process_triplet"), dict):
            metadata_triplet = operator_decision.get("process_triplet")
        if isinstance(metadata_triplet, dict):
            trigger = str(metadata_triplet.get("trigger") or "").strip()
            action = str(metadata_triplet.get("action") or "").strip()
            outcome = str(metadata_triplet.get("outcome") or "").strip()
            confidence = metadata_triplet.get("confidence")
            if trigger or action or outcome:
                if not isinstance(confidence, (int, float)):
                    confidence = float(metadata.get("llm_confidence") or metadata.get("confidence") or 0.85)
                return {
                    "trigger": trigger,
                    "action": action,
                    "outcome": outcome,
                    "confidence": max(0.0, min(1.0, round(float(confidence), 3))),
                }

        normalized = _normalize_statement_text(claim_text)
        trigger = ""
        action = ""
        outcome = ""
        pattern_if_then = re.search(
            r"\b(?:if|when|если|когда)\b\s+(?P<trigger>[^.]{3,240}?)\s*(?:,|then|то)\s+(?P<action>[^.]{3,280})",
            normalized,
        )
        if pattern_if_then:
            trigger = str(pattern_if_then.group("trigger") or "").strip(" ,.;:")
            action = str(pattern_if_then.group("action") or "").strip(" ,.;:")
        else:
            pattern_steps = re.search(
                r"\b(?:process|workflow|procedure|runbook|playbook|sop|процесс|процедура|регламент|инструкция)\b[:\s-]*(?P<action>[^.]{6,320})",
                normalized,
            )
            if pattern_steps:
                action = str(pattern_steps.group("action") or "").strip(" ,.;:")

        pattern_outcome = re.search(
            r"\b(?:result|outcome|verify|sla|resolution|итог|результат|проверить|проверка)\b[:\s-]*(?P<outcome>[^.]{3,220})",
            normalized,
        )
        if pattern_outcome:
            outcome = str(pattern_outcome.group("outcome") or "").strip(" ,.;:")

        return {
            "trigger": trigger,
            "action": action,
            "outcome": outcome,
            "confidence": max(0.0, min(1.0, round(float(metadata.get("llm_confidence") or metadata.get("confidence") or 0.55), 3))),
        }

    def _extract_list_values(*values: Any, limit: int = 6) -> list[str]:
        collected: list[str] = []

        def _collect(value: Any) -> None:
            if isinstance(value, list):
                for item in value:
                    _collect(item)
                return
            if isinstance(value, dict):
                for field in ("name", "tool", "title", "id", "source", "source_system", "ticket_id", "case_id"):
                    text = str(value.get(field) or "").strip()
                    if text:
                        collected.append(text[:180])
                        return
                return
            text = str(value or "").strip()
            if text:
                collected.append(text[:180])

        for value in values:
            _collect(value)
        deduped: list[str] = []
        seen: set[str] = set()
        for item in collected:
            marker = item.lower()
            if marker in seen:
                continue
            seen.add(marker)
            deduped.append(item)
            if len(deduped) >= limit:
                break
        return deduped

    def _purpose_for_category(category: str) -> str:
        normalized = str(category or "").strip().lower()
        if normalized == "policy":
            return "Keep execution aligned with approved policy and route ambiguous changes to review."
        if normalized in {"incident", "access"}:
            return "Contain operational risk quickly and preserve a safe escalation path."
        if normalized in {"runbook", "process"}:
            return "Execute repeatable operating steps with clear escalation and verification."
        return "Convert recurring operational signals into repeatable, auditable action."

    def _process_title(trigger: str, action: str, category: str, owner_agents: list[str]) -> str:
        if trigger:
            seed = trigger
        elif action:
            seed = action
        elif owner_agents:
            seed = f"{owner_agents[0]} workflow"
        else:
            seed = f"{category} workflow"
        normalized = re.sub(r"\s+", " ", str(seed or "").replace("_", " ")).strip(" .,:;-")
        normalized = normalized[:80] if normalized else f"{category.title()} workflow"
        if normalized.lower().endswith("playbook"):
            return normalized
        return f"{normalized[:1].upper()}{normalized[1:]} Playbook"

    def _owner_agents_from_metadata(metadata: dict[str, Any], *, fallback: str | None = None) -> list[str]:
        owners = _extract_list_values(
            metadata.get("agent_id"),
            metadata.get("runtime_agent_id"),
            metadata.get("agent_ids"),
            metadata.get("owner_agent"),
            metadata.get("owner_agents"),
            metadata.get("claim_entity_key"),
            fallback,
            limit=4,
        )
        cleaned = [item for item in owners if item.lower() not in {"process", "policy", "decision"}]
        return cleaned[:4]

    def _verification_steps(output: str, escalation: str, *, confidence: float) -> list[str]:
        steps = []
        if output:
            steps.append(f"Check that outcome is explicit: {output}.")
        else:
            steps.append("Check that the action closed the loop and removed repeat escalation signals.")
        if confidence < 0.75:
            steps.append("Confirm the rule against a second source before broad reuse.")
        steps.append(f"Watch for escalation condition: {escalation}")
        return steps[:3]

    def _human_loop_guidance(category: str, escalation: str, *, confidence: float, exceptions: list[str]) -> str:
        normalized = str(category or "").strip().lower()
        if normalized in {"policy", "access"}:
            return "Human approval required before publishing or applying this rule broadly."
        if confidence < 0.7:
            return "Human confirmation recommended because evidence confidence is still low."
        if exceptions:
            return "Escalate to a human when an exception path or repeated failure appears."
        return f"Autonomous execution is acceptable until this escalation boundary is hit: {escalation}"

    rows: list[tuple[Any, ...]] = []
    query_limit = max(20, min(800, int(max_signals) * 10))
    reflection_signals = _load_recent_agent_reflection_signals(
        cur,
        project_id=project_id,
        days=45,
        max_agents=max(50, int(max_signals) * 6),
    )
    bundle_rows = _load_evidence_bundles_for_bootstrap(
        cur,
        project_id=project_id,
        bundle_types=["process", "policy", "decision"],
        statuses=["ready", "candidate"],
        limit=max(12, min(120, int(max_signals) * 4)),
    )
    if _wiki_feature_table_exists(cur, "public.claims"):
        cur.execute(
            """
            SELECT claim_text, category, metadata, evidence
            FROM claims
            WHERE project_id = %s
              AND status <> 'rejected'
              AND (
                lower(COALESCE(category, '')) IN ('process', 'policy', 'runbook', 'incident', 'access')
                OR lower(COALESCE(claim_text, '')) SIMILAR TO '%%(process|runbook|playbook|procedure|if|when|then|escalat)%%'
              )
            ORDER BY updated_at DESC
            LIMIT %s
            """,
            (project_id, query_limit),
        )
        rows = cur.fetchall() or []
    playbooks: list[dict[str, Any]] = []
    seen: set[str] = set()
    for bundle in bundle_rows:
        sample_claims = bundle.get("sample_claims") if isinstance(bundle.get("sample_claims"), list) else []
        sample_entry = sample_claims[0] if sample_claims and isinstance(sample_claims[0], dict) else {}
        claim_text = str(sample_entry.get("claim_text") or "").strip()
        metadata = sample_entry.get("metadata") if isinstance(sample_entry.get("metadata"), dict) else {}
        bundle_metadata = bundle.get("metadata") if isinstance(bundle.get("metadata"), dict) else {}
        merged_metadata = {
            **bundle_metadata,
            **metadata,
            "source_system": bundle_metadata.get("source_systems") or metadata.get("source_system"),
            "source": bundle.get("bundle_key"),
            "confidence": bundle.get("quality_score"),
        }
        if not claim_text:
            claim_text = (
                f"{str(bundle.get('entity_key') or 'process')} {str(bundle.get('bundle_type') or 'process')} "
                f"bundle with support {int(bundle.get('support_count') or 0)} and source diversity {int(bundle.get('source_diversity') or 0)}."
            )
        normalized = _normalize_statement_text(claim_text)[:200]
        if normalized in seen:
            continue
        seen.add(normalized)
        category = str(sample_entry.get("category") or bundle.get("bundle_type") or "process").strip() or "process"
        process_triplet = _extract_process_triplet(claim_text, merged_metadata)
        trigger = str(process_triplet.get("trigger") or "").strip() or str(bundle.get("entity_key") or claim_text[:100])
        action = str(process_triplet.get("action") or "").strip() or _derive_action_candidate(claim_text, category)
        output = str(process_triplet.get("outcome") or "").strip()
        confidence = float(process_triplet.get("confidence") or bundle.get("quality_score") or 0.0)
        escalation = _derive_escalation_rule(claim_text, confidence, category)
        ticket_signal = _extract_ticket_outcome_signal(merged_metadata)
        source_refs = _extract_list_values(
            merged_metadata.get("source_system"),
            merged_metadata.get("source"),
            merged_metadata.get("namespace"),
            (bundle_metadata.get("source_systems") if isinstance(bundle_metadata.get("source_systems"), list) else None),
            limit=4,
        )
        tools_used = _extract_list_values(
            merged_metadata.get("tool_name"),
            merged_metadata.get("tool"),
            merged_metadata.get("tool_names"),
            limit=5,
        )
        inputs = _extract_list_values(source_refs, merged_metadata.get("entity_key"), merged_metadata.get("subject"), limit=4)
        steps = [
            f"Confirm trigger: {trigger}.",
            f"Execute action: {action}.",
        ]
        if output:
            steps.append(f"Verify expected outcome: {output}.")
        else:
            steps.append("Verify outcome against SLA/policy expectations before closing the loop.")
        exceptions: list[str] = []
        if ticket_signal.get("negative"):
            exceptions.append("If prior resolution outcome was negative, escalate immediately instead of retrying the same flow.")
        if confidence < 0.7:
            exceptions.append("If evidence confidence is low, require human confirmation before broad rollout.")
        if category.lower() in {"policy", "access"}:
            exceptions.append("Policy/access changes must not bypass approval guardrails.")
        evidence_summary = _extract_list_values(
            source_refs,
            ticket_signal.get("ticket_ids"),
            ticket_signal.get("outcome"),
            f"bundle_support={int(bundle.get('support_count') or 0)}",
            f"bundle_status={str(bundle.get('bundle_status') or 'candidate')}",
            limit=6,
        )
        owner_agents = _owner_agents_from_metadata(
            merged_metadata,
            fallback=str(bundle.get("entity_key") or "") if str(bundle.get("bundle_type") or "") == "capability" else None,
        )
        verification = _verification_steps(output, escalation, confidence=confidence)
        human_loop = _human_loop_guidance(category, escalation, confidence=confidence, exceptions=exceptions)
        decision_refs = _extract_list_values(
            merged_metadata.get("decision"),
            merged_metadata.get("decisions"),
            merged_metadata.get("operator_decision"),
            limit=4,
        )
        artifacts = _extract_list_values(
            source_refs,
            ticket_signal.get("ticket_ids"),
            merged_metadata.get("task_id"),
            merged_metadata.get("session_id"),
            limit=5,
        )
        playbooks.append(
            {
                "title": _process_title(trigger, action, category, owner_agents),
                "purpose": _purpose_for_category(category),
                "category": category,
                "owners": owner_agents,
                "trigger": trigger,
                "action": action,
                "inputs": inputs,
                "steps": steps,
                "exceptions": exceptions,
                "output": output or str(ticket_signal.get("outcome") or "verified action outcome"),
                "escalation": escalation,
                "verification": verification,
                "human_loop": human_loop,
                "tools": tools_used,
                "artifacts": artifacts,
                "decision_refs": decision_refs,
                "evidence": evidence_summary,
            }
        )
        if len(playbooks) >= max(6, min(50, int(max_signals))):
            break
    for row in rows:
        claim_text = str(row[0] or "").strip()
        category = str(row[1] or "operations").strip() or "operations"
        metadata = row[2] if isinstance(row[2], dict) else {}
        evidence = row[3] if len(row) > 3 and isinstance(row[3], list) else []
        if not claim_text or len(claim_text) < 20:
            continue
        normalized = _normalize_statement_text(claim_text)[:200]
        if normalized in seen:
            continue
        seen.add(normalized)
        process_triplet = _extract_process_triplet(claim_text, metadata)
        trigger = str(process_triplet.get("trigger") or "").strip() or claim_text[:100]
        action = str(process_triplet.get("action") or "").strip() or _derive_action_candidate(claim_text, category)
        output = str(process_triplet.get("outcome") or "").strip()
        confidence = float(process_triplet.get("confidence") or metadata.get("llm_confidence") or metadata.get("confidence") or 0.0)
        escalation = _derive_escalation_rule(claim_text, confidence, category)
        ticket_signal = _extract_ticket_outcome_signal(metadata)
        source_refs = _extract_list_values(
            metadata.get("source_system"),
            metadata.get("source"),
            metadata.get("namespace"),
            *[
                item.get("source_system") if isinstance(item, dict) else None
                for item in evidence
            ],
            *[
                item.get("source_id") if isinstance(item, dict) else None
                for item in evidence
            ],
            limit=4,
        )
        tools_used = _extract_list_values(
            metadata.get("tool_name"),
            metadata.get("tool"),
            metadata.get("tool_names"),
            *[
                item.get("tool_name") if isinstance(item, dict) else None
                for item in evidence
            ],
            limit=5,
        )
        inputs = _extract_list_values(source_refs, metadata.get("entity_key"), metadata.get("subject"), limit=4)
        ticket_ids = [str(item).strip() for item in (ticket_signal.get("ticket_ids") or []) if str(item).strip()]
        steps = [
            f"Confirm trigger: {trigger}.",
            f"Execute action: {action}.",
        ]
        if output:
            steps.append(f"Verify expected outcome: {output}.")
        else:
            steps.append("Verify outcome against SLA/policy expectations before closing the loop.")
        exceptions: list[str] = []
        if ticket_signal.get("negative"):
            exceptions.append("If prior resolution outcome was negative, escalate immediately instead of retrying the same flow.")
        if confidence < 0.7:
            exceptions.append("If evidence confidence is low, require human confirmation before broad rollout.")
        if category.lower() in {"policy", "access"}:
            exceptions.append("Policy/access changes must not bypass approval guardrails.")
        evidence_summary = _extract_list_values(source_refs, ticket_ids, ticket_signal.get("outcome"), limit=6)
        owner_agents = _owner_agents_from_metadata(metadata)
        verification = _verification_steps(output, escalation, confidence=confidence)
        human_loop = _human_loop_guidance(category, escalation, confidence=confidence, exceptions=exceptions)
        decision_refs = _extract_list_values(
            metadata.get("decision"),
            metadata.get("decisions"),
            metadata.get("operator_decision"),
            ticket_ids,
            limit=4,
        )
        artifacts = _extract_list_values(source_refs, ticket_ids, metadata.get("task_id"), metadata.get("session_id"), limit=5)
        playbooks.append(
            {
                "title": _process_title(trigger, action, category, owner_agents),
                "purpose": _purpose_for_category(category),
                "category": category,
                "owners": owner_agents,
                "trigger": trigger,
                "action": action,
                "inputs": inputs,
                "steps": steps,
                "exceptions": exceptions,
                "output": output or str(ticket_signal.get("outcome") or "verified action outcome"),
                "escalation": escalation,
                "verification": verification,
                "human_loop": human_loop,
                "tools": tools_used,
                "artifacts": artifacts,
                "decision_refs": decision_refs,
                "evidence": evidence_summary,
            }
        )
        if len(playbooks) >= max(6, min(50, int(max_signals))):
            break

    for agent_id, signal in list(reflection_signals.items())[: max(4, min(24, int(max_signals) * 2))]:
        durable_rules = [str(item).strip() for item in (signal.get("durable_rules") or []) if str(item).strip()]
        actions_taken = [str(item).strip() for item in (signal.get("actions_taken") or []) if str(item).strip()]
        escalations = [str(item).strip() for item in (signal.get("escalations") or []) if str(item).strip()]
        sources_used = [str(item).strip() for item in (signal.get("sources") or []) if str(item).strip()]
        tools_used = [str(item).strip() for item in (signal.get("tools") or []) if str(item).strip()]
        decisions = [str(item).strip() for item in (signal.get("decisions") or []) if str(item).strip()]
        if not durable_rules and not actions_taken:
            continue
        trigger = durable_rules[0] if durable_rules else f"Agent {agent_id} receives a workflow task"
        action = actions_taken[0] if actions_taken else "apply the durable rule and document the result"
        category = "process"
        normalized = _normalize_statement_text(f"{agent_id}:{trigger}:{action}")[:200]
        if normalized in seen:
            continue
        seen.add(normalized)
        exceptions = []
        if escalations:
            exceptions.append(f"Escalate when {escalations[0]}")
        human_loop = _human_loop_guidance(category, escalations[0] if escalations else "repeat failures", confidence=0.81, exceptions=exceptions)
        playbooks.append(
            {
                "title": _process_title(trigger, action, category, [agent_id]),
                "purpose": "Capture durable operator knowledge discovered during agent debriefs and turn it into reusable SOP.",
                "category": category,
                "owners": [agent_id],
                "trigger": trigger,
                "action": action,
                "inputs": _extract_list_values(sources_used, f"agent:{agent_id}", limit=4),
                "steps": [
                    f"Review the durable rule: {trigger}.",
                    f"Execute the known action pattern: {action}.",
                    "Write back the resolution and update the wiki page if the rule changed.",
                ],
                "exceptions": exceptions,
                "output": str(signal.get("latest_outcome") or "verified workflow outcome"),
                "escalation": escalations[0] if escalations else "Escalate to reviewer when the debrief reveals a new exception.",
                "verification": _verification_steps(
                    str(signal.get("latest_outcome") or ""),
                    escalations[0] if escalations else "repeat failures",
                    confidence=0.81,
                ),
                "human_loop": human_loop,
                "tools": tools_used[:5],
                "artifacts": _extract_list_values(sources_used, tools_used, limit=5),
                "decision_refs": decisions[:3],
                "evidence": _extract_list_values(
                    durable_rules[:2],
                    decisions[:2],
                    f"reflection_count={int(signal.get('count') or 0)}",
                    limit=6,
                ),
            }
        )
        if len(playbooks) >= max(6, min(50, int(max_signals))):
            break

    lines = [
        "# Process Playbooks",
        "",
        "Canonical operational runbooks synthesized from durable memory signals.",
        "Each playbook is structured for onboarding and repeat execution, not just summary browsing.",
        "",
        "## Playbook Index",
        "| Playbook | Area | Trigger | Escalation |",
        "|---|---|---|---|",
    ]
    if playbooks:
        for item in playbooks:
            lines.append(
                f"| {str(item['title']).replace('|', '/')} | `{item['category']}` | {str(item['trigger'])[:90].replace('|', '/')} | {str(item['escalation'])[:110].replace('|', '/')} |"
            )
        lines.extend(["", "## Canonical Runbooks"])
        for index, item in enumerate(playbooks, start=1):
            lines.extend(
                [
                    "",
                    f"### {index}. {item['title']}",
                    f"- Purpose: {item['purpose']}",
                    f"- Owners: {'; '.join(item['owners']) if item['owners'] else 'runtime owner inference pending'}",
                    f"- Trigger: {item['trigger']}",
                    f"- Inputs: {'; '.join(item['inputs']) if item['inputs'] else 'runtime signal + current policy context'}",
                    "- Steps:",
                    *[f"  - {step}" for step in item["steps"]],
                    "- Exceptions:",
                    *([f"  - {step}" for step in item["exceptions"]] if item["exceptions"] else ["  - No special exception captured yet; use standard escalation if confidence drops."]),
                    f"- Outputs: {item['output']}",
                    "- Verification:",
                    *[f"  - {step}" for step in item["verification"]],
                    f"- Human-in-the-loop: {item['human_loop']}",
                    f"- Escalation: {item['escalation']}",
                    f"- Tools used: {', '.join(item['tools']) if item['tools'] else 'runtime tool discovery pending'}",
                    f"- Artifacts / systems: {'; '.join(item['artifacts']) if item['artifacts'] else 'runtime systems + source evidence'}",
                    *([f"- Decision trail: {'; '.join(item['decision_refs'])}"] if item["decision_refs"] else []),
                    f"- Source evidence: {'; '.join(item['evidence']) if item['evidence'] else 'claim text + category evidence'}",
                ]
            )
    else:
        lines.extend(
            [
                "| Policy Playbook | `policy` | Customer-facing policy mismatch | Escalate to approver if SLA/compliance impact exists. |",
                "| Operations Playbook | `operations` | Repeated route/access failure | Escalate to on-call when repeated >= 3 times in 24h. |",
                "",
                "## Canonical Runbooks",
                "",
                "### 1. Policy Playbook",
                "- Purpose: Keep execution aligned with approved policy and route ambiguous changes to review.",
                "- Trigger: Customer-facing policy mismatch.",
                "- Inputs: Trusted policy source; affected entity context; recent operator note.",
                "- Steps:",
                "  - Confirm mismatch against current policy page.",
                "  - Open policy review task and attach evidence from 2+ sources.",
                "  - Pause autonomous rollout until approver decision exists.",
                "- Exceptions:",
                "  - If mismatch has finance/compliance impact, skip conditional rollout and require human approval.",
                "- Outputs: Updated reviewed policy statement or rejected change request.",
                "- Escalation: Escalate to approver if SLA/compliance impact exists.",
                "- Tools used: policy wiki, ticketing, operator review queue.",
                "- Source evidence: trusted policy source + operator escalation signal.",
            ]
        )
    lines.extend(
        [
            "",
            "## How To Use",
            "1. Start from trigger condition in runtime event or operator note.",
            "2. Validate inputs and source evidence before executing a step.",
            "3. Follow the runbook sequence, then escalate on low confidence or high impact.",
            "",
        ]
    )
    return [
        {
            "title": "Process Playbooks",
            "slug": _space_slug(space_key, "process-playbooks"),
            "page_type": "runbook",
            "markdown": "\n".join(lines),
        }
    ]


def _build_company_operating_context_bootstrap_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_signals: int,
) -> list[dict[str, str]]:
    source_counts: list[tuple[str, int]] = []
    if _legacy_import_sources_table_exists_from_cursor(cur):
        cur.execute(
            """
            SELECT source_type, COUNT(*)::int
            FROM legacy_import_sources
            WHERE project_id = %s
              AND enabled = TRUE
            GROUP BY source_type
            ORDER BY COUNT(*) DESC, source_type ASC
            LIMIT 20
            """,
            (project_id,),
        )
        source_counts = [(str(row[0] or "unknown"), int(row[1] or 0)) for row in (cur.fetchall() or [])]

    matrix: list[dict[str, Any]] = []
    if _agent_directory_table_exists_from_cursor(cur):
        matrix = _build_agent_capability_matrix(cur, project_id=project_id, max_agents=200)
    if not matrix:
        matrix = _build_runtime_agent_capability_matrix(cur, project_id=project_id, max_agents=200)
    team_rollup: dict[str, int] = {}
    for item in matrix:
        team = str(item.get("team") or "Runtime Agents")
        team_rollup[team] = int(team_rollup.get(team, 0)) + 1

    claims_rollup: list[tuple[str, int]] = []
    if _wiki_feature_table_exists(cur, "public.claims"):
        cur.execute(
            """
            SELECT category, COUNT(*)::int
            FROM claims
            WHERE project_id = %s
              AND status <> 'rejected'
            GROUP BY category
            ORDER BY COUNT(*) DESC, category ASC
            LIMIT %s
            """,
            (project_id, max(5, min(30, int(max_signals)))),
        )
        claims_rollup = [(str(row[0] or "general"), int(row[1] or 0)) for row in (cur.fetchall() or [])]

    lines = [
        "# Company Operating Context",
        "",
        "## Snapshot",
        f"- Project: `{project_id}`",
        f"- Active agents discovered: `{len(matrix)}`",
        f"- Connected data sources: `{sum(count for _, count in source_counts)}`",
        "",
        "## Team Topology",
        "| Team | Agents |",
        "|---|---:|",
    ]
    if team_rollup:
        for team, total in sorted(team_rollup.items(), key=lambda item: (-item[1], item[0].lower()))[:20]:
            lines.append(f"| {team} | {int(total)} |")
    else:
        lines.append("| Runtime Agents | 0 |")
    lines.extend(
        [
            "",
            "## Knowledge Domains",
            "| Domain | Signals |",
            "|---|---:|",
        ]
    )
    if claims_rollup:
        for category, total in claims_rollup:
            lines.append(f"| `{category}` | {int(total)} |")
    else:
        lines.append("| `operations` | 0 |")
    lines.extend(
        [
            "",
            "## Data Backbone",
            "| Source Type | Connected Streams |",
            "|---|---:|",
        ]
    )
    if source_counts:
        for source_type, total in source_counts[:20]:
            lines.append(f"| `{source_type}` | {int(total)} |")
    else:
        lines.append("| `n/a` | 0 |")
    lines.extend(
        [
            "",
            "## Core Operating Principles",
            "- Durable policy/process knowledge should be published to wiki; event payload streams stay in operational lane.",
            "- Escalation is mandatory when SLA/compliance/customer-impact risks are detected.",
            "- Agent actions should be constrained by tool guardrails and approval rules.",
            "",
        ]
    )
    return [
        {
            "title": "Company Operating Context",
            "slug": _space_slug(space_key, "company-operating-context"),
            "page_type": "operations",
            "markdown": "\n".join(lines),
        }
    ]


def _build_daily_operations_digest_bootstrap_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_days: int = 7,
) -> list[dict[str, str]]:
    rows: list[tuple[Any, ...]] = []
    if _wiki_feature_table_exists(cur, "public.agent_daily_worklogs"):
        cur.execute(
            """
            SELECT worklog_date, summary
            FROM agent_daily_worklogs
            WHERE project_id = %s
            ORDER BY worklog_date DESC
            LIMIT %s
            """,
            (project_id, max(1, min(30, int(max_days))) * 300),
        )
        rows = cur.fetchall() or []

    day_totals: dict[str, dict[str, int]] = {}
    for row in rows:
        worklog_date = row[0]
        summary = row[1] if isinstance(row[1], dict) else {}
        if worklog_date is None:
            continue
        day_key = worklog_date.isoformat()
        bucket = day_totals.get(day_key)
        if bucket is None:
            bucket = {
                "events_total": 0,
                "tasks_done": 0,
                "tasks_blocked": 0,
                "drafts_proposed": 0,
                "pages_authored": 0,
                "agents_reporting": 0,
            }
            day_totals[day_key] = bucket
        bucket["events_total"] += int(summary.get("events_total") or 0)
        bucket["tasks_done"] += int(summary.get("tasks_done") or 0)
        bucket["tasks_blocked"] += int(summary.get("tasks_blocked") or 0)
        bucket["drafts_proposed"] += int(summary.get("drafts_proposed") or 0)
        bucket["pages_authored"] += int(summary.get("pages_authored") or 0)
        bucket["agents_reporting"] += 1

    lines = [
        "# Daily Operations Digest",
        "",
        "Aggregated operational daily summaries to prevent draft/page fragmentation.",
        "",
        "## Last Days",
        "| Date | Agents Reporting | Events | Tasks Done | Tasks Blocked | Drafts Proposed | Pages Authored |",
        "|---|---:|---:|---:|---:|---:|---:|",
    ]
    if day_totals:
        for day_key in sorted(day_totals.keys(), reverse=True)[: max(1, min(14, int(max_days)))]:
            bucket = day_totals[day_key]
            lines.append(
                f"| {day_key} | {bucket['agents_reporting']} | {bucket['events_total']} | {bucket['tasks_done']} | "
                f"{bucket['tasks_blocked']} | {bucket['drafts_proposed']} | {bucket['pages_authored']} |"
            )
    else:
        lines.append("| n/a | 0 | 0 | 0 | 0 | 0 | 0 |")
    lines.extend(
        [
            "",
            "## Notes",
            "- Daily-summary-like signals should aggregate here instead of creating standalone wiki pages.",
            "- Promote to process/policy pages only durable and reusable knowledge patterns.",
            "",
        ]
    )
    return [
        {
            "title": "Daily Operations Digest",
            "slug": _space_slug(space_key, "daily-operations-digest"),
            "page_type": "operations",
            "markdown": "\n".join(lines),
        }
    ]


def _derive_action_candidate(text: str, category: str) -> str:
    normalized = text.lower()
    if any(token in normalized for token in ("escalat", "urgent", "critical", "severe", "blocked")):
        return "Open escalation task and notify on-call owner."
    if any(token in normalized for token in ("policy", "rule", "must", "forbidden", "required")):
        return "Update policy page and assign reviewer."
    if any(token in normalized for token in ("delay", "late", "timeout", "failed", "error")):
        return "Trigger mitigation runbook and add incident note."
    if "logistics" in category or "dispatch" in category:
        return "Apply dispatch fallback route and notify operations channel."
    return "Create/refresh runbook step and monitor repeat signals."


def _derive_escalation_rule(text: str, confidence: float, category: str) -> str:
    normalized = text.lower()
    if confidence < 0.7:
        return "Escalate if repeated by >=2 independent sources in 24h."
    if any(token in normalized for token in ("critical", "urgent", "incident", "outage")):
        return "Immediate escalation to on-call with incident severity."
    if "policy" in category or "compliance" in category:
        return "Require human review before publish."
    return "Escalate when SLA risk is detected or customer impact is explicit."


def _is_high_signal_operational_logic_claim(
    *,
    claim_text: str,
    category: str,
    metadata: dict[str, Any] | None = None,
) -> bool:
    text = str(claim_text or "").strip()
    if len(text) < 24:
        return False
    normalized_text = _normalize_statement_text(text)
    normalized_category = str(category or "").strip().lower()
    metadata_dict = metadata if isinstance(metadata, dict) else {}
    ingestion_classification = str(metadata_dict.get("ingestion_classification") or "").strip().lower()
    if ingestion_classification in {"operational_stream", "pii_sensitive_stream"}:
        return False
    if (
        (text.startswith("{") and text.endswith("}")) or (text.startswith("[") and text.endswith("]"))
    ) and _count_json_like_keys(text) >= 3:
        return False
    noisy_keywords = (
        "order_id",
        "invoice_id",
        "payload",
        "event_stream",
        "telemetry",
        "runtime_event",
        "wand_employee",
        "wand_transport_vehicle",
        "_sheet_",
    )
    if any(keyword in normalized_text for keyword in noisy_keywords):
        return False
    if normalized_category in {"policy", "process", "runbook", "incident", "access"}:
        return True
    procedural_keywords = ("if ", "when ", "then ", "must ", "required ", "escalat", "handoff", "runbook", "process")
    return any(keyword in normalized_text for keyword in procedural_keywords)


def _build_operational_logic_bootstrap_page(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    max_signals: int,
) -> list[dict[str, str]]:
    rows: list[tuple[Any, ...]] = []
    query_limit = max(20, min(1000, int(max_signals) * 10))
    if _wiki_feature_table_exists(cur, "public.claims"):
        cur.execute(
            """
            SELECT claim_text, category, metadata
            FROM claims
            WHERE project_id = %s
              AND status <> 'rejected'
            ORDER BY updated_at DESC
            LIMIT %s
            """,
            (project_id, query_limit),
        )
        rows = cur.fetchall() or []
    if not rows:
        cur.execute(
            """
            SELECT claim_payload
            FROM claim_proposals
            WHERE project_id = %s
            ORDER BY updated_at DESC
            LIMIT %s
            """,
            (project_id, query_limit),
        )
        rows = cur.fetchall() or []

    entries: list[dict[str, Any]] = []
    seen: set[str] = set()
    for row in rows:
        if len(row) >= 3:
            claim_text = str(row[0] or "").strip()
            category = str(row[1] or "operations").strip() or "operations"
            metadata = row[2] if isinstance(row[2], dict) else {}
            confidence = float(metadata.get("llm_confidence") or metadata.get("confidence") or 0.0)
        else:
            payload = row[0] if isinstance(row[0], dict) else {}
            claim_text = str(payload.get("claim_text") or "").strip()
            category = str(payload.get("category") or "operations").strip() or "operations"
            metadata = payload.get("metadata") if isinstance(payload.get("metadata"), dict) else {}
            confidence = float(payload.get("confidence") or 0.0)
        if not claim_text:
            continue
        if not _is_high_signal_operational_logic_claim(claim_text=claim_text, category=category, metadata=metadata):
            continue
        normalized_key = _normalize_statement_text(claim_text)[:180]
        if not normalized_key or normalized_key in seen:
            continue
        seen.add(normalized_key)
        entries.append(
            {
                "comment": claim_text[:180],
                "signal": category,
                "action_candidate": _derive_action_candidate(claim_text, category),
                "escalation_rule": _derive_escalation_rule(claim_text, confidence, category),
                "confidence": confidence,
            }
        )
        if len(entries) >= max(5, min(200, int(max_signals))):
            break

    lines = [
        "# Operational Logic Map",
        "",
        "## Pattern Template",
        "`comment -> signal -> action candidate -> escalation rule`",
        "",
        "## Synthesized Patterns",
        "| Comment | Signal | Action Candidate | Escalation Rule |",
        "|---|---|---|---|",
    ]
    if entries:
        for item in entries:
            lines.append(
                f"| {item['comment'].replace('|', '/')} | `{item['signal']}` | {item['action_candidate']} | {item['escalation_rule']} |"
            )
    else:
        fallback_rows = [
            (
                "Customer reports policy mismatch with current execution",
                "policy",
                "Open policy review task and attach evidence from at least 2 independent sources.",
                "Escalate to approver if mismatch impacts SLA/finance/compliance.",
            ),
            (
                "Agent sees repeated access failure in same location",
                "incident",
                "Trigger escalation runbook and publish temporary workaround in reviewed mode.",
                "Escalate immediately when failure repeats >= 3 times within 24h.",
            ),
            (
                "Operator confirms durable customer preference",
                "preference",
                "Update preference page and inject context for matching entity intents.",
                "Escalate only if preference conflicts with active policy.",
            ),
        ]
        for comment, signal, action_candidate, escalation_rule in fallback_rows:
            lines.append(f"| {comment} | `{signal}` | {action_candidate} | {escalation_rule} |")
    lines.extend(
        [
            "",
            "## Governance",
            "- Noise goes to operational/event layer; only reusable patterns stay in wiki.",
            "- Policy-like updates require human review when confidence is low or impact is high.",
            "- Use this map to document `when -> do -> escalate` process logic, not raw payload history.",
            "",
        ]
    )
    return [
        {
            "title": "Operational Logic Map",
            "slug": _space_slug(space_key, "operational-logic-map"),
            "page_type": "process",
            "markdown": "\n".join(lines),
        }
    ]


def _build_agent_wiki_bootstrap_pages(
    conn,
    *,
    project_id: str,
    space_key: str,
    include_data_sources_catalog: bool,
    include_agent_capability_profile: bool,
    include_operational_logic: bool,
    include_tooling_map: bool,
    include_process_playbooks: bool,
    include_company_operating_context: bool,
    include_first_run_starter: bool,
    include_state_snapshot: bool,
    max_sources: int,
    max_agents: int,
    max_signals: int,
) -> list[dict[str, str]]:
    pages: list[dict[str, str]] = []
    if include_first_run_starter:
        pages.extend(_build_first_run_starter_pages("standard", space_key=space_key, include_decisions_log=True))
    else:
        pages.append(_build_decisions_log_seed_page(space_key))
    with conn.cursor() as cur:
        if include_data_sources_catalog:
            pages.extend(
                _build_data_sources_catalog_pages(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_sources=max_sources,
                )
            )
        if include_agent_capability_profile:
            pages.extend(
                _build_agent_capability_bootstrap_page(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_agents=max_agents,
                )
            )
        if include_tooling_map:
            pages.extend(
                _build_tooling_map_bootstrap_page(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_agents=max_agents,
                )
            )
        if include_operational_logic:
            pages.extend(
                _build_operational_logic_bootstrap_page(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_signals=max_signals,
                )
            )
        if include_process_playbooks:
            pages.extend(
                _build_process_playbooks_bootstrap_page(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_signals=max_signals,
                )
            )
        pages.extend(
            _build_decisions_log_compiler_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_entries=max(12, min(40, max_signals)),
            )
        )
        if include_company_operating_context:
            pages.extend(
                _build_company_operating_context_bootstrap_page(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_signals=max_signals,
                )
            )
            pages.extend(
                _build_daily_operations_digest_bootstrap_page(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    max_days=min(14, max(3, int(max_signals // 4) or 7)),
                )
            )
    if include_state_snapshot:
        state_preview = _build_wiki_state_snapshot(
            conn,
            project_id=project_id,
            space_key=space_key,
            max_workstreams=min(50, max(6, max_signals)),
            max_open_items=min(200, max(10, max_signals * 2)),
            max_people_watch=min(100, max(8, max_agents)),
            max_metrics=min(100, max(6, max_signals)),
        )
        pages.append(
            {
                "title": "Wiki State Snapshot",
                "slug": str(state_preview.get("target_slug") or _space_slug(space_key, "state")),
                "page_type": "state",
                "markdown": str(state_preview.get("markdown") or "# Wiki State Snapshot\n"),
            }
        )
    deduped_map: dict[str, dict[str, str]] = {}
    for spec in pages:
        slug = _normalize_wiki_slug(str(spec.get("slug") or spec.get("title") or "page"), str(spec.get("title") or "page"))
        deduped_map[slug] = {
            "title": str(spec.get("title") or slug),
            "slug": slug,
            "page_type": str(spec.get("page_type") or "operations"),
            "markdown": str(spec.get("markdown") or f"# {str(spec.get('title') or slug)}\n"),
        }
    return list(deduped_map.values())


def _evaluate_agent_capability_bootstrap_contract(
    markdown: str,
    *,
    min_sections: int = 4,
    min_facts: int = 6,
) -> dict[str, Any]:
    text = str(markdown or "")
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    normalized = text.lower()
    required_sections = [
        "## Orgchart",
        "## Capability Matrix",
        "## Capability Signals",
        "## Handoffs",
    ]
    present_sections = [section for section in required_sections if section.lower() in normalized]
    missing_sections = [section for section in required_sections if section.lower() not in normalized]
    fact_lines = [
        line
        for line in lines
        if (
            line.startswith("- ")
            and any(
                marker in line.lower()
                for marker in (
                    "team / role",
                    "typical actions",
                    "escalation rules",
                    "toolset",
                    "data sources",
                    "constraints",
                    "scenario examples",
                )
            )
        )
    ]
    deep_dive_agents = [line for line in lines if line.startswith("### ") and "(`" in line]
    passed = bool(
        len(present_sections) >= max(1, int(min_sections))
        and len(fact_lines) >= max(1, int(min_facts))
        and len(deep_dive_agents) >= 1
    )
    return {
        "passed": passed,
        "required_sections": required_sections,
        "present_sections": present_sections,
        "missing_sections": missing_sections,
        "facts_count": len(fact_lines),
        "deep_dive_agents": len(deep_dive_agents),
        "min_sections": int(min_sections),
        "min_facts": int(min_facts),
    }


def _evaluate_data_sources_catalog_bootstrap_contract(
    markdown: str,
    *,
    min_sections: int = 3,
    min_table_rows: int = 2,
) -> dict[str, Any]:
    text = str(markdown or "")
    normalized = text.lower()
    required_sections = [
        "## Durable Source Signals",
        "## Governance",
    ]
    present_sections = [section for section in required_sections if section.lower() in normalized]
    missing_sections = [section for section in required_sections if section.lower() not in normalized]
    table_rows = [
        line.strip()
        for line in text.splitlines()
        if line.strip().startswith("|") and line.count("|") >= 3 and "Capability / Process Impact" not in line
    ]
    has_impact_column = "capability / process impact" in normalized
    has_agent_usage = "used by agents" in normalized or "## agent usage" in normalized
    passed = bool(
        len(present_sections) >= max(1, int(min_sections) - 1)
        and len(table_rows) >= max(1, int(min_table_rows))
        and has_impact_column
        and has_agent_usage
    )
    return {
        "passed": passed,
        "required_sections": required_sections,
        "present_sections": present_sections,
        "missing_sections": missing_sections,
        "table_rows": len(table_rows),
        "has_impact_column": bool(has_impact_column),
        "has_agent_usage": bool(has_agent_usage),
        "min_sections": int(min_sections),
        "min_table_rows": int(min_table_rows),
    }


def _evaluate_process_playbooks_bootstrap_contract(
    markdown: str,
    *,
    min_playbooks: int = 1,
    min_fact_lines: int = 7,
) -> dict[str, Any]:
    text = str(markdown or "")
    normalized = text.lower()
    required_sections = [
        "## Playbook Index",
        "## Canonical Runbooks",
        "## How To Use",
    ]
    present_sections = [section for section in required_sections if section.lower() in normalized]
    missing_sections = [section for section in required_sections if section.lower() not in normalized]
    playbook_headings = [line for line in text.splitlines() if line.strip().startswith("### ")]
    fact_lines = [
        line.strip()
        for line in text.splitlines()
        if line.strip().startswith("- ")
        and any(
            marker in line.lower()
            for marker in (
                "purpose:",
                "trigger:",
                "inputs:",
                "outputs:",
                "escalation:",
                "tools used:",
                "source evidence:",
            )
        )
    ]
    has_steps = "- Steps:" in text or "  - " in text
    has_exceptions = "- Exceptions:" in text
    passed = bool(
        len(present_sections) == len(required_sections)
        and len(playbook_headings) >= max(1, int(min_playbooks))
        and len(fact_lines) >= max(1, int(min_fact_lines))
        and has_steps
        and has_exceptions
    )
    return {
        "passed": passed,
        "required_sections": required_sections,
        "present_sections": present_sections,
        "missing_sections": missing_sections,
        "playbook_count": len(playbook_headings),
        "facts_count": len(fact_lines),
        "has_steps": bool(has_steps),
        "has_exceptions": bool(has_exceptions),
        "min_playbooks": int(min_playbooks),
        "min_fact_lines": int(min_fact_lines),
    }


def _evaluate_company_operating_context_contract(markdown: str) -> dict[str, Any]:
    text = str(markdown or "")
    normalized = text.lower()
    required_sections = [
        "## Snapshot",
        "## Team Topology",
        "## Data Backbone",
        "## Core Operating Principles",
    ]
    present_sections = [section for section in required_sections if section.lower() in normalized]
    missing_sections = [section for section in required_sections if section.lower() not in normalized]
    fact_lines = [line for line in text.splitlines() if line.strip().startswith("- ")]
    passed = bool(len(present_sections) >= 3 and len(fact_lines) >= 6)
    return {
        "passed": passed,
        "required_sections": required_sections,
        "present_sections": present_sections,
        "missing_sections": missing_sections,
        "facts_count": len(fact_lines),
    }


def _evaluate_decisions_log_bootstrap_contract(
    markdown: str,
    *,
    min_entries: int = 2,
) -> dict[str, Any]:
    text = str(markdown or "")
    normalized = text.lower()
    required_sections = [
        "## How To Use",
        "## Decision Index",
        "## Decisions Log",
    ]
    present_sections = [section for section in required_sections if section.lower() in normalized]
    missing_sections = [section for section in required_sections if section.lower() not in normalized]
    decision_entries = [
        line.strip()
        for line in text.splitlines()
        if line.strip().startswith("- ")
        and re.match(r"-\s+\d{4}-\d{2}-\d{2}\s+-\s+", line.strip()) is not None
        and "source:" in line.lower()
    ]
    passed = bool(len(present_sections) == len(required_sections) and len(decision_entries) >= max(1, int(min_entries)))
    return {
        "passed": passed,
        "required_sections": required_sections,
        "present_sections": present_sections,
        "missing_sections": missing_sections,
        "entries_count": len(decision_entries),
        "min_entries": int(min_entries),
    }


def _evaluate_bootstrap_page_contract(
    *,
    slug: str,
    page_type: str,
    markdown: str,
) -> dict[str, Any]:
    leaf = _bootstrap_page_leaf(slug)
    normalized_type = str(page_type or "").strip().lower()
    if leaf == "agent-capability-profile" or normalized_type == "agent_profile":
        return {"kind": "agent_profile", **_evaluate_agent_capability_bootstrap_contract(markdown)}
    if leaf == "data-sources-catalog" or normalized_type == "data_map":
        return {"kind": "data_sources_catalog", **_evaluate_data_sources_catalog_bootstrap_contract(markdown)}
    if leaf == "process-playbooks" or normalized_type in {"process", "runbook", "policy"}:
        return {"kind": "process_playbooks", **_evaluate_process_playbooks_bootstrap_contract(markdown)}
    if leaf == "company-operating-context":
        return {"kind": "company_operating_context", **_evaluate_company_operating_context_contract(markdown)}
    if leaf == "decisions-log" or normalized_type == "decision_log":
        return {"kind": "decisions_log", **_evaluate_decisions_log_bootstrap_contract(markdown)}
    schema = _evaluate_wiki_schema_contract(markdown=markdown, page_type=page_type, slug=slug)
    return {
        "kind": "schema_only",
        "passed": bool(schema.get("passed")),
        "missing_sections": list(schema.get("missing_markers") or []),
        "required_sections": [],
        "present_sections": [],
    }


def _agent_wiki_bootstrap_dod(
    *,
    pages: list[dict[str, str]] | None = None,
    created_slugs: list[str] | None = None,
) -> dict[str, Any]:
    scope = {str(item.get("slug") or "") for item in (pages or [])}
    if created_slugs:
        scope.update(str(item or "") for item in created_slugs)
    has_agent = any(slug.startswith("agents/") or slug.endswith("/agent-capability-profile") or slug == "agent-capability-profile" for slug in scope)
    has_data_sources = any("data-sources-catalog" in slug or slug.endswith("/data-map") or slug == "data-map" for slug in scope)
    has_process = any("operational-logic-map" in slug or "runbook" in slug for slug in scope)
    has_tooling_map = any(slug.endswith("/tooling-map") or slug == "tooling-map" for slug in scope)
    has_company_context = any(slug.endswith("/company-operating-context") or slug == "company-operating-context" for slug in scope)
    has_state_snapshot = any(slug.endswith("/state") or slug == "state" for slug in scope)
    has_decisions_log = any(slug.endswith("/decisions-log") or slug == "decisions-log" for slug in scope)
    return {
        "agent_page": bool(has_agent),
        "data_sources_page": bool(has_data_sources),
        "operational_process_page": bool(has_process),
        "tooling_map_page": bool(has_tooling_map),
        "company_operating_context_page": bool(has_company_context),
        "state_snapshot_page": bool(has_state_snapshot),
        "decisions_log_page": bool(has_decisions_log),
        "published_minimum_ready": bool(has_agent and has_data_sources and has_process and has_tooling_map and has_company_context),
        "step0_baseline_ready": bool(has_state_snapshot and has_decisions_log),
        "pages_total": len(scope),
    }


def _is_core_bootstrap_page_slug(slug: str) -> bool:
    normalized = _normalize_wiki_slug(str(slug or ""), str(slug or "page"))
    leaf = normalized.split("/")[-1]
    core_leaves = {
        "agent-capability-profile",
        "tooling-map",
        "process-playbooks",
        "operational-logic-map",
        "company-operating-context",
        "data-sources-catalog",
        "state",
        "decisions-log",
    }
    return leaf in core_leaves


