def _bootstrap_page_leaf(slug: str) -> str:
    normalized = _normalize_wiki_slug(str(slug or ""), str(slug or "page"))
    return normalized.split("/")[-1]


def _bootstrap_page_importance(*, slug: str, page_type: str) -> dict[str, Any]:
    leaf = _bootstrap_page_leaf(slug)
    default = {
        "leaf": leaf,
        "priority": 20,
        "label": "normal",
        "publish_floor": 0.0,
        "reason": "General supporting documentation.",
    }
    template = _BOOTSTRAP_PAGE_IMPORTANCE_BY_LEAF.get(leaf)
    if template is None:
        if str(page_type or "").strip().lower() in {"policy", "process", "runbook", "agent_profile", "data_map"}:
            template = {
                "priority": 64,
                "label": "medium",
                "publish_floor": 0.26,
                "reason": "Knowledge-like page type with reusable onboarding value.",
            }
        else:
            template = default
    return {
        **default,
        **template,
        "leaf": leaf,
    }


def _prepend_bootstrap_publish_notice(
    markdown: str,
    *,
    title: str,
    importance: dict[str, Any],
    quality_assessment: dict[str, Any],
) -> str:
    text = str(markdown or "")
    if not text.strip():
        text = f"# {title}\n"
    if "<!-- synapse-bootstrap-warning -->" in text:
        return text
    missing_required = [str(item).strip() for item in (quality_assessment.get("missing_required_markers") or []) if str(item).strip()]
    placeholder_hits = [str(item).strip() for item in (quality_assessment.get("placeholder_hits") or []) if str(item).strip()]
    quality_score = round(float(quality_assessment.get("quality_score") or 0.0), 2)
    warning_lines = [
        "> <!-- synapse-bootstrap-warning -->",
        f"> Bootstrap note: this page is published because `{importance.get('leaf')}` is high-priority onboarding knowledge.",
        f"> Current confidence: `{quality_score}` (`{importance.get('label')}` priority).",
    ]
    if missing_required:
        warning_lines.append(f"> Missing signals to enrich next: {', '.join(missing_required[:4])}.")
    if placeholder_hits:
        warning_lines.append(f"> Placeholder-like content still present: {', '.join(placeholder_hits[:3])}.")
    warning_lines.append("> Synapse will keep enriching this page as stronger evidence and runtime signals arrive.")
    warning_block = "\n".join(warning_lines)

    lines = text.splitlines()
    if lines and lines[0].startswith("# "):
        return "\n".join([lines[0], "", warning_block, "", *lines[1:]])
    return "\n".join([warning_block, "", text])


def _build_agent_wiki_bootstrap_quality_report(
    *,
    plan_pages: list[dict[str, str]],
    page_result: dict[str, Any] | None = None,
) -> dict[str, Any]:
    plan_by_slug: dict[str, dict[str, str]] = {}
    for page in plan_pages:
        slug = _normalize_wiki_slug(str(page.get("slug") or page.get("title") or "page"), str(page.get("title") or "page"))
        plan_by_slug[slug] = page

    core_planned_slugs = sorted([slug for slug in plan_by_slug.keys() if _is_core_bootstrap_page_slug(slug)])
    state_planned_slugs = sorted([slug for slug in plan_by_slug.keys() if slug.endswith("/state") or slug == "state"])
    decisions_planned_slugs = sorted([slug for slug in plan_by_slug.keys() if slug.endswith("/decisions-log") or slug == "decisions-log"])
    status_by_slug: dict[str, str] = {}
    quality_by_slug: dict[str, dict[str, Any]] = {}
    importance_by_slug = {
        slug: _bootstrap_page_importance(
            slug=slug,
            page_type=str((plan_by_slug.get(slug) or {}).get("page_type") or "operations"),
        )
        for slug in plan_by_slug.keys()
    }
    created_rows = list((page_result or {}).get("created") or [])
    for row in created_rows:
        slug = _normalize_wiki_slug(str(row.get("slug") or ""), str(row.get("slug") or "page"))
        status = str(row.get("status") or "unknown").strip().lower() or "unknown"
        status_by_slug[slug] = status
        quality = row.get("quality_gate") if isinstance(row.get("quality_gate"), dict) else {}
        quality_by_slug[slug] = quality

    placeholder_hits = 0
    token_total = 0
    for slug in core_planned_slugs:
        markdown = str((plan_by_slug.get(slug) or {}).get("markdown") or "")
        words = re.findall(r"[a-zа-я0-9_]+", markdown.lower())
        token_total += len(words)
        for token in _BOOTSTRAP_PLACEHOLDER_TOKENS:
            placeholder_hits += markdown.lower().count(token)
    placeholder_ratio = round(float(placeholder_hits) / float(max(1, token_total)), 4)

    core_published = [slug for slug in core_planned_slugs if status_by_slug.get(slug) == "published"]
    core_reviewed = [slug for slug in core_planned_slugs if status_by_slug.get(slug) == "reviewed"]
    core_missing = [slug for slug in core_planned_slugs if slug not in status_by_slug]
    published_with_warnings = [
        slug for slug in core_published if bool((quality_by_slug.get(slug) or {}).get("forced_publish_core"))
    ]
    core_priority_backlog = [
        {
            "slug": slug,
            "priority": int((importance_by_slug.get(slug) or {}).get("priority") or 0),
            "label": str((importance_by_slug.get(slug) or {}).get("label") or "normal"),
            "status": status_by_slug.get(slug, "missing"),
        }
        for slug in core_planned_slugs
        if status_by_slug.get(slug) != "published"
    ]
    core_priority_backlog.sort(key=lambda item: (-int(item["priority"]), str(item["slug"])))
    not_published_reasons: list[dict[str, Any]] = []
    for slug in core_reviewed:
        quality = quality_by_slug.get(slug) or {}
        not_published_reasons.append(
            {
                "slug": slug,
                "reason": "quality_gate",
                "quality_score": float(quality.get("quality_score") or 0.0),
                "missing_required_markers": list(quality.get("missing_required_markers") or []),
                "placeholder_hits": list(quality.get("placeholder_hits") or []),
                "importance": importance_by_slug.get(slug) or {},
            }
        )

    report = {
        "core_pages": {
            "planned": len(core_planned_slugs),
            "published": len(core_published),
            "reviewed": len(core_reviewed),
            "missing": len(core_missing),
            "published_slugs": core_published,
            "reviewed_slugs": core_reviewed,
            "missing_slugs": core_missing,
            "published_with_warnings": published_with_warnings,
            "priority_backlog": core_priority_backlog[:10],
        },
        "step0": {
            "state_planned": state_planned_slugs,
            "state_published": [slug for slug in state_planned_slugs if status_by_slug.get(slug) == "published"],
            "decisions_planned": decisions_planned_slugs,
            "decisions_published": [slug for slug in decisions_planned_slugs if status_by_slug.get(slug) == "published"],
        },
        "placeholder_ratio_core": float(placeholder_ratio),
        "page_importance": [
            {
                "slug": slug,
                "status": status_by_slug.get(slug, "planned"),
                **(importance_by_slug.get(slug) or {}),
            }
            for slug in sorted(core_planned_slugs, key=lambda item: (-int((importance_by_slug.get(item) or {}).get("priority") or 0), item))
        ],
        "quality_findings": {
            "not_published_reasons": not_published_reasons,
        },
        "pass": bool(len(core_published) >= max(4, len(core_planned_slugs) // 2) and placeholder_ratio < 0.10),
    }
    if not created_rows:
        report["mode"] = "preview"
        report["next_action"] = "apply_bootstrap_to_materialize_status_and_quality_findings"
    else:
        report["mode"] = "applied"
    return report


def _build_bundle_promotion_pages(
    cur: Any,
    *,
    project_id: str,
    space_key: str,
    include_data_sources_catalog: bool,
    include_agent_capability_profile: bool,
    include_process_playbooks: bool,
    include_decisions_log: bool,
    include_company_operating_context: bool,
    include_operational_logic_map: bool,
    max_sources: int,
    max_agents: int,
    max_signals: int,
) -> list[dict[str, str]]:
    pages: list[dict[str, str]] = []
    if include_data_sources_catalog:
        pages.extend(
            _build_data_sources_catalog_pages(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_sources=max_sources,
            )
        )
    if include_agent_capability_profile:
        pages.extend(
            _build_agent_capability_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_agents=max_agents,
            )
        )
    if include_process_playbooks:
        pages.extend(
            _build_process_playbooks_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_signals=max_signals,
            )
        )
    if include_decisions_log:
        pages.extend(
            _build_decisions_log_compiler_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_entries=max(16, min(80, int(max_signals))),
            )
        )
    if include_company_operating_context:
        pages.extend(
            _build_company_operating_context_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_signals=max_signals,
            )
        )
    if include_operational_logic_map:
        pages.extend(
            _build_operational_logic_bootstrap_page(
                cur,
                project_id=project_id,
                space_key=space_key,
                max_signals=max_signals,
            )
        )
    return pages


def _upsert_compiler_pages(
    conn,
    *,
    project_id: str,
    updated_by: str,
    profile: str,
    pages: list[dict[str, str]],
    requested_status: str,
    bootstrap_publish_core: bool,
) -> dict[str, Any]:
    created: list[dict[str, Any]] = []
    updated: list[dict[str, Any]] = []
    skipped: list[dict[str, Any]] = []
    downgraded_to_reviewed = 0
    force_published_core_pages = 0

    with conn.cursor() as cur:
        for spec in pages:
            title = str(spec.get("title") or "").strip()
            slug = _normalize_wiki_slug(str(spec.get("slug") or title), title)
            page_type = str(spec.get("page_type") or "operations").strip().lower() or "operations"
            markdown = _apply_wiki_schema_contract(
                markdown=str(spec.get("markdown") or f"# {title}\n"),
                title=title,
                page_type=page_type,
                slug=slug,
                status=requested_status,
                generated_at=datetime.now(UTC),
            )
            space_key = _wiki_space_key_from_slug(slug)
            entity_key = slug
            policy_check = _check_wiki_policy_access(
                cur,
                project_id=project_id,
                space_key=space_key,
                actor=updated_by,
                action="write",
                page_id=None,
            )
            if not policy_check["allowed"]:
                skipped.append(
                    {
                        "slug": slug,
                        "title": title,
                        "reason": "wiki_policy_denied",
                        "detail": str(policy_check.get("reason") or "not_allowed"),
                    }
                )
                continue

            status = requested_status
            schema_contract = _evaluate_wiki_schema_contract(
                markdown=markdown,
                page_type=page_type,
                slug=slug,
            )
            forced_publish_core = False
            importance = _bootstrap_page_importance(slug=slug, page_type=page_type)
            if status == "published":
                guard = _resolve_agent_publish_mode(
                    cur,
                    project_id=project_id,
                    actor=updated_by,
                    page_type=page_type,
                )
                if str(guard.get("mode") or "") == "human_required":
                    status = "reviewed"
                    downgraded_to_reviewed += 1
                elif not bool(schema_contract.get("passed")):
                    if bootstrap_publish_core and _is_core_bootstrap_page_slug(slug):
                        markdown = _prepend_bootstrap_publish_notice(
                            markdown,
                            title=title,
                            importance=importance,
                            quality_assessment={
                                "publish_warning": "bundle_promotion_core_override",
                                "missing_required_markers": list(schema_contract.get("missing_markers") or []),
                                "placeholder_hits": [],
                                "quality_score": 0.0,
                                "schema_contract": schema_contract,
                            },
                        )
                        forced_publish_core = True
                        force_published_core_pages += 1
                    else:
                        status = "reviewed"
                        downgraded_to_reviewed += 1

            cur.execute(
                """
                SELECT id, title, slug, entity_key, page_type, status, current_version
                FROM wiki_pages
                WHERE project_id = %s
                  AND slug = %s
                LIMIT 1
                """,
                (project_id, slug),
            )
            page_row = cur.fetchone()

            if page_row is None:
                page_id = uuid4()
                cur.execute(
                    """
                    INSERT INTO wiki_pages (
                      id, project_id, page_type, title, slug, entity_key, status, current_version, metadata
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s, 1, %s)
                    """,
                    (
                        page_id,
                        project_id,
                        page_type,
                        title,
                        slug,
                        entity_key,
                        status,
                        Jsonb(
                            {
                                "source": "bundle_promotion",
                                "updated_by": updated_by,
                                "profile": profile,
                                "compiler_page": True,
                            }
                        ),
                    ),
                )
                cur.execute(
                    """
                    INSERT INTO wiki_page_versions (
                      id, page_id, version, markdown, ast_json, source, created_by, change_summary
                    )
                    VALUES (%s, %s, 1, %s, %s, 'human', %s, %s)
                    """,
                    (uuid4(), page_id, markdown, Jsonb([]), updated_by, "Created by bundle promotion"),
                )
                sections = _extract_sections_from_markdown(markdown)
                statement_count = 0
                for index, section in enumerate(sections):
                    section_key = str(section.get("section_key") or f"section_{index + 1}")
                    heading = str(section.get("heading") or _section_heading_from_key(section_key))
                    statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
                    cur.execute(
                        """
                        INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                        VALUES (%s, %s, %s, %s, %s)
                        ON CONFLICT (page_id, section_key) DO UPDATE
                        SET heading = EXCLUDED.heading,
                            order_index = EXCLUDED.order_index,
                            statement_count = EXCLUDED.statement_count
                        """,
                        (page_id, section_key, heading, index, len(statements)),
                    )
                    for statement in statements:
                        statement_count += 1
                        cur.execute(
                            """
                            INSERT INTO wiki_statements (
                              id, project_id, page_id, section_key, statement_text, normalized_text,
                              claim_fingerprint, status, metadata, valid_from
                            )
                            VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, NOW())
                            """,
                            (
                                uuid4(),
                                project_id,
                                page_id,
                                section_key,
                                statement,
                                _normalize_statement_text(statement),
                                _compute_claim_fingerprint(project_id, entity_key, page_type, statement),
                                Jsonb({"source": "bundle_promotion", "updated_by": updated_by}),
                            ),
                        )
                created.append(
                    {
                        "id": str(page_id),
                        "slug": slug,
                        "title": title,
                        "status": status,
                        "current_version": 1,
                        "statements": statement_count,
                        "quality_gate": {
                            "forced_publish_core": bool(forced_publish_core),
                            "schema_contract": schema_contract,
                        },
                    }
                )
                continue

            page_id = page_row[0]
            existing_title = str(page_row[1] or title).strip() or title
            existing_slug = str(page_row[2] or slug).strip() or slug
            existing_entity_key = str(page_row[3] or entity_key).strip() or entity_key
            current_version = int(page_row[6] or 1)
            cur.execute(
                """
                SELECT markdown
                FROM wiki_page_versions
                WHERE page_id = %s
                  AND version = %s
                LIMIT 1
                """,
                (page_id, current_version),
            )
            latest_row = cur.fetchone()
            latest_markdown = str(latest_row[0] or "") if latest_row is not None else ""
            if latest_markdown.strip() == markdown.strip() and str(page_row[5] or status).strip() == status and str(page_row[4] or page_type).strip() == page_type:
                skipped.append({"slug": existing_slug, "title": existing_title, "reason": "no_change"})
                continue

            next_version = current_version + 1
            cur.execute(
                """
                INSERT INTO wiki_page_versions (
                  id, page_id, version, markdown, ast_json, source, created_by, change_summary
                )
                VALUES (%s, %s, %s, %s, %s, 'human', %s, %s)
                """,
                (uuid4(), page_id, next_version, markdown, Jsonb([]), updated_by, "Refreshed by bundle promotion"),
            )
            cur.execute(
                """
                UPDATE wiki_pages
                SET title = %s,
                    page_type = %s,
                    status = %s,
                    current_version = %s,
                    updated_at = NOW(),
                    metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb
                WHERE id = %s
                """,
                (
                    title or existing_title,
                    page_type,
                    status,
                    next_version,
                    Jsonb(
                        {
                            "source": "bundle_promotion",
                            "updated_by": updated_by,
                            "profile": profile,
                            "compiler_page": True,
                        }
                    ),
                    page_id,
                ),
            )
            cur.execute(
                """
                UPDATE wiki_statements
                SET status = 'superseded',
                    valid_to = COALESCE(valid_to, NOW()),
                    updated_at = NOW(),
                    metadata = COALESCE(metadata, '{}'::jsonb) || %s::jsonb
                WHERE page_id = %s
                  AND status = 'active'
                """,
                (Jsonb({"superseded_by": updated_by, "superseded_by_version": next_version}), page_id),
            )
            sections = _extract_sections_from_markdown(markdown)
            statement_count = 0
            for index, section in enumerate(sections):
                section_key = str(section.get("section_key") or f"section_{index + 1}").strip() or f"section_{index + 1}"
                heading = str(section.get("heading") or _section_heading_from_key(section_key)).strip()
                statements = [str(item).strip() for item in (section.get("statements") or []) if str(item).strip()]
                cur.execute(
                    """
                    INSERT INTO wiki_sections (page_id, section_key, heading, order_index, statement_count)
                    VALUES (%s, %s, %s, %s, %s)
                    ON CONFLICT (page_id, section_key) DO UPDATE
                    SET heading = EXCLUDED.heading,
                        order_index = EXCLUDED.order_index,
                        statement_count = EXCLUDED.statement_count
                    """,
                    (page_id, section_key, heading or _section_heading_from_key(section_key), index, len(statements)),
                )
                for statement in statements:
                    statement_count += 1
                    cur.execute(
                        """
                        INSERT INTO wiki_statements (
                          id, project_id, page_id, section_key, statement_text, normalized_text,
                          claim_fingerprint, status, metadata, valid_from
                        )
                        VALUES (%s, %s, %s, %s, %s, %s, %s, 'active', %s, NOW())
                        """,
                        (
                            uuid4(),
                            project_id,
                            page_id,
                            section_key,
                            statement,
                            _normalize_statement_text(statement),
                            _compute_claim_fingerprint(project_id, existing_entity_key, page_type, statement),
                            Jsonb({"source": "bundle_promotion", "updated_by": updated_by, "page_version": next_version}),
                        ),
                    )
            updated.append(
                {
                    "id": str(page_id),
                    "slug": existing_slug,
                    "title": title or existing_title,
                    "status": status,
                    "current_version": next_version,
                    "statements": statement_count,
                    "quality_gate": {
                        "forced_publish_core": bool(forced_publish_core),
                        "schema_contract": schema_contract,
                    },
                }
            )

    return {
        "created": created,
        "updated": updated,
        "skipped": skipped,
        "summary": {
            "created": len(created),
            "updated": len(updated),
            "skipped": len(skipped),
            "published_downgraded_to_reviewed": int(downgraded_to_reviewed),
            "force_published_core_pages": int(force_published_core_pages),
        },
    }


def _build_bundle_promotion_summary(
    cur: Any,
    *,
    project_id: str,
    max_items: int = 8,
) -> dict[str, Any]:
    if not _wiki_feature_table_exists(cur, "public.evidence_bundles"):
        return {
            "available": False,
            "bundles_total": 0,
            "ready_total": 0,
            "candidate_total": 0,
            "observed_total": 0,
            "suppressed_total": 0,
            "top_page_types": [],
            "top_taxonomy_classes": [],
        }
    cur.execute(
        """
        SELECT bundle_status, COUNT(*)::bigint
        FROM evidence_bundles
        WHERE project_id = %s
        GROUP BY 1
        """,
        (project_id,),
    )
    status_counts: dict[str, int] = {}
    for row in cur.fetchall() or []:
        key = str(row[0] or "unknown").strip().lower() or "unknown"
        status_counts[key] = int(row[1] or 0)
    cur.execute(
        """
        SELECT suggested_page_type, COUNT(*)::bigint
        FROM evidence_bundles
        WHERE project_id = %s
        GROUP BY 1
        ORDER BY COUNT(*) DESC, suggested_page_type ASC
        LIMIT %s
        """,
        (project_id, int(max_items)),
    )
    top_page_types = [
        {
            "suggested_page_type": str(row[0] or "operations").strip().lower() or "operations",
            "count": int(row[1] or 0),
        }
        for row in (cur.fetchall() or [])
    ]
    cur.execute(
        """
        SELECT COALESCE(metadata->>'knowledge_taxonomy_class', 'unknown') AS taxonomy_class, COUNT(*)::bigint
        FROM evidence_bundles
        WHERE project_id = %s
        GROUP BY 1
        ORDER BY COUNT(*) DESC, taxonomy_class ASC
        LIMIT %s
        """,
        (project_id, int(max_items)),
    )
    top_taxonomy_classes = [
        {
            "knowledge_taxonomy_class": str(row[0] or "unknown").strip().lower() or "unknown",
            "count": int(row[1] or 0),
        }
        for row in (cur.fetchall() or [])
    ]
    bundles_total = sum(status_counts.values())
    return {
        "available": True,
        "bundles_total": int(bundles_total),
        "ready_total": int(status_counts.get("ready", 0)),
        "candidate_total": int(status_counts.get("candidate", 0)),
        "observed_total": int(status_counts.get("observed", 0)),
        "suppressed_total": int(status_counts.get("suppressed", 0)),
        "top_page_types": top_page_types,
        "top_taxonomy_classes": top_taxonomy_classes,
    }


def _bundle_promotion_scope_for_page_type(page_type: str | None) -> dict[str, bool]:
    normalized = str(page_type or "").strip().lower()
    scope = {
        "include_data_sources_catalog": False,
        "include_agent_capability_profile": False,
        "include_process_playbooks": False,
        "include_decisions_log": False,
        "include_company_operating_context": False,
        "include_operational_logic_map": False,
    }
    if normalized == "agent_profile":
        scope["include_agent_capability_profile"] = True
        scope["include_company_operating_context"] = True
    elif normalized == "data_map":
        scope["include_data_sources_catalog"] = True
        scope["include_company_operating_context"] = True
    elif normalized in {"process", "runbook", "policy"}:
        scope["include_process_playbooks"] = True
        scope["include_operational_logic_map"] = True
        scope["include_decisions_log"] = True
        scope["include_company_operating_context"] = True
    elif normalized == "decision_log":
        scope["include_decisions_log"] = True
        scope["include_process_playbooks"] = True
        scope["include_operational_logic_map"] = True
    else:
        for key in scope.keys():
            scope[key] = True
    return scope


def _run_inline_bundle_promotion(
    conn,
    *,
    project_id: str,
    updated_by: str,
    space_key: str,
    requested_status: str = "published",
    bootstrap_publish_core: bool = True,
    page_type_scope: str | None = None,
    max_sources: int = 20,
    max_agents: int = 12,
    max_signals: int = 50,
) -> dict[str, Any]:
    with conn.cursor() as cur:
        scope = _bundle_promotion_scope_for_page_type(page_type_scope)
        plan_pages = _build_bundle_promotion_pages(
            cur,
            project_id=project_id,
            space_key=_normalize_space_key(space_key or "", default="operations"),
            include_data_sources_catalog=bool(scope.get("include_data_sources_catalog")),
            include_agent_capability_profile=bool(scope.get("include_agent_capability_profile")),
            include_process_playbooks=bool(scope.get("include_process_playbooks")),
            include_decisions_log=bool(scope.get("include_decisions_log")),
            include_company_operating_context=bool(scope.get("include_company_operating_context")),
            include_operational_logic_map=bool(scope.get("include_operational_logic_map")),
            max_sources=int(max_sources),
            max_agents=int(max_agents),
            max_signals=int(max_signals),
        )
    upsert = _upsert_compiler_pages(
        conn,
        project_id=project_id,
        updated_by=updated_by,
        profile="bundle_promotion_inline",
        pages=plan_pages,
        requested_status=requested_status,
        bootstrap_publish_core=bool(bootstrap_publish_core),
    )
    return {
        "scope": {
            "space_key": _normalize_space_key(space_key or "", default="operations"),
            "page_type_scope": str(page_type_scope or "").strip().lower() or None,
            **_bundle_promotion_scope_for_page_type(page_type_scope),
        },
        "plan": {"pages_total": len(plan_pages)},
        **upsert,
    }


def _is_daily_summary_like_draft_row(
    *,
    page_slug: str | None,
    page_title: str | None,
    page_entity_key: str | None,
    markdown_patch: str | None,
    semantic_diff: dict[str, Any] | None,
    gatekeeper_features: dict[str, Any] | None,
) -> bool:
    features = gatekeeper_features if isinstance(gatekeeper_features, dict) else {}
    if bool(features.get("has_daily_summary_noise")):
        return True
    daily_hits = features.get("ingestion_daily_summary_hits")
    if isinstance(daily_hits, list) and any(str(item or "").strip() for item in daily_hits):
        return True

    semantic = semantic_diff if isinstance(semantic_diff, dict) else {}
    semantic_summary = str(semantic.get("summary") or "").strip().lower()
    if "daily summary" in semantic_summary or "worklog" in semantic_summary:
        return True

    haystack = " ".join(
        [
            str(page_slug or "").strip().lower(),
            str(page_title or "").strip().lower(),
            str(page_entity_key or "").strip().lower(),
            str(markdown_patch or "").strip().lower(),
            str(semantic.get("after") or "").strip().lower(),
            str(features.get("ingestion_classification") or "").strip().lower(),
        ]
    )
    return any(keyword in haystack for keyword in _DAILY_SUMMARY_DRAFT_KEYWORDS)


def _build_project_wiki_quality_report_from_rows(
    *,
    project_id: str,
    published_pages: list[dict[str, Any]],
    open_drafts: list[dict[str, Any]],
    reviewed_pages: list[dict[str, Any]] | None = None,
    window_days: int,
    placeholder_ratio_max: float,
    daily_summary_draft_ratio_max: float,
    min_core_published: int,
) -> dict[str, Any]:
    reviewed_pages = list(reviewed_pages or [])
    pages_by_slug: dict[str, dict[str, Any]] = {}
    for row in published_pages:
        slug = _normalize_wiki_slug(str(row.get("slug") or ""), str(row.get("title") or "page"))
        if not slug:
            continue
        item = dict(row)
        item["slug"] = slug
        item["leaf"] = slug.split("/")[-1]
        pages_by_slug[slug] = item

    core_rows = [row for row in pages_by_slug.values() if str(row.get("leaf") or "") in _BOOTSTRAP_CORE_REQUIRED_LEAVES]
    core_leaves_published = {str(row.get("leaf") or "") for row in core_rows}
    core_missing_required = sorted(list(_BOOTSTRAP_CORE_REQUIRED_LEAVES - core_leaves_published))
    reviewed_core_rows: list[dict[str, Any]] = []
    for row in reviewed_pages:
        slug = _normalize_wiki_slug(str(row.get("slug") or ""), str(row.get("title") or "page"))
        if not slug:
            continue
        leaf = slug.split("/")[-1]
        if leaf not in _BOOTSTRAP_CORE_REQUIRED_LEAVES:
            continue
        item = dict(row)
        item["slug"] = slug
        item["leaf"] = leaf
        reviewed_core_rows.append(item)

    token_total = 0
    placeholder_hits_total = 0
    thin_pages: list[dict[str, Any]] = []
    schema_rows: list[dict[str, Any]] = []
    for row in core_rows:
        markdown = str(row.get("markdown") or "")
        page_type = str(row.get("page_type") or "operations")
        slug = str(row.get("slug") or "")
        schema_contract = _evaluate_wiki_schema_contract(
            markdown=markdown,
            page_type=page_type,
            slug=slug,
        )
        schema_rows.append(
            {
                "slug": slug,
                "page_type": page_type,
                "passed": bool(schema_contract.get("passed")),
                "missing_markers": list(schema_contract.get("missing_markers") or []),
                "backlinks_count": int(schema_contract.get("backlinks_count") or 0),
                "missing_frontmatter": list(schema_contract.get("missing_frontmatter") or []),
            }
        )
        words = re.findall(r"[a-zа-я0-9_]+", markdown.lower())
        token_total += len(words)
        for token in _BOOTSTRAP_PLACEHOLDER_TOKENS:
            placeholder_hits_total += markdown.lower().count(token)
        word_count = len(words)
        if word_count < 80:
            thin_pages.append(
                {
                    "slug": str(row.get("slug") or ""),
                    "title": str(row.get("title") or ""),
                    "word_count": int(word_count),
                }
            )

    placeholder_ratio = round(float(placeholder_hits_total) / float(max(1, token_total)), 4)
    schema_passed_total = len([item for item in schema_rows if bool(item.get("passed"))])
    schema_coverage_ratio = round(float(schema_passed_total) / float(max(1, len(schema_rows))), 4)
    schema_missing_samples = [item for item in schema_rows if not bool(item.get("passed"))][:10]

    open_drafts_total = len(open_drafts)
    daily_summary_open_rows = [row for row in open_drafts if bool(row.get("is_daily_summary_like"))]
    daily_summary_open_total = len(daily_summary_open_rows)
    daily_summary_open_ratio = round(float(daily_summary_open_total) / float(max(1, open_drafts_total)), 4)

    thresholds = {
        "placeholder_ratio_core_max": float(max(0.0, min(1.0, placeholder_ratio_max))),
        "daily_summary_open_draft_ratio_max": float(max(0.0, min(1.0, daily_summary_draft_ratio_max))),
        "min_core_published": int(max(1, min(50, min_core_published))),
    }

    reviewed_reason_counter: dict[str, int] = {}
    weak_family_counter: dict[str, int] = {}
    missing_signal_counter: dict[str, int] = {}
    reviewed_core_backlog: list[dict[str, Any]] = []

    def _bump(counter: dict[str, int], key: str | None) -> None:
        text = str(key or "").strip()
        if not text:
            return
        counter[text] = int(counter.get(text, 0)) + 1

    for row in reviewed_core_rows:
        page_type = str(row.get("page_type") or "operations").strip().lower() or "operations"
        metadata = row.get("metadata") if isinstance(row.get("metadata"), dict) else {}
        bootstrap_quality_gate = (
            metadata.get("bootstrap_quality_gate") if isinstance(metadata.get("bootstrap_quality_gate"), dict) else {}
        )
        reason = str(bootstrap_quality_gate.get("publish_warning") or "quality_gate").strip().lower() or "quality_gate"
        quality_score = float(bootstrap_quality_gate.get("quality_score") or 0.0)
        missing_required_markers = [
            str(item).strip()
            for item in (bootstrap_quality_gate.get("missing_required_markers") or [])
            if str(item).strip()
        ]
        placeholder_hits = [
            str(item).strip()
            for item in (bootstrap_quality_gate.get("placeholder_hits") or [])
            if str(item).strip()
        ]
        _bump(reviewed_reason_counter, reason)
        _bump(weak_family_counter, page_type)
        for marker in missing_required_markers:
            _bump(missing_signal_counter, marker)
        for hit in placeholder_hits:
            _bump(missing_signal_counter, f"placeholder:{hit}")
        reviewed_core_backlog.append(
            {
                "slug": str(row.get("slug") or ""),
                "title": str(row.get("title") or ""),
                "page_type": page_type,
                "reason": reason,
                "quality_score": quality_score,
                "missing_required_markers": missing_required_markers,
                "placeholder_hits": placeholder_hits,
            }
        )

    for item in schema_missing_samples:
        for marker in list(item.get("missing_markers") or []):
            _bump(missing_signal_counter, str(marker))
        _bump(weak_family_counter, str(item.get("page_type") or "operations"))

    checks = {
        "core_required_pages_present": bool(len(core_missing_required) == 0),
        "core_publish_coverage": bool(len(core_rows) >= int(thresholds["min_core_published"])),
        "placeholder_ratio_core": bool(placeholder_ratio <= float(thresholds["placeholder_ratio_core_max"])),
        "daily_summary_open_draft_ratio": bool(
            open_drafts_total == 0 or daily_summary_open_ratio <= float(thresholds["daily_summary_open_draft_ratio_max"])
        ),
    }
    overall_pass = all(bool(value) for value in checks.values())

    warnings: list[dict[str, Any]] = []
    if not checks["core_required_pages_present"]:
        warnings.append(
            {
                "code": "core_required_pages_missing",
                "severity": "critical",
                "missing_slugs": core_missing_required,
            }
        )
    if not checks["core_publish_coverage"]:
        warnings.append(
            {
                "code": "core_publish_coverage_low",
                "severity": "critical",
                "published_core": len(core_rows),
                "min_required": int(thresholds["min_core_published"]),
            }
        )
    if not checks["placeholder_ratio_core"]:
        warnings.append(
            {
                "code": "placeholder_ratio_core_high",
                "severity": "warning",
                "ratio": float(placeholder_ratio),
                "threshold": float(thresholds["placeholder_ratio_core_max"]),
            }
        )
    if not checks["daily_summary_open_draft_ratio"]:
        warnings.append(
            {
                "code": "daily_summary_draft_ratio_high",
                "severity": "warning",
                "ratio": float(daily_summary_open_ratio),
                "threshold": float(thresholds["daily_summary_open_draft_ratio_max"]),
                "open_drafts_total": int(open_drafts_total),
                "daily_summary_open_drafts": int(daily_summary_open_total),
            }
        )
    if thin_pages:
        warnings.append(
            {
                "code": "thin_core_pages",
                "severity": "warning",
                "count": len(thin_pages),
                "samples": thin_pages[:8],
            }
        )
    if schema_missing_samples:
        warnings.append(
            {
                "code": "schema_contract_core_incomplete",
                "severity": "warning",
                "coverage_ratio": float(schema_coverage_ratio),
                "samples": schema_missing_samples,
            }
        )
    if reviewed_core_backlog:
        warnings.append(
            {
                "code": "reviewed_core_backlog",
                "severity": "warning",
                "count": len(reviewed_core_backlog),
                "samples": reviewed_core_backlog[:8],
            }
        )

    weak_page_families = [
        {"page_type": key, "count": int(value)}
        for key, value in sorted(weak_family_counter.items(), key=lambda item: (-item[1], item[0]))[:10]
    ]
    missing_signals = [
        {"signal": key, "count": int(value)}
        for key, value in sorted(missing_signal_counter.items(), key=lambda item: (-item[1], item[0]))[:12]
    ]
    reviewed_reason_summary = [
        {"reason": key, "count": int(value)}
        for key, value in sorted(reviewed_reason_counter.items(), key=lambda item: (-item[1], item[0]))[:10]
    ]

    return {
        "project_id": project_id,
        "window_days": int(window_days),
        "generated_at": datetime.now(UTC).isoformat(),
        "quality": {
            "pass": bool(overall_pass),
            "checks": checks,
            "thresholds": thresholds,
        },
        "core_pages": {
            "required_leaves": sorted(list(_BOOTSTRAP_CORE_REQUIRED_LEAVES)),
            "published_total": len(core_rows),
            "published_slugs": sorted([str(row.get("slug") or "") for row in core_rows]),
            "reviewed_total": len(reviewed_core_rows),
            "reviewed_slugs": sorted([str(row.get("slug") or "") for row in reviewed_core_rows]),
            "missing_required_leaves": core_missing_required,
            "thin_pages": thin_pages[:25],
        },
        "content_quality": {
            "placeholder_ratio_core": float(placeholder_ratio),
            "placeholder_hits_core": int(placeholder_hits_total),
            "core_word_count_total": int(token_total),
        },
        "schema_contract": {
            "coverage_ratio_core": float(schema_coverage_ratio),
            "passed_pages": int(schema_passed_total),
            "core_pages_total": int(len(schema_rows)),
            "missing_samples": schema_missing_samples,
        },
        "draft_noise": {
            "open_drafts_total": int(open_drafts_total),
            "daily_summary_open_drafts": int(daily_summary_open_total),
            "daily_summary_open_draft_ratio": float(daily_summary_open_ratio),
            "daily_summary_samples": [
                {
                    "draft_id": str(item.get("draft_id") or ""),
                    "page_slug": str(item.get("page_slug") or ""),
                    "page_title": str(item.get("page_title") or ""),
                }
                for item in daily_summary_open_rows[:8]
            ],
        },
        "reviewed_core_backlog": reviewed_core_backlog[:25],
        "reviewed_reason_summary": reviewed_reason_summary,
        "weak_page_families": weak_page_families,
        "signals_missing": missing_signals,
        "warnings": warnings,
    }


def _build_project_wiki_richness_benchmark_from_rows(
    *,
    project_id: str,
    published_pages: list[dict[str, Any]],
    open_drafts: list[dict[str, Any]],
    reviewed_pages: list[dict[str, Any]] | None = None,
    window_days: int,
    placeholder_ratio_max: float,
    daily_summary_draft_ratio_max: float,
    min_core_published: int,
    min_contract_pass_ratio: float = 0.8,
    min_average_page_score: float = 0.72,
) -> dict[str, Any]:
    quality_report = _build_project_wiki_quality_report_from_rows(
        project_id=project_id,
        published_pages=published_pages,
        open_drafts=open_drafts,
        reviewed_pages=reviewed_pages,
        window_days=window_days,
        placeholder_ratio_max=placeholder_ratio_max,
        daily_summary_draft_ratio_max=daily_summary_draft_ratio_max,
        min_core_published=min_core_published,
    )
    pages_by_slug: dict[str, dict[str, Any]] = {}
    for row in published_pages:
        slug = _normalize_wiki_slug(str(row.get("slug") or ""), str(row.get("title") or "page"))
        if slug:
            item = dict(row)
            item["slug"] = slug
            pages_by_slug[slug] = item

    required_leaves = sorted(list(_BOOTSTRAP_CORE_REQUIRED_LEAVES))
    page_results: list[dict[str, Any]] = []
    total_score = 0.0
    contract_passed = 0
    for leaf in required_leaves:
        row = next((item for item in pages_by_slug.values() if _bootstrap_page_leaf(str(item.get("slug") or "")) == leaf), None)
        if row is None:
            page_results.append(
                {
                    "leaf": leaf,
                    "slug": None,
                    "page_type": None,
                    "published": False,
                    "passed": False,
                    "score": 0.0,
                    "reason": "missing",
                }
            )
            continue
        markdown = str(row.get("markdown") or "")
        page_type = str(row.get("page_type") or "operations")
        contract = _evaluate_bootstrap_page_contract(
            slug=str(row.get("slug") or ""),
            page_type=page_type,
            markdown=markdown,
        )
        schema = _evaluate_wiki_schema_contract(
            markdown=markdown,
            page_type=page_type,
            slug=str(row.get("slug") or ""),
        )
        words = re.findall(r"[a-zа-я0-9_]+", markdown.lower())
        placeholder_hits = sum(markdown.lower().count(token) for token in _BOOTSTRAP_PLACEHOLDER_TOKENS)
        placeholder_ratio = round(float(placeholder_hits) / float(max(1, len(words))), 4)
        section_total = max(1, len(list(contract.get("required_sections") or [])))
        section_present = len(list(contract.get("present_sections") or []))
        section_coverage = round(float(section_present) / float(section_total), 4)
        word_target = max(60, int(_WIKI_ENRICHMENT_MIN_WORDS_BY_PAGE_TYPE.get(page_type, 90)))
        word_score = min(1.0, float(len(words)) / float(word_target))
        page_score = round(
            max(
                0.0,
                min(
                    1.0,
                    0.4 * (1.0 if bool(contract.get("passed")) else 0.0)
                    + 0.2 * section_coverage
                    + 0.2 * word_score
                    + 0.2 * (1.0 - min(1.0, placeholder_ratio / 0.1)),
                ),
            ),
            4,
        )
        total_score += page_score
        if bool(contract.get("passed")):
            contract_passed += 1
        page_results.append(
            {
                "leaf": leaf,
                "slug": str(row.get("slug") or ""),
                "page_type": page_type,
                "published": True,
                "passed": bool(contract.get("passed")),
                "score": page_score,
                "word_count": len(words),
                "placeholder_ratio": float(placeholder_ratio),
                "schema_passed": bool(schema.get("passed")),
                "contract": contract,
            }
        )

    average_page_score = round(float(total_score) / float(max(1, len(page_results))), 4)
    contract_pass_ratio = round(float(contract_passed) / float(max(1, len(required_leaves))), 4)
    quality_checks = (quality_report.get("quality") or {}).get("checks") if isinstance(quality_report.get("quality"), dict) else {}
    quality_pass = bool((quality_report.get("quality") or {}).get("pass"))
    checks = {
        "core_required_pages_present": bool(quality_checks.get("core_required_pages_present")),
        "core_publish_coverage": bool(quality_checks.get("core_publish_coverage")),
        "placeholder_ratio_core": bool(quality_checks.get("placeholder_ratio_core")),
        "daily_summary_open_draft_ratio": bool(quality_checks.get("daily_summary_open_draft_ratio")),
        "page_contract_pass_ratio": bool(contract_pass_ratio >= float(max(0.0, min(1.0, min_contract_pass_ratio)))),
        "average_page_score": bool(average_page_score >= float(max(0.0, min(1.0, min_average_page_score)))),
    }
    overall_pass = bool(quality_pass and all(bool(value) for value in checks.values()))
    warnings: list[dict[str, Any]] = []
    missing_or_failed = [item for item in page_results if not bool(item.get("passed"))]
    if missing_or_failed:
        warnings.append(
            {
                "code": "page_contract_failures",
                "severity": "warning",
                "count": len(missing_or_failed),
                "samples": [
                    {
                        "leaf": item.get("leaf"),
                        "slug": item.get("slug"),
                        "reason": item.get("reason") or "contract_failed",
                        "missing_sections": list(((item.get("contract") or {}).get("missing_sections") or []))[:6],
                    }
                    for item in missing_or_failed[:8]
                ],
            }
        )
    if average_page_score < float(min_average_page_score):
        warnings.append(
            {
                "code": "average_page_score_low",
                "severity": "warning",
                "value": float(average_page_score),
                "threshold": float(min_average_page_score),
            }
        )
    if contract_pass_ratio < float(min_contract_pass_ratio):
        warnings.append(
            {
                "code": "contract_pass_ratio_low",
                "severity": "warning",
                "value": float(contract_pass_ratio),
                "threshold": float(min_contract_pass_ratio),
            }
        )
    return {
        "project_id": project_id,
        "window_days": int(window_days),
        "generated_at": datetime.now(UTC).isoformat(),
        "benchmark_version": "richness.v1",
        "pass": overall_pass,
        "checks": checks,
        "thresholds": {
            "placeholder_ratio_max": float(placeholder_ratio_max),
            "daily_summary_draft_ratio_max": float(daily_summary_draft_ratio_max),
            "min_core_published": int(min_core_published),
            "min_contract_pass_ratio": float(min_contract_pass_ratio),
            "min_average_page_score": float(min_average_page_score),
        },
        "scores": {
            "average_page_score": float(average_page_score),
            "contract_pass_ratio": float(contract_pass_ratio),
        },
        "pages": page_results,
        "warnings": warnings,
        "quality_report": quality_report,
    }


def _load_project_wiki_quality_rows(
    *,
    project_id: str,
    days: int,
) -> tuple[list[dict[str, Any]], list[dict[str, Any]], list[dict[str, Any]]]:
    published_pages: list[dict[str, Any]] = []
    open_drafts: list[dict[str, Any]] = []
    reviewed_pages: list[dict[str, Any]] = []
    cutoff = datetime.now(UTC) - timedelta(days=max(1, int(days)))

    with get_conn() as conn:
        with conn.cursor() as cur:
            has_pages = _public_table_exists(conn, "wiki_pages")
            has_versions = _public_table_exists(conn, "wiki_page_versions")
            has_drafts = _public_table_exists(conn, "wiki_draft_changes")
            has_gatekeeper = _public_table_exists(conn, "gatekeeper_decisions")

            if has_pages:
                markdown_sql = (
                    "COALESCE((SELECT pv.markdown FROM wiki_page_versions pv WHERE pv.page_id = p.id ORDER BY pv.version DESC LIMIT 1), '')"
                    if has_versions
                    else "''"
                )
                cur.execute(
                    f"""
                    SELECT
                      p.id::text,
                      p.slug,
                      p.title,
                      p.entity_key,
                      p.page_type,
                      p.status,
                      p.updated_at,
                      {markdown_sql} AS markdown,
                      p.metadata
                    FROM wiki_pages p
                    WHERE p.project_id = %s
                      AND p.status IN ('published', 'reviewed')
                    ORDER BY p.updated_at DESC
                    """,
                    (project_id,),
                )
                for row in (cur.fetchall() or []):
                    item = {
                        "id": str(row[0] or ""),
                        "slug": str(row[1] or ""),
                        "title": str(row[2] or ""),
                        "entity_key": str(row[3] or ""),
                        "page_type": str(row[4] or ""),
                        "status": str(row[5] or ""),
                        "updated_at": row[6].isoformat() if isinstance(row[6], datetime) else None,
                        "markdown": str(row[7] or ""),
                        "metadata": row[8] if isinstance(row[8], dict) else {},
                    }
                    if str(row[5] or "") == "reviewed":
                        reviewed_pages.append(item)
                    else:
                        published_pages.append(item)

            if has_drafts:
                gatekeeper_join_sql = (
                    "LEFT JOIN gatekeeper_decisions g ON g.claim_id = d.claim_id"
                    if has_gatekeeper
                    else ""
                )
                gatekeeper_features_sql = "g.features" if has_gatekeeper else "'{}'::jsonb"
                cur.execute(
                    f"""
                    SELECT
                      d.id::text,
                      d.status,
                      d.markdown_patch,
                      d.semantic_diff,
                      p.slug,
                      p.title,
                      p.entity_key,
                      {gatekeeper_features_sql}
                    FROM wiki_draft_changes d
                    LEFT JOIN wiki_pages p ON p.id = d.page_id
                    {gatekeeper_join_sql}
                    WHERE d.project_id = %s
                      AND d.status IN ('pending_review', 'blocked_conflict')
                      AND d.created_at >= %s
                    ORDER BY d.created_at DESC
                    LIMIT 10000
                    """,
                    (project_id, cutoff),
                )
                for row in (cur.fetchall() or []):
                    semantic_diff = row[3] if isinstance(row[3], dict) else {}
                    gatekeeper_features = row[7] if isinstance(row[7], dict) else {}
                    open_drafts.append(
                        {
                            "draft_id": str(row[0] or ""),
                            "status": str(row[1] or ""),
                            "markdown_patch": str(row[2] or ""),
                            "semantic_diff": semantic_diff,
                            "page_slug": str(row[4] or ""),
                            "page_title": str(row[5] or ""),
                            "page_entity_key": str(row[6] or ""),
                            "gatekeeper_features": gatekeeper_features,
                            "is_daily_summary_like": _is_daily_summary_like_draft_row(
                                page_slug=str(row[4] or ""),
                                page_title=str(row[5] or ""),
                                page_entity_key=str(row[6] or ""),
                                markdown_patch=str(row[2] or ""),
                                semantic_diff=semantic_diff,
                                gatekeeper_features=gatekeeper_features,
                            ),
                        }
                    )
    return published_pages, open_drafts, reviewed_pages


def _build_project_wiki_quality_report(
    *,
    project_id: str,
    days: int,
    placeholder_ratio_max: float,
    daily_summary_draft_ratio_max: float,
    min_core_published: int,
) -> dict[str, Any]:
    published_pages, open_drafts, reviewed_pages = _load_project_wiki_quality_rows(
        project_id=project_id,
        days=days,
    )

    return _build_project_wiki_quality_report_from_rows(
        project_id=project_id,
        published_pages=published_pages,
        open_drafts=open_drafts,
        reviewed_pages=reviewed_pages,
        window_days=int(max(1, days)),
        placeholder_ratio_max=float(placeholder_ratio_max),
        daily_summary_draft_ratio_max=float(daily_summary_draft_ratio_max),
        min_core_published=int(min_core_published),
    )


def _build_project_wiki_richness_benchmark(
    *,
    project_id: str,
    days: int,
    placeholder_ratio_max: float,
    daily_summary_draft_ratio_max: float,
    min_core_published: int,
    min_contract_pass_ratio: float,
    min_average_page_score: float,
) -> dict[str, Any]:
    published_pages, open_drafts, reviewed_pages = _load_project_wiki_quality_rows(
        project_id=project_id,
        days=days,
    )
    return _build_project_wiki_richness_benchmark_from_rows(
        project_id=project_id,
        published_pages=published_pages,
        open_drafts=open_drafts,
        reviewed_pages=reviewed_pages,
        window_days=int(max(1, days)),
        placeholder_ratio_max=float(placeholder_ratio_max),
        daily_summary_draft_ratio_max=float(daily_summary_draft_ratio_max),
        min_core_published=int(min_core_published),
        min_contract_pass_ratio=float(min_contract_pass_ratio),
        min_average_page_score=float(min_average_page_score),
    )


def _build_adoption_knowledge_gap_report(
    *,
    project_id: str,
    days: int,
    max_items_per_bucket: int = 8,
) -> dict[str, Any]:
    published_pages, open_drafts, reviewed_pages = _load_project_wiki_quality_rows(project_id=project_id, days=days)
    quality_report = _build_project_wiki_quality_report_from_rows(
        project_id=project_id,
        published_pages=published_pages,
        open_drafts=open_drafts,
        reviewed_pages=reviewed_pages,
        window_days=int(max(1, days)),
        placeholder_ratio_max=0.10,
        daily_summary_draft_ratio_max=0.20,
        min_core_published=6,
    )
    benchmark = _build_project_wiki_richness_benchmark_from_rows(
        project_id=project_id,
        published_pages=published_pages,
        open_drafts=open_drafts,
        reviewed_pages=reviewed_pages,
        window_days=int(max(1, days)),
        placeholder_ratio_max=0.10,
        daily_summary_draft_ratio_max=0.20,
        min_core_published=6,
        min_contract_pass_ratio=0.80,
        min_average_page_score=0.72,
    )
    pipeline = get_adoption_pipeline_visibility(project_id=project_id, days=days)

    candidate_bundles: list[dict[str, Any]] = []
    reflection_rows: list[dict[str, Any]] = []
    with get_conn() as conn:
        with conn.cursor() as cur:
            if _wiki_feature_table_exists(cur, "public.evidence_bundles"):
                cur.execute(
                    """
                    SELECT
                      bundle_key,
                      bundle_type,
                      suggested_page_type,
                      entity_key,
                      bundle_status,
                      support_count,
                      quality_score,
                      metadata
                    FROM evidence_bundles
                    WHERE project_id = %s
                      AND bundle_status IN ('candidate', 'observed')
                    ORDER BY quality_score DESC, support_count DESC, last_seen_at DESC NULLS LAST
                    LIMIT %s
                    """,
                    (project_id, max(10, int(max_items_per_bucket) * 4)),
                )
                for row in (cur.fetchall() or []):
                    candidate_bundles.append(
                        {
                            "bundle_key": str(row[0] or ""),
                            "bundle_type": str(row[1] or ""),
                            "suggested_page_type": str(row[2] or ""),
                            "entity_key": str(row[3] or ""),
                            "bundle_status": str(row[4] or ""),
                            "support_count": int(row[5] or 0),
                            "quality_score": float(row[6] or 0.0),
                            "metadata": row[7] if isinstance(row[7], dict) else {},
                        }
                    )
            if _public_table_exists(conn, "events"):
                cutoff = datetime.now(UTC) - timedelta(days=max(1, int(days)))
                cur.execute(
                    """
                    SELECT payload, observed_at
                    FROM events
                    WHERE project_id = %s
                      AND event_type = 'system_signal'
                      AND observed_at >= %s
                      AND COALESCE(payload->>'source_system', '') = 'agent_reflection'
                    ORDER BY observed_at DESC
                    LIMIT %s
                    """,
                    (project_id, cutoff, max(20, int(max_items_per_bucket) * 12)),
                )
                for row in (cur.fetchall() or []):
                    payload = row[0] if isinstance(row[0], dict) else {}
                    reflection = payload.get("reflection") if isinstance(payload.get("reflection"), dict) else {}
                    reflection_rows.append(
                        {
                            "reflection": reflection,
                            "observed_at": row[1].isoformat() if isinstance(row[1], datetime) else None,
                        }
                    )

    question_counts: dict[str, int] = {}
    escalation_counts: dict[str, int] = {}
    for item in reflection_rows:
        reflection = item.get("reflection") if isinstance(item.get("reflection"), dict) else {}
        for question in reflection.get("follow_up_questions") or []:
            text = str(question or "").strip()
            if not text:
                continue
            question_counts[text] = int(question_counts.get(text, 0)) + 1
        for escalation in reflection.get("escalations") or []:
            text = str(escalation or "").strip()
            if not text:
                continue
            escalation_counts[text] = int(escalation_counts.get(text, 0)) + 1

    page_failures = [
        {
            "leaf": item.get("leaf"),
            "slug": item.get("slug"),
            "score": item.get("score"),
            "missing_sections": list(((item.get("contract") or {}).get("missing_sections") or []))[:6],
        }
        for item in (benchmark.get("pages") or [])
        if isinstance(item, dict) and not bool(item.get("passed"))
    ][: max_items_per_bucket]
    candidate_gap_items = [
        {
            "bundle_key": item.get("bundle_key"),
            "bundle_type": item.get("bundle_type"),
            "suggested_page_type": item.get("suggested_page_type"),
            "entity_key": item.get("entity_key"),
            "bundle_status": item.get("bundle_status"),
            "support_count": item.get("support_count"),
            "quality_score": item.get("quality_score"),
        }
        for item in candidate_bundles[:max_items_per_bucket]
    ]
    unresolved_questions = [
        {"question": text, "count": count}
        for text, count in sorted(question_counts.items(), key=lambda item: (-item[1], item[0]))[:max_items_per_bucket]
    ]
    repeated_escalations = [
        {"escalation": text, "count": count}
        for text, count in sorted(escalation_counts.items(), key=lambda item: (-item[1], item[0]))[:max_items_per_bucket]
    ]
    conversions = (pipeline.get("conversions") if isinstance(pipeline.get("conversions"), dict) else {})
    bottlenecks = {
        "events_to_claims": float(conversions.get("events_to_claims") or 0.0) if conversions.get("events_to_claims") is not None else None,
        "claims_to_drafts": float(conversions.get("claims_to_drafts") or 0.0) if conversions.get("claims_to_drafts") is not None else None,
        "drafts_to_pages": float(conversions.get("drafts_to_pages") or 0.0) if conversions.get("drafts_to_pages") is not None else None,
    }
    suggestions: list[dict[str, Any]] = []
    if page_failures:
        suggestions.append(
            {
                "action": "enrich_core_pages",
                "reason": "Core wiki pages exist but are still structurally incomplete or shallow.",
                "count": len(page_failures),
            }
        )
    if candidate_gap_items:
        suggestions.append(
            {
                "action": "promote_candidate_bundles",
                "reason": "Durable evidence bundles exist but are not yet reflected in published pages.",
                "count": len(candidate_gap_items),
            }
        )
    if unresolved_questions:
        suggestions.append(
            {
                "action": "answer_repeated_agent_questions",
                "reason": "Repeated follow-up questions from agent reflections indicate missing reusable documentation.",
                "count": len(unresolved_questions),
            }
        )
    if repeated_escalations:
        suggestions.append(
            {
                "action": "codify_escalation_patterns",
                "reason": "Repeated escalations should become explicit runbooks or policy pages.",
                "count": len(repeated_escalations),
            }
        )
    return {
        "project_id": project_id,
        "window_days": int(days),
        "generated_at": datetime.now(UTC).isoformat(),
        "summary": {
            "page_failures": len(page_failures),
            "candidate_bundles": len(candidate_gap_items),
            "unresolved_questions": len(unresolved_questions),
            "repeated_escalations": len(repeated_escalations),
        },
        "pipeline_bottlenecks": bottlenecks,
        "page_enrichment_gaps": page_failures,
        "candidate_knowledge_bundles": candidate_gap_items,
        "unresolved_agent_questions": unresolved_questions,
        "repeated_escalations": repeated_escalations,
        "suggestions": suggestions,
        "quality_report": {
            "pass": bool((quality_report.get("quality") or {}).get("pass")),
            "checks": (quality_report.get("quality") or {}).get("checks"),
        },
        "richness_benchmark": {
            "pass": bool(benchmark.get("pass")),
            "checks": benchmark.get("checks"),
            "scores": benchmark.get("scores"),
        },
    }


def _build_human_guided_synthesis_prompts(
    *,
    project_id: str,
    days: int,
    max_items: int,
) -> dict[str, Any]:
    gap_report = _build_adoption_knowledge_gap_report(
        project_id=project_id,
        days=days,
        max_items_per_bucket=max_items,
    )
    prompts: list[dict[str, Any]] = []
    prompt_type_counts: dict[str, int] = {}

    def _append_prompt(payload: dict[str, Any]) -> None:
        prompt_type = str(payload.get("prompt_type") or "unknown").strip().lower() or "unknown"
        payload["prompt_id"] = payload.get("prompt_id") or f"{prompt_type}:{len(prompts) + 1}"
        prompts.append(payload)
        prompt_type_counts[prompt_type] = int(prompt_type_counts.get(prompt_type, 0)) + 1

    for item in (gap_report.get("candidate_knowledge_bundles") or [])[:max_items]:
        if not isinstance(item, dict):
            continue
        bundle_type = str(item.get("bundle_type") or "knowledge")
        page_type = str(item.get("suggested_page_type") or "operations")
        entity_key = str(item.get("entity_key") or "this area")
        taxonomy_class = "procedural" if page_type in {"process", "runbook", "policy"} else "semantic"
        expected_sections = (
            ["purpose", "trigger", "inputs", "steps", "exceptions", "escalation", "verification"]
            if taxonomy_class == "procedural"
            else ["summary", "rules", "constraints", "source_of_truth", "owner"]
        )
        _append_prompt(
            {
                "prompt_type": "bundle_follow_up",
                "target_kind": "agent_or_operator",
                "bundle_key": item.get("bundle_key"),
                "entity_key": entity_key,
                "page_type": page_type,
                "knowledge_taxonomy_class": taxonomy_class,
                "normalized_target_type": (
                    "process_playbook"
                    if taxonomy_class == "procedural"
                    else ("agent_profile" if page_type == "agent_profile" else "fact")
                ),
                "priority": "high" if str(item.get("bundle_status") or "") == "ready" else "medium",
                "why_now": (
                    f"Bundle `{item.get('bundle_key')}` already has support_count={int(item.get('support_count') or 0)} "
                    f"but still needs structured synthesis before it becomes a reliable wiki page."
                ),
                "question": f"What is the durable rule or repeatable procedure for {entity_key}?",
                "follow_up": [
                    f"What trigger starts the {bundle_type} workflow?",
                    "What exact action should the agent take?",
                    "What escalation or approval rule applies?",
                    "What source of truth should be linked on the wiki page?",
                ],
                "expected_sections": expected_sections,
            }
        )

    for item in (gap_report.get("unresolved_agent_questions") or [])[:max_items]:
        if not isinstance(item, dict):
            continue
        question = str(item.get("question") or "").strip()
        if not question:
            continue
        _append_prompt(
            {
                "prompt_type": "repeated_question",
                "target_kind": "operator",
                "knowledge_taxonomy_class": "semantic",
                "normalized_target_type": "fact",
                "question": question,
                "why_now": (
                    f"Agents asked this {int(item.get('count') or 0)} times, which suggests a missing stable answer "
                    "in the published wiki."
                ),
                "follow_up": [
                    "Should this answer become a published wiki page or section update?",
                    "Is the answer stable across cases or only temporary?",
                    "Which source or owner confirms the answer?",
                ],
                "expected_sections": ["answer", "scope", "owner", "source_of_truth"],
                "repeat_count": int(item.get("count") or 0),
            }
        )

    for item in (gap_report.get("page_enrichment_gaps") or [])[:max_items]:
        if not isinstance(item, dict):
            continue
        missing_sections = [str(section).strip() for section in (item.get("missing_sections") or []) if str(section).strip()]
        _append_prompt(
            {
                "prompt_type": "page_enrichment",
                "target_kind": "operator",
                "page_slug": item.get("slug"),
                "knowledge_taxonomy_class": "semantic",
                "normalized_target_type": "fact",
                "question": f"What concrete details are missing to make `{item.get('leaf')}` production-useful?",
                "why_now": (
                    f"Page `{item.get('slug')}` is below the richness threshold with score={float(item.get('score') or 0.0):.2f}."
                ),
                "follow_up": missing_sections[:6] or ["Add durable facts, process steps, and source-backed details."],
                "expected_sections": missing_sections[:6] or ["durable_facts", "process_steps", "source_backing"],
                "score": item.get("score"),
            }
        )

    limited_prompts = prompts[: max(1, min(100, max_items * 3))]
    return {
        "project_id": project_id,
        "window_days": int(days),
        "generated_at": datetime.now(UTC).isoformat(),
        "prompts": limited_prompts,
        "summary": {
            "prompts_total": len(limited_prompts),
            "source": "knowledge_gap_analysis",
            "by_type": {
                key: int(value)
                for key, value in sorted(prompt_type_counts.items(), key=lambda item: item[0])
            },
        },
    }


def _build_knowledge_gap_task_specs(
    *,
    gap_report: dict[str, Any],
    created_by: str,
    assignee: str | None,
    limit_per_kind: int,
    include_candidate_bundles: bool,
    include_page_enrichment_gaps: bool,
    include_unresolved_questions: bool,
    include_repeated_escalations: bool,
) -> list[dict[str, Any]]:
    project_id = str(gap_report.get("project_id") or "").strip()
    specs: list[dict[str, Any]] = []

    def _append(spec: dict[str, Any]) -> None:
        gap_key = str(spec.get("gap_key") or "").strip()
        if not gap_key:
            return
        specs.append(
            {
                "project_id": project_id,
                "title": str(spec.get("title") or "").strip(),
                "description": str(spec.get("description") or "").strip() or None,
                "status": "todo",
                "priority": str(spec.get("priority") or "normal").strip().lower() or "normal",
                "source": "system",
                "assignee": str(assignee or "").strip() or None,
                "entity_key": str(spec.get("entity_key") or "").strip() or None,
                "category": "knowledge_gap",
                "created_by": created_by,
                "updated_by": created_by,
                "metadata": {
                    "knowledge_gap_key": gap_key,
                    "knowledge_gap_kind": str(spec.get("kind") or "").strip(),
                    "knowledge_gap_payload": spec.get("payload") if isinstance(spec.get("payload"), dict) else {},
                },
            }
        )

    if include_candidate_bundles:
        for item in (gap_report.get("candidate_knowledge_bundles") or [])[:limit_per_kind]:
            if not isinstance(item, dict):
                continue
            bundle_key = str(item.get("bundle_key") or "").strip()
            if not bundle_key:
                continue
            suggested = str(item.get("suggested_page_type") or "operations").strip() or "operations"
            entity_key = str(item.get("entity_key") or "").strip() or None
            _append(
                {
                    "gap_key": f"candidate_bundle:{bundle_key}",
                    "kind": "candidate_bundle",
                    "title": f"Promote durable knowledge bundle: {bundle_key}",
                    "description": (
                        f"Bundle `{bundle_key}` has support_count={int(item.get('support_count') or 0)} "
                        f"and should be compiled into `{suggested}` documentation."
                    ),
                    "priority": "high" if str(item.get("bundle_status") or "") == "ready" else "normal",
                    "entity_key": entity_key,
                    "payload": item,
                }
            )

    if include_page_enrichment_gaps:
        for item in (gap_report.get("page_enrichment_gaps") or [])[:limit_per_kind]:
            if not isinstance(item, dict):
                continue
            slug = str(item.get("slug") or "").strip()
            if not slug:
                continue
            missing = [str(section).strip() for section in (item.get("missing_sections") or []) if str(section).strip()]
            _append(
                {
                    "gap_key": f"page_enrichment:{slug}",
                    "kind": "page_enrichment",
                    "title": f"Enrich wiki page: {slug}",
                    "description": (
                        f"Page `{slug}` is below richness threshold "
                        f"(score={float(item.get('score') or 0.0):.2f}). "
                        f"Missing sections: {', '.join(missing[:6]) or 'durable facts'}."
                    ),
                    "priority": "high",
                    "entity_key": slug,
                    "payload": item,
                }
            )

    if include_unresolved_questions:
        for item in (gap_report.get("unresolved_agent_questions") or [])[:limit_per_kind]:
            if not isinstance(item, dict):
                continue
            question = str(item.get("question") or "").strip()
            if not question:
                continue
            question_key = _slugify_segment(question)[:120] or "question"
            _append(
                {
                    "gap_key": f"unresolved_question:{question_key}",
                    "kind": "unresolved_question",
                    "title": f"Answer repeated agent question",
                    "description": (
                        f"Agents asked this question {int(item.get('count') or 0)} times: {question}"
                    ),
                    "priority": "normal",
                    "entity_key": question_key,
                    "payload": item,
                }
            )

    if include_repeated_escalations:
        for item in (gap_report.get("repeated_escalations") or [])[:limit_per_kind]:
            if not isinstance(item, dict):
                continue
            escalation = str(item.get("escalation") or "").strip()
            if not escalation:
                continue
            escalation_key = _slugify_segment(escalation)[:120] or "escalation"
            _append(
                {
                    "gap_key": f"repeated_escalation:{escalation_key}",
                    "kind": "repeated_escalation",
                    "title": "Codify repeated escalation pattern",
                    "description": (
                        f"Escalation repeated {int(item.get('count') or 0)} times: {escalation}"
                    ),
                    "priority": "high",
                    "entity_key": escalation_key,
                    "payload": item,
                }
            )

    return specs


def _upsert_knowledge_gap_tasks(
    conn,
    *,
    project_id: str,
    specs: list[dict[str, Any]],
) -> dict[str, Any]:
    created: list[dict[str, Any]] = []
    updated: list[dict[str, Any]] = []
    skipped: list[dict[str, Any]] = []
    with conn.cursor() as cur:
        for spec in specs:
            metadata = spec.get("metadata") if isinstance(spec.get("metadata"), dict) else {}
            gap_key = str(metadata.get("knowledge_gap_key") or "").strip()
            if not gap_key:
                continue
            cur.execute(
                """
                SELECT
                  id::text,
                  title,
                  description,
                  status,
                  priority,
                  assignee,
                  entity_key,
                  category,
                  metadata,
                  created_by,
                  updated_by,
                  created_at,
                  updated_at
                FROM synapse_tasks
                WHERE project_id = %s
                  AND COALESCE(metadata->>'knowledge_gap_key', '') = %s
                ORDER BY
                  CASE status
                    WHEN 'todo' THEN 0
                    WHEN 'in_progress' THEN 1
                    WHEN 'blocked' THEN 2
                    WHEN 'done' THEN 3
                    ELSE 4
                  END,
                  updated_at DESC
                LIMIT 1
                """,
                (project_id, gap_key),
            )
            row = cur.fetchone()
            if row is None:
                task_id = uuid4()
                cur.execute(
                    """
                    INSERT INTO synapse_tasks (
                      id, project_id, title, description, status, priority, source, assignee,
                      entity_key, category, due_at, metadata, created_by, updated_by, created_at, updated_at
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NULL, %s, %s, %s, NOW(), NOW())
                    """,
                    (
                        task_id,
                        project_id,
                        spec["title"],
                        spec.get("description"),
                        spec.get("status") or "todo",
                        spec.get("priority") or "normal",
                        spec.get("source") or "system",
                        spec.get("assignee"),
                        spec.get("entity_key"),
                        spec.get("category"),
                        Jsonb(metadata),
                        spec.get("created_by"),
                        spec.get("updated_by") or spec.get("created_by"),
                    ),
                )
                _insert_task_event(
                    cur,
                    task_id=task_id,
                    project_id=project_id,
                    event_type="created",
                    actor=str(spec.get("created_by") or "system"),
                    payload={"reason": "knowledge_gap_sync", "knowledge_gap_key": gap_key},
                )
                created.append({"task_id": str(task_id), "knowledge_gap_key": gap_key, "title": spec["title"]})
                continue

            existing = _serialize_task_row(row)
            if str(existing.get("status") or "") not in _TASK_ACTIVE_STATUSES:
                skipped.append(
                    {
                        "task_id": str(existing.get("id") or ""),
                        "knowledge_gap_key": gap_key,
                        "reason": f"existing_task_closed:{existing.get('status')}",
                    }
                )
                continue

            changed: dict[str, Any] = {}
            for key in ("title", "description", "priority", "assignee", "entity_key", "category"):
                if existing.get(key) != spec.get(key):
                    changed[key] = {"from": existing.get(key), "to": spec.get(key)}
            if existing.get("metadata") != metadata:
                changed["metadata"] = {"from": existing.get("metadata"), "to": metadata}
            if not changed:
                skipped.append(
                    {
                        "task_id": str(existing.get("id") or ""),
                        "knowledge_gap_key": gap_key,
                        "reason": "no_change",
                    }
                )
                continue
            cur.execute(
                """
                UPDATE synapse_tasks
                SET title = %s,
                    description = %s,
                    priority = %s,
                    assignee = %s,
                    entity_key = %s,
                    category = %s,
                    metadata = %s,
                    updated_by = %s,
                    updated_at = NOW()
                WHERE id = %s
                  AND project_id = %s
                """,
                (
                    spec["title"],
                    spec.get("description"),
                    spec.get("priority") or "normal",
                    spec.get("assignee"),
                    spec.get("entity_key"),
                    spec.get("category"),
                    Jsonb(metadata),
                    spec.get("updated_by") or spec.get("created_by"),
                    UUID(str(existing.get("id"))),
                    project_id,
                ),
            )
            _insert_task_event(
                cur,
                task_id=UUID(str(existing.get("id"))),
                project_id=project_id,
                event_type="updated",
                actor=str(spec.get("updated_by") or spec.get("created_by") or "system"),
                payload={"reason": "knowledge_gap_sync", "changes": changed, "knowledge_gap_key": gap_key},
            )
            updated.append({"task_id": str(existing.get("id") or ""), "knowledge_gap_key": gap_key, "title": spec["title"]})
    return {
        "created": created,
        "updated": updated,
        "skipped": skipped,
        "summary": {
            "created": len(created),
            "updated": len(updated),
            "skipped": len(skipped),
        },
    }


def _build_adoption_signal_noise_audit(
    *,
    project_id: str,
    days: int,
    max_items_per_bucket: int = 8,
) -> dict[str, Any]:
    pipeline = get_adoption_pipeline_visibility(project_id=project_id, days=days)
    quality_report = _build_project_wiki_quality_report(
        project_id=project_id,
        days=int(days),
        placeholder_ratio_max=0.10,
        daily_summary_draft_ratio_max=0.20,
        min_core_published=6,
    )
    richness_benchmark = _build_project_wiki_richness_benchmark(
        project_id=project_id,
        days=int(days),
        placeholder_ratio_max=0.10,
        daily_summary_draft_ratio_max=0.20,
        min_core_published=6,
        min_contract_pass_ratio=0.80,
        min_average_page_score=0.72,
    )
    gap_report = _build_adoption_knowledge_gap_report(
        project_id=project_id,
        days=int(days),
        max_items_per_bucket=max_items_per_bucket,
    )
    rejection_diagnostics = get_adoption_rejection_diagnostics(
        project_id=project_id,
        days=int(days),
        sample_limit=min(8, max(3, int(max_items_per_bucket))),
    )

    bundle_status_counts: dict[str, int] = {}
    bundle_taxonomy_counts: dict[str, int] = {}
    bundle_target_type_counts: dict[str, int] = {}
    page_type_publish_counts: dict[str, int] = {}
    page_type_reviewed_counts: dict[str, int] = {}

    with get_conn() as conn:
        with conn.cursor() as cur:
            if _wiki_feature_table_exists(cur, "public.evidence_bundles"):
                cur.execute(
                    """
                    SELECT
                      bundle_status,
                      metadata->>'knowledge_taxonomy_class',
                      metadata->>'normalized_target_type',
                      COUNT(*)::bigint
                    FROM evidence_bundles
                    WHERE project_id = %s
                    GROUP BY 1, 2, 3
                    """,
                    (project_id,),
                )
                for row in cur.fetchall() or []:
                    status_key = str(row[0] or "unknown").strip().lower() or "unknown"
                    taxonomy_key = str(row[1] or "unknown").strip().lower() or "unknown"
                    target_key = str(row[2] or "unknown").strip().lower() or "unknown"
                    count = int(row[3] or 0)
                    bundle_status_counts[status_key] = int(bundle_status_counts.get(status_key, 0)) + count
                    bundle_taxonomy_counts[taxonomy_key] = int(bundle_taxonomy_counts.get(taxonomy_key, 0)) + count
                    bundle_target_type_counts[target_key] = int(bundle_target_type_counts.get(target_key, 0)) + count
            if _public_table_exists(conn, "wiki_pages"):
                cur.execute(
                    """
                    SELECT page_type, status, COUNT(*)::bigint
                    FROM wiki_pages
                    WHERE project_id = %s
                      AND status IN ('published', 'reviewed')
                    GROUP BY 1, 2
                    """,
                    (project_id,),
                )
                for row in cur.fetchall() or []:
                    page_type = str(row[0] or "operations").strip().lower() or "operations"
                    status = str(row[1] or "").strip().lower()
                    count = int(row[2] or 0)
                    if status == "published":
                        page_type_publish_counts[page_type] = int(page_type_publish_counts.get(page_type, 0)) + count
                    elif status == "reviewed":
                        page_type_reviewed_counts[page_type] = int(page_type_reviewed_counts.get(page_type, 0)) + count

    def _top(counter: dict[str, int], key_name: str, *, limit: int = 8) -> list[dict[str, Any]]:
        return [
            {key_name: key, "count": int(value)}
            for key, value in sorted(counter.items(), key=lambda item: (-item[1], item[0]))[:limit]
        ]

    accepted = int((pipeline.get("pipeline") or {}).get("accepted") or 0)
    rejected_event_like = int(pipeline.get("rejected_event_like") or 0)
    total_bundles = sum(bundle_status_counts.values())
    ready_bundles = int(bundle_status_counts.get("ready", 0))
    published_total = sum(page_type_publish_counts.values())
    reviewed_total = sum(page_type_reviewed_counts.values())

    return {
        "project_id": project_id,
        "window_days": int(days),
        "generated_at": datetime.now(UTC).isoformat(),
        "summary": {
            "evidence_rejected_pct": round(float(rejected_event_like) / float(max(1, accepted)), 4),
            "bundle_promotion_ratio": round(float(ready_bundles) / float(max(1, total_bundles)), 4),
            "published_pages_total": int(published_total),
            "reviewed_pages_total": int(reviewed_total),
            "placeholder_ratio_core": float((quality_report.get("content_quality") or {}).get("placeholder_ratio_core") or 0.0),
            "quality_pass": bool((quality_report.get("quality") or {}).get("pass")),
            "richness_pass": bool(richness_benchmark.get("pass")),
        },
        "pipeline": {
            "stages": pipeline.get("stages"),
            "conversions": pipeline.get("conversions"),
            "signal_noise_ratio": pipeline.get("signal_noise_ratio"),
            "extraction": pipeline.get("extraction"),
            "warnings": pipeline.get("warnings"),
            "bottleneck": pipeline.get("bottleneck"),
        },
        "bundles": {
            "total": int(total_bundles),
            "by_status": _top(bundle_status_counts, "status", limit=12),
            "by_taxonomy_class": _top(bundle_taxonomy_counts, "knowledge_taxonomy_class", limit=12),
            "by_target_type": _top(bundle_target_type_counts, "normalized_target_type", limit=12),
        },
        "publish_mix": {
            "published_by_page_type": _top(page_type_publish_counts, "page_type", limit=12),
            "reviewed_by_page_type": _top(page_type_reviewed_counts, "page_type", limit=12),
        },
        "quality": {
            "report": {
                "pass": bool((quality_report.get("quality") or {}).get("pass")),
                "checks": (quality_report.get("quality") or {}).get("checks"),
                "weak_page_families": quality_report.get("weak_page_families"),
                "signals_missing": quality_report.get("signals_missing"),
                "reviewed_core_backlog": quality_report.get("reviewed_core_backlog"),
            },
            "richness_benchmark": {
                "pass": bool(richness_benchmark.get("pass")),
                "checks": richness_benchmark.get("checks"),
                "scores": richness_benchmark.get("scores"),
            },
        },
        "top_noisy_source_families": {
            "source_types": ((rejection_diagnostics.get("top_blocked_patterns") or {}).get("source_types") or [])[:8],
            "source_systems": ((rejection_diagnostics.get("top_blocked_patterns") or {}).get("source_systems") or [])[:8],
            "tool_names": ((rejection_diagnostics.get("top_blocked_patterns") or {}).get("tool_names") or [])[:8],
            "drop_reasons": (rejection_diagnostics.get("top_preclaim_drop_reasons") or [])[:8],
        },
        "knowledge_gaps": {
            "candidate_knowledge_bundles": (gap_report.get("candidate_knowledge_bundles") or [])[:max_items_per_bucket],
            "page_enrichment_gaps": (gap_report.get("page_enrichment_gaps") or [])[:max_items_per_bucket],
            "unresolved_agent_questions": (gap_report.get("unresolved_agent_questions") or [])[:max_items_per_bucket],
        },
    }


def _list_adoption_safe_mode_audit_events(
    *,
    project_id: str,
    days: int,
    limit: int = 12,
) -> list[dict[str, Any]]:
    since = datetime.now(UTC) - timedelta(days=max(1, int(days)))
    rows: list[tuple[Any, ...]] = []
    with get_conn() as conn:
        with conn.cursor() as cur:
            if not _wiki_feature_table_exists(cur, "public.gatekeeper_calibration_queue_control_events"):
                return []
            cur.execute(
                """
                SELECT
                  id,
                  action,
                  actor,
                  reason,
                  payload,
                  created_at
                FROM gatekeeper_calibration_queue_control_events
                WHERE project_id = %s
                  AND created_at >= %s
                  AND action = ANY(%s)
                ORDER BY created_at DESC, id DESC
                LIMIT %s
                """,
                (
                    project_id,
                    since,
                    ["adoption_safe_mode_recommended", "adoption_safe_mode_applied"],
                    max(1, min(100, int(limit))),
                ),
            )
            rows = cur.fetchall() or []
    return [
        {
            "id": int(row[0]),
            "action": str(row[1] or ""),
            "actor": str(row[2] or ""),
            "reason": str(row[3] or "") or None,
            "payload": row[4] if isinstance(row[4], dict) else {},
            "created_at": row[5].isoformat() if row[5] is not None else None,
        }
        for row in rows
    ]


def _build_adoption_signal_noise_stability_monitor(
    *,
    project_id: str,
    days: int,
    max_items_per_bucket: int = 8,
) -> dict[str, Any]:
    pipeline = get_adoption_pipeline_visibility(project_id=project_id, days=days)
    audit = _build_adoption_signal_noise_audit(
        project_id=project_id,
        days=days,
        max_items_per_bucket=max_items_per_bucket,
    )
    recent_safe_mode_events = _list_adoption_safe_mode_audit_events(
        project_id=project_id,
        days=max(days, 14),
        limit=max(6, max_items_per_bucket),
    )

    warnings = list(pipeline.get("warnings") or []) if isinstance(pipeline.get("warnings"), list) else []
    derived_alerts: list[dict[str, Any]] = []
    summary = audit.get("summary") if isinstance(audit.get("summary"), dict) else {}
    bundles = audit.get("bundles") if isinstance(audit.get("bundles"), dict) else {}
    quality = audit.get("quality") if isinstance(audit.get("quality"), dict) else {}
    quality_report = quality.get("report") if isinstance(quality.get("report"), dict) else {}
    richness = quality.get("richness_benchmark") if isinstance(quality.get("richness_benchmark"), dict) else {}
    bundle_status_rows = bundles.get("by_status") if isinstance(bundles.get("by_status"), list) else []
    candidate_bundle_total = sum(
        int(item.get("count") or 0)
        for item in bundle_status_rows
        if isinstance(item, dict) and str(item.get("status") or "") in {"candidate", "observed"}
    )
    bundle_promotion_ratio = float(summary.get("bundle_promotion_ratio") or 0.0)
    rejected_pct = float(summary.get("evidence_rejected_pct") or 0.0)
    placeholder_ratio = float(summary.get("placeholder_ratio_core") or 0.0)

    if rejected_pct >= 0.9:
        derived_alerts.append(
            {
                "code": "evidence_rejected_pct_high",
                "severity": "critical",
                "message": "Most incoming evidence is being rejected before durable promotion.",
                "value": rejected_pct,
                "threshold": 0.9,
            }
        )
    elif rejected_pct >= 0.75:
        derived_alerts.append(
            {
                "code": "evidence_rejected_pct_watch",
                "severity": "warning",
                "message": "Evidence rejection is high; useful knowledge may be over-filtered.",
                "value": rejected_pct,
                "threshold": 0.75,
            }
        )
    if candidate_bundle_total >= 5 and bundle_promotion_ratio <= 0.15:
        derived_alerts.append(
            {
                "code": "bundle_promotion_backlog",
                "severity": "warning" if candidate_bundle_total < 10 else "critical",
                "message": "Durable candidate bundles are accumulating faster than they reach ready/published state.",
                "candidate_bundles": int(candidate_bundle_total),
                "bundle_promotion_ratio": bundle_promotion_ratio,
            }
        )
    if not bool(quality_report.get("pass")):
        derived_alerts.append(
            {
                "code": "wiki_quality_not_passing",
                "severity": "warning",
                "message": "Core wiki quality gates are currently failing.",
                "checks": quality_report.get("checks"),
            }
        )
    if not bool(richness.get("pass")):
        derived_alerts.append(
            {
                "code": "wiki_richness_not_passing",
                "severity": "warning",
                "message": "Published core pages remain shallow or structurally incomplete.",
                "scores": richness.get("scores"),
                "checks": richness.get("checks"),
            }
        )
    if placeholder_ratio >= 0.15:
        derived_alerts.append(
            {
                "code": "placeholder_pressure_high",
                "severity": "warning",
                "message": "Core pages still contain too much placeholder content.",
                "value": placeholder_ratio,
                "threshold": 0.15,
            }
        )

    merged_alerts = _merge_adoption_warnings(warnings, derived_alerts)
    critical = [item for item in merged_alerts if isinstance(item, dict) and str(item.get("severity") or "") == "critical"]
    warning_only = [item for item in merged_alerts if isinstance(item, dict) and str(item.get("severity") or "") == "warning"]
    state = "healthy"
    if critical:
        state = "critical"
    elif warning_only:
        state = "watch"

    latest_recommendation = next(
        (
            item
            for item in recent_safe_mode_events
            if isinstance(item, dict) and str(item.get("action") or "") == "adoption_safe_mode_recommended"
        ),
        None,
    )
    latest_applied = next(
        (
            item
            for item in recent_safe_mode_events
            if isinstance(item, dict) and str(item.get("action") or "") == "adoption_safe_mode_applied"
        ),
        None,
    )
    safe_mode = {
        "state": (
            "applied_recently"
            if latest_applied is not None
            else ("recommended" if critical else "not_needed")
        ),
        "should_recommend": bool(critical and latest_applied is None),
        "latest_recommendation": latest_recommendation,
        "latest_applied": latest_applied,
        "recommend_endpoint": "/v1/adoption/safe-mode/recommend",
        "apply_endpoint": "/v1/adoption/safe-mode/enable",
    }

    return {
        "project_id": project_id,
        "window_days": int(days),
        "generated_at": datetime.now(UTC).isoformat(),
        "status": state,
        "alerts": merged_alerts,
        "safe_mode": safe_mode,
        "summary": {
            "critical_alerts": len(critical),
            "warning_alerts": len(warning_only),
            "candidate_bundle_total": int(candidate_bundle_total),
            "bundle_promotion_ratio": bundle_promotion_ratio,
            "evidence_rejected_pct": rejected_pct,
            "placeholder_ratio_core": placeholder_ratio,
        },
        "pipeline": {
            "bottleneck": pipeline.get("bottleneck"),
            "claims_floor_guard": pipeline.get("claims_floor_guard"),
            "draft_flood_guard": pipeline.get("draft_flood_guard"),
        },
        "recent_safe_mode_events": recent_safe_mode_events,
        "signal_noise_audit": {
            "summary": summary,
            "top_noisy_source_families": audit.get("top_noisy_source_families"),
        },
        "quality": {
            "report": quality_report,
            "richness_benchmark": richness,
        },
    }


