@app.post("/v1/adoption/sync-presets/execute", response_model=None)
def execute_adoption_sync_preset(
    payload: AdoptionSyncPresetExecuteRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")
    if not payload.dry_run:
        confirm = str(payload.confirm_project_id or "").strip()
        if confirm != project_id:
            raise HTTPException(status_code=422, detail="confirm_project_id_mismatch")

    updated_by = str(payload.updated_by or "").strip() or "ops_admin"
    reviewed_by = str(payload.reviewed_by or "").strip() or updated_by
    warnings: list[dict[str, Any]] = []
    response: dict[str, Any] = {
        "status": "ok",
        "preset_key": payload.preset_key,
        "project_id": project_id,
        "dry_run": bool(payload.dry_run),
        "generated_at": datetime.now(UTC).isoformat(),
    }

    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/sync-presets/execute",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        try:
            recommendation = get_wiki_bootstrap_approve_recommendation(project_id=project_id)
            response["recommendation"] = recommendation
            quick_preset_key = "noise_guarded" if str(payload.preset_key).strip().lower() == "enterprise_curated_safe" else None
            response["quality_preset"] = {
                "requested": payload.preset_key,
                "resolved_policy_quick_preset": quick_preset_key,
                "recommended_noise_preset": "enterprise_wiki_bootstrap",
                "drop_ingestion_classes": ["operational_stream", "pii_sensitive_stream"],
            }

            if quick_preset_key:
                response["policy_quick_apply"] = apply_adoption_policy_calibration_quick_loop(
                    AdoptionPolicyCalibrationQuickApplyRequest(
                        project_id=project_id,
                        updated_by=updated_by,
                        preset_key=quick_preset_key,
                        dry_run=bool(payload.dry_run),
                        confirm_project_id=project_id if not payload.dry_run else None,
                        note="Applied from adoption sync preset.",
                    )
                )

            if payload.apply_bootstrap_profile:
                response["bootstrap_profile"] = apply_adoption_bootstrap_profile(
                    AdoptionBootstrapProfileApplyRequest(
                        project_id=project_id,
                        updated_by=updated_by,
                        profile="initial_import",
                        dry_run=bool(payload.dry_run),
                        confirm_project_id=project_id if not payload.dry_run else None,
                        note="Applied from adoption sync preset.",
                    ),
                    idempotency_key=None,
                )

            if payload.queue_enabled_sources and not payload.dry_run:
                response["sync_queue"] = _queue_enabled_legacy_sources_for_project(
                    conn,
                    project_id=project_id,
                    requested_by=updated_by,
                )
                processor_health = _legacy_sync_processor_health(
                    conn,
                    project_id=project_id,
                    lookback_minutes=int(payload.sync_processor_lookback_minutes),
                )
                response["sync_queue_processor"] = processor_health
                response["sync_cursor_health"] = _legacy_sync_cursor_health(
                    conn,
                    project_id=project_id,
                    stale_after_hours=24,
                )
                if (
                    int((response.get("sync_queue") or {}).get("queued") or 0) > 0
                    and str(processor_health.get("status") or "") == "unavailable"
                ):
                    warning_payload = {
                        "code": "legacy_sync_processor_unavailable",
                        "severity": "critical",
                        "message": (
                            "Legacy sync runs were queued but no recent queue processor activity was detected. "
                            "Start/repair the worker legacy sync scheduler."
                        ),
                        "reason_code": processor_health.get("reason_code"),
                        "lookback_minutes": int(processor_health.get("lookback_minutes") or payload.sync_processor_lookback_minutes),
                        "queue": processor_health.get("queue"),
                        "activity": processor_health.get("activity"),
                        "next_action": "run_legacy_sync_scheduler",
                    }
                    warnings.append(warning_payload)
                    if bool(payload.fail_on_sync_processor_unavailable):
                        response["status"] = "failed"
                        response["warnings"] = warnings
                        mark_request_completed(
                            conn,
                            endpoint="/v1/adoption/sync-presets/execute",
                            idempotency_key=idempotency_key,
                            status_code=503,
                            response_body=response,
                        )
                        return JSONResponse(status_code=503, content=response)
                cursor_health = response.get("sync_cursor_health") if isinstance(response.get("sync_cursor_health"), dict) else {}
                if str(cursor_health.get("status") or "").strip().lower() == "critical":
                    warnings.append(
                        {
                            "code": "legacy_sync_cursor_health_critical",
                            "severity": "critical",
                            "message": (
                                "Polling connectors are missing/stale cursor progression. "
                                "Risk of repeated full scans and noisy ingestion batches."
                            ),
                            "next_action": "check /v1/adoption/sync/cursor-health and source sql_cursor_state_key settings",
                            "cursor_health": cursor_health,
                        }
                    )
            else:
                response["sync_queue"] = {
                    "available": _legacy_import_sources_table_exists(conn),
                    "queued": 0,
                    "already_queued": 0,
                    "sources_scanned": 0,
                    "run_ids": [],
                    "skipped": bool(payload.dry_run) or not payload.queue_enabled_sources,
                }
                if bool(payload.dry_run):
                    response["sync_queue_processor"] = {
                        "status": "dry_run",
                        "processor_available": None,
                        "lookback_minutes": int(payload.sync_processor_lookback_minutes),
                    }

            if payload.run_bootstrap_approve:
                recommended = recommendation.get("recommended") if isinstance(recommendation, dict) else {}
                if not isinstance(recommended, dict):
                    recommended = {}
                response["bootstrap_approve"] = run_wiki_bootstrap_approve(
                    WikiBootstrapApproveRunRequest(
                        project_id=project_id,
                        reviewed_by=reviewed_by,
                        source_system=payload.source_system,
                        dry_run=bool(payload.dry_run),
                        limit=max(1, min(2000, int(recommended.get("limit") or 50))),
                        sample_size=max(1, min(200, int(recommended.get("sample_size") or 15))),
                        min_confidence=max(0.0, min(1.0, float(recommended.get("min_confidence") or 0.9))),
                        require_conflict_free=bool(recommended.get("require_conflict_free", True)),
                        trusted_source_systems=[
                            str(item) for item in (recommended.get("trusted_source_systems") or []) if str(item).strip()
                        ],
                        allow_large_batch=bool(recommended.get("allow_large_batch", False)),
                        require_trusted_sources_on_apply=bool(recommended.get("require_trusted_sources_on_apply", True)),
                    )
                )

            if payload.include_starter_pages and not payload.dry_run:
                response["starter_pages"] = run_adoption_first_run_bootstrap(
                    AdoptionFirstRunBootstrapRequest(
                        project_id=project_id,
                        created_by=updated_by,
                        profile=payload.starter_profile,
                        publish=True,
                        include_state_snapshot=True,
                    )
                )

            if payload.include_role_template and payload.role_template_key and not payload.dry_run:
                response["role_template"] = apply_adoption_wiki_space_template(
                    AdoptionWikiSpaceTemplateApplyRequest(
                        project_id=project_id,
                        updated_by=updated_by,
                        template_key=payload.role_template_key,
                        space_key=payload.role_template_space_key,
                        publish=True,
                    )
                )
            if payload.run_bundle_promotion:
                response["bundle_promotion"] = run_adoption_bundle_promotion(
                    AdoptionBundlePromotionRunRequest(
                        project_id=project_id,
                        updated_by=updated_by,
                        dry_run=bool(payload.dry_run),
                        confirm_project_id=project_id if not payload.dry_run else None,
                        publish=bool(payload.bundle_promotion_publish),
                        bootstrap_publish_core=bool(payload.bundle_promotion_bootstrap_publish_core),
                        space_key=str(payload.bundle_promotion_space_key or "operations"),
                    ),
                    idempotency_key=None,
                )
            pipeline_visibility: dict[str, Any] | None = None
            rejection_diagnostics: dict[str, Any] | None = None
            try:
                pipeline_visibility = get_adoption_pipeline_visibility(
                    project_id=project_id,
                    days=14,
                    source_systems=None,
                    namespaces=None,
                )
                rejection_diagnostics = get_adoption_rejection_diagnostics(
                    project_id=project_id,
                    days=14,
                    sample_limit=5,
                )
                response["pipeline_visibility"] = pipeline_visibility
                response["rejection_diagnostics"] = rejection_diagnostics
            except Exception as explainability_exc:  # pragma: no cover - defensive envelope
                warnings.append(
                    {
                        "code": "explainability_unavailable",
                        "severity": "warning",
                        "message": f"Could not build explainability snapshot: {explainability_exc}",
                    }
                )
            warnings = _merge_adoption_warnings(warnings, _build_adoption_pipeline_pressure_warnings(pipeline_visibility))

            critical_warning_present = _has_critical_adoption_warnings(warnings)
            response["auto_safe_mode"] = {
                "enabled": bool(payload.auto_apply_safe_mode_on_critical),
                "triggered": False,
                "reason": "none",
            }
            if critical_warning_present:
                response["auto_safe_mode"]["reason"] = "critical_warning_detected"
                if bool(payload.auto_apply_safe_mode_on_critical):
                    response["safe_mode"] = enable_adoption_safe_mode(
                        AdoptionSafeModeEnableRequest(
                            project_id=project_id,
                            updated_by=updated_by,
                            dry_run=bool(payload.dry_run),
                            confirm_project_id=project_id if not payload.dry_run else None,
                            note="Applied automatically by sync preset due to critical diagnostics.",
                        )
                    )
                    response["auto_safe_mode"]["triggered"] = not bool(payload.dry_run)

            response["explainability"] = _build_adoption_sync_explainability(
                warnings=warnings,
                pipeline_visibility=pipeline_visibility,
                rejection_diagnostics=rejection_diagnostics,
            )
            if warnings:
                response["warnings"] = warnings

            mark_request_completed(
                conn,
                endpoint="/v1/adoption/sync-presets/execute",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/sync-presets/execute",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/adoption/agent-wiki-bootstrap", response_model=None)
def run_adoption_agent_wiki_bootstrap(
    payload: AdoptionAgentWikiBootstrapRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")
    if not payload.dry_run:
        confirm = str(payload.confirm_project_id or "").strip()
        if confirm != project_id:
            raise HTTPException(status_code=422, detail="confirm_project_id_mismatch")

    actor = str(payload.updated_by or "").strip() or "web_ui"
    space_key = _normalize_space_key(payload.space_key or "", default="operations")
    requested_status = "published" if bool(payload.publish) else "reviewed"

    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/agent-wiki-bootstrap",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        try:
            plan_pages = _build_agent_wiki_bootstrap_pages(
                conn,
                project_id=project_id,
                space_key=space_key,
                include_data_sources_catalog=bool(payload.include_data_sources_catalog),
                include_agent_capability_profile=bool(payload.include_agent_capability_profile),
                include_operational_logic=bool(payload.include_operational_logic),
                include_tooling_map=bool(payload.include_tooling_map),
                include_process_playbooks=bool(payload.include_process_playbooks),
                include_company_operating_context=bool(payload.include_company_operating_context),
                include_first_run_starter=bool(payload.include_first_run_starter),
                include_state_snapshot=bool(payload.include_state_snapshot),
                max_sources=int(payload.max_sources),
                max_agents=int(payload.max_agents),
                max_signals=int(payload.max_signals),
            )
            page_preview = [
                {
                    "title": str(item.get("title") or ""),
                    "slug": str(item.get("slug") or ""),
                    "page_type": str(item.get("page_type") or "operations"),
                    "words": len(str(item.get("markdown") or "").split()),
                    "importance": _bootstrap_page_importance(
                        slug=str(item.get("slug") or ""),
                        page_type=str(item.get("page_type") or "operations"),
                    ),
                }
                for item in plan_pages
            ]
            response: dict[str, Any] = {
                "status": "ok",
                "project_id": project_id,
                "dry_run": bool(payload.dry_run),
                "space_key": space_key,
                "requested_status": requested_status,
                "bootstrap_publish_core": bool(payload.bootstrap_publish_core),
                "plan": {
                    "pages_total": len(page_preview),
                    "pages": page_preview,
                },
                "quality_routing": {
                    "event_lane_recommended_noise_preset": "off",
                    "knowledge_lane_recommended_noise_preset": "enterprise_wiki_bootstrap",
                    "note": "Operational/event stream stays out of wiki pages; reusable process knowledge is promoted.",
                },
                "preview_apply_flow": {
                    "step_1": "preview",
                    "step_2": "apply",
                    "apply_hint": "rerun this endpoint with dry_run=false and confirm_project_id",
                    "apply_payload_template": {
                        "project_id": project_id,
                        "updated_by": actor,
                        "dry_run": False,
                        "confirm_project_id": project_id,
                        "publish": bool(payload.publish),
                        "bootstrap_publish_core": bool(payload.bootstrap_publish_core),
                        "space_key": space_key,
                        "include_state_snapshot": bool(payload.include_state_snapshot),
                    },
                },
                "definition_of_done": _agent_wiki_bootstrap_dod(pages=plan_pages),
                "quality_report": _build_agent_wiki_bootstrap_quality_report(
                    plan_pages=plan_pages,
                    page_result=None,
                ),
                "generated_at": datetime.now(UTC).isoformat(),
            }
            if bool(payload.dry_run):
                response["next_action"] = "rerun_with_dry_run=false_and_confirm_project_id"
            if not payload.dry_run:
                force_publish_slugs = (
                    [
                        slug
                        for slug in [str(item.get("slug") or "") for item in plan_pages]
                        if _is_core_bootstrap_page_slug(slug)
                    ]
                    if bool(payload.bootstrap_publish_core and payload.publish)
                    else []
                )
                page_result = _insert_bootstrap_pages(
                    conn,
                    project_id=project_id,
                    created_by=actor,
                    profile="agent_wiki_bootstrap",
                    pages=plan_pages,
                    requested_status=requested_status,
                    policy_space_fallback_enabled=True,
                    policy_space_fallback_candidates=[space_key, "logistics", "general"],
                    force_publish_slugs=force_publish_slugs,
                )
                if int((page_result.get("summary") or {}).get("created") or 0) <= 0 and int(
                    (page_result.get("summary") or {}).get("skipped") or 0
                ) > 0:
                    response.update(
                        {
                            "status": "failed",
                            "error": "bootstrap_policy_denied",
                            "hint": "No writable wiki space was found for this actor. Add owner access or change target space.",
                            "policy_space_fallback": page_result.get("policy_space_fallback"),
                            "skipped": page_result.get("skipped"),
                        }
                    )
                    mark_request_completed(
                        conn,
                        endpoint="/v1/adoption/agent-wiki-bootstrap",
                        idempotency_key=idempotency_key,
                        status_code=409,
                        response_body=response,
                    )
                    return JSONResponse(status_code=409, content=response)
                created_slugs = [str(item.get("slug") or "") for item in (page_result.get("created") or [])]
                response.update(page_result)
                response["definition_of_done"] = _agent_wiki_bootstrap_dod(
                    pages=plan_pages,
                    created_slugs=created_slugs,
                )
                response["quality_report"] = _build_agent_wiki_bootstrap_quality_report(
                    plan_pages=plan_pages,
                    page_result=page_result,
                )
                if bool(payload.include_state_snapshot):
                    response["state_snapshot"] = _sync_wiki_state_snapshot_page(
                        conn,
                        project_id=project_id,
                        updated_by=actor,
                        space_key=space_key,
                        status=requested_status,
                    )

            mark_request_completed(
                conn,
                endpoint="/v1/adoption/agent-wiki-bootstrap",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/agent-wiki-bootstrap",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/adoption/bundle-promotion/run", response_model=None)
def run_adoption_bundle_promotion(
    payload: AdoptionBundlePromotionRunRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")
    if not payload.dry_run:
        confirm = str(payload.confirm_project_id or "").strip()
        if confirm != project_id:
            raise HTTPException(status_code=422, detail="confirm_project_id_mismatch")

    actor = str(payload.updated_by or "").strip() or "ops_admin"
    space_key = _normalize_space_key(payload.space_key or "", default="operations")
    requested_status = "published" if bool(payload.publish) else "reviewed"

    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/bundle-promotion/run",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        try:
            with conn.cursor() as cur:
                plan_pages = _build_bundle_promotion_pages(
                    cur,
                    project_id=project_id,
                    space_key=space_key,
                    include_data_sources_catalog=bool(payload.include_data_sources_catalog),
                    include_agent_capability_profile=bool(payload.include_agent_capability_profile),
                    include_process_playbooks=bool(payload.include_process_playbooks),
                    include_decisions_log=bool(payload.include_decisions_log),
                    include_company_operating_context=bool(payload.include_company_operating_context),
                    include_operational_logic_map=bool(payload.include_operational_logic_map),
                    max_sources=int(payload.max_sources),
                    max_agents=int(payload.max_agents),
                    max_signals=int(payload.max_signals),
                )
                bundle_summary = _build_bundle_promotion_summary(
                    cur,
                    project_id=project_id,
                    max_items=8,
                )
            page_preview = [
                {
                    "title": str(item.get("title") or ""),
                    "slug": str(item.get("slug") or ""),
                    "page_type": str(item.get("page_type") or "operations"),
                    "words": len(str(item.get("markdown") or "").split()),
                    "importance": _bootstrap_page_importance(
                        slug=str(item.get("slug") or ""),
                        page_type=str(item.get("page_type") or "operations"),
                    ),
                }
                for item in plan_pages
            ]
            response: dict[str, Any] = {
                "status": "ok",
                "project_id": project_id,
                "dry_run": bool(payload.dry_run),
                "space_key": space_key,
                "requested_status": requested_status,
                "bootstrap_publish_core": bool(payload.bootstrap_publish_core),
                "knowledge_compiler": {
                    "mode": "bundle_level_promotion",
                    "source": "evidence_bundles",
                    "summary": bundle_summary,
                },
                "plan": {
                    "pages_total": len(page_preview),
                    "pages": page_preview,
                },
                "preview_apply_flow": {
                    "step_1": "preview",
                    "step_2": "apply",
                    "apply_hint": "rerun this endpoint with dry_run=false and confirm_project_id",
                    "apply_payload_template": {
                        "project_id": project_id,
                        "updated_by": actor,
                        "dry_run": False,
                        "confirm_project_id": project_id,
                        "publish": bool(payload.publish),
                        "bootstrap_publish_core": bool(payload.bootstrap_publish_core),
                        "space_key": space_key,
                    },
                },
                "quality_report": _build_agent_wiki_bootstrap_quality_report(
                    plan_pages=plan_pages,
                    page_result=None,
                ),
                "generated_at": datetime.now(UTC).isoformat(),
            }
            if bool(payload.dry_run):
                response["next_action"] = "rerun_with_dry_run=false_and_confirm_project_id"
            else:
                page_result = _upsert_compiler_pages(
                    conn,
                    project_id=project_id,
                    updated_by=actor,
                    profile="bundle_promotion",
                    pages=plan_pages,
                    requested_status=requested_status,
                    bootstrap_publish_core=bool(payload.bootstrap_publish_core),
                )
                response.update(page_result)
                merged_page_result = {
                    "created": [*(page_result.get("created") or []), *(page_result.get("updated") or [])],
                    "summary": page_result.get("summary") or {},
                }
                response["quality_report"] = _build_agent_wiki_bootstrap_quality_report(
                    plan_pages=plan_pages,
                    page_result=merged_page_result,
                )
            mark_request_completed(
                conn,
                endpoint="/v1/adoption/bundle-promotion/run",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/bundle-promotion/run",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/adoption/first-run/bootstrap")
def run_adoption_first_run_bootstrap(payload: AdoptionFirstRunBootstrapRequest) -> dict[str, Any]:
    pages = _build_first_run_starter_pages(
        payload.profile,
        space_key=payload.space_key,
        include_decisions_log=True,
    )
    requested_status = "published" if payload.publish else "reviewed"
    with get_conn() as conn:
        page_result = _insert_bootstrap_pages(
            conn,
            project_id=payload.project_id,
            created_by=payload.created_by,
            profile=payload.profile,
            pages=pages,
            requested_status=requested_status,
            policy_space_fallback_enabled=True,
            policy_space_fallback_candidates=[payload.space_key or "", "logistics", "general"],
        )
        state_sync_payload: dict[str, Any] | None = None
        if bool(payload.include_state_snapshot):
            state_sync_payload = _sync_wiki_state_snapshot_page(
                conn,
                project_id=payload.project_id,
                updated_by=payload.created_by,
                space_key=payload.space_key,
                status=requested_status,
            )
    if int((page_result.get("summary") or {}).get("created") or 0) <= 0 and int(
        (page_result.get("summary") or {}).get("skipped") or 0
    ) > 0:
        raise HTTPException(
            status_code=409,
            detail={
                "error": "bootstrap_policy_denied",
                "project_id": payload.project_id,
                "hint": "No writable wiki space was found for this actor. Add owner access or run bootstrap with another actor.",
                "policy_space_fallback": page_result.get("policy_space_fallback"),
                "skipped": page_result.get("skipped"),
            },
        )
    return {
        "status": "ok",
        "project_id": payload.project_id,
        "profile": payload.profile,
        "space_key": _normalize_space_key(payload.space_key or "", default=""),
        "include_state_snapshot": bool(payload.include_state_snapshot),
        "requested_status": requested_status,
        **page_result,
        "state_snapshot": state_sync_payload if bool(payload.include_state_snapshot) else None,
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/adoption/noise-presets")
def list_adoption_noise_presets(
    lane: str | None = Query(default=None, pattern="^(event|knowledge)$"),
) -> dict[str, Any]:
    if lane is None:
        recommended = {"event": "off", "knowledge": "enterprise_wiki_bootstrap"}
    else:
        recommended = {lane: "off" if lane == "event" else "enterprise_wiki_bootstrap"}
    presets = [
        {
            "key": key,
            "label": str(config.get("label") or key),
            "description": str(config.get("description") or "").strip(),
            "drop_json_payload": bool(config.get("drop_json_payload")),
            "min_json_keys": int(config.get("min_json_keys") or 0),
            "matches": {
                "source_id_patterns": list(config.get("source_id_patterns") or []),
                "category_patterns": list(config.get("category_patterns") or []),
            },
        }
        for key, config in _BACKFILL_NOISE_PRESET_DEFS.items()
    ]
    return {
        "lane": lane,
        "recommended_by_lane": recommended,
        "presets": presets,
        "generated_at": datetime.now(UTC).isoformat(),
    }


@app.get("/v1/adoption/rejections/diagnostics")
def get_adoption_rejection_diagnostics(
    project_id: str,
    days: int = Query(default=14, ge=1, le=90),
    sample_limit: int = Query(default=5, ge=1, le=25),
) -> dict[str, Any]:
    cutoff = datetime.now(UTC) - timedelta(days=days)
    preclaim_drop_reason_counts: dict[str, int] = {}

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  d.claim_id::text,
                  d.rationale,
                  d.features,
                  d.updated_at,
                  c.entity_key,
                  c.category,
                  c.claim_text
                FROM gatekeeper_decisions d
                LEFT JOIN claims c ON c.id = d.claim_id AND c.project_id = d.project_id
                WHERE d.project_id = %s
                  AND d.tier = 'operational_memory'
                  AND d.updated_at >= %s
                ORDER BY d.updated_at DESC
                LIMIT 2000
                """,
                (project_id, cutoff),
            )
            rows = cur.fetchall() or []
        if _memory_backfill_batches_table_exists(conn) and _backfill_batch_has_reason_counters(conn):
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT COALESCE(drop_reason_counts, '{}'::jsonb)
                    FROM memory_backfill_batches
                    WHERE project_id = %s
                      AND updated_at >= %s
                    ORDER BY updated_at DESC
                    LIMIT 5000
                    """,
                    (project_id, cutoff),
                )
                for row in cur.fetchall() or []:
                    bucket = row[0] if isinstance(row[0], dict) else {}
                    for key, value in bucket.items():
                        reason_key = str(key or "").strip().lower()
                        if not reason_key:
                            continue
                        preclaim_drop_reason_counts[reason_key] = int(
                            preclaim_drop_reason_counts.get(reason_key, 0)
                        ) + int(value or 0)

    reason_counts: dict[str, int] = {}
    blocked_source_type_counts: dict[str, int] = {}
    blocked_source_system_counts: dict[str, int] = {}
    blocked_tool_counts: dict[str, int] = {}
    examples: list[dict[str, Any]] = []

    def _bump(counter: dict[str, int], key: str | None) -> None:
        text = str(key or "").strip().lower()
        if not text:
            return
        counter[text] = int(counter.get(text, 0)) + 1

    def _bump_many(counter: dict[str, int], values: Any) -> None:
        if not isinstance(values, list):
            return
        for value in values:
            _bump(counter, str(value or ""))

    def _reason_tags(features: dict[str, Any], rationale: str) -> list[str]:
        tags: list[str] = []
        classification = str(features.get("ingestion_classification") or "").strip().lower()
        if classification:
            tags.append(f"classification:{classification}")
        if bool(features.get("ingestion_default_deny_block")):
            tags.append("ingestion_default_deny")
        if bool(features.get("blocked_by_source_id")):
            tags.append("blocked_source_id")
        if bool(features.get("blocked_by_source_type")):
            tags.append("blocked_source_type")
        if bool(features.get("blocked_by_source_system")):
            tags.append("blocked_source_system")
        if bool(features.get("blocked_by_category")):
            tags.append("blocked_category")
        if bool(features.get("blocked_by_entity")):
            tags.append("blocked_entity")
        if bool(features.get("has_event_stream_shape")):
            tags.append("event_stream_shape")
        if bool(features.get("backfill_without_durable_signal")):
            tags.append("backfill_without_durable_signal")
        if bool(features.get("insufficient_support")):
            tags.append("insufficient_support")
        if bool(features.get("looks_like_runtime_noise")):
            tags.append("runtime_noise")
        if not tags and bool(features.get("routing_hard_block")):
            tags.append("routing_hard_block")
        if not tags and rationale:
            tags.append("rationale_only")
        return tags

    for row in rows:
        claim_id = str(row[0] or "")
        rationale = str(row[1] or "").strip()
        features = row[2] if isinstance(row[2], dict) else {}
        updated_at = row[3]
        entity_key = str(row[4] or "")
        category = str(row[5] or "")
        claim_text = str(row[6] or "")

        tags = _reason_tags(features, rationale)
        for tag in tags:
            _bump(reason_counts, tag)

        _bump_many(blocked_source_type_counts, features.get("incoming_source_types"))
        _bump_many(blocked_source_system_counts, features.get("incoming_source_systems"))
        _bump_many(blocked_tool_counts, features.get("incoming_tool_names"))

        if len(examples) < sample_limit:
            examples.append(
                {
                    "claim_id": claim_id,
                    "entity_key": entity_key,
                    "category": category,
                    "reason_tags": tags,
                    "rationale": rationale,
                    "updated_at": updated_at.isoformat() if updated_at is not None else None,
                    "claim_text_snippet": claim_text[:240],
                }
            )

    def _top(counter: dict[str, int], *, limit: int = 8) -> list[dict[str, Any]]:
        return [
            {"key": key, "count": int(count)}
            for key, count in sorted(counter.items(), key=lambda item: (-item[1], item[0]))[:limit]
        ]

    top_reasons = _top(reason_counts, limit=10)
    top_preclaim_reasons = _top(preclaim_drop_reason_counts, limit=10)
    top_source_types = _top(blocked_source_type_counts, limit=10)
    top_source_systems = _top(blocked_source_system_counts, limit=10)
    top_tool_names = _top(blocked_tool_counts, limit=10)

    suggestions: list[dict[str, str]] = []
    reason_top_keys = {item["key"] for item in top_reasons[:5]}
    reason_top_keys.update({item["key"] for item in top_preclaim_reasons[:5]})
    if "blocked_source_type" in reason_top_keys or "blocked_source_system" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.blocked_source_type_keywords / blocked_source_system_keywords",
                "hint": "Use `/v1/backfill/knowledge` for curated memory imports instead of event lane defaults.",
            }
        )
    if "event_stream_shape" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.event_stream_min_*",
                "hint": "Snapshot-like payloads dominate; pre-filter order/telemetry events before backfill.",
            }
        )
    if "event_like_low_signal" in reason_top_keys or "event_transport_low_signal" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.high_signal_route_keywords / high_signal_min_keyword_hits",
                "hint": "Extraction is too strict; promote policy/process/runbook markers into high-signal route lane.",
            }
        )
    if "backfill_without_durable_signal" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.min_durable_signal_hits_for_backfill / backfill_requires_policy_signal",
                "hint": "For first migration, use bootstrap profile with softer durable-signal thresholds.",
            }
        )
    if "insufficient_support" in reason_top_keys:
        suggestions.append(
            {
                "knob": "routing_policy.min_sources_for_wiki_candidate / min_evidence_for_wiki_candidate",
                "hint": "Many records are single-source; bootstrap import should apply curated auto-approve sampling.",
            }
        )
    if not suggestions:
        suggestions.append(
            {
                "knob": "routing_policy",
                "hint": "No dominant reject pattern detected; inspect sample rejections and adjust policy by reason tags.",
            }
        )

    return {
        "project_id": project_id,
        "window_days": int(days),
        "since": cutoff.isoformat(),
        "generated_at": datetime.now(UTC).isoformat(),
        "summary": {
            "rejected_total": len(rows),
            "sampled_examples": len(examples),
            "preclaim_dropped_total": int(sum(preclaim_drop_reason_counts.values())),
        },
        "top_reject_reasons": top_reasons,
        "top_preclaim_drop_reasons": top_preclaim_reasons,
        "top_blocked_patterns": {
            "source_types": top_source_types,
            "source_systems": top_source_systems,
            "tool_names": top_tool_names,
        },
        "examples": examples,
        "suggested_policy_knobs": suggestions,
    }


@app.get("/v1/adoption/rejections/why")
def get_adoption_rejection_why(
    project_id: str,
    days: int = Query(default=14, ge=1, le=90),
    sample_limit: int = Query(default=5, ge=1, le=25),
) -> dict[str, Any]:
    response = get_adoption_rejection_diagnostics(
        project_id=project_id,
        days=days,
        sample_limit=sample_limit,
    )
    response["alias"] = "/v1/adoption/rejections/diagnostics"
    return response


@app.get("/v1/adoption/pipeline/visibility")
def get_adoption_pipeline_visibility(
    project_id: str,
    days: int = Query(default=14, ge=1, le=90),
    source_systems: str | None = Query(default=None),
    namespaces: str | None = Query(default=None),
) -> dict[str, Any]:
    source_filters = _normalize_source_system_csv(source_systems)
    namespace_filters = _normalize_namespace_csv(namespaces)
    cutoff = datetime.now(UTC) - timedelta(days=days)

    accepted_records = 0
    events_total = 0
    claims_total = 0
    drafts_total = 0
    pages_total = 0
    pages_from_published = 0
    pages_from_published_window = 0
    queue_pending_review = 0
    queue_blocked_conflict = 0
    rejected_event_like = 0
    kept_durable = 0
    trusted_bypass = 0
    accepted_source = "events_estimated"
    extraction_drop_reasons: dict[str, int] = {}
    extraction_keep_reasons: dict[str, int] = {}
    draft_flood_max_open_per_page = int(_DEFAULT_GATEKEEPER_ROUTING_POLICY.get("draft_flood_max_open_per_page") or 200)
    draft_flood_max_open_per_entity = int(_DEFAULT_GATEKEEPER_ROUTING_POLICY.get("draft_flood_max_open_per_entity") or 400)
    queue_pressure_open_drafts_threshold = int(
        _DEFAULT_GATEKEEPER_ROUTING_POLICY.get("queue_pressure_safe_mode_open_drafts_threshold") or 5000
    )
    queue_pressure_open_drafts_per_page_threshold = int(
        _DEFAULT_GATEKEEPER_ROUTING_POLICY.get("queue_pressure_safe_mode_open_drafts_per_page_threshold") or 200
    )
    claims_floor_min_events = int(_DEFAULT_GATEKEEPER_ROUTING_POLICY.get("claims_floor_min_events") or 120)
    claims_floor_alert_after_minutes = int(_DEFAULT_GATEKEEPER_ROUTING_POLICY.get("claims_floor_alert_after_minutes") or 20)
    claims_floor_min_conversion_ratio = float(_DEFAULT_GATEKEEPER_ROUTING_POLICY.get("claims_floor_min_conversion_ratio") or 0.01)
    first_event_at: datetime | None = None
    last_event_at: datetime | None = None
    max_open_drafts_per_page = 0
    max_open_drafts_per_entity = 0
    pages_over_open_draft_limit = 0
    entities_over_open_draft_limit = 0
    top_draft_pressure_pages: list[dict[str, Any]] = []
    top_draft_pressure_entities: list[dict[str, Any]] = []

    with get_conn() as conn:
        with conn.cursor() as cur:
            routing_policy = _load_project_routing_policy(conn, project_id=project_id)
            draft_flood_max_open_per_page = max(
                50,
                int(routing_policy.get("draft_flood_max_open_per_page") or draft_flood_max_open_per_page),
            )
            draft_flood_max_open_per_entity = max(
                50,
                int(routing_policy.get("draft_flood_max_open_per_entity") or draft_flood_max_open_per_entity),
            )
            queue_pressure_open_drafts_threshold = max(
                100,
                int(
                    routing_policy.get("queue_pressure_safe_mode_open_drafts_threshold")
                    or queue_pressure_open_drafts_threshold
                ),
            )
            queue_pressure_open_drafts_per_page_threshold = max(
                50,
                int(
                    routing_policy.get("queue_pressure_safe_mode_open_drafts_per_page_threshold")
                    or queue_pressure_open_drafts_per_page_threshold
                ),
            )
            claims_floor_min_events = max(
                1,
                int(routing_policy.get("claims_floor_min_events") or claims_floor_min_events),
            )
            claims_floor_alert_after_minutes = max(
                1,
                int(routing_policy.get("claims_floor_alert_after_minutes") or claims_floor_alert_after_minutes),
            )
            claims_floor_min_conversion_ratio = max(
                0.0,
                min(
                    1.0,
                    float(routing_policy.get("claims_floor_min_conversion_ratio") or claims_floor_min_conversion_ratio),
                ),
            )

            if _memory_backfill_batches_table_exists(conn):
                params: list[Any] = [project_id, cutoff]
                where_sql = ["project_id = %s", "updated_at >= %s"]
                if source_filters:
                    where_sql.append("LOWER(source_system) = ANY(%s::text[])")
                    params.append(source_filters)
                if _backfill_batch_has_decision_counters(conn):
                    cur.execute(
                        f"""
                        SELECT
                          COALESCE(SUM(total_items), 0)::bigint,
                          COALESCE(SUM(inserted_events), 0)::bigint,
                          COALESCE(SUM(generated_claims), 0)::bigint,
                          COALESCE(SUM(dropped_event_like), 0)::bigint,
                          COALESCE(SUM(kept_durable), 0)::bigint,
                          COALESCE(SUM(trusted_bypass), 0)::bigint
                        FROM memory_backfill_batches
                        WHERE {' AND '.join(where_sql)}
                        """,
                        tuple(params),
                    )
                    row = cur.fetchone() or (0, 0, 0, 0, 0, 0)
                else:
                    cur.execute(
                        f"""
                        SELECT
                          COALESCE(SUM(total_items), 0)::bigint,
                          COALESCE(SUM(inserted_events), 0)::bigint,
                          COALESCE(SUM(generated_claims), 0)::bigint
                        FROM memory_backfill_batches
                        WHERE {' AND '.join(where_sql)}
                        """,
                        tuple(params),
                    )
                    batch_row = cur.fetchone() or (0, 0, 0)
                    row = (batch_row[0], batch_row[1], batch_row[2], 0, 0, 0)
                batch_total_items = int(row[0] or 0)
                rejected_event_like = int(row[3] or 0)
                kept_durable = int(row[4] or 0)
                trusted_bypass = int(row[5] or 0)
                if not namespace_filters:
                    accepted_records = batch_total_items
                    accepted_source = "memory_backfill_batches"

                if _backfill_batch_has_reason_counters(conn):
                    cur.execute(
                        f"""
                        SELECT
                          COALESCE(drop_reason_counts, '{{}}'::jsonb),
                          COALESCE(keep_reason_counts, '{{}}'::jsonb)
                        FROM memory_backfill_batches
                        WHERE {' AND '.join(where_sql)}
                        ORDER BY updated_at DESC
                        LIMIT 5000
                        """,
                        tuple(params),
                    )
                    for drop_counts_raw, keep_counts_raw in (cur.fetchall() or []):
                        drop_counts = drop_counts_raw if isinstance(drop_counts_raw, dict) else {}
                        keep_counts = keep_counts_raw if isinstance(keep_counts_raw, dict) else {}
                        for key, value in drop_counts.items():
                            reason_key = str(key or "").strip().lower()
                            if not reason_key:
                                continue
                            extraction_drop_reasons[reason_key] = int(extraction_drop_reasons.get(reason_key, 0)) + int(
                                value or 0
                            )
                        for key, value in keep_counts.items():
                            reason_key = str(key or "").strip().lower()
                            if not reason_key:
                                continue
                            extraction_keep_reasons[reason_key] = int(extraction_keep_reasons.get(reason_key, 0)) + int(
                                value or 0
                            )

            event_filters = ["e.project_id = %s", "e.event_type = 'memory_backfill'", "e.observed_at >= %s"]
            event_params: list[Any] = [project_id, cutoff]
            if source_filters:
                event_filters.append(
                    """
                    LOWER(
                      COALESCE(
                        NULLIF(e.payload->'backfill'->>'source_system', ''),
                        NULLIF(e.payload->>'source_system', ''),
                        NULLIF(e.payload->'metadata'->>'source_system', ''),
                        NULLIF(e.payload->'metadata'->>'source', '')
                      )
                    ) = ANY(%s::text[])
                    """.strip()
                )
                event_params.append(source_filters)
            if namespace_filters:
                event_filters.append(
                    """
                    LOWER(
                      COALESCE(
                        NULLIF(e.payload->'metadata'->>'namespace', ''),
                        NULLIF(e.payload->>'namespace', ''),
                        NULLIF(e.payload->'metadata'->>'source_namespace', '')
                      )
                    ) = ANY(%s::text[])
                    """.strip()
                )
                event_params.append(namespace_filters)
            cur.execute(
                f"""
                SELECT
                  COUNT(*)::bigint,
                  MIN(e.observed_at),
                  MAX(e.observed_at)
                FROM events e
                WHERE {' AND '.join(event_filters)}
                """,
                tuple(event_params),
            )
            event_row = cur.fetchone()
            events_total = int((event_row[0] if event_row else 0) or 0)
            first_event_at = event_row[1] if (event_row and isinstance(event_row[1], datetime)) else None
            last_event_at = event_row[2] if (event_row and isinstance(event_row[2], datetime)) else None
            if accepted_records <= 0:
                accepted_records = events_total
                accepted_source = "events_estimated"

            if _public_table_exists(conn, "claims"):
                claim_filters = ["c.project_id = %s", "c.created_at >= %s"]
                claim_params: list[Any] = [project_id, cutoff]
                if source_filters or namespace_filters:
                    evidence_filters: list[str] = []
                    if source_filters:
                        evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        claim_params.append(source_filters)
                    if namespace_filters:
                        evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        claim_params.append(namespace_filters)
                    claim_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(c.evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT COUNT(*)::bigint
                    FROM claims c
                    WHERE {' AND '.join(claim_filters)}
                    """,
                    tuple(claim_params),
                )
                claim_row = cur.fetchone()
                claims_total = int((claim_row[0] if claim_row else 0) or 0)

            if _public_table_exists(conn, "wiki_draft_changes"):
                draft_filters = ["d.project_id = %s", "d.created_at >= %s"]
                draft_params: list[Any] = [project_id, cutoff]
                if source_filters or namespace_filters:
                    draft_evidence_filters: list[str] = []
                    if source_filters:
                        draft_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        draft_params.append(source_filters)
                    if namespace_filters:
                        draft_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        draft_params.append(namespace_filters)
                    draft_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(d.evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(draft_evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT COUNT(*)::bigint
                    FROM wiki_draft_changes d
                    WHERE {' AND '.join(draft_filters)}
                    """,
                    tuple(draft_params),
                )
                draft_row = cur.fetchone()
                drafts_total = int((draft_row[0] if draft_row else 0) or 0)

            pages_from_moderation = 0
            if _public_table_exists(conn, "moderation_actions") and _public_table_exists(conn, "wiki_draft_changes"):
                page_filters = [
                    "ma.project_id = %s",
                    "ma.action_type = 'approve'",
                    "ma.created_at >= %s",
                    "d.page_id IS NOT NULL",
                ]
                page_params: list[Any] = [project_id, cutoff]
                if source_filters or namespace_filters:
                    page_evidence_filters: list[str] = []
                    if source_filters:
                        page_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        page_params.append(source_filters)
                    if namespace_filters:
                        page_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        page_params.append(namespace_filters)
                    page_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(d.evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(page_evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT COUNT(DISTINCT d.page_id)::bigint
                    FROM moderation_actions ma
                    JOIN wiki_draft_changes d ON d.id = ma.draft_id
                    WHERE {' AND '.join(page_filters)}
                    """,
                    tuple(page_params),
                )
                page_row = cur.fetchone()
                pages_from_moderation = int((page_row[0] if page_row else 0) or 0)

            pages_from_published = 0
            if _public_table_exists(conn, "wiki_pages"):
                cur.execute(
                    """
                    SELECT
                      COUNT(*)::bigint,
                      COUNT(*) FILTER (WHERE updated_at >= %s)::bigint
                    FROM wiki_pages
                    WHERE project_id = %s
                      AND status = 'published'
                    """,
                    (cutoff, project_id),
                )
                published_row = cur.fetchone() or (0, 0)
                pages_from_published = int((published_row[0] if published_row else 0) or 0)
                pages_from_published_window = int((published_row[1] if published_row else 0) or 0)

            if source_filters or namespace_filters:
                # For scoped diagnostic views, moderation-linked pages remain source-attributed.
                # Bootstrap/starter pages have no evidence channel, so include windowed published
                # count as unscoped fallback to avoid false "0 pages" impressions.
                pages_total = max(int(pages_from_moderation), int(pages_from_published_window))
            else:
                pages_total = max(int(pages_from_moderation), int(pages_from_published))

            if _public_table_exists(conn, "wiki_draft_changes"):
                queue_filters = ["project_id = %s", "status IN ('pending_review', 'blocked_conflict')"]
                queue_params: list[Any] = [project_id]
                if source_filters or namespace_filters:
                    queue_evidence_filters: list[str] = []
                    if source_filters:
                        queue_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source_system', ''),
                                NULLIF(ev->'metadata'->>'source', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        queue_params.append(source_filters)
                    if namespace_filters:
                        queue_evidence_filters.append(
                            """
                            LOWER(
                              COALESCE(
                                NULLIF(ev->'metadata'->>'namespace', ''),
                                NULLIF(ev->>'namespace', ''),
                                NULLIF(ev->'metadata'->>'source_namespace', '')
                              )
                            ) = ANY(%s::text[])
                            """.strip()
                        )
                        queue_params.append(namespace_filters)
                    queue_filters.append(
                        f"""
                        EXISTS (
                          SELECT 1
                          FROM jsonb_array_elements(COALESCE(evidence, '[]'::jsonb)) ev
                          WHERE {' AND '.join(queue_evidence_filters)}
                        )
                        """.strip()
                    )
                cur.execute(
                    f"""
                    SELECT
                      COUNT(*) FILTER (WHERE status = 'pending_review')::bigint,
                      COUNT(*) FILTER (WHERE status = 'blocked_conflict')::bigint
                    FROM wiki_draft_changes
                    WHERE {' AND '.join(queue_filters)}
                    """,
                    tuple(queue_params),
                )
                queue_row = cur.fetchone() or (0, 0)
                queue_pending_review = int(queue_row[0] or 0)
                queue_blocked_conflict = int(queue_row[1] or 0)
                if _public_table_exists(conn, "wiki_pages"):
                    cur.execute(
                        """
                        WITH page_open AS (
                          SELECT
                            d.page_id,
                            COUNT(*)::bigint AS open_drafts
                          FROM wiki_draft_changes d
                          WHERE d.project_id = %s
                            AND d.status IN ('pending_review', 'blocked_conflict')
                          GROUP BY d.page_id
                        )
                        SELECT
                          p.slug,
                          p.title,
                          p.entity_key,
                          po.open_drafts
                        FROM page_open po
                        LEFT JOIN wiki_pages p ON p.id = po.page_id
                        ORDER BY po.open_drafts DESC, p.slug ASC
                        LIMIT 5
                        """,
                        (project_id,),
                    )
                    page_pressure_rows = cur.fetchall() or []
                    for row in page_pressure_rows:
                        open_drafts = int(row[3] or 0)
                        max_open_drafts_per_page = max(max_open_drafts_per_page, open_drafts)
                        top_draft_pressure_pages.append(
                            {
                                "slug": str(row[0] or ""),
                                "title": str(row[1] or ""),
                                "entity_key": str(row[2] or ""),
                                "open_drafts": open_drafts,
                            }
                        )

                    cur.execute(
                        """
                        WITH page_open AS (
                          SELECT
                            p.entity_key,
                            COUNT(*)::bigint AS open_drafts
                          FROM wiki_draft_changes d
                          JOIN wiki_pages p ON p.id = d.page_id
                          WHERE d.project_id = %s
                            AND d.status IN ('pending_review', 'blocked_conflict')
                          GROUP BY p.entity_key
                        )
                        SELECT entity_key, open_drafts
                        FROM page_open
                        ORDER BY open_drafts DESC, entity_key ASC
                        LIMIT 5
                        """,
                        (project_id,),
                    )
                    entity_pressure_rows = cur.fetchall() or []
                    for row in entity_pressure_rows:
                        open_drafts = int(row[1] or 0)
                        max_open_drafts_per_entity = max(max_open_drafts_per_entity, open_drafts)
                        top_draft_pressure_entities.append(
                            {
                                "entity_key": str(row[0] or ""),
                                "open_drafts": open_drafts,
                            }
                        )

                    cur.execute(
                        """
                        WITH page_open AS (
                          SELECT d.page_id, COUNT(*)::bigint AS open_drafts
                          FROM wiki_draft_changes d
                          WHERE d.project_id = %s
                            AND d.status IN ('pending_review', 'blocked_conflict')
                          GROUP BY d.page_id
                        )
                        SELECT COUNT(*)::bigint
                        FROM page_open
                        WHERE open_drafts > %s
                        """,
                        (project_id, draft_flood_max_open_per_page),
                    )
                    row = cur.fetchone()
                    pages_over_open_draft_limit = int(row[0] or 0) if row else 0

                    cur.execute(
                        """
                        WITH entity_open AS (
                          SELECT p.entity_key, COUNT(*)::bigint AS open_drafts
                          FROM wiki_draft_changes d
                          JOIN wiki_pages p ON p.id = d.page_id
                          WHERE d.project_id = %s
                            AND d.status IN ('pending_review', 'blocked_conflict')
                          GROUP BY p.entity_key
                        )
                        SELECT COUNT(*)::bigint
                        FROM entity_open
                        WHERE open_drafts > %s
                        """,
                        (project_id, draft_flood_max_open_per_entity),
                    )
                    row = cur.fetchone()
                    entities_over_open_draft_limit = int(row[0] or 0) if row else 0

    def _stage_ratio(prev_value: int, next_value: int) -> float | None:
        if prev_value <= 0:
            return None
        return round(float(next_value) / float(prev_value), 4)

    stages = [
        {"key": "accepted", "label": "Accepted", "count": int(max(0, accepted_records))},
        {"key": "events", "label": "Events", "count": int(max(0, events_total))},
        {"key": "claims", "label": "Claims", "count": int(max(0, claims_total))},
        {"key": "drafts", "label": "Drafts", "count": int(max(0, drafts_total))},
        {"key": "pages", "label": "Pages", "count": int(max(0, pages_total))},
    ]
    transitions: list[dict[str, Any]] = []
    for index in range(len(stages) - 1):
        left = stages[index]
        right = stages[index + 1]
        drop_count = max(0, int(left["count"]) - int(right["count"]))
        drop_ratio = round(float(drop_count) / float(max(int(left["count"]), 1)), 4)
        transitions.append(
            {
                "from_stage": str(left["key"]),
                "to_stage": str(right["key"]),
                "from_count": int(left["count"]),
                "to_count": int(right["count"]),
                "drop_count": int(drop_count),
                "drop_ratio": float(drop_ratio),
                "conversion_ratio": _stage_ratio(int(left["count"]), int(right["count"])),
            }
        )

    bottleneck: dict[str, Any] | None = None
    if transitions:
        top = max(transitions, key=lambda item: (float(item["drop_ratio"]), int(item["drop_count"])))
        if int(top["drop_count"]) > 0:
            hint_by_stage = {
                ("accepted", "events"): "High dedup/noise at ingestion edge. Review source IDs and event-shape suppression.",
                ("events", "claims"): "Events are not turning into claims. Inspect worker extraction rules and record quality.",
                ("claims", "drafts"): "Claims are blocked before draft stage. Review gatekeeper thresholds and rejection diagnostics.",
                ("drafts", "pages"): "Moderation/publish is bottlenecked. Use bootstrap sampling or auto-publish policy tuning.",
            }
            ratio_value = float(top["drop_ratio"])
            level = "healthy"
            if ratio_value >= 0.5:
                level = "critical"
            elif ratio_value >= 0.25:
                level = "watch"
            bottleneck = {
                **top,
                "status": level,
                "hint": hint_by_stage.get((str(top["from_stage"]), str(top["to_stage"])), "Inspect stage diagnostics."),
            }

    queue_open_total = int(queue_pending_review + queue_blocked_conflict)
    pressure_warnings: list[dict[str, Any]] = []
    if queue_open_total > queue_pressure_open_drafts_threshold:
        pressure_warnings.append(
            {
                "code": "draft_queue_pressure",
                "severity": "critical",
                "message": (
                    "Open drafts queue exceeds safe OOTB threshold; enable stricter routing and safe mode."
                ),
                "open_drafts_total": queue_open_total,
                "threshold": queue_pressure_open_drafts_threshold,
            }
        )
    page_pressure_threshold = max(draft_flood_max_open_per_page, queue_pressure_open_drafts_per_page_threshold)
    if max_open_drafts_per_page > page_pressure_threshold:
        pressure_warnings.append(
            {
                "code": "draft_flood_page_limit",
                "severity": "critical",
                "message": "A page has too many open drafts; draft-flood guard should be enabled/tightened.",
                "max_open_drafts_per_page": max_open_drafts_per_page,
                "threshold": page_pressure_threshold,
                "pages_over_limit": int(max(0, pages_over_open_draft_limit)),
                "top_pages": top_draft_pressure_pages[:3],
            }
        )
    if max_open_drafts_per_entity > draft_flood_max_open_per_entity:
        pressure_warnings.append(
            {
                "code": "draft_flood_entity_limit",
                "severity": "critical",
                "message": "An entity has too many open drafts; noisy stream is dominating wiki synthesis.",
                "max_open_drafts_per_entity": max_open_drafts_per_entity,
                "threshold": draft_flood_max_open_per_entity,
                "entities_over_limit": int(max(0, entities_over_open_draft_limit)),
                "top_entities": top_draft_pressure_entities[:3],
            }
        )

    events_to_claims_conversion = _stage_ratio(int(stages[1]["count"]), int(stages[2]["count"]))
    now_utc = datetime.now(UTC)
    first_event_age_minutes: float | None = None
    if first_event_at is not None:
        first_event_age_minutes = round(
            max(0.0, (now_utc - first_event_at).total_seconds() / 60.0),
            2,
        )
    claims_floor_triggered = bool(
        int(events_total) >= int(claims_floor_min_events)
        and int(claims_total) == 0
        and first_event_age_minutes is not None
        and float(first_event_age_minutes) >= float(claims_floor_alert_after_minutes)
    )
    if claims_floor_triggered:
        pressure_warnings.append(
            {
                "code": "events_claims_zero_floor",
                "severity": "critical",
                "message": (
                    "Events are flowing but no claims were generated within the floor window."
                ),
                "events": int(events_total),
                "claims": int(claims_total),
                "min_events": int(claims_floor_min_events),
                "alert_after_minutes": int(claims_floor_alert_after_minutes),
                "observed_age_minutes": float(first_event_age_minutes or 0.0),
                "next_action": "run_adoption_rejections_diagnostics_and_relax_high_signal_thresholds",
            }
        )

    def _counter_items(counter: dict[str, int], *, limit: int = 12) -> list[dict[str, Any]]:
        total = max(0, sum(int(value or 0) for value in counter.values()))
        rows: list[dict[str, Any]] = []
        for key, count in sorted(counter.items(), key=lambda item: (-int(item[1] or 0), str(item[0]))):
            value = int(count or 0)
            if value <= 0:
                continue
            rows.append(
                {
                    "reason": str(key),
                    "count": value,
                    "share": round(float(value) / float(max(1, total)), 4),
                }
            )
            if len(rows) >= max(1, int(limit)):
                break
        return rows

    return {
        "project_id": project_id,
        "window_days": int(days),
        "since": cutoff.isoformat(),
        "generated_at": datetime.now(UTC).isoformat(),
        "filters_applied": {
            "source_systems": source_filters,
            "namespaces": namespace_filters,
        },
        "pipeline": {
            "accepted": int(stages[0]["count"]),
            "events": int(stages[1]["count"]),
            "claims": int(stages[2]["count"]),
            "drafts": int(stages[3]["count"]),
            "pages": int(stages[4]["count"]),
        },
        "accepted_source": accepted_source,
        "rejected_event_like": int(max(0, rejected_event_like)),
        "signal_noise_ratio": {
            "signal_claims_per_rejected_event": round(
                float(max(0, claims_total)) / float(max(1, int(max(0, rejected_event_like)))),
                4,
            ),
            "signal_claims_per_event": round(
                float(max(0, claims_total)) / float(max(1, int(max(0, events_total)))),
                4,
            ),
        },
        "extraction": {
            "kept_durable": int(max(0, kept_durable)),
            "trusted_bypass": int(max(0, trusted_bypass)),
            "drop_reasons": _counter_items(extraction_drop_reasons, limit=20),
            "keep_reasons": _counter_items(extraction_keep_reasons, limit=20),
            "drop_reasons_total": int(max(0, sum(int(v or 0) for v in extraction_drop_reasons.values()))),
            "keep_reasons_total": int(max(0, sum(int(v or 0) for v in extraction_keep_reasons.values()))),
        },
        "claims_floor_guard": {
            "min_events": int(claims_floor_min_events),
            "alert_after_minutes": int(claims_floor_alert_after_minutes),
            "min_conversion_ratio": float(claims_floor_min_conversion_ratio),
            "events_total": int(events_total),
            "claims_total": int(claims_total),
            "events_to_claims_conversion": events_to_claims_conversion,
            "first_event_at": first_event_at.isoformat() if first_event_at is not None else None,
            "last_event_at": last_event_at.isoformat() if last_event_at is not None else None,
            "first_event_age_minutes": first_event_age_minutes,
            "triggered": claims_floor_triggered,
        },
        "conversions": {
            "accepted_to_events": _stage_ratio(int(stages[0]["count"]), int(stages[1]["count"])),
            "events_to_claims": events_to_claims_conversion,
            "claims_to_drafts": _stage_ratio(int(stages[2]["count"]), int(stages[3]["count"])),
            "drafts_to_pages": _stage_ratio(int(stages[3]["count"]), int(stages[4]["count"])),
        },
        "draft_queue": {
            "pending_review": queue_pending_review,
            "blocked_conflict": queue_blocked_conflict,
            "open_total": queue_open_total,
        },
        "draft_flood_guard": {
            "thresholds": {
                "max_open_per_page": int(draft_flood_max_open_per_page),
                "max_open_per_entity": int(draft_flood_max_open_per_entity),
                "safe_mode_open_drafts_threshold": int(queue_pressure_open_drafts_threshold),
                "safe_mode_open_drafts_per_page_threshold": int(queue_pressure_open_drafts_per_page_threshold),
            },
            "max_open_per_page": int(max_open_drafts_per_page),
            "max_open_per_entity": int(max_open_drafts_per_entity),
            "pages_over_limit": int(max(0, pages_over_open_draft_limit)),
            "entities_over_limit": int(max(0, entities_over_open_draft_limit)),
            "top_pages": top_draft_pressure_pages,
            "top_entities": top_draft_pressure_entities,
        },
        "page_channels": {
            "from_moderation": int(pages_from_moderation),
            "from_published_total": int(pages_from_published),
            "from_published_window": int(pages_from_published_window),
            "scope_limited": bool(source_filters or namespace_filters),
            "scope_note": (
                "Published fallback includes project-level pages without evidence attribution."
                if source_filters or namespace_filters
                else "Project-wide page counts."
            ),
        },
        "stages": stages,
        "transitions": transitions,
        "bottleneck": bottleneck,
        "warnings": pressure_warnings,
    }


