@app.get("/v1/adoption/kpi")
def get_adoption_kpi(
    project_id: str,
    days: int = Query(default=30, ge=1, le=180),
) -> dict[str, Any]:
    cutoff = datetime.now(UTC) - timedelta(days=days)
    first_ingest_at: datetime | None = None
    first_draft_at: datetime | None = None
    first_publish_at: datetime | None = None
    publish_total = 0
    rollback_total = 0

    pipeline = get_adoption_pipeline_visibility(project_id=project_id, days=days)
    accepted_total = int((pipeline.get("pipeline") or {}).get("accepted") or 0)
    rejected_event_like = int(pipeline.get("rejected_event_like") or 0)
    wiki_quality = get_adoption_wiki_quality_report(project_id=project_id, days=min(days, 90))
    richness_benchmark = get_adoption_wiki_richness_benchmark(project_id=project_id, days=min(days, 90))

    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT MIN(observed_at)
                FROM events
                WHERE project_id = %s
                  AND event_type = 'memory_backfill'
                """,
                (project_id,),
            )
            row = cur.fetchone()
            if row and row[0] is not None:
                first_ingest_at = row[0]

            if _public_table_exists(conn, "wiki_draft_changes"):
                cur.execute(
                    """
                    SELECT MIN(created_at)
                    FROM wiki_draft_changes
                    WHERE project_id = %s
                    """,
                    (project_id,),
                )
                row = cur.fetchone()
                if row and row[0] is not None:
                    first_draft_at = row[0]

            if _public_table_exists(conn, "moderation_actions"):
                cur.execute(
                    """
                    SELECT MIN(created_at)
                    FROM moderation_actions
                    WHERE project_id = %s
                      AND action_type = 'approve'
                    """,
                    (project_id,),
                )
                row = cur.fetchone()
                if row and row[0] is not None:
                    first_publish_at = row[0]

                cur.execute(
                    """
                    SELECT COUNT(*)::bigint
                    FROM moderation_actions
                    WHERE project_id = %s
                      AND action_type = 'approve'
                      AND created_at >= %s
                    """,
                    (project_id, cutoff),
                )
                row = cur.fetchone()
                publish_total = int(row[0] or 0) if row else 0

            if _public_table_exists(conn, "wiki_page_versions"):
                cur.execute(
                    """
                    SELECT COUNT(*)::bigint
                    FROM wiki_page_versions page_versions
                    JOIN wiki_pages pages ON pages.id = page_versions.page_id
                    WHERE pages.project_id = %s
                      AND page_versions.created_at >= %s
                      AND (
                        LOWER(COALESCE(page_versions.change_summary, '')) LIKE 'rollback to version%%'
                        OR LOWER(COALESCE(page_versions.change_summary, '')) LIKE 'rollback%%'
                      )
                    """,
                    (project_id, cutoff),
                )
                row = cur.fetchone()
                rollback_total = int(row[0] or 0) if row else 0

    def _seconds_between(start: datetime | None, end: datetime | None) -> int | None:
        if start is None or end is None:
            return None
        delta = end - start
        return max(0, int(delta.total_seconds()))

    time_to_first_draft = _seconds_between(first_ingest_at, first_draft_at)
    time_to_first_publish = _seconds_between(first_ingest_at, first_publish_at)
    draft_noise_ratio = round(float(rejected_event_like) / float(max(accepted_total, 1)), 4)
    publish_revert_rate = round(float(rollback_total) / float(max(publish_total, 1)), 4)

    alert_thresholds = {
        "time_to_first_draft_max_sec": 6 * 3600,
        "time_to_first_publish_max_sec": 24 * 3600,
        "draft_noise_ratio_max": 0.35,
        "publish_revert_rate_max": 0.08,
    }
    alerts: list[dict[str, Any]] = []
    if time_to_first_draft is not None and time_to_first_draft > alert_thresholds["time_to_first_draft_max_sec"]:
        alerts.append(
            {
                "metric": "time_to_first_draft",
                "status": "warning",
                "value_sec": time_to_first_draft,
                "threshold_sec": alert_thresholds["time_to_first_draft_max_sec"],
                "hint": "Backfill is not yielding drafts quickly; run curated dry-run explain and adjust source/noise filters.",
            }
        )
    if time_to_first_publish is not None and time_to_first_publish > alert_thresholds["time_to_first_publish_max_sec"]:
        alerts.append(
            {
                "metric": "time_to_first_publish",
                "status": "warning",
                "value_sec": time_to_first_publish,
                "threshold_sec": alert_thresholds["time_to_first_publish_max_sec"],
                "hint": "Moderation path is slow; use bootstrap recommendation and queue diagnostics.",
            }
        )
    if draft_noise_ratio > alert_thresholds["draft_noise_ratio_max"]:
        alerts.append(
            {
                "metric": "draft_noise_ratio",
                "status": "warning",
                "value": draft_noise_ratio,
                "threshold": alert_thresholds["draft_noise_ratio_max"],
                "hint": "Draft noise is high; tighten backfill curation and event-shape suppression.",
            }
        )
    if publish_total >= 5 and publish_revert_rate > alert_thresholds["publish_revert_rate_max"]:
        alerts.append(
            {
                "metric": "publish_revert_rate",
                "status": "warning",
                "value": publish_revert_rate,
                "threshold": alert_thresholds["publish_revert_rate_max"],
                "hint": "Revert rate is elevated; enable stricter process simulation or human-required publish mode.",
            }
        )
    wiki_quality_checks = wiki_quality.get("quality", {}).get("checks") if isinstance(wiki_quality.get("quality"), dict) else {}
    if not bool((wiki_quality.get("quality") or {}).get("pass")):
        alerts.append(
            {
                "metric": "wiki_quality",
                "status": "warning",
                "value": bool((wiki_quality.get("quality") or {}).get("pass")),
                "hint": "Core wiki quality gates are not met; inspect /v1/adoption/wiki-quality/report for actionable gaps.",
                "checks": wiki_quality_checks,
            }
        )
    if not bool(richness_benchmark.get("pass")):
        alerts.append(
            {
                "metric": "wiki_richness_benchmark",
                "status": "warning",
                "value": bool(richness_benchmark.get("pass")),
                "hint": "Core pages are present but still too shallow or structurally incomplete; inspect /v1/adoption/wiki-richness/benchmark.",
                "checks": richness_benchmark.get("checks"),
                "scores": richness_benchmark.get("scores"),
            }
        )

    return {
        "project_id": project_id,
        "window_days": int(days),
        "generated_at": datetime.now(UTC).isoformat(),
        "kpi": {
            "time_to_first_draft_sec": time_to_first_draft,
            "time_to_first_publish_sec": time_to_first_publish,
            "draft_noise_ratio": draft_noise_ratio,
            "publish_revert_rate": publish_revert_rate,
        },
        "supporting": {
            "first_ingest_at": first_ingest_at.isoformat() if first_ingest_at is not None else None,
            "first_draft_at": first_draft_at.isoformat() if first_draft_at is not None else None,
            "first_publish_at": first_publish_at.isoformat() if first_publish_at is not None else None,
            "accepted_records": accepted_total,
            "rejected_event_like": rejected_event_like,
            "publish_total_window": publish_total,
            "rollback_total_window": rollback_total,
        },
        "thresholds": alert_thresholds,
        "alerts": alerts,
        "wiki_quality": wiki_quality,
        "wiki_richness_benchmark": richness_benchmark,
    }


def _build_adoption_policy_calibration_quick_recommendation(
    *,
    project_id: str,
    days: int = 14,
) -> dict[str, Any]:
    diagnostics = get_adoption_rejection_diagnostics(project_id=project_id, days=days, sample_limit=8)
    pipeline = get_adoption_pipeline_visibility(project_id=project_id, days=days)
    config_payload = get_gatekeeper_config(project_id=project_id)
    current_config = config_payload.get("config") if isinstance(config_payload.get("config"), dict) else {}
    current_routing = _normalize_gatekeeper_routing_policy(current_config.get("routing_policy"))

    reason_counts = {
        str(item.get("key") or ""): int(item.get("count") or 0)
        for item in (diagnostics.get("top_reject_reasons") if isinstance(diagnostics.get("top_reject_reasons"), list) else [])
        if str(item.get("key") or "").strip()
    }
    rejected_total = int((diagnostics.get("summary") or {}).get("rejected_total") or 0)
    event_pressure = (
        reason_counts.get("event_stream_shape", 0)
        + reason_counts.get("runtime_noise", 0)
        + reason_counts.get("blocked_source_type", 0)
        + reason_counts.get("blocked_source_system", 0)
    )
    support_pressure = reason_counts.get("insufficient_support", 0) + reason_counts.get("backfill_without_durable_signal", 0)
    event_pressure_ratio = float(event_pressure) / float(max(rejected_total, 1))
    support_pressure_ratio = float(support_pressure) / float(max(rejected_total, 1))

    bottleneck = pipeline.get("bottleneck") if isinstance(pipeline.get("bottleneck"), dict) else {}
    bottleneck_key = (
        str(bottleneck.get("from_stage") or "").strip().lower(),
        str(bottleneck.get("to_stage") or "").strip().lower(),
    )
    bottleneck_drop_ratio = float(bottleneck.get("drop_ratio") or 0.0)
    rejected_event_like = int(pipeline.get("rejected_event_like") or 0)
    accepted = int((pipeline.get("pipeline") or {}).get("accepted") or 0)
    event_like_ratio = float(rejected_event_like) / float(max(accepted, 1))

    presets: dict[str, dict[str, Any]] = {}
    presets["noise_guarded"] = {
        "preset_key": "noise_guarded",
        "title": "Noise-guarded routing",
        "reason": "Event-like payloads dominate rejected claims.",
        "routing_policy_patch": {
            "event_stream_min_token_hits": max(2, min(8, int(current_routing.get("event_stream_min_token_hits") or 2) + 1)),
            "event_stream_min_kv_hits": max(2, min(8, int(current_routing.get("event_stream_min_kv_hits") or 2) + 1)),
            "min_durable_signal_hits_for_backfill": max(
                2,
                min(10, int(current_routing.get("min_durable_signal_hits_for_backfill") or 1)),
            ),
            "backfill_requires_policy_signal": True,
            "ingestion_classification_default_deny_classes": ["operational_stream", "pii_sensitive_stream"],
            "operational_stream_keywords": [
                "wand_employee",
                "wand_transport_vehicle",
                "_sheet_",
                "order_snapshot",
                "invoice_snapshot",
                "telemetry",
                "event_stream",
            ],
            "durable_signal_keywords": [
                "business_rule",
                "company_operating_model",
                "logistics_kpi_framework",
                *list(current_routing.get("durable_signal_keywords") or []),
            ],
        },
    }
    presets["bootstrap_relaxed"] = {
        "preset_key": "bootstrap_relaxed",
        "title": "Bootstrap-relaxed routing",
        "reason": "Claims are blocked before draft stage due to strict durable-signal gates.",
        "routing_policy_patch": {
            "min_durable_signal_hits_for_backfill": max(
                0,
                int(current_routing.get("min_durable_signal_hits_for_backfill") or 1) - 1,
            ),
            "min_sources_for_wiki_candidate": max(
                1,
                int(current_routing.get("min_sources_for_wiki_candidate") or 2) - 1,
            ),
            "min_evidence_for_wiki_candidate": max(
                1,
                int(current_routing.get("min_evidence_for_wiki_candidate") or 2) - 1,
            ),
            "backfill_requires_policy_signal": False,
        },
    }
    presets["balanced"] = {
        "preset_key": "balanced",
        "title": "Balanced calibration",
        "reason": "No single dominant failure mode; apply conservative tuning.",
        "routing_policy_patch": {
            "event_stream_min_token_hits": max(2, min(6, int(current_routing.get("event_stream_min_token_hits") or 2))),
            "event_stream_min_kv_hits": max(2, min(6, int(current_routing.get("event_stream_min_kv_hits") or 2))),
            "min_durable_signal_hits_for_backfill": max(
                1,
                min(6, int(current_routing.get("min_durable_signal_hits_for_backfill") or 1)),
            ),
        },
    }

    recommended_key = "balanced"
    if event_pressure_ratio >= 0.35 or event_like_ratio >= 0.35:
        recommended_key = "noise_guarded"
    elif bottleneck_key == ("claims", "drafts") and (
        support_pressure_ratio >= 0.3 or bottleneck_drop_ratio >= 0.25
    ):
        recommended_key = "bootstrap_relaxed"

    recommended = presets.get(recommended_key, presets["balanced"])
    target_routing = _normalize_gatekeeper_routing_policy(
        _deep_merge_dict(current_routing, recommended.get("routing_policy_patch") or {})
    )
    changed_keys = [
        key
        for key in sorted(target_routing.keys())
        if target_routing.get(key) != current_routing.get(key)
    ]

    return {
        "project_id": project_id,
        "window_days": int(days),
        "generated_at": datetime.now(UTC).isoformat(),
        "recommended": {
            **recommended,
            "changed_routing_keys": changed_keys,
        },
        "presets": list(presets.values()),
        "inputs": {
            "event_pressure_ratio": round(event_pressure_ratio, 4),
            "support_pressure_ratio": round(support_pressure_ratio, 4),
            "event_like_ratio": round(event_like_ratio, 4),
            "bottleneck": bottleneck if isinstance(bottleneck, dict) else None,
        },
        "current_routing_policy": current_routing,
        "target_routing_policy": target_routing,
        "diagnostics": diagnostics,
        "pipeline": pipeline,
    }


def _has_critical_adoption_warnings(warnings: list[dict[str, Any]]) -> bool:
    for item in warnings:
        if not isinstance(item, dict):
            continue
        if str(item.get("severity") or "").strip().lower() == "critical":
            return True
    return False


def _merge_adoption_warnings(
    existing: list[dict[str, Any]] | None,
    additional: list[dict[str, Any]] | None,
) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    seen: set[str] = set()
    for item in (existing or []) + (additional or []):
        if not isinstance(item, dict):
            continue
        code = str(item.get("code") or "").strip().lower()
        message = str(item.get("message") or "").strip().lower()
        key = f"{code}|{message}"
        if key in seen:
            continue
        seen.add(key)
        out.append(dict(item))
    return out


def _build_adoption_pipeline_pressure_warnings(pipeline_visibility: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not isinstance(pipeline_visibility, dict):
        return []

    claims_floor_guard = (
        pipeline_visibility.get("claims_floor_guard")
        if isinstance(pipeline_visibility.get("claims_floor_guard"), dict)
        else {}
    )
    draft_queue = pipeline_visibility.get("draft_queue") if isinstance(pipeline_visibility.get("draft_queue"), dict) else {}
    draft_flood_guard = (
        pipeline_visibility.get("draft_flood_guard")
        if isinstance(pipeline_visibility.get("draft_flood_guard"), dict)
        else {}
    )
    thresholds = draft_flood_guard.get("thresholds") if isinstance(draft_flood_guard.get("thresholds"), dict) else {}

    queue_open_total = int(draft_queue.get("open_total") or 0)
    queue_threshold = int(thresholds.get("safe_mode_open_drafts_threshold") or 5000)
    max_open_per_page = int(draft_flood_guard.get("max_open_per_page") or 0)
    max_open_per_entity = int(draft_flood_guard.get("max_open_per_entity") or 0)
    max_open_page_threshold = int(thresholds.get("safe_mode_open_drafts_per_page_threshold") or 200)
    max_open_entity_threshold = int(thresholds.get("max_open_per_entity") or 400)

    warnings: list[dict[str, Any]] = []
    if queue_open_total > queue_threshold:
        warnings.append(
            {
                "code": "draft_queue_pressure",
                "severity": "critical",
                "message": "Open draft queue is above safe OOTB threshold.",
                "open_drafts_total": queue_open_total,
                "threshold": queue_threshold,
                "next_action": "enable_adoption_safe_mode",
            }
        )
    if max_open_per_page > max_open_page_threshold:
        warnings.append(
            {
                "code": "draft_flood_page_limit",
                "severity": "critical",
                "message": "Single wiki page exceeded safe open-draft threshold.",
                "max_open_per_page": max_open_per_page,
                "threshold": max_open_page_threshold,
                "next_action": "tighten_high_signal_routing",
            }
        )
    if max_open_per_entity > max_open_entity_threshold:
        warnings.append(
            {
                "code": "draft_flood_entity_limit",
                "severity": "critical",
                "message": "Single entity exceeded safe open-draft threshold.",
                "max_open_per_entity": max_open_per_entity,
                "threshold": max_open_entity_threshold,
                "next_action": "tighten_high_signal_routing",
            }
        )
    if bool(claims_floor_guard.get("triggered")):
        warnings.append(
            {
                "code": "events_claims_zero_floor",
                "severity": "critical",
                "message": "Events are accumulating but claims remain zero beyond floor threshold.",
                "events": int(claims_floor_guard.get("events_total") or 0),
                "claims": int(claims_floor_guard.get("claims_total") or 0),
                "min_events": int(claims_floor_guard.get("min_events") or 0),
                "alert_after_minutes": int(claims_floor_guard.get("alert_after_minutes") or 0),
                "next_action": "inspect_extraction_drop_reasons_and_relax_high_signal_lane",
            }
        )
    else:
        conversion = claims_floor_guard.get("events_to_claims_conversion")
        min_conversion = float(claims_floor_guard.get("min_conversion_ratio") or 0.0)
        events_total = int(claims_floor_guard.get("events_total") or 0)
        if conversion is not None and events_total >= int(claims_floor_guard.get("min_events") or 0):
            conversion_value = float(conversion)
            if conversion_value < min_conversion:
                warnings.append(
                    {
                        "code": "events_claims_low_conversion",
                        "severity": "warning",
                        "message": "Events→claims conversion is below configured floor.",
                        "conversion": conversion_value,
                        "min_conversion_ratio": min_conversion,
                        "events": events_total,
                        "next_action": "review_high_signal_keywords_or_backfill_classifier",
                    }
                )
    return warnings


def _build_adoption_sync_explainability(
    *,
    warnings: list[dict[str, Any]],
    pipeline_visibility: dict[str, Any] | None,
    rejection_diagnostics: dict[str, Any] | None,
) -> dict[str, Any]:
    top_reasons = (
        rejection_diagnostics.get("top_reject_reasons")
        if isinstance(rejection_diagnostics, dict) and isinstance(rejection_diagnostics.get("top_reject_reasons"), list)
        else []
    )
    extraction = (
        pipeline_visibility.get("extraction")
        if isinstance(pipeline_visibility, dict) and isinstance(pipeline_visibility.get("extraction"), dict)
        else {}
    )
    extraction_drop_reasons = (
        extraction.get("drop_reasons")
        if isinstance(extraction.get("drop_reasons"), list)
        else []
    )
    reason_counts: dict[str, int] = {}
    for item in top_reasons:
        if not isinstance(item, dict):
            continue
        key = str(item.get("key") or "").strip().lower()
        if not key:
            continue
        reason_counts[key] = int(item.get("count") or 0)
    for item in extraction_drop_reasons:
        if not isinstance(item, dict):
            continue
        key = str(item.get("reason") or "").strip().lower()
        if not key:
            continue
        reason_counts[key] = int(reason_counts.get(key, 0)) + int(item.get("count") or 0)
    total_rejections = int(
        (rejection_diagnostics or {}).get("summary", {}).get("rejected_total", 0)
        if isinstance((rejection_diagnostics or {}).get("summary"), dict)
        else 0
    )

    classification_count = sum(count for key, count in reason_counts.items() if key.startswith("classification:"))
    quality_gate_tags = {
        "event_stream_shape",
        "insufficient_support",
        "backfill_without_durable_signal",
        "runtime_noise",
        "event_like_low_signal",
        "event_transport_low_signal",
        "worker_exception",
    }
    routing_policy_tags = {
        "ingestion_default_deny",
        "blocked_source_id",
        "blocked_source_type",
        "blocked_source_system",
        "blocked_category",
        "blocked_entity",
        "routing_hard_block",
        "ingestion_classification:operational_stream",
        "ingestion_classification:pii_sensitive_stream",
    }
    quality_gate_count = sum(count for key, count in reason_counts.items() if key in quality_gate_tags)
    routing_policy_count = sum(count for key, count in reason_counts.items() if key in routing_policy_tags)

    critical_warnings = [
        item
        for item in warnings
        if isinstance(item, dict) and str(item.get("severity") or "").strip().lower() == "critical"
    ]
    warning_codes = [
        str(item.get("code") or "").strip().lower()
        for item in warnings
        if isinstance(item, dict) and str(item.get("code") or "").strip()
    ]
    runtime_guard_count = len(warning_codes)

    stages = (
        pipeline_visibility.get("pipeline")
        if isinstance(pipeline_visibility, dict) and isinstance(pipeline_visibility.get("pipeline"), dict)
        else {}
    )
    accepted = int(stages.get("accepted") or 0)
    claims = int(stages.get("claims") or 0)
    drafts = int(stages.get("drafts") or 0)
    pages = int(stages.get("pages") or 0)
    claims_gap = max(0, accepted - claims)
    draft_gap = max(0, claims - drafts)
    publish_gap = max(0, drafts - pages)

    bucket_counts = {
        "quality_gate": quality_gate_count,
        "routing_policy": routing_policy_count,
        "classification": classification_count,
        "runtime_guardrails": runtime_guard_count,
    }
    bucket_total = sum(bucket_counts.values())

    def _top_tags(keys: set[str], *, prefix: str | None = None, limit: int = 3) -> list[str]:
        selected: list[tuple[str, int]] = []
        for key, count in reason_counts.items():
            if prefix and key.startswith(prefix):
                selected.append((key, count))
                continue
            if key in keys:
                selected.append((key, count))
        selected.sort(key=lambda item: (-item[1], item[0]))
        return [item[0] for item in selected[:limit]]

    reason_buckets = {
        "quality_gate": {
            "count": int(quality_gate_count),
            "share": round(float(quality_gate_count / bucket_total), 4) if bucket_total > 0 else 0.0,
            "top_tags": _top_tags(quality_gate_tags),
        },
        "routing_policy": {
            "count": int(routing_policy_count),
            "share": round(float(routing_policy_count / bucket_total), 4) if bucket_total > 0 else 0.0,
            "top_tags": _top_tags(routing_policy_tags),
        },
        "classification": {
            "count": int(classification_count),
            "share": round(float(classification_count / bucket_total), 4) if bucket_total > 0 else 0.0,
            "top_tags": _top_tags(set(), prefix="classification:"),
        },
        "runtime_guardrails": {
            "count": int(runtime_guard_count),
            "share": round(float(runtime_guard_count / bucket_total), 4) if bucket_total > 0 else 0.0,
            "top_tags": warning_codes[:3],
        },
    }

    primary_bucket = max(reason_buckets.items(), key=lambda item: int((item[1] or {}).get("count") or 0))[0]
    if int((reason_buckets.get(primary_bucket) or {}).get("count") or 0) <= 0:
        primary_bucket = "none"

    return {
        "status": "ok",
        "generated_at": datetime.now(UTC).isoformat(),
        "summary": {
            "total_rejections": int(total_rejections),
            "critical_warnings": len(critical_warnings),
            "primary_bucket": primary_bucket,
        },
        "reason_buckets": reason_buckets,
        "pipeline_gap": {
            "accepted_to_claims": claims_gap,
            "claims_to_drafts": draft_gap,
            "drafts_to_pages": publish_gap,
        },
    }


def _build_adoption_safe_mode_target_config(*, current_config: dict[str, Any]) -> dict[str, Any]:
    current_routing = _normalize_gatekeeper_routing_policy(current_config.get("routing_policy"))
    routing_patch = {
        "event_stream_min_token_hits": max(3, int(current_routing.get("event_stream_min_token_hits") or 2)),
        "event_stream_min_kv_hits": max(3, int(current_routing.get("event_stream_min_kv_hits") or 2)),
        "min_durable_signal_hits_for_backfill": max(
            2,
            int(current_routing.get("min_durable_signal_hits_for_backfill") or 1),
        ),
        "min_sources_for_wiki_candidate": max(
            2,
            int(current_routing.get("min_sources_for_wiki_candidate") or 2),
        ),
        "min_evidence_for_wiki_candidate": max(
            2,
            int(current_routing.get("min_evidence_for_wiki_candidate") or 2),
        ),
        "backfill_requires_policy_signal": True,
        "emit_reinforcement_drafts": False,
        "draft_flood_max_open_per_page": min(
            200,
            max(100, int(current_routing.get("draft_flood_max_open_per_page") or 200)),
        ),
        "draft_flood_max_open_per_entity": min(
            400,
            max(150, int(current_routing.get("draft_flood_max_open_per_entity") or 400)),
        ),
        "queue_pressure_safe_mode_open_drafts_threshold": min(
            5000,
            max(500, int(current_routing.get("queue_pressure_safe_mode_open_drafts_threshold") or 5000)),
        ),
        "queue_pressure_safe_mode_open_drafts_per_page_threshold": min(
            200,
            max(80, int(current_routing.get("queue_pressure_safe_mode_open_drafts_per_page_threshold") or 200)),
        ),
        "ingestion_classification_default_deny_classes": ["operational_stream", "pii_sensitive_stream"],
        "publish_mode_by_assertion_class": {
            "policy": "human_required",
            "process": "human_required",
            "preference": "conditional",
            "incident": "human_required",
            "event": "human_required",
            "fact": "human_required",
        },
    }
    target_routing = _normalize_gatekeeper_routing_policy(_deep_merge_dict(current_routing, routing_patch))
    changed_routing_keys = [
        key for key in sorted(target_routing.keys()) if target_routing.get(key) != current_routing.get(key)
    ]
    current_publish_mode_by_category = (
        current_config.get("publish_mode_by_category")
        if isinstance(current_config.get("publish_mode_by_category"), dict)
        else {}
    )
    target_publish_mode_by_category = dict(current_publish_mode_by_category)
    for key in ("policy", "process", "runbook", "incident", "compliance", "security"):
        target_publish_mode_by_category[key] = "human_required"

    target_config = {
        "publish_mode_default": "human_required",
        "publish_mode_by_category": target_publish_mode_by_category,
        "auto_publish_min_score": max(0.95, float(current_config.get("auto_publish_min_score", 0.9))),
        "auto_publish_min_sources": max(3, int(current_config.get("auto_publish_min_sources", 3))),
        "auto_publish_require_golden": True,
        "auto_publish_allow_conflicts": False,
        "routing_policy": target_routing,
    }
    changed_config_keys = [
        key
        for key in sorted(target_config.keys())
        if target_config.get(key) != current_config.get(key)
    ]
    return {
        "current_routing_policy": current_routing,
        "target_routing_policy": target_routing,
        "target_config": target_config,
        "changed_routing_keys": changed_routing_keys,
        "changed_config_keys": changed_config_keys,
    }


@app.post("/v1/adoption/safe-mode/enable", response_model=None)
def enable_adoption_safe_mode(payload: AdoptionSafeModeEnableRequest) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")
    if not payload.dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if confirm_value != project_id:
            raise HTTPException(status_code=422, detail="confirm_project_id_mismatch")

    current_config_payload = get_gatekeeper_config(project_id=project_id)
    current_config = (
        current_config_payload.get("config") if isinstance(current_config_payload.get("config"), dict) else {}
    )
    target_payload = _build_adoption_safe_mode_target_config(current_config=current_config)
    response: dict[str, Any] = {
        "status": "dry_run" if payload.dry_run else "applied",
        "project_id": project_id,
        "changed_routing_keys": target_payload.get("changed_routing_keys"),
        "changed_config_keys": target_payload.get("changed_config_keys"),
        "current_routing_policy": target_payload.get("current_routing_policy"),
        "target_routing_policy": target_payload.get("target_routing_policy"),
        "target_config": target_payload.get("target_config"),
        "generated_at": datetime.now(UTC).isoformat(),
    }
    if payload.dry_run:
        response["next_action"] = "rerun_with_dry_run=false_and_confirm_project_id"
        return response

    snapshot_payload = create_gatekeeper_config_snapshot(
        GatekeeperConfigSnapshotCreateRequest(
            project_id=project_id,
            approved_by=payload.updated_by,
            source="manual",
            note=payload.note or "Auto safe mode snapshot before strict governance apply.",
            config=current_config,
            guardrails_met=True,
            calibration_report={
                "safe_mode": True,
                "changed_routing_keys": target_payload.get("changed_routing_keys"),
                "changed_config_keys": target_payload.get("changed_config_keys"),
            },
            artifact_refs={"safe_mode_endpoint": "/v1/adoption/safe-mode/enable"},
        )
    )
    snapshot = snapshot_payload.get("snapshot") if isinstance(snapshot_payload.get("snapshot"), dict) else {}
    target_config = target_payload.get("target_config") if isinstance(target_payload.get("target_config"), dict) else {}

    updated = upsert_gatekeeper_config(
        GatekeeperConfigUpsertRequest(
            project_id=project_id,
            updated_by=payload.updated_by,
            min_sources_for_golden=int(current_config.get("min_sources_for_golden", 3)),
            conflict_free_days=int(current_config.get("conflict_free_days", 7)),
            min_score_for_golden=float(current_config.get("min_score_for_golden", 0.72)),
            operational_short_text_len=int(current_config.get("operational_short_text_len", 32)),
            operational_short_token_len=int(current_config.get("operational_short_token_len", 5)),
            llm_assist_enabled=bool(current_config.get("llm_assist_enabled", False)),
            llm_provider=str(current_config.get("llm_provider", "openai")),
            llm_model=str(current_config.get("llm_model", "gpt-4.1-mini")),
            llm_score_weight=float(current_config.get("llm_score_weight", 0.35)),
            llm_min_confidence=float(current_config.get("llm_min_confidence", 0.65)),
            llm_timeout_ms=int(current_config.get("llm_timeout_ms", 3500)),
            publish_mode_default=str(target_config.get("publish_mode_default") or "human_required"),
            publish_mode_by_category=(
                target_config.get("publish_mode_by_category")
                if isinstance(target_config.get("publish_mode_by_category"), dict)
                else {}
            ),
            routing_policy=(
                target_config.get("routing_policy")
                if isinstance(target_config.get("routing_policy"), dict)
                else _normalize_gatekeeper_routing_policy(None)
            ),
            auto_publish_min_score=float(target_config.get("auto_publish_min_score") or 0.95),
            auto_publish_min_sources=int(target_config.get("auto_publish_min_sources") or 3),
            auto_publish_require_golden=bool(target_config.get("auto_publish_require_golden", True)),
            auto_publish_allow_conflicts=bool(target_config.get("auto_publish_allow_conflicts", False)),
        )
    )
    event_id = _append_operation_queue_control_event(
        project_id=project_id,
        action="adoption_safe_mode_applied",
        actor=str(payload.updated_by or "ops_admin"),
        reason=payload.note or "Adoption safe mode applied.",
        paused_until=None,
        payload={
            "snapshot_id": snapshot.get("id"),
            "changed_routing_keys": target_payload.get("changed_routing_keys"),
            "changed_config_keys": target_payload.get("changed_config_keys"),
            "target_config": target_config,
        },
    )
    response["snapshot_id"] = snapshot.get("id")
    response["audit_event_id"] = event_id
    response["applied_config"] = updated.get("config") if isinstance(updated, dict) else None
    return response


@app.get("/v1/adoption/policy-calibration/quick-loop")
def get_adoption_policy_calibration_quick_loop(
    project_id: str,
    days: int = Query(default=14, ge=1, le=90),
) -> dict[str, Any]:
    payload = _build_adoption_policy_calibration_quick_recommendation(project_id=project_id, days=days)
    payload["apply_endpoint"] = "/v1/adoption/policy-calibration/quick-loop/apply"
    payload["rollback_preview_endpoint"] = "/v1/gatekeeper/config/rollback/preview"
    return payload


@app.post("/v1/adoption/safe-mode/recommend", response_model=None)
def recommend_adoption_safe_mode(payload: AdoptionSafeModeRecommendRequest) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")
    if not payload.dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if confirm_value != project_id:
            raise HTTPException(status_code=422, detail="confirm_project_id_mismatch")

    monitor = _build_adoption_signal_noise_stability_monitor(
        project_id=project_id,
        days=int(payload.days),
        max_items_per_bucket=8,
    )
    response: dict[str, Any] = {
        "status": "dry_run" if payload.dry_run else "recorded",
        "project_id": project_id,
        "monitor": monitor,
        "generated_at": datetime.now(UTC).isoformat(),
    }
    if payload.dry_run:
        response["next_action"] = "rerun_with_dry_run=false_and_confirm_project_id"
        return response

    safe_mode = monitor.get("safe_mode") if isinstance(monitor.get("safe_mode"), dict) else {}
    event_id = _append_operation_queue_control_event(
        project_id=project_id,
        action="adoption_safe_mode_recommended",
        actor=str(payload.recommended_by or "ops_admin"),
        reason=payload.note or "Stability monitor recommended adoption safe mode.",
        paused_until=None,
        payload={
            "monitor_status": monitor.get("status"),
            "alerts": monitor.get("alerts"),
            "safe_mode": safe_mode,
            "summary": monitor.get("summary"),
            "days": int(payload.days),
        },
    )
    response["event_id"] = event_id
    return response


@app.post("/v1/adoption/policy-calibration/quick-loop/apply", response_model=None)
def apply_adoption_policy_calibration_quick_loop(payload: AdoptionPolicyCalibrationQuickApplyRequest) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")
    if not payload.dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if not confirm_value or confirm_value != project_id:
            raise HTTPException(
                status_code=422,
                detail={
                    "error": "policy_quick_apply_confirmation_required",
                    "message": "For non-dry-run apply, `confirm_project_id` must exactly match `project_id`.",
                    "project_id": project_id,
                },
            )

    quick = _build_adoption_policy_calibration_quick_recommendation(project_id=project_id, days=14)
    recommended = quick.get("recommended") if isinstance(quick.get("recommended"), dict) else {}
    presets = quick.get("presets") if isinstance(quick.get("presets"), list) else []
    selected_key = str(payload.preset_key or recommended.get("preset_key") or "").strip().lower()
    selected: dict[str, Any] | None = None
    for item in presets:
        if not isinstance(item, dict):
            continue
        if str(item.get("preset_key") or "").strip().lower() == selected_key:
            selected = item
            break
    if selected is None:
        raise HTTPException(
            status_code=422,
            detail={
                "error": "policy_quick_preset_invalid",
                "preset_key": selected_key,
                "allowed_presets": [
                    str(item.get("preset_key") or "")
                    for item in presets
                    if isinstance(item, dict) and str(item.get("preset_key") or "").strip()
                ],
            },
        )

    current_config_payload = get_gatekeeper_config(project_id=project_id)
    current_config = (
        current_config_payload.get("config") if isinstance(current_config_payload.get("config"), dict) else {}
    )
    current_routing = _normalize_gatekeeper_routing_policy(current_config.get("routing_policy"))
    patch = selected.get("routing_policy_patch") if isinstance(selected.get("routing_policy_patch"), dict) else {}
    target_routing = _normalize_gatekeeper_routing_policy(_deep_merge_dict(current_routing, patch))
    changed_keys = [key for key in sorted(target_routing.keys()) if current_routing.get(key) != target_routing.get(key)]

    response_base = {
        "project_id": project_id,
        "preset": selected,
        "changed_routing_keys": changed_keys,
        "current_routing_policy": current_routing,
        "target_routing_policy": target_routing,
        "rollback_preview_endpoint": "/v1/gatekeeper/config/rollback/preview",
        "generated_at": datetime.now(UTC).isoformat(),
    }
    if payload.dry_run:
        return {
            "status": "dry_run",
            **response_base,
            "next_action": "rerun_with_dry_run=false_and_confirm_project_id",
        }

    snapshot_payload = create_gatekeeper_config_snapshot(
        GatekeeperConfigSnapshotCreateRequest(
            project_id=project_id,
            approved_by=payload.updated_by,
            source="manual",
            note=payload.note or f"Quick policy calibration snapshot ({selected_key})",
            config=current_config,
            guardrails_met=True,
            calibration_report={
                "quick_loop": True,
                "preset_key": selected_key,
                "changed_routing_keys": changed_keys,
            },
            artifact_refs={
                "quick_loop_endpoint": "/v1/adoption/policy-calibration/quick-loop",
                "applied_at": datetime.now(UTC).isoformat(),
            },
        )
    )
    snapshot = snapshot_payload.get("snapshot") if isinstance(snapshot_payload.get("snapshot"), dict) else {}
    upsert_payload = GatekeeperConfigUpsertRequest(
        project_id=project_id,
        updated_by=payload.updated_by,
        min_sources_for_golden=int(current_config.get("min_sources_for_golden", 3)),
        conflict_free_days=int(current_config.get("conflict_free_days", 7)),
        min_score_for_golden=float(current_config.get("min_score_for_golden", 0.72)),
        operational_short_text_len=int(current_config.get("operational_short_text_len", 32)),
        operational_short_token_len=int(current_config.get("operational_short_token_len", 5)),
        llm_assist_enabled=bool(current_config.get("llm_assist_enabled", False)),
        llm_provider=str(current_config.get("llm_provider", "openai")),
        llm_model=str(current_config.get("llm_model", "gpt-4.1-mini")),
        llm_score_weight=float(current_config.get("llm_score_weight", 0.35)),
        llm_min_confidence=float(current_config.get("llm_min_confidence", 0.65)),
        llm_timeout_ms=int(current_config.get("llm_timeout_ms", 3500)),
        publish_mode_default=str(current_config.get("publish_mode_default", "auto_publish")),
        publish_mode_by_category=(
            current_config.get("publish_mode_by_category")
            if isinstance(current_config.get("publish_mode_by_category"), dict)
            else {}
        ),
        routing_policy=target_routing,
        auto_publish_min_score=float(current_config.get("auto_publish_min_score", 0.9)),
        auto_publish_min_sources=int(current_config.get("auto_publish_min_sources", 3)),
        auto_publish_require_golden=bool(current_config.get("auto_publish_require_golden", True)),
        auto_publish_allow_conflicts=bool(current_config.get("auto_publish_allow_conflicts", False)),
    )
    updated = upsert_gatekeeper_config(upsert_payload)
    return {
        "status": "applied",
        **response_base,
        "snapshot_id": snapshot.get("id"),
        "applied_config": updated.get("config") if isinstance(updated, dict) else None,
    }


@app.post("/v1/adoption/project-reset", response_model=None)
def run_adoption_project_reset(
    payload: AdoptionProjectResetRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    scopes = _normalize_adoption_project_reset_scopes(payload.scopes)
    requested_by = _normalize_source_system(payload.requested_by, default="ops_admin")
    reason = str(payload.reason or "").strip() or None
    reset_id = uuid4()

    if not payload.dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if not confirm_value or confirm_value != payload.project_id:
            raise HTTPException(
                status_code=422,
                detail={
                    "error": "project_reset_confirmation_required",
                    "message": "For non-dry-run reset, `confirm_project_id` must exactly match `project_id`.",
                    "project_id": payload.project_id,
                },
            )

    with get_conn() as conn:
        if not _adoption_project_resets_table_exists(conn):
            raise HTTPException(
                status_code=503,
                detail={
                    "error": "adoption_project_reset_unavailable",
                    "message": "adoption_project_resets table is not available. Apply migration 056_adoption_project_resets.sql.",
                },
            )
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/project-reset",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        preview: dict[str, Any] = {}
        deleted_tables: dict[str, int] = {}
        try:
            preview = _collect_adoption_project_reset_preview(
                conn,
                project_id=payload.project_id,
                scopes=scopes,
                cascade_cleanup_orphan_draft_pages=bool(payload.cascade_cleanup_orphan_draft_pages),
            )
            if payload.dry_run:
                _insert_adoption_project_reset_audit(
                    conn,
                    reset_id=reset_id,
                    project_id=payload.project_id,
                    requested_by=requested_by,
                    reason=reason,
                    scopes=scopes,
                    dry_run=True,
                    status="dry_run",
                    rows_preview=preview,
                    rows_deleted={},
                )
                response = {
                    "status": "dry_run",
                    "reset_id": str(reset_id),
                    "project_id": payload.project_id,
                    "requested_by": requested_by,
                    "scopes": scopes,
                    "cascade_cleanup_orphan_draft_pages": bool(payload.cascade_cleanup_orphan_draft_pages),
                    "preview": preview,
                    "next_action": "rerun_with_dry_run=false_and_confirm_project_id",
                }
                mark_request_completed(
                    conn,
                    endpoint="/v1/adoption/project-reset",
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response

            deleted_tables = _apply_adoption_project_reset(
                conn,
                project_id=payload.project_id,
                scopes=scopes,
                cascade_cleanup_orphan_draft_pages=bool(payload.cascade_cleanup_orphan_draft_pages),
            )
            deleted_total = int(sum(int(value) for value in deleted_tables.values()))
            _insert_adoption_project_reset_audit(
                conn,
                reset_id=reset_id,
                project_id=payload.project_id,
                requested_by=requested_by,
                reason=reason,
                scopes=scopes,
                dry_run=False,
                status="completed",
                rows_preview=preview,
                rows_deleted={"rows_total": deleted_total, "tables": deleted_tables},
            )
            response = {
                "status": "completed",
                "reset_id": str(reset_id),
                "project_id": payload.project_id,
                "requested_by": requested_by,
                "scopes": scopes,
                "cascade_cleanup_orphan_draft_pages": bool(payload.cascade_cleanup_orphan_draft_pages),
                "preview": preview,
                "deleted": {"rows_total": deleted_total, "tables": deleted_tables},
            }
            mark_request_completed(
                conn,
                endpoint="/v1/adoption/project-reset",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            try:
                _insert_adoption_project_reset_audit(
                    conn,
                    reset_id=reset_id,
                    project_id=payload.project_id,
                    requested_by=requested_by,
                    reason=reason,
                    scopes=scopes,
                    dry_run=bool(payload.dry_run),
                    status="failed",
                    rows_preview=preview,
                    rows_deleted={"tables": deleted_tables},
                    error_message=str(exc)[:2000],
                )
            except Exception:
                pass
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/project-reset",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


@app.post("/v1/adoption/bootstrap-profile/apply", response_model=None)
def apply_adoption_bootstrap_profile(
    payload: AdoptionBootstrapProfileApplyRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    project_id = str(payload.project_id or "").strip()
    if not project_id:
        raise HTTPException(status_code=422, detail="project_id_required")

    profile = _normalize_adoption_bootstrap_profile(payload.profile)
    updated_by = str(payload.updated_by or "").strip() or "ops_admin"
    note = str(payload.note or "").strip() or None
    dry_run = bool(payload.dry_run)

    if not dry_run:
        confirm_value = str(payload.confirm_project_id or "").strip()
        if not confirm_value or confirm_value != project_id:
            raise HTTPException(
                status_code=422,
                detail={
                    "error": "bootstrap_profile_confirmation_required",
                    "message": "For non-dry-run apply, `confirm_project_id` must exactly match `project_id`.",
                    "project_id": project_id,
                },
            )

    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint="/v1/adoption/bootstrap-profile/apply",
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        try:
            current_payload = get_gatekeeper_config(project_id=project_id)
            current_config = current_payload.get("config") if isinstance(current_payload, dict) else {}
            if not isinstance(current_config, dict):
                current_config = {}
            recommendation_payload = get_wiki_bootstrap_approve_recommendation(project_id=project_id)
            recommendation = (
                recommendation_payload.get("recommended") if isinstance(recommendation_payload, dict) else {}
            )
            recommendation_diagnostics = (
                recommendation_payload.get("diagnostics") if isinstance(recommendation_payload, dict) else {}
            )
            if not isinstance(recommendation, dict):
                recommendation = {}
            if not isinstance(recommendation_diagnostics, dict):
                recommendation_diagnostics = {}

            target_config = _build_adoption_bootstrap_profile_target_config(
                profile=profile,
                current_config=current_config,
            )
            config_diff = _build_adoption_bootstrap_profile_diff(
                current_config=current_config,
                target_config=target_config,
            )
            response_base: dict[str, Any] = {
                "project_id": project_id,
                "profile": profile,
                "updated_by": updated_by,
                "dry_run": dry_run,
                "gatekeeper": {
                    "current": _adoption_bootstrap_profile_gatekeeper_excerpt(current_config),
                    "target": _adoption_bootstrap_profile_gatekeeper_excerpt(target_config),
                    "diff": config_diff,
                },
                "bootstrap_recommendation": recommendation,
                "diagnostics": recommendation_diagnostics,
                "safety": {
                    "confirm_required_for_apply": True,
                    "rollback_hint": {
                        "gatekeeper_snapshots_endpoint": (
                            f"/v1/gatekeeper/config/snapshots?project_id={quote(project_id)}&source=manual"
                        ),
                        "rollback_preview_endpoint": "/v1/gatekeeper/config/rollback/preview",
                        "bootstrap_approve_endpoint": "/v1/wiki/drafts/bootstrap-approve/run",
                    },
                },
                "generated_at": datetime.now(UTC).isoformat(),
            }

            if dry_run:
                response = {
                    "status": "dry_run",
                    **response_base,
                    "next_action": "rerun_with_dry_run=false_and_confirm_project_id",
                }
                mark_request_completed(
                    conn,
                    endpoint="/v1/adoption/bootstrap-profile/apply",
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response

            upsert_payload = _normalize_gatekeeper_config_for_apply(
                project_id=project_id,
                config=target_config,
                updated_by=updated_by,
            )
            upsert_result = upsert_gatekeeper_config(upsert_payload)
            applied_config = upsert_result.get("config") if isinstance(upsert_result, dict) else {}
            if not isinstance(applied_config, dict):
                applied_config = target_config

            snapshot_id: str | None = None
            snapshot_warning: str | None = None
            if _public_table_exists(conn, "gatekeeper_config_snapshots"):
                try:
                    snapshot_result = create_gatekeeper_config_snapshot(
                        GatekeeperConfigSnapshotCreateRequest(
                            project_id=project_id,
                            approved_by=updated_by,
                            source="manual",
                            note=note or f"Adoption bootstrap profile '{profile}' applied.",
                            config=applied_config,
                            artifact_refs={
                                "adoption": {
                                    "profile": profile,
                                    "recommended_bootstrap": recommendation,
                                }
                            },
                        )
                    )
                    snapshot_id = (
                        snapshot_result.get("snapshot", {}).get("id")
                        if isinstance(snapshot_result, dict)
                        else None
                    )
                except Exception as exc:  # pragma: no cover
                    snapshot_warning = str(exc)
            else:
                snapshot_warning = "gatekeeper_config_snapshots table is unavailable; snapshot skipped."

            response = {
                "status": "applied",
                **response_base,
                "dry_run": False,
                "gatekeeper": {
                    **response_base["gatekeeper"],
                    "applied": _adoption_bootstrap_profile_gatekeeper_excerpt(applied_config),
                },
                "snapshot_id": snapshot_id,
            }
            if snapshot_warning:
                response["warning"] = snapshot_warning

            mark_request_completed(
                conn,
                endpoint="/v1/adoption/bootstrap-profile/apply",
                idempotency_key=idempotency_key,
                status_code=200,
                response_body=response,
            )
            return response
        except Exception as exc:
            mark_request_failed(
                conn,
                endpoint="/v1/adoption/bootstrap-profile/apply",
                idempotency_key=idempotency_key,
                error_message=str(exc),
            )
            raise


