@app.get("/v1/agents")
def list_agent_directory(
    project_id: str,
    status: str | None = Query(default=None, pattern="^(active|idle|paused|offline|retired)$"),
    team: str | None = Query(default=None),
    limit: int = Query(default=100, ge=1, le=500),
) -> Any:
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            return {"profiles": [], "summary": {"total": 0, "status_counts": {}, "team_counts": {}}}
        filters = ["project_id = %s"]
        params: list[Any] = [project_id]
        if isinstance(status, str) and status.strip():
            filters.append("status = %s")
            params.append(status.strip().lower())
        normalized_team = str(team or "").strip()
        if normalized_team:
            filters.append("lower(COALESCE(team, '')) = lower(%s)")
            params.append(normalized_team)
        params.append(int(limit))
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT
                  id,
                  project_id,
                  agent_id,
                  display_name,
                  team,
                  role,
                  status,
                  responsibilities,
                  tools,
                  data_sources,
                  limits,
                  metadata,
                  created_by,
                  updated_by,
                  last_seen_at,
                  created_at,
                  updated_at
                FROM agent_directory_profiles
                WHERE {' AND '.join(filters)}
                ORDER BY
                  CASE status
                    WHEN 'active' THEN 0
                    WHEN 'idle' THEN 1
                    WHEN 'paused' THEN 2
                    WHEN 'offline' THEN 3
                    ELSE 4
                  END,
                  updated_at DESC
                LIMIT %s
                """,
                tuple(params),
            )
            rows = cur.fetchall() or []
            profiles = [_serialize_agent_profile_row(row) for row in rows]
            cur.execute(
                """
                SELECT status, COUNT(*)::int
                FROM agent_directory_profiles
                WHERE project_id = %s
                GROUP BY status
                """,
                (project_id,),
            )
            status_rows = cur.fetchall() or []
            status_counts = {str(row[0]): int(row[1]) for row in status_rows if row and row[0]}
            cur.execute(
                """
                SELECT COALESCE(NULLIF(trim(team), ''), 'Unassigned') AS team_name, COUNT(*)::int
                FROM agent_directory_profiles
                WHERE project_id = %s
                GROUP BY team_name
                ORDER BY COUNT(*) DESC, team_name ASC
                LIMIT 50
                """,
                (project_id,),
            )
            team_rows = cur.fetchall() or []
            team_counts = {str(row[0]): int(row[1]) for row in team_rows if row and row[0]}
    return {
        "profiles": profiles,
        "summary": {
            "total": len(profiles),
            "status_counts": status_counts,
            "team_counts": team_counts,
        },
    }


@app.get("/v1/agents/orgchart")
def get_agent_orgchart(
    project_id: str,
    include_handoffs: bool = Query(default=True),
    include_retired: bool = Query(default=False),
    max_agents: int = Query(default=1000, ge=1, le=5000),
    max_edges: int = Query(default=2000, ge=1, le=10000),
) -> Any:
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            with conn.cursor() as cur:
                matrix = _build_runtime_agent_capability_matrix(
                    cur,
                    project_id=project_id,
                    max_agents=max_agents,
                )
            nodes = [
                {
                    "agent_id": str(item.get("agent_id") or ""),
                    "display_name": str(item.get("display_name") or item.get("agent_id") or "Agent"),
                    "team": str(item.get("team") or "Runtime Agents"),
                    "role": str(item.get("role") or "Runtime Agent"),
                    "status": str(item.get("status") or "active"),
                    "profile_slug": f"agents/{_slugify_segment(str(item.get('agent_id') or 'agent'))}",
                    "last_seen_at": str(item.get("last_success_at") or ""),
                    "source": "runtime_inferred",
                }
                for item in matrix
                if str(item.get("agent_id") or "").strip()
            ]
            team_counts: dict[str, int] = {}
            for node in nodes:
                team_name = str(node.get("team") or "Runtime Agents")
                team_counts[team_name] = int(team_counts.get(team_name, 0)) + 1
            teams = [
                {"team": team, "agents_total": total}
                for team, total in sorted(team_counts.items(), key=lambda item: (-item[1], item[0].lower()))
            ]
            return {
                "nodes": nodes,
                "edges": [],
                "teams": teams,
                "summary": {"nodes_total": len(nodes), "edges_total": 0, "teams_total": len(teams)},
                "source": "runtime_inferred",
            }
        with conn.cursor() as cur:
            filters = ["project_id = %s"]
            params: list[Any] = [project_id]
            if not include_retired:
                filters.append("status <> 'retired'")
            params.append(int(max_agents))
            cur.execute(
                f"""
                SELECT
                  agent_id,
                  display_name,
                  team,
                  role,
                  status,
                  last_seen_at,
                  updated_at
                FROM agent_directory_profiles
                WHERE {' AND '.join(filters)}
                ORDER BY
                  COALESCE(NULLIF(trim(team), ''), 'zzz') ASC,
                  COALESCE(NULLIF(trim(role), ''), 'zzz') ASC,
                  updated_at DESC
                LIMIT %s
                """,
                tuple(params),
            )
            rows = cur.fetchall() or []
            nodes: list[dict[str, Any]] = []
            team_counts: dict[str, int] = {}
            node_ids: set[str] = set()
            for row in rows:
                agent_id = str(row[0] or "").strip()
                if not agent_id:
                    continue
                display_name = str(row[1] or agent_id).strip() or agent_id
                team = str(row[2] or "").strip() or "Unassigned"
                role = str(row[3] or "").strip() or "Agent"
                status = str(row[4] or "active").strip() or "active"
                last_seen_at_value = row[5] or row[6]
                node_ids.add(agent_id)
                team_counts[team] = int(team_counts.get(team, 0)) + 1
                nodes.append(
                    {
                        "agent_id": agent_id,
                        "display_name": display_name,
                        "team": team,
                        "role": role,
                        "status": status,
                        "profile_slug": f"agents/{_slugify_segment(agent_id)}",
                        "last_seen_at": last_seen_at_value.isoformat() if last_seen_at_value is not None else None,
                    }
                )
            edges: list[dict[str, Any]] = []
            if include_handoffs:
                handoffs = _build_agent_handoff_map(
                    cur,
                    project_id=project_id,
                    max_edges=max_edges,
                    include_retired=include_retired,
                )
                for edge in handoffs:
                    from_agent = str(edge.get("from_agent") or "").strip()
                    to_agent = str(edge.get("to_agent") or "").strip()
                    if not from_agent or not to_agent:
                        continue
                    if from_agent not in node_ids or to_agent not in node_ids:
                        continue
                    edges.append(
                        {
                            "from_agent": from_agent,
                            "to_agent": to_agent,
                            "input_contract": edge.get("input_contract"),
                            "output_contract": edge.get("output_contract"),
                            "sla": edge.get("sla"),
                        }
                    )
            if not rows:
                matrix = _build_runtime_agent_capability_matrix(
                    cur,
                    project_id=project_id,
                    max_agents=max_agents,
                )
                nodes = [
                    {
                        "agent_id": str(item.get("agent_id") or ""),
                        "display_name": str(item.get("display_name") or item.get("agent_id") or "Agent"),
                        "team": str(item.get("team") or "Runtime Agents"),
                        "role": str(item.get("role") or "Runtime Agent"),
                        "status": str(item.get("status") or "active"),
                        "profile_slug": f"agents/{_slugify_segment(str(item.get('agent_id') or 'agent'))}",
                        "last_seen_at": str(item.get("last_success_at") or ""),
                        "source": "runtime_inferred",
                    }
                    for item in matrix
                    if str(item.get("agent_id") or "").strip()
                ]
                edges = []
                team_counts = {}
                for node in nodes:
                    team_name = str(node.get("team") or "Runtime Agents")
                    team_counts[team_name] = int(team_counts.get(team_name, 0)) + 1
    teams = [
        {"team": team, "agents_total": count}
        for team, count in sorted(team_counts.items(), key=lambda item: (-item[1], item[0].lower()))
    ]
    return {
        "nodes": nodes,
        "edges": edges,
        "teams": teams,
        "summary": {
            "nodes_total": len(nodes),
            "edges_total": len(edges),
            "teams_total": len(teams),
        },
    }


def _infer_reflection_claim_category(text: str, *, default: str = "operations") -> str:
    normalized = _normalize_statement_text(text)
    if any(token in normalized for token in ("decision", "decided", "approved", "rejected", "rollback", "owner")):
        return "decision"
    if any(token in normalized for token in ("if ", "when ", "then ", "runbook", "playbook", "process", "procedure", "escalat")):
        return "process"
    if any(token in normalized for token in ("policy", "required", "must", "forbidden", "access rule", "guardrail")):
        return "policy"
    if any(token in normalized for token in ("capability", "tool", "tooling", "data source", "handoff")):
        return "capability"
    return default


def _build_agent_reflection_claim_payloads(
    payload: AgentReflectionSubmitRequest,
    *,
    observed_at: datetime,
) -> list[dict[str, Any]]:
    claims: list[dict[str, Any]] = []
    base_metadata = {
        "reflection": {
            "outcome": payload.outcome,
            "summary": payload.summary,
            "what_changed": list(payload.what_changed or [])[:20],
            "durable_rules": list(payload.durable_rules or [])[:20],
            "learned_rules": list(payload.learned_rules or [])[:20],
            "follow_up_questions": list(payload.follow_up_questions or [])[:20],
            "follow_up_actions": list(payload.follow_up_actions or [])[:20],
            "uncertainties": list(payload.uncertainties or [])[:20],
            "tools_used": list(payload.tools_used or [])[:20],
            "data_sources_used": list(payload.data_sources_used or [])[:20],
            "actions_taken": list(payload.actions_taken or [])[:20],
            "escalations": list(payload.escalations or [])[:20],
            "reflected_by": payload.reflected_by,
            "task_id": payload.task_id,
            "session_id": payload.session_id,
        }
    }
    evidence = [
        {
            "source_type": "human_note",
            "source_id": f"reflection:{payload.agent_id}:{payload.task_id or payload.session_id or observed_at.date().isoformat()}",
            "session_id": payload.session_id,
            "snippet": payload.summary[:280],
            "observed_at": observed_at.isoformat(),
            "tool_name": "agent_reflection",
            "url": None,
            "agent_id": payload.agent_id,
        }
    ]

    def _append_claim(
        *,
        claim_text: str,
        category: str,
        entity_key: str,
        confidence: float | None = None,
        metadata_patch: dict[str, Any] | None = None,
    ) -> None:
        normalized_text = str(claim_text or "").strip()
        if len(normalized_text) < 4:
            return
        metadata = _deep_merge_dict(dict(base_metadata), dict(metadata_patch or {}))
        claims.append(
            {
                "id": str(uuid4()),
                "schema_version": "v1",
                "project_id": payload.project_id,
                "entity_key": entity_key,
                "category": category,
                "claim_text": normalized_text[:4000],
                "status": "draft",
                "confidence": confidence,
                "metadata": metadata,
                "evidence": evidence,
            }
        )

    normalized_rules = _normalize_agent_directory_items(
        [*list(payload.durable_rules or []), *list(payload.learned_rules or [])],
        limit=80,
    )
    for rule in normalized_rules:
        category = _infer_reflection_claim_category(rule, default="process")
        _append_claim(
            claim_text=rule,
            category=category,
            entity_key=payload.agent_id,
            confidence=0.84,
            metadata_patch={"reflection_kind": "durable_rule"},
        )

    for decision in _normalize_agent_directory_items(list(payload.decisions_made or []), limit=80):
        _append_claim(
            claim_text=decision,
            category="decision",
            entity_key=payload.agent_id,
            confidence=0.87,
            metadata_patch={
                "reflection_kind": "decision",
                "operator_decision": {
                    "outcome": "applied",
                    "source": f"reflection://{payload.agent_id}",
                    "ticket_ids": [],
                },
            },
        )

    for item in payload.insights or []:
        if str(item.durability or "durable").strip().lower() == "temporary":
            continue
        category = _infer_reflection_claim_category(item.claim_text, default=item.category or "operations")
        _append_claim(
            claim_text=item.claim_text,
            category=category,
            entity_key=str(item.entity_key or payload.agent_id).strip() or payload.agent_id,
            confidence=item.confidence if item.confidence is not None else (0.75 if item.durability == "episodic" else 0.82),
            metadata_patch={
                "reflection_kind": "insight",
                "insight_durability": item.durability,
                **(item.metadata or {}),
            },
        )

    normalized_actions_taken = _normalize_agent_directory_items(
        [*list(payload.actions_taken or []), *list(payload.follow_up_actions or [])],
        limit=10,
    )
    if normalized_actions_taken or payload.tools_used or payload.data_sources_used:
        action_text = "; ".join(normalized_actions_taken[:6]) or "performed workflow actions"
        tool_text = ", ".join(_normalize_agent_directory_items(list(payload.tools_used or []), limit=6)) or "runtime tools"
        source_text = ", ".join(_normalize_agent_directory_items(list(payload.data_sources_used or []), limit=6)) or "runtime sources"
        capability_claim = f"Agent {payload.agent_id} can {action_text} using tools {tool_text} and data sources {source_text}."
        _append_claim(
            claim_text=capability_claim,
            category="capability",
            entity_key=payload.agent_id,
            confidence=0.78,
            metadata_patch={"reflection_kind": "capability_summary"},
        )
    return claims


@app.post("/v1/agents/reflections", response_model=None)
def submit_agent_reflection(
    payload: AgentReflectionSubmitRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = "/v1/agents/reflections"
    observed_at = payload.observed_at or datetime.now(UTC)
    claims = _build_agent_reflection_claim_payloads(payload, observed_at=observed_at)
    reflection_event_id = str(uuid4())
    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                if _public_table_exists(conn, "events"):
                    cur.execute(
                        """
                        INSERT INTO events (
                          id, project_id, agent_id, session_id, event_type, payload, observed_at
                        )
                        VALUES (%s, %s, %s, %s, 'system_signal', %s, %s)
                        ON CONFLICT (id) DO NOTHING
                        """,
                        (
                            reflection_event_id,
                            payload.project_id,
                            payload.agent_id,
                            payload.session_id,
                            Jsonb(
                                {
                                    "reflection": payload.model_dump(mode="json"),
                                    "source_system": "agent_reflection",
                                    "_tags": ["reflection", "debrief", f"agent:{payload.agent_id}"],
                                }
                            ),
                            observed_at,
                        ),
                    )

                queued = 0
                for claim_payload in claims:
                    cur.execute(
                        """
                        INSERT INTO claim_proposals (claim_id, project_id, claim_payload, status)
                        VALUES (%s, %s, %s, 'queued')
                        ON CONFLICT (claim_id) DO UPDATE
                        SET claim_payload = EXCLUDED.claim_payload,
                            status = 'queued',
                            updated_at = NOW()
                        """,
                        (
                            claim_payload["id"],
                            payload.project_id,
                            Jsonb(claim_payload),
                        ),
                    )
                    queued += 1

                agent_profile_updated = False
                if payload.update_agent_profile and _agent_directory_table_exists(conn):
                    cur.execute(
                        """
                        SELECT tools, data_sources, metadata
                        FROM agent_directory_profiles
                        WHERE project_id = %s
                          AND lower(agent_id) = lower(%s)
                        LIMIT 1
                        """,
                        (payload.project_id, payload.agent_id),
                    )
                    row = cur.fetchone()
                    if row is not None:
                        existing_tools = row[0] if isinstance(row[0], list) else []
                        existing_sources = row[1] if isinstance(row[1], list) else []
                        existing_metadata = row[2] if isinstance(row[2], dict) else {}
                        merged_tools = _normalize_agent_directory_items([*existing_tools, *list(payload.tools_used or [])], limit=300)
                        merged_sources = _normalize_agent_directory_items([*existing_sources, *list(payload.data_sources_used or [])], limit=300)
                        next_metadata = dict(existing_metadata)
                        next_metadata["latest_reflection"] = {
                            "summary": payload.summary[:400],
                            "outcome": payload.outcome,
                            "observed_at": observed_at.isoformat(),
                            "task_id": payload.task_id,
                            "actions_taken": normalized_actions_taken[:10],
                            "escalations": list(payload.escalations or [])[:10],
                            "uncertainties": list(payload.uncertainties or [])[:10],
                        }
                        cur.execute(
                            """
                            UPDATE agent_directory_profiles
                            SET tools = %s,
                                data_sources = %s,
                                metadata = %s,
                                updated_by = %s,
                                last_seen_at = %s,
                                updated_at = NOW()
                            WHERE project_id = %s
                              AND lower(agent_id) = lower(%s)
                            """,
                            (
                                Jsonb(merged_tools),
                                Jsonb(merged_sources),
                                Jsonb(next_metadata),
                                payload.reflected_by,
                                observed_at,
                                payload.project_id,
                                payload.agent_id,
                            ),
                        )
                        agent_profile_updated = cur.rowcount > 0

                response = {
                    "status": "ok",
                    "project_id": payload.project_id,
                    "agent_id": payload.agent_id,
                    "event_id": reflection_event_id,
                    "queued_claims": queued,
                    "decision_claims": len([item for item in claims if str(item.get("category") or "") == "decision"]),
                    "capability_claims": len([item for item in claims if str(item.get("category") or "") == "capability"]),
                    "agent_profile_updated": agent_profile_updated,
                    "generated_at": datetime.now(UTC).isoformat(),
                }
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.post("/v1/agents/register", response_model=None)
def register_agent_directory_profile(
    payload: AgentDirectoryRegisterRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = "/v1/agents/register"
    request_payload = payload.model_dump(mode="json")
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            return JSONResponse(
                status_code=409,
                content={
                    "error": "agent_directory_unavailable",
                    "detail": "Run DB migration 051_agent_directory.sql before registering agent profiles.",
                },
            )
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                agent_id = str(payload.agent_id or "").strip()
                if not agent_id:
                    raise HTTPException(status_code=422, detail="agent_id_required")
                display_name = str(payload.display_name or "").strip() or agent_id
                status = str(payload.status or "active").strip().lower()
                if status not in _AGENT_DIRECTORY_ALLOWED_STATUSES:
                    status = "active"
                responsibilities = _normalize_agent_directory_items(payload.responsibilities, limit=120)
                tools = _normalize_agent_directory_items(payload.tools, limit=200)
                data_sources = _normalize_agent_directory_items(payload.data_sources, limit=200)
                limits = _normalize_agent_directory_items(payload.limits, limit=120)
                metadata = payload.metadata if isinstance(payload.metadata, dict) else {}
                team = str(payload.team or "").strip() or None
                role = str(payload.role or "").strip() or None
                actor = str(payload.updated_by or "synapse_agent").strip() or "synapse_agent"
                resolved_last_seen = payload.last_seen_at or datetime.now(UTC)

                cur.execute(
                    """
                    INSERT INTO agent_directory_profiles (
                      id,
                      project_id,
                      agent_id,
                      display_name,
                      team,
                      role,
                      status,
                      responsibilities,
                      tools,
                      data_sources,
                      limits,
                      metadata,
                      created_by,
                      updated_by,
                      last_seen_at,
                      created_at,
                      updated_at
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NOW(), NOW())
                    ON CONFLICT (project_id, agent_id) DO UPDATE
                    SET display_name = EXCLUDED.display_name,
                        team = EXCLUDED.team,
                        role = EXCLUDED.role,
                        status = EXCLUDED.status,
                        responsibilities = EXCLUDED.responsibilities,
                        tools = EXCLUDED.tools,
                        data_sources = EXCLUDED.data_sources,
                        limits = EXCLUDED.limits,
                        metadata = EXCLUDED.metadata,
                        updated_by = EXCLUDED.updated_by,
                        last_seen_at = EXCLUDED.last_seen_at,
                        updated_at = NOW()
                    """,
                    (
                        uuid4(),
                        payload.project_id,
                        agent_id,
                        display_name,
                        team,
                        role,
                        status,
                        Jsonb(responsibilities),
                        Jsonb(tools),
                        Jsonb(data_sources),
                        Jsonb(limits),
                        Jsonb(metadata),
                        actor,
                        actor,
                        resolved_last_seen,
                    ),
                )
                cur.execute(
                    """
                    SELECT
                      id,
                      project_id,
                      agent_id,
                      display_name,
                      team,
                      role,
                      status,
                      responsibilities,
                      tools,
                      data_sources,
                      limits,
                      metadata,
                      created_by,
                      updated_by,
                      last_seen_at,
                      created_at,
                      updated_at
                    FROM agent_directory_profiles
                    WHERE project_id = %s
                      AND agent_id = %s
                    LIMIT 1
                    """,
                    (payload.project_id, agent_id),
                )
                row = cur.fetchone()
                if row is None:
                    raise HTTPException(status_code=500, detail="agent_directory_upsert_failed")
                profile = _serialize_agent_profile_row(row)
                page_sync = _sync_agent_directory_pages(
                    cur,
                    project_id=payload.project_id,
                    actor=actor,
                    profile=profile,
                    ensure_scaffold=bool(payload.ensure_scaffold),
                    include_daily_report_stub=bool(payload.include_daily_report_stub),
                )
                response = {
                    "status": "ok",
                    "profile": profile,
                    "page_sync": page_sync,
                }
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.get("/v1/agents/publish-policy")
def get_agent_publish_policy(project_id: str, agent_id: str) -> Any:
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            return JSONResponse(status_code=409, content={"error": "agent_directory_unavailable"})
        with conn.cursor() as cur:
            policy = _load_agent_publish_policy(cur, project_id=project_id, agent_id=agent_id)
    return {
        "project_id": project_id,
        "agent_id": agent_id,
        "policy": policy,
    }


@app.put("/v1/agents/publish-policy", response_model=None)
def upsert_agent_publish_policy(
    payload: AgentPublishPolicyUpsertRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = "/v1/agents/publish-policy"
    request_payload = payload.model_dump(mode="json")
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            return JSONResponse(status_code=409, content={"error": "agent_directory_unavailable"})
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                normalized_policy = _normalize_agent_publish_policy(
                    {
                        "default_mode": payload.default_mode,
                        "by_page_type": payload.by_page_type or {},
                    }
                )
                cur.execute(
                    """
                    SELECT metadata
                    FROM agent_directory_profiles
                    WHERE project_id = %s
                      AND lower(agent_id) = lower(%s)
                    LIMIT 1
                    """,
                    (payload.project_id, payload.agent_id),
                )
                row = cur.fetchone()
                if row is None:
                    response = {
                        "error": "agent_profile_not_found",
                        "project_id": payload.project_id,
                        "agent_id": payload.agent_id,
                    }
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=404,
                        response_body=response,
                    )
                    return JSONResponse(status_code=404, content=response)
                metadata = row[0] if isinstance(row[0], dict) else {}
                metadata["publish_policy"] = normalized_policy
                metadata["publish_policy_updated_by"] = payload.updated_by
                metadata["publish_policy_updated_at"] = datetime.now(UTC).isoformat()
                cur.execute(
                    """
                    UPDATE agent_directory_profiles
                    SET metadata = %s,
                        updated_by = %s,
                        updated_at = NOW()
                    WHERE project_id = %s
                      AND lower(agent_id) = lower(%s)
                    """,
                    (
                        Jsonb(metadata),
                        payload.updated_by,
                        payload.project_id,
                        payload.agent_id,
                    ),
                )
                response = {
                    "status": "ok",
                    "project_id": payload.project_id,
                    "agent_id": payload.agent_id,
                    "policy": normalized_policy,
                    "updated_by": payload.updated_by,
                }
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.post("/v1/agents/worklogs/sync", response_model=None)
def sync_agent_daily_worklogs(
    payload: AgentDailyWorklogSyncRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = "/v1/agents/worklogs/sync"
    request_payload = payload.model_dump(mode="json")
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            return JSONResponse(status_code=409, content={"error": "agent_directory_unavailable"})
        if not _agent_daily_worklogs_table_exists(conn):
            return JSONResponse(
                status_code=409,
                content={
                    "error": "agent_daily_worklogs_unavailable",
                    "detail": "Run DB migration 052_agent_daily_worklogs.sql before syncing worklogs.",
                },
            )
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )
        with conn.cursor() as cur:
            try:
                target_timezone = _resolve_agent_worklog_timezone(
                    conn,
                    project_id=payload.project_id,
                    override_timezone=payload.timezone,
                )
                target_date = _resolve_agent_worklog_target_date(
                    requested_date=payload.worklog_date,
                    timezone_name=target_timezone,
                )
                agent_filters = ["project_id = %s"]
                agent_params: list[Any] = [payload.project_id]
                if not payload.include_retired:
                    agent_filters.append("status <> 'retired'")
                cur.execute(
                    f"""
                    SELECT
                      id,
                      project_id,
                      agent_id,
                      display_name,
                      team,
                      role,
                      status,
                      responsibilities,
                      tools,
                      data_sources,
                      limits,
                      metadata,
                      created_by,
                      updated_by,
                      last_seen_at,
                      created_at,
                      updated_at
                    FROM agent_directory_profiles
                    WHERE {' AND '.join(agent_filters)}
                    ORDER BY
                      CASE status
                        WHEN 'active' THEN 0
                        WHEN 'idle' THEN 1
                        WHEN 'paused' THEN 2
                        WHEN 'offline' THEN 3
                        ELSE 4
                      END,
                      updated_at DESC
                    LIMIT %s
                    """,
                    tuple([*agent_params, int(payload.max_agents)]),
                )
                profile_rows = cur.fetchall() or []
                profiles = [_serialize_agent_profile_row(row) for row in profile_rows]
                scanned = 0
                generated = 0
                profiles_with_updates = 0
                skipped_idle = 0
                skipped_trigger = 0
                updated_pages: list[str] = []
                worklog_dates: list[date] = [target_date - timedelta(days=offset) for offset in range(max(1, int(payload.days_back)))]
                for profile in profiles:
                    agent_id = str(profile.get("agent_id") or "").strip()
                    if not agent_id:
                        continue
                    profile_slug = str(profile.get("profile_slug") or f"agents/{_slugify_segment(agent_id)}")
                    scanned += 1
                    generated_for_agent = 0
                    for worklog_date in worklog_dates:
                        day_start, day_end = _agent_worklog_day_bounds_utc(
                            worklog_date=worklog_date,
                            timezone_name=target_timezone,
                        )
                        summary = _build_agent_daily_worklog_summary(
                            cur,
                            project_id=payload.project_id,
                            agent_id=agent_id,
                            day_start=day_start,
                            day_end=day_end,
                        )
                        if payload.trigger_mode == "session_close" and int(summary.get("session_close_events") or 0) <= 0:
                            skipped_trigger += 1
                            continue
                        if payload.trigger_mode == "task_close" and int(summary.get("task_close_updates") or 0) <= 0:
                            skipped_trigger += 1
                            continue
                        meaningful = _is_agent_worklog_meaningful(
                            summary,
                            min_activity_score=int(payload.min_activity_score),
                        )
                        summary["meaningful"] = bool(meaningful)
                        summary["timezone"] = target_timezone
                        summary["trigger_mode"] = payload.trigger_mode
                        summary["trigger_reason"] = payload.trigger_reason
                        if not payload.include_idle_days and not meaningful:
                            skipped_idle += 1
                            continue
                        entry_markdown = _render_agent_daily_worklog_entry(
                            profile=profile,
                            worklog_date=worklog_date,
                            summary=summary,
                        )
                        cur.execute(
                            """
                            INSERT INTO agent_daily_worklogs (
                              id,
                              project_id,
                              agent_id,
                              worklog_date,
                              summary,
                              markdown,
                              generated_by,
                              generated_at,
                              updated_at
                            )
                            VALUES (%s, %s, %s, %s, %s, %s, %s, NOW(), NOW())
                            ON CONFLICT (project_id, agent_id, worklog_date) DO UPDATE
                            SET summary = EXCLUDED.summary,
                                markdown = EXCLUDED.markdown,
                                generated_by = EXCLUDED.generated_by,
                                generated_at = NOW(),
                                updated_at = NOW()
                            """,
                            (
                                uuid4(),
                                payload.project_id,
                                agent_id,
                                worklog_date,
                                Jsonb(summary),
                                entry_markdown,
                                payload.generated_by,
                            ),
                        )
                        generated += 1
                        generated_for_agent += 1
                    if generated_for_agent > 0:
                        profiles_with_updates += 1
                    cur.execute(
                        """
                        SELECT worklog_date, markdown
                        FROM agent_daily_worklogs
                        WHERE project_id = %s
                          AND agent_id = %s
                        ORDER BY worklog_date DESC
                        LIMIT %s
                        """,
                        (payload.project_id, agent_id, int(payload.max_logs_per_agent_page)),
                    )
                    log_rows = cur.fetchall() or []
                    if not log_rows and generated_for_agent <= 0:
                        continue
                    report_entries = [str(item[1] or "").strip() for item in log_rows if item and item[1]]
                    reports_markdown = _render_agent_daily_reports_page(
                        display_name=str(profile.get("display_name") or agent_id),
                        entries=report_entries,
                    )
                    page_result = _upsert_wiki_page_system(
                        cur,
                        project_id=payload.project_id,
                        actor=payload.generated_by,
                        slug=f"{profile_slug}/daily-reports",
                        title=f"{profile.get('display_name') or agent_id} Daily Reports",
                        page_type="operations",
                        entity_key=agent_id,
                        markdown=reports_markdown,
                        status="published",
                        change_summary=f"Generated daily worklogs for {agent_id}",
                    )
                    page_slug = str(page_result.get("page", {}).get("slug") or "")
                    if page_slug:
                        updated_pages.append(page_slug)
                response = {
                    "status": "ok",
                    "project_id": payload.project_id,
                    "target_date": target_date.isoformat(),
                    "timezone": target_timezone,
                    "days_back": int(payload.days_back),
                    "profiles_scanned": scanned,
                    "profiles_with_updates": profiles_with_updates,
                    "worklogs_generated": generated,
                    "include_idle_days": bool(payload.include_idle_days),
                    "min_activity_score": int(payload.min_activity_score),
                    "trigger_mode": payload.trigger_mode,
                    "skipped_idle": skipped_idle,
                    "skipped_trigger": skipped_trigger,
                    "updated_daily_report_pages": sorted(set(updated_pages)),
                    "generated_by": payload.generated_by,
                }
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.get("/v1/agents/capability-matrix")
def get_agent_capability_matrix(
    project_id: str,
    min_confidence: float = Query(default=0.0, ge=0.0, le=1.0),
    max_agents: int = Query(default=500, ge=1, le=5000),
) -> Any:
    with get_conn() as conn:
        if not _agent_directory_table_exists(conn):
            return {"matrix": [], "summary": {"total": 0, "avg_confidence": 0.0}}
        if not _agent_daily_worklogs_table_exists(conn):
            return JSONResponse(
                status_code=409,
                content={
                    "error": "agent_daily_worklogs_unavailable",
                    "detail": "Run DB migration 052_agent_daily_worklogs.sql before querying capability matrix.",
                },
            )
        with conn.cursor() as cur:
            matrix = _build_agent_capability_matrix(
                cur,
                project_id=project_id,
                max_agents=max_agents,
            )
    filtered = [item for item in matrix if float(item.get("confidence") or 0.0) >= float(min_confidence)]
    avg_confidence = round(
        sum(float(item.get("confidence") or 0.0) for item in filtered) / max(1, len(filtered)),
        4,
    )
    return {
        "matrix": filtered,
        "summary": {
            "total": len(filtered),
            "avg_confidence": avg_confidence,
        },
    }


