@app.get("/v1/agents/provenance")
def list_agent_provenance(
    project_id: str,
    agent_id: str | None = Query(default=None),
    page_slug: str | None = Query(default=None),
    limit: int = Query(default=100, ge=1, le=500),
) -> Any:
    with get_conn() as conn:
        with conn.cursor() as cur:
            filters = ["p.project_id = %s"]
            params: list[Any] = [project_id]
            normalized_agent_id = str(agent_id or "").strip()
            if normalized_agent_id:
                filters.append("lower(COALESCE(v.created_by, '')) = lower(%s)")
                params.append(normalized_agent_id)
            else:
                filters.append("COALESCE(v.created_by, '') <> ''")
            normalized_slug = str(page_slug or "").strip()
            if normalized_slug:
                filters.append("p.slug = %s")
                params.append(_normalize_wiki_slug(normalized_slug, normalized_slug))
            params.append(int(limit))
            cur.execute(
                f"""
                SELECT
                  v.id::text,
                  p.id::text,
                  p.slug,
                  p.title,
                  p.page_type,
                  p.status,
                  p.current_version,
                  v.version,
                  v.source,
                  v.created_by,
                  v.change_summary,
                  v.created_at
                FROM wiki_page_versions v
                JOIN wiki_pages p ON p.id = v.page_id
                WHERE {' AND '.join(filters)}
                ORDER BY v.created_at DESC
                LIMIT %s
                """,
                tuple(params),
            )
            rows = cur.fetchall() or []
    activities = [
        _build_agent_provenance_activity(
            activity_id=str(row[0]),
            page_id=str(row[1]),
            slug=str(row[2] or ""),
            title=str(row[3] or row[2] or ""),
            page_type=str(row[4] or "operations"),
            page_status=str(row[5] or "published"),
            current_version=int(row[6] or 0),
            version=int(row[7] or 0),
            source=str(row[8] or ""),
            created_by=str(row[9] or ""),
            change_summary=str(row[10] or ""),
            created_at=row[11],
        )
        for row in rows
    ]
    rollback_ready = sum(1 for item in activities if bool(item.get("rollback", {}).get("possible")))
    return {
        "activities": activities,
        "summary": {
            "total": len(activities),
            "rollback_ready": rollback_ready,
            "agent_id": normalized_agent_id or None,
            "page_slug": _normalize_wiki_slug(normalized_slug, normalized_slug) if normalized_slug else None,
        },
    }


@app.post("/v1/agents/provenance/{activity_id}/rollback", response_model=None)
def rollback_agent_provenance_activity(
    activity_id: UUID,
    payload: AgentProvenanceRollbackRequest,
    request: Request,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  v.id::text,
                  p.id::text,
                  p.slug,
                  p.title,
                  p.page_type,
                  p.status,
                  p.current_version,
                  v.version,
                  v.source,
                  v.created_by,
                  v.change_summary,
                  v.created_at
                FROM wiki_page_versions v
                JOIN wiki_pages p ON p.id = v.page_id
                WHERE v.id = %s
                  AND p.project_id = %s
                LIMIT 1
                """,
                (activity_id, payload.project_id),
            )
            row = cur.fetchone()
            if row is None:
                return JSONResponse(
                    status_code=404,
                    content={
                        "error": "agent_activity_not_found",
                        "project_id": payload.project_id,
                        "activity_id": str(activity_id),
                    },
                )
            activity = _build_agent_provenance_activity(
                activity_id=str(row[0]),
                page_id=str(row[1]),
                slug=str(row[2] or ""),
                title=str(row[3] or row[2] or ""),
                page_type=str(row[4] or "operations"),
                page_status=str(row[5] or "published"),
                current_version=int(row[6] or 0),
                version=int(row[7] or 0),
                source=str(row[8] or ""),
                created_by=str(row[9] or ""),
                change_summary=str(row[10] or ""),
                created_at=row[11],
            )
    rollback_meta = activity.get("rollback") if isinstance(activity.get("rollback"), dict) else {}
    if not bool(rollback_meta.get("possible")):
        return JSONResponse(
            status_code=409,
            content={
                "error": "agent_activity_rollback_not_allowed",
                "project_id": payload.project_id,
                "activity": activity,
            },
        )
    if bool(payload.require_latest_activity) and int(activity.get("current_version") or 0) != int(activity.get("version") or 0):
        return JSONResponse(
            status_code=409,
            content={
                "error": "agent_activity_not_latest_on_page",
                "project_id": payload.project_id,
                "activity": activity,
            },
        )
    target_version = int(rollback_meta.get("target_version") or 0)
    if target_version <= 0:
        return JSONResponse(
            status_code=409,
            content={
                "error": "agent_activity_rollback_target_invalid",
                "project_id": payload.project_id,
                "activity": activity,
            },
        )
    rollback_summary = (
        payload.change_summary.strip()
        if isinstance(payload.change_summary, str) and payload.change_summary.strip()
        else None
    ) or (
        f"One-click rollback of activity {activity.get('activity_id')} "
        f"(agent={activity.get('created_by') or 'unknown'}) by {payload.rolled_back_by}"
    )
    wiki_payload = WikiPageRollbackRequest(
        project_id=payload.project_id,
        rolled_back_by=payload.rolled_back_by,
        target_version=target_version,
        status=payload.status or str(activity.get("page_status") or "published"),
        change_summary=rollback_summary,
    )
    rollback_result = rollback_wiki_page(
        slug=str(activity.get("slug") or ""),
        payload=wiki_payload,
        request=request,
        idempotency_key=(
            f"{idempotency_key}:agent-activity:{str(activity_id)}"
            if isinstance(idempotency_key, str) and idempotency_key.strip()
            else None
        ),
    )
    if isinstance(rollback_result, JSONResponse):
        return rollback_result
    if isinstance(rollback_result, dict):
        rollback_result["agent_activity"] = activity
        rollback_result["agent_activity_rollback"] = {
            "activity_id": str(activity_id),
            "target_version": target_version,
            "rolled_back_by": payload.rolled_back_by,
        }
    return rollback_result


@app.get("/v1/tasks")
def list_tasks(
    project_id: str,
    status: str | None = Query(default=None, pattern="^(todo|in_progress|blocked|done|canceled)$"),
    assignee: str | None = Query(default=None),
    entity_key: str | None = Query(default=None),
    include_closed: bool = Query(default=False),
    limit: int = Query(default=100, ge=1, le=500),
) -> dict[str, Any]:
    filters = ["project_id = %s"]
    params: list[Any] = [project_id]
    if status is not None:
        filters.append("status = %s")
        params.append(status)
    elif not include_closed:
        filters.append("status = ANY(%s)")
        params.append(list(_TASK_ACTIVE_STATUSES))

    normalized_assignee = assignee.strip() if isinstance(assignee, str) else ""
    if normalized_assignee:
        filters.append("assignee = %s")
        params.append(normalized_assignee)

    normalized_entity = entity_key.strip().lower() if isinstance(entity_key, str) else ""
    if normalized_entity:
        filters.append("lower(COALESCE(entity_key, '')) = %s")
        params.append(normalized_entity)

    params.append(limit)
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                f"""
                SELECT
                  id::text,
                  project_id,
                  title,
                  description,
                  status,
                  priority,
                  source,
                  assignee,
                  entity_key,
                  category,
                  due_at,
                  created_by,
                  metadata,
                  updated_by,
                  created_at,
                  updated_at
                FROM synapse_tasks
                WHERE {' AND '.join(filters)}
                ORDER BY
                  CASE status
                    WHEN 'in_progress' THEN 0
                    WHEN 'blocked' THEN 1
                    WHEN 'todo' THEN 2
                    WHEN 'done' THEN 3
                    ELSE 4
                  END,
                  CASE priority
                    WHEN 'critical' THEN 0
                    WHEN 'high' THEN 1
                    WHEN 'normal' THEN 2
                    ELSE 3
                  END,
                  updated_at DESC
                LIMIT %s
                """,
                tuple(params),
            )
            rows = cur.fetchall()
    return {"tasks": [_serialize_task_row(row) for row in rows]}


@app.get("/v1/tasks/{task_id}")
def get_task(
    task_id: UUID,
    project_id: str,
    events_limit: int = Query(default=100, ge=0, le=500),
    links_limit: int = Query(default=100, ge=0, le=500),
) -> Any:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  id::text,
                  project_id,
                  title,
                  description,
                  status,
                  priority,
                  source,
                  assignee,
                  entity_key,
                  category,
                  due_at,
                  created_by,
                  metadata,
                  updated_by,
                  created_at,
                  updated_at
                FROM synapse_tasks
                WHERE id = %s
                  AND project_id = %s
                LIMIT 1
                """,
                (task_id, project_id),
            )
            row = cur.fetchone()
            if row is None:
                return JSONResponse(status_code=404, content={"error": "task_not_found"})

            events: list[dict[str, Any]] = []
            if events_limit > 0:
                cur.execute(
                    """
                    SELECT
                      id::text,
                      task_id::text,
                      project_id,
                      event_type,
                      actor,
                      payload,
                      created_at
                    FROM synapse_task_events
                    WHERE task_id = %s
                    ORDER BY created_at DESC
                    LIMIT %s
                    """,
                    (task_id, events_limit),
                )
                events = [_serialize_task_event_row(item) for item in cur.fetchall()]

            links: list[dict[str, Any]] = []
            if links_limit > 0:
                cur.execute(
                    """
                    SELECT
                      id::text,
                      task_id::text,
                      project_id,
                      link_type,
                      link_ref,
                      note,
                      metadata,
                      created_by,
                      created_at
                    FROM synapse_task_links
                    WHERE task_id = %s
                    ORDER BY created_at DESC
                    LIMIT %s
                    """,
                    (task_id, links_limit),
                )
                links = [_serialize_task_link_row(item) for item in cur.fetchall()]

    return {"task": _serialize_task_row(row), "events": events, "links": links}


@app.post("/v1/tasks", response_model=None)
def upsert_task(
    payload: TaskUpsertRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = "/v1/tasks"
    request_payload = payload.model_dump(mode="json")
    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=request_payload,
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        with conn.cursor() as cur:
            try:
                resolved_task_id = payload.task_id or uuid4()
                cur.execute(
                    """
                    SELECT
                      id::text,
                      project_id,
                      title,
                      description,
                      status,
                      priority,
                      source,
                      assignee,
                      entity_key,
                      category,
                      due_at,
                      created_by,
                      metadata,
                      updated_by,
                      created_at,
                      updated_at
                    FROM synapse_tasks
                    WHERE id = %s
                      AND project_id = %s
                    LIMIT 1
                    """,
                    (resolved_task_id, payload.project_id),
                )
                existing = cur.fetchone()

                description = payload.description.strip() if isinstance(payload.description, str) else None
                assignee = payload.assignee.strip() if isinstance(payload.assignee, str) else None
                entity_key = payload.entity_key.strip() if isinstance(payload.entity_key, str) else None
                category = payload.category.strip() if isinstance(payload.category, str) else None
                updated_by = payload.updated_by or payload.created_by
                metadata = payload.metadata or {}
                operation = "created"

                if existing is None:
                    cur.execute(
                        """
                        INSERT INTO synapse_tasks (
                          id,
                          project_id,
                          title,
                          description,
                          status,
                          priority,
                          source,
                          assignee,
                          entity_key,
                          category,
                          due_at,
                          metadata,
                          created_by,
                          updated_by,
                          created_at,
                          updated_at
                        )
                        VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, NOW(), NOW())
                        """,
                        (
                            resolved_task_id,
                            payload.project_id,
                            payload.title.strip(),
                            description,
                            payload.status,
                            payload.priority,
                            payload.source,
                            assignee,
                            entity_key,
                            category,
                            payload.due_at,
                            Jsonb(metadata),
                            payload.created_by,
                            updated_by,
                        ),
                    )
                else:
                    operation = "updated"
                    cur.execute(
                        """
                        UPDATE synapse_tasks
                        SET title = %s,
                            description = %s,
                            status = %s,
                            priority = %s,
                            source = %s,
                            assignee = %s,
                            entity_key = %s,
                            category = %s,
                            due_at = %s,
                            metadata = %s,
                            updated_by = %s,
                            updated_at = NOW()
                        WHERE id = %s
                          AND project_id = %s
                        """,
                        (
                            payload.title.strip(),
                            description,
                            payload.status,
                            payload.priority,
                            payload.source,
                            assignee,
                            entity_key,
                            category,
                            payload.due_at,
                            Jsonb(metadata),
                            updated_by,
                            resolved_task_id,
                            payload.project_id,
                        ),
                    )

                cur.execute(
                    """
                    SELECT
                      id::text,
                      project_id,
                      title,
                      description,
                      status,
                      priority,
                      source,
                      assignee,
                      entity_key,
                      category,
                      due_at,
                      created_by,
                      metadata,
                      updated_by,
                      created_at,
                      updated_at
                    FROM synapse_tasks
                    WHERE id = %s
                      AND project_id = %s
                    LIMIT 1
                    """,
                    (resolved_task_id, payload.project_id),
                )
                row = cur.fetchone()
                if row is None:
                    raise HTTPException(status_code=500, detail="task_upsert_failed")
                serialized_task = _serialize_task_row(row)

                if existing is None:
                    _insert_task_event(
                        cur,
                        task_id=resolved_task_id,
                        project_id=payload.project_id,
                        event_type="created",
                        actor=payload.created_by,
                        payload={"task": serialized_task},
                    )
                else:
                    existing_task = _serialize_task_row(existing)
                    changed: dict[str, Any] = {}
                    for key in [
                        "title",
                        "description",
                        "status",
                        "priority",
                        "source",
                        "assignee",
                        "entity_key",
                        "category",
                        "due_at",
                        "metadata",
                    ]:
                        if existing_task.get(key) != serialized_task.get(key):
                            changed[key] = {"from": existing_task.get(key), "to": serialized_task.get(key)}

                    if changed:
                        _insert_task_event(
                            cur,
                            task_id=resolved_task_id,
                            project_id=payload.project_id,
                            event_type="updated",
                            actor=updated_by,
                            payload={"changes": changed},
                        )
                    if existing_task.get("status") != serialized_task.get("status"):
                        _insert_task_event(
                            cur,
                            task_id=resolved_task_id,
                            project_id=payload.project_id,
                            event_type="status_changed",
                            actor=updated_by,
                            payload={"from": existing_task.get("status"), "to": serialized_task.get("status")},
                        )
                    if not changed:
                        operation = "noop"

                response = {"status": operation, "task": serialized_task}
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


@app.post("/v1/tasks/{task_id}/status", response_model=None)
def update_task_status(
    task_id: UUID,
    payload: TaskStatusUpdateRequest,
    idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
) -> Any:
    endpoint = f"/v1/tasks/{task_id}/status"
    with get_conn() as conn:
        maybe_cleanup_expired_requests(conn)
        decision = acquire_request_slot(
            conn,
            endpoint=endpoint,
            idempotency_key=idempotency_key,
            request_payload=payload.model_dump(mode="json"),
        )
        if decision.mode == "replay":
            return JSONResponse(
                status_code=decision.response_code or 200,
                content=decision.response_body or {},
                headers={"X-Idempotent-Replay": "true"},
            )

        with conn.cursor() as cur:
            try:
                cur.execute(
                    """
                    SELECT status
                    FROM synapse_tasks
                    WHERE id = %s
                      AND project_id = %s
                    LIMIT 1
                    """,
                    (task_id, payload.project_id),
                )
                row = cur.fetchone()
                if row is None:
                    response = {"error": "task_not_found"}
                    mark_request_completed(
                        conn,
                        endpoint=endpoint,
                        idempotency_key=idempotency_key,
                        status_code=404,
                        response_body=response,
                    )
                    return JSONResponse(status_code=404, content=response)
                previous_status = str(row[0])

                cur.execute(
                    """
                    UPDATE synapse_tasks
                    SET status = %s,
                        updated_by = %s,
                        updated_at = NOW()
                    WHERE id = %s
                      AND project_id = %s
                    """,
                    (payload.status, payload.updated_by, task_id, payload.project_id),
                )

                _insert_task_event(
                    cur,
                    task_id=task_id,
                    project_id=payload.project_id,
                    event_type="status_changed",
                    actor=payload.updated_by,
                    payload={
                        "from": previous_status,
                        "to": payload.status,
                        "note": payload.note.strip() if isinstance(payload.note, str) else None,
                    },
                )

                cur.execute(
                    """
                    SELECT
                      id::text,
                      project_id,
                      title,
                      description,
                      status,
                      priority,
                      source,
                      assignee,
                      entity_key,
                      category,
                      due_at,
                      created_by,
                      metadata,
                      updated_by,
                      created_at,
                      updated_at
                    FROM synapse_tasks
                    WHERE id = %s
                      AND project_id = %s
                    LIMIT 1
                    """,
                    (task_id, payload.project_id),
                )
                task_row = cur.fetchone()
                response = {
                    "status": "ok",
                    "changed": previous_status != payload.status,
                    "task": _serialize_task_row(task_row),
                }
                mark_request_completed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    status_code=200,
                    response_body=response,
                )
                return response
            except Exception as exc:
                mark_request_failed(
                    conn,
                    endpoint=endpoint,
                    idempotency_key=idempotency_key,
                    error_message=str(exc),
                )
                raise


