@app.get("/v1/simulator/runs/{run_id}")
def get_simulator_run(
    run_id: UUID,
    project_id: str,
    findings_limit: int = Query(default=50, ge=0, le=1000),
) -> Any:
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute(
                """
                SELECT
                  id::text,
                  project_id,
                  status,
                  mode,
                  created_by,
                  config,
                  result,
                  sessions_scanned,
                  findings_total,
                  error_message,
                  started_at,
                  finished_at,
                  created_at,
                  updated_at
                FROM agent_simulator_runs
                WHERE id = %s
                  AND project_id = %s
                LIMIT 1
                """,
                (run_id, project_id),
            )
            row = cur.fetchone()
            if row is None:
                return JSONResponse(status_code=404, content={"error": "simulator_run_not_found"})

            cur.execute(
                """
                SELECT
                  id::text,
                  session_id,
                  policy_id,
                  entity_key,
                  category,
                  impact_kind,
                  severity,
                  impact_score,
                  rationale,
                  evidence_excerpt,
                  session_first_seen,
                  session_last_seen,
                  session_event_count,
                  metadata,
                  created_at
                FROM agent_simulator_findings
                WHERE run_id = %s
                ORDER BY impact_score DESC, created_at DESC
                LIMIT %s
                """,
                (run_id, findings_limit),
            )
            finding_rows = cur.fetchall()

    findings = [
        {
            "id": item[0],
            "session_id": item[1],
            "policy_id": item[2],
            "entity_key": item[3],
            "category": item[4],
            "impact_kind": item[5],
            "severity": item[6],
            "impact_score": float(item[7]),
            "rationale": item[8],
            "evidence_excerpt": item[9],
            "session_first_seen": None if item[10] is None else item[10].isoformat(),
            "session_last_seen": None if item[11] is None else item[11].isoformat(),
            "session_event_count": int(item[12]),
            "metadata": item[13],
            "created_at": item[14].isoformat(),
        }
        for item in finding_rows
    ]
    return {
        "run": {
            "id": row[0],
            "project_id": row[1],
            "status": row[2],
            "mode": row[3],
            "created_by": row[4],
            "config": row[5],
            "result": row[6],
            "sessions_scanned": int(row[7]),
            "findings_total": int(row[8]),
            "error_message": row[9],
            "started_at": row[10].isoformat(),
            "finished_at": None if row[11] is None else row[11].isoformat(),
            "created_at": row[12].isoformat(),
            "updated_at": row[13].isoformat(),
        },
        "findings": findings,
    }
